@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');

/* Fix for Frappe/ERPNext Headers */
header.navbar, .navbar, .top-navbar, footer, .web-footer, .footer-subscribe, .footer-section { display: none !important; }

body { 
    direction: rtl; 
    margin: 0; 
    background-color: #bfeaf4; 
    font-family: 'Cairo', sans-serif; 
}

/* Container Adjustments */
.mobile-app { position: relative; min-height: 100vh; background-color: #bfeaf4; }
.mobile-app-body { padding: 1rem; padding-top: 65px !important; }
.mobile-empty-text { margin-top: 4rem; text-align: center; color: #0b1b22; font-weight: 800; opacity: 0.6; }

/* Topbar Fixed Structure */
.mobile-topbar {
    position: fixed; top: 0; left: 0; right: 0; height: 55px;
    background: rgba(255, 255, 255, 0.4); 
    border-bottom: 1px solid rgba(0,0,0,0.15);
    backdrop-filter: blur(8px);
    display: flex; justify-content: space-between; align-items: center;
    padding: 0 12px; z-index: 1100;
}
.topbar-right, .topbar-left { display: flex; align-items: center; gap: 8px; }
.topbar-text { font-weight: 900; font-size: 16px; color: #0b1b22; }

/* Icon Buttons (Yellow Circles) */
.icon-btn {
    background: #ffe26b; border: 1px solid rgba(0,0,0,0.2); border-radius: 999px;
    font-size: 18px; cursor: pointer; color: #0b1b22; width: 38px; height: 38px;
    display: flex; align-items: center; justify-content: center; padding: 0;
    box-shadow: 0 4px 10px rgba(0,0,0,0.1);
}

/* Order Cards */
.order-list { padding: 0.5rem 0.5rem 5rem 0.5rem; }
.order-card {
    background: #ffd23c; border-radius: 16px; border: 1px solid rgba(0,0,0,0.15);
    padding: 12px; margin-bottom: 10px; display: flex; align-items: center;
    cursor: pointer; box-shadow: 0 10px 30px rgba(0,0,0,0.08);
}
/* Status Pills and Colors */
.order-status-pill {
    display: inline-flex; 
    align-items: center; 
    padding: 2px 8px;
    border-radius: 12px; 
    font-size: 11px; 
    background: #e6f4ff; 
    color: #004b80;
    font-weight: 700;
}

.order-dot { 
    width: 8px; 
    height: 8px; 
    border-radius: 50%; 
    margin-left: 6px; 
}

/* Status Specific Colors */
.order-dot-green  { background: #0a7a0a; }
.order-dot-orange { background: #ff9800; }
.order-dot-red    { background: #d32f2f; }
.closed-card { border-right: 8px solid #2f8f3a !important; background: #ffffff !important; }

.order-card-customer { font-weight: 900; color: #0b1b22; font-size: 14px; }
.order-card-amount { font-weight: 900; color: #2f8f3a; font-size: 15px; }
.order-card-line2 { display: flex; justify-content: space-between; font-weight: 700; opacity: 0.8; font-size: 12px; }
.order-card-line3 { font-size: 11px; margin-top: 6px; font-weight: 600; color: #333; }
.order-card-line3 .val { font-weight: 900; color: #000; }

/* FAB (+) */
.mobile-fab {
    position: fixed; bottom: 25px; left: 20px; width: 60px; height: 60px;
    border-radius: 50%; font-size: 35px; border: 1px solid rgba(0,0,0,0.2);
    background-color: #ffd23c; color: #0b1b22; font-weight: 900;
    box-shadow: 0 8px 20px rgba(0,0,0,0.2); cursor: pointer;
    display: flex; align-items: center; justify-content: center; z-index: 1000;
}

/* Modal / Popup Styling */
.modal-overlay {
    position: fixed; inset: 0; background: rgba(0,0,0,0.4); 
    display: none; justify-content: center; align-items: center; z-index: 2000; backdrop-filter: blur(5px);
}
.modal-box {
    background: #bfeaf4; width: 90%; max-width: 400px; padding: 25px;
    border-radius: 24px; border: 1px solid rgba(0,0,0,0.2); text-align: right;
}
.modal-title { font-weight: 900; font-size: 18px; text-align: center; margin-bottom: 20px; }
.modal-btn { 
    width: 100%; border: 1px solid rgba(0,0,0,0.1); padding: 14px; 
    border-radius: 999px; font-size: 18px; font-weight: 900; cursor: pointer; font-family: 'Cairo';
}
.modal-btn-primary { background: #ffe26b; color: #0b1b22; margin-bottom: 12px; }
.modal-btn-secondary { background: #ffffff; color: #333; }
.modal-btn-cancel { background: transparent; border: none; width: 100%; margin-top: 15px; font-weight: 700; color: #666; cursor: pointer; font-family: 'Cairo'; }

/* Drawer */
.drawer { position: fixed; top: 0; right: 0; width: 260px; height: 100%; background: white; z-index: 1201; }
.drawer-header { padding: 20px; background: #ffe26b; font-weight: 900; }
.drawer-item { display: block; padding: 15px; border-bottom: 1px solid #eee; text-decoration: none; color: #333; font-weight: 700; }

.hidden { display: none !important; }
.order-card-left { 
    flex: 1; 
}

.order-card-line1 { 
    display: flex; 
    justify-content: space-between; 
    align-items: center;
    margin-bottom: 4px; 
}

.order-card-customer { 
    font-weight: 800; /* Cairo bold */
    color: #0b1b22;
    font-size: 14px; 
}

.order-card-amount { 
    font-weight: 800; 
    color: #2f8f3a; 
    font-size: 14px; 
}

