const ERPNEXT_BASE_URL = window.location.origin;

let DEFAULT_COMPANY      = null;
let DEFAULT_WAREHOUSE    = null;
let DEFAULT_PRICE_LIST   = null;
let SALESPERSON_NAME     = null;

let LOGGED_USER_EMAIL = (window.LOGGED_IN_USER && window.LOGGED_IN_USER !== "{{ frappe.session.user }}")
  ? window.LOGGED_IN_USER
  : null;

let openOrders = [];
let closedOrders = [];

// ============= HELPERS =============
function getCsrfToken() {
  if (window.frappe && frappe.csrf_token) return frappe.csrf_token;
  const meta = document.querySelector('meta[name="csrf-token"]');
  return (meta && meta.content) ? meta.content : null;
}

async function erpRequest(path, options = {}) {
  const url = path.startsWith("http") ? path : ERPNEXT_BASE_URL + path;
  const headers = Object.assign({}, options.headers || {});
  if ((options.method || "GET") !== "GET") {
    headers["Content-Type"] = "application/json";
    headers["X-Frappe-CSRF-Token"] = getCsrfToken();
  }
  const resp = await fetch(url, Object.assign({}, options, { headers, credentials: "include" }));
  const txt = await resp.text();
  if (!resp.ok) throw new Error("Status " + resp.status);
  try { return JSON.parse(txt); } catch { return txt; }
}

// ============= DATA LOADING =============
async function loadDefaultsFromERPNext() {
  try {
    const gd = await erpRequest("/api/resource/Global Defaults/Global Defaults?fields=" + encodeURIComponent(JSON.stringify(["default_company", "default_price_list"])));
    DEFAULT_COMPANY = gd.data.default_company;
    DEFAULT_PRICE_LIST = gd.data.default_price_list;
    if (LOGGED_USER_EMAIL) {
      const u = await erpRequest("/api/resource/User/" + encodeURIComponent(LOGGED_USER_EMAIL) + "?fields=[\"warehouse\",\"full_name\"]");
      DEFAULT_WAREHOUSE = u.data.warehouse;
      SALESPERSON_NAME = u.data.full_name;
    }
  } catch (e) { console.warn(e); }
}

async function loadOpenOrdersFromERPNext() {
  try {
    const fields = ["name","customer_name","transaction_date","grand_total","status","docstatus","owner"];
    // Hide completed/closed from the main list
    const filters = [["Sales Order", "docstatus", "!=", 2], ["Sales Order", "status", "not in", ["Closed", "Completed"]]];
    if (LOGGED_USER_EMAIL) filters.push(["Sales Order", "owner", "=", LOGGED_USER_EMAIL]);
    const data = await erpRequest("/api/resource/Sales Order?fields=" + encodeURIComponent(JSON.stringify(fields)) + "&filters=" + encodeURIComponent(JSON.stringify(filters)) + "&order_by=transaction_date desc");
    openOrders = data.data || [];
    renderOrdersList();
  } catch (e) { alert("فشل تحميل الطلبات"); }
}

// ============= HISTORY VIEW =============
async function loadClosedOrders() {
    closeDrawer(); 
    document.getElementById("listScreen").innerHTML = '<div class="mobile-empty-text">جاري تحميل الطلبيات المغلقة...</div>';
    try {
        const filters = [["Sales Order", "status", "in", ["Closed", "Completed"]]];
        if (LOGGED_USER_EMAIL) filters.push(["Sales Order", "owner", "=", LOGGED_USER_EMAIL]);
        const data = await erpRequest("/api/resource/Sales Order?fields=[\"name\",\"customer_name\",\"transaction_date\",\"grand_total\"]&filters=" + encodeURIComponent(JSON.stringify(filters)) + "&order_by=customer_name asc, transaction_date desc");
        closedOrders = data.data || [];
        renderClosedOrdersList();
    } catch (e) { alert("فشل التحميل"); }
}

function renderClosedOrdersList() {
    const listEl = document.getElementById("listScreen");
    listEl.innerHTML = '<h3 style="padding:10px; color:#004b80; text-align:right;">📁 الطلبيات المغلقة</h3><div id="closedList" class="order-list"></div>';
    const container = document.getElementById("closedList");
    if (!closedOrders.length) {
        container.innerHTML = '<div class="mobile-empty-text">لا توجد طلبيات مغلقة</div>';
        return;
    }
    closedOrders.forEach(order => {
        const card = document.createElement("div");
        card.className = "order-card closed-card";
        card.innerHTML = `
            <div class="order-card-left">
                <div class="order-card-line1">
                    <div class="order-card-customer">${order.customer_name}</div>
                    <div class="order-card-amount">${Number(order.grand_total).toLocaleString()} د.ل</div>
                </div>
                <div class="order-card-line2">
                    <div style="font-size:11px;">${order.transaction_date} | ${order.name}</div>
                    <button class="icon-btn" onclick="printOrderCopy('${order.name}')" style="width:auto; padding:0 10px; font-size:11px; height:30px;">📄 طباعة نسخة</button>
                </div>
            </div>`;
        container.appendChild(card);
    });
}

function printOrderCopy(name) {
    window.open(`/api/method/frappe.utils.print_format.download_pdf?doctype=Sales Order&name=${encodeURIComponent(name)}&format=ArabicPeintDraft`, '_blank');
}

// ============= RENDER MAIN LIST =============
function renderOrdersList() {
  const listEl = document.getElementById("ordersList");
  listEl.innerHTML = "";
  if (!openOrders.length) { document.getElementById("ordersEmptyText").style.display = "block"; return; }
  document.getElementById("ordersEmptyText").style.display = "none";
  openOrders.forEach(order => {
    const card = document.createElement("div");
    card.className = "order-card";
    card.innerHTML = `
        <div class="order-card-left">
            <div class="order-card-line1">
                <div class="order-card-amount">${Number(order.grand_total).toLocaleString()} د.ل</div>
                <div class="order-card-customer">${order.customer_name}</div>
            </div>
            <div class="order-card-line2">
                <div style="font-size:11px;">${order.transaction_date} | ${order.name}</div>
                <div class="order-status-pill"><span class="order-dot ${order.docstatus===1?'order-dot-green':'order-dot-orange'}"></span> ${order.status}</div>
            </div>
        </div>`;
    card.onclick = () => window.location.href = `/split_sales?order_name=${encodeURIComponent(order.name)}`;
    listEl.appendChild(card);
  });
}

// ============= UI ACTIONS =============
function showOrderTypeModal() { document.getElementById("orderTypeModal").style.display = "flex"; }
function hideOrderTypeModal() { document.getElementById("orderTypeModal").style.display = "none"; }
function navTo(type) { window.location.href = (type === 'sales') ? '/split_sales' : '/split_return'; }
function toggleDrawer() { document.getElementById("drawer").classList.toggle("hidden"); document.getElementById("drawerOverlay").classList.toggle("hidden"); }
function closeDrawer() { document.getElementById("drawer").classList.add("hidden"); document.getElementById("drawerOverlay").classList.add("hidden"); }

document.addEventListener("DOMContentLoaded", async () => {
    const fab = document.querySelector(".mobile-fab");
    if(fab) fab.onclick = showOrderTypeModal;
    await loadDefaultsFromERPNext();
    await loadOpenOrdersFromERPNext();
});

