@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');

/* --- Hide Default UI --- */
footer, .web-footer, .powered-by, .get-updates, header.navbar { display: none !important; }

:root { 
    --bg: #bfeaf4; 
    --yellow: #ffd23c; 
    --yellow2: #ffe26b; 
    --green: #2f8f3a; 
    --green2: #2aa334; 
    --shadow: 0 10px 30px rgba(0,0,0,.08); 
}

body { 
    background-color: var(--bg) !important; 
    direction: rtl; 
    font-family: "Cairo", sans-serif; 
    margin: 0; 
    color: #0b1b22;
}

/* --- Topbar --- */
.sr-topbar { 
    position: sticky; top: 0; z-index: 1100; display: flex; gap: 8px; align-items: center; 
    padding: 10px 12px; background: rgba(255,255,255,.35); 
    border-bottom: 1px solid rgba(0,0,0,.15); backdrop-filter: blur(6px); 
}
.sr-btn-icon { 
    border: 1px solid rgba(0,0,0,.25); cursor: pointer; border-radius: 999px; 
    padding: 8px 12px; font-weight: 900; font-size: 16px; 
    box-shadow: var(--shadow); background: var(--yellow2); 
}
.sr-title { font-weight: 900; font-size: 16px; flex: 1; }

/* --- Search & Pills --- */
.sr-wrap { max-width: 1100px; margin: 0 auto; padding: 12px; }

.sr-pill-search { 
    width: 100%; height: 48px; border-radius: 999px; 
    border: 1px solid rgba(0,0,0,0.2); padding: 0 20px; 
    font-family: "Cairo"; font-weight: 800; background: var(--yellow);
    box-shadow: var(--shadow); outline: none;
}

.agent-statement-btn {
    border: 1px solid rgba(0,0,0,0.1);
    background: #fff;
    color: #0b1b22;
    padding: 10px 18px;
    border-radius: 999px;
    font-weight: 900;
    cursor: pointer;
    box-shadow: var(--shadow);
}

/* --- Ledger Cards --- */
.debt-item-card { 
    background: #ffffff; margin: 0; border-radius: 12px; padding: 15px; 
    display: flex; justify-content: space-between; align-items: center; 
    border: 1px solid rgba(0,0,0,0.1);
}

.ledger-date-header {
    background: var(--green); 
    padding: 6px 15px; font-weight: 900; color: #fff; 
    font-size: 13px; margin: 15px 15px 5px 15px; border-radius: 999px;
    display: inline-flex; align-items: center; gap: 5px;
}

/* --- Swipe Functionality --- */
.swipe-row { position: relative; overflow: hidden; margin: 8px 15px; border-radius: 12px; box-shadow: var(--shadow); }
.swipe-card { position: relative; z-index: 2; transition: transform 0.2s ease; margin: 0 !important; }
.swipe-actions { position: absolute; inset: 0 auto 0 0; display: flex; gap: 8px; align-items: center; padding: 0 12px; z-index: 1; background: rgba(0,0,0,0.03); }
.swipe-row.open .swipe-card { transform: translateX(140px); }

.swipe-btn { border: none; border-radius: 999px; padding: 8px 16px; font-weight: 900; cursor: pointer; font-family: 'Cairo'; }
.edit-btn { background: var(--green); color: #fff; }
.delete-btn { background: #ef4444; color: #fff; }

/* --- FAB Button --- */
.sr-fab {
    position: fixed; bottom: 90px; left: 25px; width: 60px; height: 60px;
    border-radius: 50%; font-size: 35px; font-weight: 900;
    border: 1px solid rgba(0,0,0,0.2); z-index: 1050;
    background-color: var(--yellow); color: #0b1b22;
    box-shadow: 0 8px 20px rgba(0,0,0,0.2); cursor: pointer;
    display: flex; align-items: center; justify-content: center;
}

/* --- Modals --- */
.modal-overlay { 
    position: fixed; inset: 0; background: rgba(0,0,0,0.4); 
    display: flex; justify-content: center; align-items: center; 
    z-index: 3000; backdrop-filter: blur(4px); padding: 15px;
}
.modal-box { 
    background: var(--bg); width: 100%; max-width: 450px; 
    border-radius: 24px; border: 1px solid rgba(0,0,0,0.2); box-shadow: var(--shadow); 
    display: flex; flex-direction: column; max-height: 85vh; overflow: hidden;
}

.sr-btn { 
    border: 1px solid rgba(0,0,0,0.2); cursor: pointer; border-radius: 999px; 
    padding: 12px; font-family: "Cairo", sans-serif; font-weight: 900; 
    box-shadow: var(--shadow); background: #fff; color: #0b1b22;
}
.sr-btn.primary { background: var(--yellow2); }
.modal-btn-cancel { text-align: center; margin-top: 15px; color: #666; font-weight: 700; cursor: pointer; }

/* --- Agent Table --- */
.agent-table-wrap { overflow-y: auto; flex-grow: 1; border-top: 1px solid rgba(0,0,0,0.1); border-bottom: 1px solid rgba(0,0,0,0.1); background: #fff; }
.agent-table { width: 100%; border-collapse: collapse; }
.agent-td-label { padding: 12px 15px; border-bottom: 1px solid #f1f5f9; font-weight: 700; color: #334155; }
.agent-td-val { padding: 12px 15px; border-bottom: 1px solid #f1f5f9; direction: ltr; text-align: left; font-weight: 900; color: #0b1b22; }

/* --- Print --- */
@media print {
    body * { visibility: hidden; }
    #agentStatementModal, #agentStatementModal * { visibility: visible; }
    #agentStatementModal { position: absolute; left: 0; top: 0; width: 100%; background: white !important; }
    .modal-box { box-shadow: none !important; border: none !important; max-height: none !important; width: 100% !important; overflow: visible !important; }
    .agent-table-wrap { overflow: visible !important; }
    .sr-btn-icon, .agent-modal-actions, .modal-btn-cancel { display: none !important; }
}

.hidden { display: none !important; }

/* --- Hide Frappe Page Header (Home + Title bar) --- */
.page-head,
.page-head-content,
.page-breadcrumbs,
.breadcrumb,
.page-title,
.title-area,
.page-title .title-text,
.page-title .indicator-pill,
.page-title .btn,
.page-head .btn-home,
.page-head .btn-back {
  display: none !important;
  height: 0 !important;
  min-height: 0 !important;
  padding: 0 !important;
  margin: 0 !important;
  border: 0 !important;
}

/* Remove the empty space left behind */
.layout-main-section-wrapper,
.layout-main-section,
.page-body,
.main-section {
  padding-top: 0 !important;
  margin-top: 0 !important;
}
/* --- FORCE HIDE: Frappe Website Top Navbar (Home bar) --- */
.navbar,
.navbar.navbar-light,
.navbar.navbar-expand,
.navbar.navbar-expand-lg,
.navbar.navbar-dark,
.website-navbar,
.web-header,
.top-navbar,
.sticky-top {
  display: none !important;
  height: 0 !important;
  min-height: 0 !important;
  padding: 0 !important;
  margin: 0 !important;
  border: 0 !important;
}

/* Remove space left by the hidden navbar */
body,
.web-page,
.page-container,
.page-content-wrapper,
.main-section,
.page_content,
#page-mobile-debt,     /* safe even if not found */
#page-mobile_debt {    /* safe even if not found */
  padding-top: 0 !important;
  margin-top: 0 !important;
}

/* Some themes put an extra wrapper above content */
.navbar + .page-container,
.navbar + .container,
.navbar + .page-content-wrapper {
  margin-top: 0 !important;
  padding-top: 0 !important;
}
#navbar, .topbar, .page-head, .page-head-content { display:none !important; }

/* --- Topbar Alignment Fix --- */
.sr-topbar {
    display: flex !important;
    /* Use row-reverse to force Title (first element) to the right and Buttons (rest) to the left */
    flex-direction: row-reverse !important; 
    justify-content: space-between !important;
    align-items: center !important;
    padding: 10px 12px;
    height: 55px;
    width: 100%;
    box-sizing: border-box;
}

/* Container for buttons to keep them grouped on the left */
.topbar-buttons {
    display: flex !important;
    gap: 8px !important;
}

/* Reset title flex to prevent it from stretching */
.sr-title {
    flex: none !important;
    font-weight: 900;
    font-size: 16px;
}

/* --- Topbar Alignment Fix --- */
.sr-topbar { 
    display: flex !important;
    /* Force LTR flow for the container to pin buttons left and title right */
    flex-direction: row !important; 
    justify-content: space-between !important; 
    align-items: center !important;
    padding: 10px 15px !important;
    height: 55px;
    width: 100%;
    box-sizing: border-box;
    direction: ltr !important; 
}

/* Container for icons to keep them grouped on the left */
.topbar-left {
    display: flex !important;
    gap: 8px !important;
    direction: ltr !important;
}

/* Ensure the title stays on the right and keeps Arabic text direction */
.sr-title { 
    font-weight: 900; 
    font-size: 16px; 
    flex: none !important;
    direction: rtl !important; 
}

