frappe.ready(function () {
    let START = 0;
    const LIMIT = 20;
    let HAS_MORE = true;
    let LOADING = false;

    // Store all items loaded (for search filtering)
    let ALL_CARDS = [];

    // Initial load
    reset_and_load();
    //-------hide add button
        // Week UI Lock (hide/disable + button when outside allowed window)
    applyWeekUiLock();

    function applyWeekUiLock() {
        // Default: show button
        const $btn = $('#add-btn');
        $btn.removeClass('fab-disabled').show();

        frappe.call({
            method: "libyan_modern_trading.api.debt_week.week_allowed",   // <-- we will create this method next if not existing
            args: {},
            callback: function (r) {
                const data = (r && r.message) ? r.message : null;
                if (!data) return;

                if (!data.allowed) {
                    // Hide or disable (I recommend disable so user understands why)
                    $btn.addClass('fab-disabled');

                    // Optional: also prevent opening modal
                    $btn.off('click').on('click', function () {
                        frappe.msgprint({
                            title: "مغلق",
                            message: "🔒 لا يمكن إضافة عمليات خارج فترة الأسبوع المسموح بها.",
                            indicator: "red"
                        });
                    });
                }
            }
        });
    }


    //-------hide add button


    // Add Button
    $('#add-btn').on('click', function () {
        $('#selection-modal').removeClass('hidden');
    });

    // Search (works on rendered cards)
    $("#ledger_search").on("keyup", function () {
        let value = ($(this).val() || "").toLowerCase();
        $(".debt-item-card").each(function () {
            $(this).toggle($(this).text().toLowerCase().indexOf(value) > -1);
        });
    });

    // Infinite scroll trigger (sentinel)
    if (!document.getElementById("ledger-sentinel")) {
        $('#ledger-list').after('<div id="ledger-sentinel" style="height:1px;"></div>');
    }

    const sentinel = document.getElementById("ledger-sentinel");
    const io = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) load_more();
        });
    }, { root: null, rootMargin: "200px", threshold: 0 });

    io.observe(sentinel);

    // Refresh button (optional)
    window.reset_and_load = reset_and_load;

    function reset_and_load() {
        START = 0;
        HAS_MORE = true;
        LOADING = false;
        ALL_CARDS = [];
        $('#ledger-list').html('<div class="text-center p-5 text-muted">جاري تحميل السجل...</div>');
        load_more(true);
    }

    function load_more(isFirst = false) {
        if (LOADING || !HAS_MORE) return;
        LOADING = true;

        if (isFirst) {
            $('#ledger-list').html('<div class="text-center p-5 text-muted">...Loading...</div>');
        } else {
            if (!$('#ledger-loading').length) {
                $('#ledger-list').append('<div id="ledger-loading" class="text-center p-3 text-muted">تحميل المزيد...</div>');
            }
        }

        frappe.call({
            method: "get_debt_ledger",
            args: { start: START, limit: LIMIT },
            callback: function (r) {
                LOADING = false;
                $('#ledger-loading').remove();

                if (r && r.exc) {
                    $('#ledger-list').html(`<div style="color:red;padding:15px;direction:ltr;text-align:left;"><pre>${r.exc}</pre></div>`);
                    return;
                }
                if (!r || !r.message) {
                    $('#ledger-list').html('<div class="text-center p-5">⚠️ Empty Response</div>');
                    return;
                }
                if (r.message.__error) {
                    $('#ledger-list').html(`<div style="color:red;padding:15px;direction:ltr;text-align:left;"><pre>${r.message.__error}</pre></div>`);
                    return;
                }

                // Render append
                const grouped = r.message.ledger || {};
                append_grouped(grouped);

                // Pagination meta
                const meta = r.message.meta || {};
                HAS_MORE = !!meta.has_more;

                START += LIMIT;

                // If nothing at all (after filtering)
                if ($('.debt-item-card').length === 0 && !HAS_MORE) {
                    $('#ledger-list').html('<div class="text-center p-5">لا توجد سجلات</div>');
                }
            },
            error: function (xhr) {
                LOADING = false;
                $('#ledger-loading').remove();
                let resp = xhr.responseText || "";
                resp = resp.length > 500 ? resp.substring(0, 500) + "..." : resp;
                $('#ledger-list').html(`<div style="background:#d32f2f;color:#fff;padding:15px;direction:ltr;text-align:left;"><b>Connection Failed</b><pre style="white-space:pre-wrap;margin:0;">${resp}</pre></div>`);
            }
        });
    }

    // Filter out 'خصم تسوية' so they are hidden from the user
    function append_grouped(grouped) {
        if (!grouped || typeof grouped !== "object") return;

        // If first load and it was "loading..." text, clear it
        if ($('#ledger-list').find('.debt-item-card').length === 0 && $('#ledger-list').text().includes("Loading")) {
            $('#ledger-list').empty();
        }

        const dates = Object.keys(grouped).sort().reverse();

        let html = '';

        for (let i = 0; i < dates.length; i++) {
            const date = dates[i];
            let rows = grouped[date] || [];

            // FILTER: Remove "خصم تسوية" from the list
            rows = rows.filter(item => (item.action_type || "").trim() !== 'خصم تسوية');

            // If no rows left for this date after filtering, skip the date header too
            if (rows.length === 0) continue;

            // Date header
            if (!$(`[data-date-header="${date}"]`).length) {
                html += `<div class="ledger-date-header" data-date-header="${date}">📅 ${date}</div>`;
            }

            for (let j = 0; j < rows.length; j++) {
                const item = rows[j];
                html += render_swipe_card(item);
            }
        }

        $('#ledger-list').append(html);

        // Bind swipe + actions after append
        bind_swipe_handlers();
        bind_action_buttons();
    }

    function render_swipe_card(item) {
        // Normalize action type
        const action = (item.action_type || "").trim();
        const isDep = (action === 'ايداع');
        const isReclaim = (action === 'خصم تسوية'); 

        // Color & Sign
        const color = isDep ? '#22c55e' : '#ef4444';
        const sign = isDep ? '+' : '-';

        // 1. Handle Title
        let displayTitle = item.customer || 'سحب مندوب';
        if (isReclaim) {
            displayTitle = 'خصم تسوية';
        }

        // 2. Handle Amount (Use 'percent_cust_sum' if Reclaim)
        let displayAmount = item.amount;
        if (isReclaim) {
            displayAmount = item.percent_cust_sum;
        }

        // Status Icon Logic
        let statusIcon = '';
        if (item.docstatus === 0) statusIcon = '<span style="color:orange;font-size:10px;">Draft ✎</span>';
        if (item.docstatus === 1) statusIcon = '<span style="color:green;font-size:10px;">✔ Submitted</span>';

        return `
        <div class="swipe-row" data-name="${item.name}">
          <div class="swipe-actions">
            <button class="swipe-btn edit-btn" data-name="${item.name}">تعديل</button>
            <button class="swipe-btn delete-btn" data-name="${item.name}">حذف</button>
          </div>

          <div class="swipe-card debt-item-card shadow-sm"
               data-name="${item.name}"
               style="border-right:4px solid ${color};">
            <div style="text-align:right;">
              <div style="font-weight:bold;font-size:15px;color:#334155;">
                ${displayTitle}
              </div>
              <div style="font-size:12px;color:#94a3b8;margin-top:4px;">
                ${statusIcon} | ${item.receipt_no || item.name}
              </div>
            </div>

            <div style="text-align:left;">
              <div style="color:${color};font-weight:bold;font-size:16px;">
                ${sign} ${format_money(displayAmount)}
              </div>
              <div style="font-size:11px;color:#64748b;margin-top:2px;">
                ${item.payment_type || action}
              </div>
            </div>
          </div>
        </div>`;
    }

    function bind_action_buttons() {
        // Tap card -> open form
        $('.swipe-card').off('click').on('click', function (e) {
            if ($(this).closest('.swipe-row').hasClass('open')) return;
            const name = $(this).data('name');
            window.location.href = '/mobile-debt-form_1?name=' + encodeURIComponent(name);
        });

        // Edit
        $('.edit-btn').off('click').on('click', function (e) {
            e.stopPropagation();
            const name = $(this).data('name');
            window.location.href = '/mobile-debt-form_1?name=' + encodeURIComponent(name);
        });

        // Delete
        $('.delete-btn').off('click').on('click', function (e) {
            e.stopPropagation();
            const name = $(this).data('name');

            if (!confirm("هل أنت متأكد من حذف السجل؟")) return;

            frappe.call({
                method: "delete_debt_record",
                args: { name: name },
                callback: function (r) {
                    if (r && r.message && r.message.ok) {
                        $(`.swipe-row[data-name="${name}"]`).remove();
                        reset_and_load();
                    } else {
                        const err = (r && r.message && r.message.error) ? r.message.error : "Delete failed";
                        alert("خطأ: " + err);
                    }
                },
                error: function () {
                    alert("Delete request failed");
                }
            });
        });
    }

    function bind_swipe_handlers() {
        let startX = 0;
        let currentRow = null;

        $('.swipe-card').off('touchstart').on('touchstart', function (e) {
            startX = e.originalEvent.touches[0].clientX;
            currentRow = $(this).closest('.swipe-row');
        });

        $('.swipe-card').off('touchmove').on('touchmove', function (e) {
            if (!currentRow) return;
            const x = e.originalEvent.touches[0].clientX;
            const dx = x - startX;

            if (dx < -30) {
                $('.swipe-row').not(currentRow).removeClass('open');
                currentRow.addClass('open');
            }
            if (dx > 30) {
                currentRow.removeClass('open');
            }
        });
    }

    function format_money(amount) {
        return parseFloat(amount || 0).toLocaleString('en-US', { minimumFractionDigits: 2 }) + " د.ل";
    }

    /* ======================================================
       AGENT STATEMENT MODAL
       ====================================================== */

    function fmt_din(val) {
        return "din " + Number(val || 0).toLocaleString("en-US", {
            minimumFractionDigits: 2,
            maximumFractionDigits: 2
        });
    }

    function openAgentStatementModal() {
        frappe.call({
            method: "lmt_get_agent_statement",
            args: {},
            callback: function (r) {
                if (r && r.exc) {
                    frappe.msgprint("Agent statement error<br><small style='direction:ltr;display:block'>" + r.exc + "</small>");
                    return;
                }
                if (!r || !r.message) {
                    frappe.msgprint("Agent statement: empty response");
                    return;
                }

                const d = r.message || {};
                const meta = document.getElementById("agentStatementMeta");
                const tbody = document.getElementById("agentStatementTable");

                if (!meta || !tbody) {
                    frappe.msgprint("Agent statement UI missing");
                    return;
                }

                meta.innerText = `Agent: ${d.agent || ""} | Date: ${d.today || ""}`;

                // rows: label, value
                const rows = [
                    ["إجمالي تحصيل المندوب", fmt_din(d.total_collected_all)],
                    ["إجمالي التحصيل لهذا العام", fmt_din(d.total_collected_year)],
                    ["مجموع التحصيل لهذا الأسبوع", fmt_din(d.total_collected_week)],

                    ["مجموع سحب المندوب", fmt_din(d.total_withdraw_all)],
                    ["مجموع سحب المندوب لهذا الأسبوع", fmt_din(d.total_withdraw_week)],

                    ["مجموع نسبة المندوب", fmt_din(d.commission_all)],
                    ["مجموع نسبة المندوب لهذا الأسبوع", fmt_din(d.commission_week)],

                    // Future Row
                    ["مجموع نسبة الزبون من المندوب - في المستقبل", fmt_din(d.reclaim_future)],

                    // Past Row
                    ["مجموع نسبة الزبون من المندوب - في الماضي", fmt_din(d.reclaim_past_today)],

                    // Balance Row
                    ["المتبقي من نسبة المندوب الكلية", fmt_din(d.commission_remaining_future)]
                ];

                let html = "";
                rows.forEach(row => {
                    let valStyle = "";
                    if(row[0] === "المتبقي من نسبة المندوب الكلية") {
                         if(String(row[1]).includes("-")) valStyle = 'style="color:red"'; 
                         else valStyle = 'style="color:green"';
                    }

                    html += `
                      <tr>
                        <td class="agent-td-label">${row[0]}</td>
                        <td class="agent-td-val" ${valStyle}>${row[1]}</td>
                      </tr>
                    `;
                });

                tbody.innerHTML = html;

                $("#agentStatementModal").removeClass("hidden");
            },
            error: function (xhr) {
                let resp = xhr.responseText || "";
                resp = resp.length > 700 ? resp.substring(0, 700) + "..." : resp;
                frappe.msgprint("Agent statement request failed<br><small style='direction:ltr;display:block'>" + resp + "</small>");
            }
        });
    }

    function closeAgentStatementModal() {
        $("#agentStatementModal").addClass("hidden");
    }

    function printAgentStatementModal() {
        const box = document.querySelector("#agentStatementModal .agent-modal-box");
        if (!box) return;

        const w = window.open("", "_blank");
        w.document.write(`
          <html dir="rtl">
          <head>
            <title>Agent Statement</title>
            <meta charset="utf-8"/>
            <style>
              body{font-family:Arial;padding:16px}
              .agent-modal-head, .agent-modal-actions{display:none !important;}
              table{width:100%;border-collapse:collapse;margin-top:10px}
              td{border:1px solid #000;padding:8px}
              .agent-td-val{direction:ltr;text-align:left;font-weight:800}
              .agent-td-label{font-weight:800}
            </style>
          </head>
          <body>
            ${box.innerHTML}
          </body>
          </html>
        `);
        w.document.close();
        w.focus();
        w.print();
    }

    // Bind (safe: if button not present, no error)
    $(document).on("click", "#btnAgentStatement", function () {
        openAgentStatementModal();
    });
    $(document).on("click", "#agentStatementClose", function () {
        closeAgentStatementModal();
    });
    $(document).on("click", "#agentStatementPrint", function () {
        printAgentStatementModal();
    });

}); // end frappe.ready

// MODAL FUNCTIONS
window.closeModal = function () {
    $('#selection-modal').addClass('hidden');
};

window.goToForm = function (type) {
    window.location.href = `/mobile-debt-form_1?type=${encodeURIComponent(type)}`;
};

