@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');

/* --- Reset & Global --- */
footer, .web-footer, .page-footer, header.navbar, .navbar { display: none !important; }

:root { 
    --bg: #bfeaf4; 
    --yellow: #ffd23c; 
    --yellow2: #ffe26b; 
    --green: #2f8f3a; 
    --shadow: 0 10px 30px rgba(0,0,0,.08); 
}


body { 
    direction: rtl; 
    background-color: var(--bg) !important; 
    font-family: "Cairo", sans-serif !important; 
    margin: 0; 
    color: #0b1b22;
}
/* FORCE BACKGROUND AND TOPBAR COLORS */
body, 
.appshell, 
#appContent, 
.main-section { 
    background-color: #bfeaf4 !important; 
}

.sr-topbar, .topbar { 
    background: rgba(255, 255, 255, 0.4) !important; 
    backdrop-filter: blur(8px);
    border-bottom: 1px solid rgba(0, 0, 0, 0.15) !important;
    height: 60px;
    display: flex;
    align-items: center;
    padding: 0 15px;
    position: sticky;
    top: 0;
    z-index: 1000;
}

/* Ensure the wrapper also has the background */
.sr-wrap {
    background-color: #bfeaf4 !important;
    min-height: 100vh;
}

/* --- Topbar Fix --- */
.sr-topbar { 
    position: sticky; top: 0; z-index: 1100; display: flex; gap: 8px; align-items: center; 
    padding: 10px 12px; background: rgba(255,255,255,.35); 
    border-bottom: 1px solid rgba(0,0,0,.15); backdrop-filter: blur(6px); 
}
.sr-btn-icon { 
    border: 1px solid rgba(0,0,0,0.25); cursor: pointer; border-radius: 999px; 
    padding: 8px 12px; font-weight: 900; background: var(--yellow2); box-shadow: var(--shadow); color: #0b1b22;
}
.sr-title { font-weight: 900; font-size: 16px; flex: 1; }

/* --- Container & Card Fix (Essential to stop the "Mess") --- */
.sr-wrap { 
    max-width: 600px; /* Limits width so it doesn't stretch on desktop */
    margin: 0 auto; 
    padding: 15px; 
}

.rc-card { 
    background: rgba(255,255,255,0.4) !important; 
    border: 1px solid rgba(0,0,0,0.1) !important; 
    border-radius: 20px !important; 
    padding: 20px !important; /* Restores internal spacing */
    box-shadow: var(--shadow); 
    margin-bottom: 15px;
}

.rc-title { font-weight: 900 !important; font-size: 16px; margin-bottom: 15px; color: #0b1b22; }

/* --- Forms & Pills Fix --- */
.sr-pill { 
    background: var(--yellow) !important; 
    border: 1px solid rgba(0,0,0,0.1) !important; 
    border-radius: 999px !important; 
    padding: 6px 18px !important; 
    display: flex; 
    align-items: center; 
    box-shadow: var(--shadow);
    margin-bottom: 5px;
}

.sr-input-transparent {
    flex: 1; 
    border: none !important; 
    background: transparent !important; 
    font-family: "Cairo" !important; 
    font-weight: 800; 
    font-size: 14px; 
    outline: none; 
    height: 38px; 
    color: #0b1b22;
    text-align: right;
}

.rc-label { 
    display: block; 
    margin-bottom: 6px; 
    font-size: 13px; 
    font-weight: 900; 
    color: #0b1b22; 
    padding-right: 10px;
}

.rc-hint { 
    margin-top: 5px; 
    font-size: 11px; 
    font-weight: 700; 
    color: #0b1b22; 
    opacity: 0.6; 
    margin-bottom: 15px;
}

/* --- Grid & Range Fix --- */
.rc-grid { 
    display: grid; 
    grid-template-columns: 1fr 1fr; 
    gap: 12px; 
}
.rc-span-2 { grid-column: span 2; }

.rc-last-range { 
    padding: 12px; 
    border: 1px dashed var(--green); 
    border-radius: 12px; 
    background: rgba(255,255,255,0.3); 
    color: var(--green); 
    font-weight: 900; 
    text-align: center; 
    font-size: 14px;
}

/* --- Buttons --- */
.sr-btn { 
    width: 100%;
    border: 1px solid rgba(0,0,0,0.1); 
    cursor: pointer; 
    border-radius: 999px; 
    padding: 12px; 
    font-family: "Cairo"; 
    font-weight: 900; 
    background: var(--yellow2); 
    color: #0b1b22; 
    box-shadow: var(--shadow);
}

/* --- List Item Fix (The "Submitted" area) --- */
.rc-item { 
    display: flex; 
    justify-content: space-between; 
    align-items: center; 
    padding: 15px; 
    border-radius: 16px; 
    border: 1px solid rgba(0,0,0,0.05); 
    background: #fff; 
    margin-top: 10px; 
    box-shadow: var(--shadow);
}

.rc-item-title { font-weight: 900; color: #0b1b22; font-size: 14px; }
.rc-item-range { font-weight: 900; color: var(--green); font-size: 15px; }

.hidden { display: none !important; }

javascript:
frappe.ready(function () {

  const DT = "LMT Receipt Counter";
  const FIELD_NAME = "custom_txt_4"; 

  const $initials = $("#rc_initials");
  const $min = $("#rc_min");
  const $max = $("#rc_max");
  const $save = $("#rc_save");
  const $msg = $("#rc_msg");
  const $list = $("#rc_list");
  const $last = $("#rc_last_range");

  // Get current user (Fallback to Administrator if session is lost)
  let currentUser = frappe.session.user || "Administrator"; 
  let selectedInitials = "";

  init();

  function init() {
    loadLatestRanges(); 
    fillInitialsForUser(currentUser);

    $save.on("click", function () {
      createAndSubmitStrict();
    });
  }

  function setMsg(text, type) {
    $msg.removeClass("ok err warn").addClass(type || "").text(text || "");
  }

  // --- 1. Load Initials ---
  function fillInitialsForUser(user) {
    if (!user || user === "Guest") return;

    frappe.call({
      method: "frappe.client.get_value",
      args: { doctype: "User", fieldname: FIELD_NAME, filters: { name: user } },
      callback: function (r) {
        const val = (r.message && r.message[FIELD_NAME]) ? r.message[FIELD_NAME] : "";
        selectedInitials = val;
        $initials.val(val);
        loadLastRangeForUser(currentUser, val);

        if (!val) {
           $initials.attr("placeholder", "فارغ في ملف المستخدم!");
           setMsg(`⚠️ تنبيه: لم يتم العثور على Initials في حقل ${FIELD_NAME}`, "warn");
        }
      }
    });
  }

  // --- 2. Load Last Range ---
  function loadLastRangeForUser(user, initials) {
      if (!initials) return $last.text("آخر Range: -");

      frappe.call({
        method: "frappe.client.get_list",
        args: {
          doctype: DT,
          filters: { docstatus: 1, assigned_user: user, user_initials: initials },
          fields: ["min_receipt_number", "max_receipt_number", "posting_date"],
          order_by: "posting_date desc, modified desc",
          limit_page_length: 1
        },
        callback: function (r) {
          const row = (r.message && r.message[0]) ? r.message[0] : null;
          if (!row) $last.text("آخر Range: لا يوجد");
          else $last.text(`آخر Range: ${row.min_receipt_number} → ${row.max_receipt_number} (${row.posting_date})`);
        }
      });
  }

  // --- 3. Load List ---
  function loadLatestRanges() {
    let myFilters = { docstatus: ["in", [0, 1]] }; // Show Drafts (0) & Submitted (1)

    // Admin sees all, User sees own
    if (frappe.session.user !== "Administrator") {
        myFilters.assigned_user = currentUser;
    }

    frappe.call({
      method: "frappe.client.get_list",
      args: {
        doctype: DT,
        filters: myFilters,
        fields: ["name", "assigned_user", "user_initials", "min_receipt_number", "max_receipt_number", "posting_date", "docstatus"],
        order_by: "posting_date desc, modified desc",
        limit_page_length: 50
      },
      callback: function (r) {
        const rows = r.message || [];
        if (!rows.length) {
          $list.html('<div class="text-muted p-3">لا توجد دفاتر معتمدة</div>');
          return;
        }
        let html = "";
        rows.forEach(x => {
            let statusBadge = (x.docstatus === 1) 
                ? '<span style="color:green; font-weight:bold; font-size:10px;">✔ معتمد</span>' 
                : '<span style="color:orange; font-weight:bold; font-size:10px;">✎ مسودة</span>';

            let userDisplay = (frappe.session.user === "Administrator") 
                              ? `<div style="font-size:11px; color:#64748b; margin-top:2px;">👤 ${x.assigned_user}</div>` 
                              : "";

          html += `
            <div class="rc-item">
              <div class="rc-item-right">
                <div class="rc-item-title">${escapeHtml(x.user_initials)} <span class="rc-badge" style="font-size:10px;">${x.name.split("-")[1] || "?"}</span></div>
                ${userDisplay}
                <div class="rc-item-sub">📅 ${escapeHtml(x.posting_date)}</div>
              </div>
              <div class="rc-item-left">
                <div style="text-align:left; margin-bottom:2px;">${statusBadge}</div>
                <div class="rc-item-range">${x.min_receipt_number} → ${x.max_receipt_number}</div>
              </div>
            </div>
          `;
        });
        $list.html(html);
      }
    });
  }

  // --- 4. NEW SUBMIT LOGIC (Via Server Script) ---
  function createAndSubmitStrict() {
    setMsg("", "");

    const userToSave = frappe.session.user;
    const initialsToSave = ($initials.val() || "").trim();
    const mn = Number($min.val() || 0);
    const mx = Number($max.val() || 0);

    // Validation
    if (!userToSave) return setMsg("❌ خطأ: الجلسة انتهت", "err");
    if (!initialsToSave) return setMsg("❌ الخطأ: Initials فارغ", "err");
    if (!mn || !mx) return setMsg("❌ أدخل الأرقام", "err");
    if (mn > mx) return setMsg(`❌ خطأ: الرقم الأول (${mn}) أكبر من الرقم الثاني (${mx})`, "err");

    // Lock UI
    $save.prop("disabled", true).text("...جاري المعالجة");

    // CALL THE CUSTOM API
    frappe.call({
        method: "lmt_submit_receipt", // <--- THIS IS THE FIX
        args: {
            user: userToSave,
            initials: initialsToSave,
            mn: mn,
            mx: mx
        },
        freeze: true,
        callback: function(r) {
            // Unlock UI
            $save.prop("disabled", false).text("حفظ واعتماد (Submit)");

            if (r.message && r.message.status === "success") {
                setMsg(`✅ تم الحفظ والاعتماد بنجاح: ${r.message.name}`, "ok");
                $min.val("");
                $max.val("");
                loadLatestRanges();
                loadLastRangeForUser(userToSave, initialsToSave);
            } else {
                // Handle Logic Error
                let errText = "❌ حدث خطأ غير معروف";
                if (r.message && r.message.error) errText = "❌ " + r.message.error;
                setMsg(errText, "err");
            }
        },
        error: function(err) {
            $save.prop("disabled", false).text("حفظ واعتماد (Submit)");
            console.error(err);
            setMsg("❌ فشل الاتصال بالخادم (Server Error)", "err");
        }
    });
  }

  function escapeHtml(s) {
    return String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  }

});

