javascript:
function $(id){ return document.getElementById(id); }

function setHint(msg){
  const el = $("lsHint");
  if (el) el.textContent = msg || "";
}

function getCSRF(){
  if (window.frappe && frappe.csrf_token) return frappe.csrf_token;
  const el = document.querySelector('meta[name="csrf-token"]');
  return el ? el.getAttribute("content") : "";
}

function safeNum(x){
  const n = Number(x);
  return Number.isFinite(n) ? n : 0;
}

function fmtNum(n){
  return safeNum(n).toLocaleString("en-US", {minimumFractionDigits:2, maximumFractionDigits:2});
}

function escapeHtml(str){
  return String(str || "")
    .replaceAll("&","&amp;").replaceAll("<","&lt;")
    .replaceAll(">","&gt;").replaceAll('"',"&quot;")
    .replaceAll("'","&#039;");
}

function fmtDate(dt){
  if (!dt) return "";
  return String(dt).substring(0, 10);
}

function getCurrentWeekDates(){
  const today = new Date();
  const day = today.getDay();
  const daysSinceSat = (day + 1) % 7;
  const sat = new Date(today);
  sat.setDate(today.getDate() - daysSinceSat);
  const fri = new Date(sat);
  fri.setDate(sat.getDate() + 6);
  const fmt = d => d.toISOString().split("T")[0];
  return { start: fmt(sat), end: fmt(fri) };
}

function clearSelectKeepFirst(id){
  const sel = $(id);
  while (sel.options.length > 1) sel.remove(1);
}

function populateSelect(id, list, labelField, valueField){
  valueField = valueField || "name";
  const sel = $(id);
  (list || []).forEach(item => {
    const label = item[labelField] != null ? item[labelField] : (item.name || "");
    const value = item[valueField] != null ? item[valueField] : (item.name || "");
    sel.add(new Option(label, value));
  });
}

function populateMonthSelect(){
  clearSelectKeepFirst("f_month");
  [["1","يناير"],["2","فبراير"],["3","مارس"],["4","أبريل"],
   ["5","مايو"],["6","يونيو"],["7","يوليو"],["8","أغسطس"],
   ["9","سبتمبر"],["10","أكتوبر"],["11","نوفمبر"],["12","ديسمبر"]]
  .forEach(([v,t]) => $("f_month").add(new Option(t,v)));
}

function populateTypeSelect(){
  clearSelectKeepFirst("f_type");
  $("f_type").add(new Option("شركة", "Company"));
  $("f_type").add(new Option("صيدلية", "Pharmacy"));
}

function populateDrawSelect(){
  clearSelectKeepFirst("f_draw");
  $("f_draw").add(new Option(" سحب", "with_draw"));
  $("f_draw").add(new Option(" تحصيل", "no_draw"));
}

let _dropdownsLoaded = false;
let _lastEmp = null;

async function refreshData(){
  setHint("جاري التحميل...");
  const start = $("f_start").value || "";
  const end   = $("f_end").value || "";
  const params = {
    employee:      $("f_emp").value      || "",
    draw:          $("f_draw").value     || "",
    customer:      $("f_cust").value     || "",
    customer_type: $("f_type").value     || "",
    month:         $("f_month").value    || "",
    location:      $("f_location").value || "",
    region:        $("f_region").value   || "",
    start_date:    (start && end) ? start : "",
    end_date:      (start && end) ? end   : ""
  };

  try{
    const resp = await fetch("/api/method/get_collection_dashboard_data", {
      method: "POST",
      credentials: "same-origin",
      headers: {
        "Content-Type":"application/json",
        "Accept":"application/json",
        "X-Frappe-CSRF-Token": getCSRF()
      },
      body: JSON.stringify(params)
    });

    const text = await resp.text();
    let r = {};
    try { r = JSON.parse(text); } catch(e){}

    if (!resp.ok){
      setHint("API Error " + resp.status);
      console.error("API Error:", resp.status, text);
      return;
    }

    if (!r.message){
      setHint("لا يوجد رد");
      return;
    }

    const entries = r.message.entries || [];
    renderUI(entries);

    if (!_dropdownsLoaded){
      _dropdownsLoaded = true;
      populateSelect("f_emp", r.message.employees || [], "employee_name", "name");
    }

    clearSelectKeepFirst("f_location");
    clearSelectKeepFirst("f_region");
    populateSelect("f_location", r.message.locations || [], "cost_center_name", "name");
    populateSelect("f_region",   r.message.regions   || [], "region_name", "name");

    const curEmp = $("f_emp").value || "";
    if (curEmp !== _lastEmp){
      _lastEmp = curEmp;
      clearSelectKeepFirst("f_cust");
      populateSelect("f_cust", r.message.customers || [], "customer_name", "name");
    }

    setHint("تم التحميل: " + entries.length + " سجل");

  }catch(e){
    console.error("Fetch failed:", e);
    setHint("فشل الاتصال: " + e.message);
  }
}

function renderUI(entries){
  const tbody = $("auditTableBody");
  tbody.innerHTML = "";

  let s = { company:0, pharmacy:0, chq:0, cash:0, tot:0, dis:0, comm:0, draw:0 };

  (entries || []).forEach(d => {
    const amt  = safeNum(d.amount);
    const comm = safeNum(d.agent_commission);
    const dis  = safeNum(d.percent_cust_sum);

    const isDrawRow = (d.action_type === "سحب");
    const drawAmt      = isDrawRow ? amt : 0;
    const collectionAmt = isDrawRow ? 0  : amt;

    s.tot  += collectionAmt;
    s.comm += comm;
    s.draw += drawAmt;
    s.dis  += dis;

    const ctype = (d.customer_type || d.custom_customers_type || "Company");
    if (ctype === "Pharmacy") s.pharmacy += collectionAmt;
    else s.company += collectionAmt;

    const ptype = (d.payment_type || "");
    if (ptype === "نقد") s.cash += collectionAmt;
    else if (collectionAmt > 0) s.chq += collectionAmt;

    const tr = document.createElement("tr");
    tr.innerHTML =
      "<td>" + escapeHtml(d.employee_name || d.employee || "") + "</td>" +
      "<td>" + escapeHtml(d.customer_name || d.customer || "") + "</td>" +
      "<td>" + fmtDate(d.posting_date) + "</td>" +
      "<td>" + escapeHtml(d.receipt_no || d.receipt_uid || "") + "</td>" +
      "<td>" + escapeHtml(isDrawRow ? "سحب" : ptype) + "</td>" +
      "<td>" + fmtNum(collectionAmt) + "</td>" +
      "<td>" + fmtNum(comm) + "</td>" +
      "<td>" + fmtNum(drawAmt) + "</td>" +
      "<td>" + fmtNum(dis) + "</td>";
    tbody.appendChild(tr);
  });

  updateDashboardMetrics(s);
}

function updateDashboardMetrics(s){
  $("totalWeeklyRaw").textContent        = fmtNum(s.tot);
  $("totalWeeklyFormatted").textContent  = (s.tot/1000).toFixed(2) + "k";
  $("totalPharmacy").textContent         = fmtNum(s.pharmacy);
  $("totalCompany").textContent          = fmtNum(s.company);
  $("totalCheque").textContent           = fmtNum(s.chq);
  $("totalCash").textContent             = fmtNum(s.cash);
  $("totalCustomerDiscount").textContent = "-" + fmtNum(s.dis);
  $("totalCommRaw").textContent          = fmtNum(s.comm);
  $("totalAgentWithdraw").textContent    = fmtNum(s.draw);
}

document.addEventListener("DOMContentLoaded", () => {
  const injectTopbar = () => {
    let color = window._lmtTopbarColor || '#faa06b';
    const dynStyle = document.getElementById('lmt-dynamic-sync');
    if (dynStyle) {
      const match = dynStyle.textContent.match(/\.sr-topbar[^{]*{[^}]*background-color:\s*([^!;]+)/);
      if (match) color = match[1].trim();
    }
    let existing = document.getElementById('lmt-injected-topbar');
    if (existing) existing.remove();
    const tb = document.createElement('div');
    tb.id = 'lmt-injected-topbar';
    tb.style.cssText = 'display:flex!important;align-items:center;justify-content:space-between;background-color:' + color + '!important;padding:10px 14px;position:fixed;top:0;left:0;right:0;z-index:9999;min-height:54px;direction:rtl;box-sizing:border-box;';
    tb.innerHTML = '<div style="color:#000;font-size:16px;font-weight:900;">تقرير تحصيل الديون</div><div style="display:flex;gap:6px;"><button onclick="window.history.back()" style="background:rgba(0,0,0,0.15);border:none;border-radius:8px;color:#000;font-size:18px;width:38px;height:38px;cursor:pointer;">⬅</button><button onclick="window.location.reload()" style="background:rgba(0,0,0,0.15);border:none;border-radius:8px;color:#000;font-size:18px;width:38px;height:38px;cursor:pointer;">⟳</button><button onclick="location.href=\'/mobile-home\';" style="background:rgba(0,0,0,0.15);border:none;border-radius:8px;color:#000;font-size:18px;width:38px;height:38px;cursor:pointer;">🏠</button></div>';
    document.body.insertBefore(tb, document.body.firstChild);
    const hdr = document.querySelector('.ls-header-dashboard');
    if (hdr) hdr.style.cssText += 'margin-top:54px!important;';
  };
  injectTopbar();
  setTimeout(injectTopbar, 100);
  setTimeout(injectTopbar, 500);

  const killFrappeChrome = () => {
    ["nav.navbar", ".navbar", ".page-head", ".web-footer",
     "footer", "header:not(.ls-app-wrapper header)",
     ".breadcrumb-container", ".page-container > .container-fluid > .row > .sidebar-column",
     "#navbar", ".navbar-header"].forEach(sel => {
      document.querySelectorAll(sel).forEach(el => {
        el.style.cssText = "display:none!important;height:0!important;min-height:0!important;padding:0!important;margin:0!important;";
      });
    });
    document.body.style.paddingTop = "0";
    const main = document.querySelector("main, .page-content, .page-content-wrapper");
    if (main) main.style.paddingTop = "0";
  };
  killFrappeChrome();
  setTimeout(killFrappeChrome, 100);
  setTimeout(killFrappeChrome, 500);

  const fixTopbar = () => {
    const tb = document.querySelector(".mobile-topbar");
    if (tb) {
      tb.setAttribute("style",
        "background-color:#faa06b !important;display:flex !important;position:fixed !important;" +
        "top:0 !important;left:0 !important;right:0 !important;z-index:9999 !important;" +
        "min-height:52px !important;padding:10px 14px !important;direction:rtl !important;" +
        "align-items:center !important;justify-content:space-between !important;box-sizing:border-box !important;"
      );
      tb.querySelectorAll(".icon-btn").forEach(btn => {
        btn.style.cssText = "background:rgba(255,255,255,0.3)!important;border:none;border-radius:8px;color:#fff!important;font-size:18px;width:38px;height:38px;cursor:pointer;display:inline-flex;align-items:center;justify-content:center;";
      });
      tb.querySelectorAll(".topbar-text").forEach(t => {
        t.style.cssText = "color:#fff!important;font-size:16px;font-weight:900;";
      });
    }
  };
  fixTopbar();
  setTimeout(fixTopbar, 200);
  setTimeout(fixTopbar, 800);

  const week = getCurrentWeekDates();
  $("f_start").value = week.start;
  $("f_end").value   = week.end;

  populateMonthSelect();
  populateTypeSelect();
  populateDrawSelect();

  $("f_emp").onchange = () => {
    _dropdownsLoaded = false;
    clearSelectKeepFirst("f_cust");
    $("f_cust").value = "";
    clearSelectKeepFirst("f_region");
    $("f_region").value = "";
    refreshData();
  };

  // *** FIX: month sets f_start/f_end to first/last day of selected month ***
  $("f_month").onchange = function() {
    const m = parseInt(this.value);
    if (m) {
      const year = new Date().getFullYear();
      const first = new Date(year, m - 1, 1);
      const last  = new Date(year, m, 0);
      const fmt = d => d.toISOString().split("T")[0];
      $("f_start").value = fmt(first);
      $("f_end").value   = fmt(last);
    } else {
      const week = getCurrentWeekDates();
      $("f_start").value = week.start;
      $("f_end").value   = week.end;
    }
    refreshData();
  };

  ["f_draw","f_cust","f_type","f_location","f_region"].forEach(id => {
    $(id).onchange = refreshData;
  });
  $("f_start").onchange = refreshData;
  $("f_end").onchange   = refreshData;
  $("btnRefresh").onclick = refreshData;

  refreshData();
});

