javascript:
// ===============================
// Leave Approval Page (FULL JS)
// - Guest lockout
// - Drawer toggle
// - Safe Back fallback to /mobile-home
// - Robust CSRF + error parsing
// - Tabs + load approvals + workflow action
// ===============================

$(document).ready(function() {
  try {
    if (window.LOGGED_IN_USER === 'Guest') {
      window.location.href = '/login?redirect-to=/mobile-leave-approval';
      return;
    }
  } catch(e) {}

  initTabs();
  loadApprovals();
});

// ---------- Drawer ----------
function toggleDrawer(){
  var drawer = document.getElementById("drawer");
  var overlay = document.getElementById("drawerOverlay");
  var isOpen = drawer && drawer.style.display !== "none";

  if (!drawer || !overlay) return;

  if (isOpen) {
    drawer.style.display = "none";
    overlay.style.display = "none";
  } else {
    drawer.style.display = "block";
    overlay.style.display = "block";
  }
}

function closeDrawer(){
  var drawer = document.getElementById("drawer");
  var overlay = document.getElementById("drawerOverlay");
  if (drawer) drawer.style.display = "none";
  if (overlay) overlay.style.display = "none";
}

// ---------- Safe Back (fallback to home) ----------
function safeBack(){
  try {
    // If there is no meaningful history, go home
    if (!window.history || window.history.length <= 1) {
      window.location.href = "/mobile-home";
      return;
    }
    window.history.back();
  } catch(e) {
    window.location.href = "/mobile-home";
  }
}

// ---------- Tabs ----------
function initTabs(){
  $("#tabSupervisor").on("click", function(){
    $("#tabSupervisor").addClass("active");
    $("#tabHR").removeClass("active");
    $("#panelSupervisor").removeClass("hidden");
    $("#panelHR").addClass("hidden");
  });

  $("#tabHR").on("click", function(){
    $("#tabHR").addClass("active");
    $("#tabSupervisor").removeClass("active");
    $("#panelHR").removeClass("hidden");
    $("#panelSupervisor").addClass("hidden");
  });
}

// ---------- Helpers ----------
function getCSRFToken(){
  if (window.CSRF_TOKEN && String(window.CSRF_TOKEN).trim()) return String(window.CSRF_TOKEN).trim();

  var m = document.querySelector('meta[name="csrf-token"]');
  if (m && m.getAttribute("content")) return String(m.getAttribute("content")).trim();

  var match = document.cookie.match(/(?:^|;\s*)csrf_token=([^;]+)/);
  if (match && match[1]) return decodeURIComponent(match[1]);

  return "";
}

function parseFrappeError(res){
  try {
    if (!res) return "Unknown error";

    if (res._server_messages) {
      try {
        var arr = JSON.parse(res._server_messages);
        if (Array.isArray(arr) && arr.length) {
          var last = arr[arr.length - 1];
          try {
            var obj = JSON.parse(last);
            if (obj && obj.message) return String(obj.message);
          } catch(e2) {}
          return String(last);
        }
      } catch(e1) {
        return "Server error";
      }
    }

    if (res.message && typeof res.message === "string") return res.message;
    if (res.exception) return "Exception: " + String(res.exception);
    if (res.exc_type) return "Error: " + String(res.exc_type);

    return "Request failed";
  } catch(e) {
    return "Request failed";
  }
}

function escapeHtml(s){
  return (s || "").replace(/[&<>"']/g, function(m){
    return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]);
  });
}

// ---------- API ----------
function apiGet(method, params){
  var url = "/api/method/" + method;

  params = params || {};
  params._t = new Date().getTime(); // cache-buster

  var qs = new URLSearchParams(params).toString();
  url += "?" + qs;

  return fetch(url, {
    method: "GET",
    headers: { "Accept": "application/json" },
    credentials: "same-origin"
  }).then(async function(r){
    var text = await r.text();
    var data = null;
    try { data = JSON.parse(text); } catch(e) {}

    if (!r.ok) throw { http_status: r.status, payload: data, raw: text };
    return data || {};
  });
}

function apiPost(method, body){
  var csrf = getCSRFToken();

  return fetch("/api/method/" + method, {
    method: "POST",
    headers: {
      "Accept": "application/json",
      "Content-Type": "application/x-www-form-urlencoded; charset=UTF-8",
      "X-Frappe-CSRF-Token": csrf
    },
    body: new URLSearchParams(body || {}).toString(),
    credentials: "same-origin"
  }).then(async function(r){
    var text = await r.text();
    var data = null;
    try { data = JSON.parse(text); } catch(e) {}

    if (!r.ok) throw { http_status: r.status, payload: data, raw: text };
    return data || {};
  });
}

// ---------- Load + Render ----------
function loadApprovals(){
  $("#supervisorContainer").html('<div class="items-empty">جاري التحميل...</div>');
  $("#hrContainer").html('<div class="items-empty">جاري التحميل...</div>');

  apiGet("leave_approval_get", { limit: 80 })
    .then(function(res){
      if (!res || !res.message) {
        $("#supervisorContainer").html('<div class="items-empty">Failed to load data</div>');
        $("#hrContainer").html('<div class="items-empty">Failed to load data</div>');
        return;
      }

      var sup = res.message.supervisor || [];
      var hr = res.message.hr || [];

      renderList("#supervisorContainer", sup);
      renderList("#hrContainer", hr);

      // Hide HR tab if none
      if (hr.length === 0) {
        $("#tabHR").hide();
        $("#tabSupervisor").trigger("click");
      } else {
        $("#tabHR").show();
      }

      // Auto switch if supervisor empty and HR has items
      if (sup.length === 0 && hr.length > 0) {
        $("#tabHR").trigger("click");
      }
    })
    .catch(function(err){
      var msg = "Connection failed";
      if (err && err.http_status) msg = "HTTP Error: " + err.http_status;
      if (err && err.payload) msg = parseFrappeError(err.payload);

      $("#supervisorContainer").html('<div class="items-empty">'+ escapeHtml(msg) +'</div>');
      $("#hrContainer").html('<div class="items-empty">'+ escapeHtml(msg) +'</div>');
    });
}

function renderList(containerSel, items){
  if (!items || items.length === 0) {
    $(containerSel).html('<div class="items-empty">لا يوجد طلبات بانتظار اعتمادك الآن ✅</div>');
    return;
  }

  var html = "";
  items.forEach(function(it){
    html += renderCard(it);
  });

  $(containerSel).html(html);

  $(containerSel + " .action-btn").off("click").on("click", function(){
    var docname = $(this).attr("data-doc");
    var action = $(this).attr("data-action");
    doAction(docname, action, this);
  });
}

function renderCard(it){
  var emp = escapeHtml(it.employee_name || it.employee || "");
  var leaveType = escapeHtml(it.leave_type || "-");
  var wf = escapeHtml(it.workflow_state || "-");
  var from = escapeHtml(it.from_date || "");
  var to = escapeHtml(it.to_date || "");
  var half = (it.half_day ? "نصف يوم" : "يوم كامل");
  var desc = escapeHtml(it.description || "");

  var actions = it.actions || [];
  var btns = "";

  actions.forEach(function(a){
    var cls = "action-btn";
    var au = (a || "").toUpperCase();

    if (au.indexOf("APPROV") >= 0 || a.indexOf("اعتماد") >= 0) cls += " primary";
    if (au.indexOf("REJECT") >= 0 || a.indexOf("رفض") >= 0) cls += " danger";

    btns += '<button type="button" class="'+cls+'" data-doc="'+escapeHtml(it.name)+'" data-action="'+escapeHtml(a)+'">'+escapeHtml(a)+'</button>';
  });

  var viewLink = "/app/leave-application/" + encodeURIComponent(it.name);

  return `
    <div class="card">
      <div class="card-top">
        <div style="font-weight:900; color:#0f172a;">📝 ${emp}</div>
        <div class="badge">${wf}</div>
      </div>

      <div class="meta">
        <div>نوع الإجازة: <b>${leaveType}</b></div>
        <div>من: <b>${from}</b> — إلى: <b>${to}</b> (${half})</div>
        ${desc ? `<div>السبب: ${desc}</div>` : ``}

        <div style="margin-top:6px;">
          <a href="${viewLink}" target="_blank" style="font-weight:900; color:#0ea5e9; text-decoration:none;">
            فتح الطلب في النظام ↗
          </a>
        </div>
      </div>

      <div class="actions">${btns}</div>
    </div>
  `;
}

// ---------- Action ----------
function doAction(docname, action, btnEl){
  if (!docname || !action) return;

  var $card = $(btnEl).closest(".card");
  $card.find("button").prop("disabled", true);

  apiPost("leave_approval_action", { docname: docname, action: action })
    .then(function(res){
      if (res && res.message && res.message.ok) {
        loadApprovals();
      } else {
        alert(parseFrappeError(res));
        $card.find("button").prop("disabled", false);
      }
    })
    .catch(function(err){
      var msg = "Connection failed";
      if (err && err.http_status) msg = "HTTP Error: " + err.http_status;
      if (err && err.payload) msg = parseFrappeError(err.payload);

      alert(msg);
      $card.find("button").prop("disabled", false);
    });
}

