@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');

/* --- Reset & Global Theme --- */
footer, .web-footer, .footer-subscribe, .powered-by, header.navbar, .navbar { display: none !important; }

:root { 
    --bg: #bfeaf4; 
    --yellow: #ffd23c; 
    --yellow2: #ffe26b; 
    --green: #2f8f3a; 
    --shadow: 0 10px 30px rgba(0,0,0,.08); 
}

body { 
    direction: rtl; 
    background-color: var(--bg) !important; 
    font-family: "Cairo", sans-serif !important; 
    margin: 0; 
    color: #0b1b22;
}

.wk-app { min-height: 100vh; }

/* --- Topbar Fix --- */
.wk-topbar { 
    position: sticky; top: 0; z-index: 1100; display: flex; gap: 8px; align-items: center; 
    padding: 10px 12px; background: rgba(255, 255, 255, 0.4) !important; 
    border-bottom: 1px solid rgba(0, 0, 0, 0.1) !important; backdrop-filter: blur(10px); 
    justify-content: space-between;
}

.wk-title { display: flex; align-items: center; gap: 10px; }
.wk-badge {
    width: 42px; height: 42px;
    display: flex; align-items: center; justify-content: center;
    border-radius: 14px; background: var(--yellow2);
    box-shadow: var(--shadow); font-size: 20px;
}

.wk-h1 { font-weight: 900; font-size: 18px; color: #0b1b22; }
.wk-sub { color: #0b1b22; font-size: 11px; font-weight: 700; opacity: 0.7; }

/* --- Buttons & Icons --- */
.sr-btn-icon { 
    border: 1px solid rgba(0,0,0,0.15); cursor: pointer; border-radius: 999px; 
    padding: 8px 12px; font-weight: 900; background: var(--yellow2); 
    box-shadow: var(--shadow); color: #0b1b22; text-decoration: none;
    display: flex; align-items: center; justify-content: center;
}

.sr-btn { 
    border: 1px solid rgba(0,0,0,0.1); cursor: pointer; border-radius: 999px; 
    padding: 10px 20px; font-family: "Cairo"; font-weight: 900; 
    background: #fff; color: #0b1b22; box-shadow: var(--shadow);
}
.sr-btn.primary { background: var(--green) !important; color: white !important; }

/* --- Layout Wrappers --- */
.wk-main { max-width: 900px; margin: 15px auto; padding: 0 15px 60px; display: flex; flex-direction: column; gap: 15px; }

.wk-card { 
    background: rgba(255, 255, 255, 0.4) !important; 
    border: 1px solid rgba(0, 0, 0, 0.1) !important; 
    border-radius: 20px; box-shadow: var(--shadow); 
    padding: 15px; 
}

/* --- Search Pill --- */
.sr-pill { 
    background: var(--yellow); border: 1px solid rgba(0, 0, 0, 0.15); 
    border-radius: 999px; padding: 4px 16px; display: flex; align-items: center; box-shadow: var(--shadow);
}
.sr-input-transparent {
    width: 100%; border: none !important; background: transparent !important; 
    font-family: "Cairo" !important; font-weight: 800; font-size: 15px; 
    outline: none; height: 40px; color: #0b1b22;
}

/* --- Category Chips --- */
.wk-cats { margin-top: 15px; display: flex; gap: 10px; flex-wrap: wrap; }
.wk-chip {
    border: 1px solid rgba(0, 0, 0, 0.1); background: #fff; border-radius: 999px; 
    padding: 8px 16px; cursor: pointer; font-weight: 800; font-family: 'Cairo';
    color: #0b1b22; box-shadow: var(--shadow);
}
.wk-chip:active { transform: scale(0.95); }

/* --- Wiki Items (Results) --- */
.wk-results { display: flex; flex-direction: column; gap: 12px; }
.wk-item {
    border-radius: 18px; padding: 15px; background: #fff;
    border: 1px solid rgba(0,0,0,0.05); box-shadow: 0 4px 15px rgba(0,0,0,0.03);
}
.wk-item-title { font-weight: 900; font-size: 16px; color: #0b1b22; margin-bottom: 4px; }
.wk-item-meta { color: #64748b; font-size: 12px; font-weight: 700; margin-bottom: 10px; }
.wk-link { color: var(--green); text-decoration: none; font-weight: 900; display: flex; align-items: center; gap: 6px; }

/* --- Article Styling --- */
.wk-article { line-height: 1.8; font-size: 15px; font-weight: 600; color: #334155; }
.wk-article h1, .wk-article h2, .wk-article h3 { color: #0b1b22; font-weight: 900; }
.wk-article img { max-width: 100%; border-radius: 15px; border: 1px solid rgba(0,0,0,0.1); }

.wk-state { color: #0b1b22; font-weight: 900; font-size: 13px; margin-bottom: 12px; opacity: 0.6; }
.wk-hint { font-size: 11px; font-weight: 700; color: #0b1b22; opacity: 0.5; margin-top: 10px; text-align: center; }

.hidden { display: none !important; }

/* --- Topbar Flip: Navigation Left, Title Right --- */
.wk-topbar {
    display: flex !important;
    flex-direction: row !important; /* Force layout slots: first group left, second right */
    justify-content: space-between !important;
    align-items: center !important;
    padding: 0 15px !important;
    height: 65px !important;
    direction: ltr !important; /* Establishes LTR slots to ignore global RTL flip */
}

/* NAVIGATION GROUP (Far Left) */
.wk-actions {
    display: flex !important;
    gap: 8px !important;
    flex: none !important;
}

/* TITLE GROUP (Far Right) */
.wk-title {
    display: flex !important;
    align-items: center !important;
    gap: 12px !important;
    flex: none !important;
    direction: rtl !important; /* Restores Arabic flow for title text */
