    border: 2px solid rgba(0,0,0,0.2);
    font-size: 30px;
    font-weight: 900;
    box-shadow: 0 4px 15px rgba(0,0,0,0.2);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    z-index: 1000;
    color: #0b1b22;
}

javascript:
// ========= Helpers =========
function qs(name){
  return new URLSearchParams(window.location.search).get(name);
}
function setState(msg){
  document.getElementById("state").textContent = msg || "";
}
function escapeHtml(s){
  return (s||"").replace(/[&<>"']/g, m => ({
    "&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#039;"
  }[m]));
}

// ========= API wrappers =========
async function api(method, args){
  // Use frappe.call if available; otherwise raw fetch
  if (window.frappe && frappe.call){
    const r = await frappe.call({ method, args });
    return r.message;
  }
  const res = await fetch("/api/method/" + method, {
    method: "POST",
    headers: {
      "Content-Type":"application/json",
      "X-Frappe-CSRF-Token": window.CSRF_TOKEN || ""
    },
    body: JSON.stringify(args || {})
  });
  const data = await res.json();
  if (data.exc) throw new Error(data.exc);
  return data.message;
}

// ========= UI logic =========
let CAN_EDIT = false;

async function loadPermissions(){
  const p = await api("lmt_wiki_get_user_permissions", {});
  CAN_EDIT = !!(p && p.can_edit);

  const hint = document.getElementById("permHint");
  const btnNew = document.getElementById("btnNew");

  if (CAN_EDIT){
    hint.textContent = "✅ لديك صلاحية محرر (إنشاء/تعديل/حذف).";
    btnNew.style.display = "inline-flex";
  } else {
    hint.textContent = "👁️ وضع قراءة فقط.";
    btnNew.style.display = "none";
  }
}

function renderList(items){
  const box = document.getElementById("results");
  if (!items || !items.length){
    box.innerHTML = "<div class='wk-item'>لا توجد نتائج.</div>";
    return;
  }

  box.innerHTML = items.map(it => {
    const title = escapeHtml(it.title || it.name || "");
    const snippet = escapeHtml(it.snippet || "");
    const name = encodeURIComponent(it.name || "");
    return `
      <div class="wk-item">
        <div class="wk-item-title">${title}</div>
        <div class="wk-item-meta">${snippet}</div>
        <div class="wk-item-actions">
          <a class="wk-link" href="/lmt-wiki?article=${name}">📄 فتح</a>
        </div>
      </div>
    `;
  }).join("");
}

async function search(q, category){
  setState("جاري البحث…");
  const data = await api("lmt_wiki_search_articles", { q: q || "", category: category || "" });
  renderList((data && data.items) || []);
  setState(`نتائج: ${(data && data.items && data.items.length) || 0}`);
}

async function openArticle(name){
  setState("جاري فتح المقال…");
  const data = await api("lmt_wiki_get_article", { name });
  const box = document.getElementById("results");

  if (!data || !data.title){
    box.innerHTML = "<div class='wk-item'>المقال غير موجود.</div>";
    setState("غير موجود");
    return;
  }

  // content is HTML from Help Article; we display it directly (trusted editors)
  box.innerHTML = `
    <div class="wk-item">
      <div class="wk-item-title">${escapeHtml(data.title)}</div>
      <div class="wk-item-meta">${escapeHtml(data.name)}</div>
      <div class="wk-item-actions">
        <a class="wk-link" href="/lmt-wiki">↩ رجوع</a>
        ${CAN_EDIT ? `<a class="wk-link" href="/app/help-article/${encodeURIComponent(data.name)}">✏️ تحرير</a>` : ""}
      </div>
      <div class="wk-article">${data.content || ""}</div>
    </div>
  `;
  setState("تم");
}

// ========= Bindings =========
document.addEventListener("DOMContentLoaded", async () => {
  try {
    await loadPermissions();

    const article = qs("article");
    if (article){
      await openArticle(article);
      return;
    }

    document.getElementById("btnSearch").addEventListener("click", async () => {
      const q = (document.getElementById("q").value || "").trim();
      await search(q, "");
    });

    document.getElementById("q").addEventListener("keydown", async (e) => {
      if (e.key === "Enter"){
        const q = (document.getElementById("q").value || "").trim();
        await search(q, "");
      }
    });

    document.getElementById("cats").addEventListener("click", async (e) => {
      const btn = e.target.closest("[data-cat]");
      if (!btn) return;
      const cat = btn.getAttribute("data-cat") || "";
      const q = (document.getElementById("q").value || "").trim();
      await search(q, cat);
    });

    document.getElementById("btnNew").addEventListener("click", () => {
      // Editor shortcut to create a new Help Article
      window.location.href = "/app/help-article/new-help-article-1";
    });

    setState("جاهز");
  } catch (err){
    console.error(err);
    setState("خطأ");
    document.getElementById("results").innerHTML =
      `<div class='wk-item'>حدث خطأ: ${escapeHtml(err.message || String(err))}</div>`;
  }
});

