css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');

:root{
    --bg-main: #bfeaf4;
    --yellow: #ffd23c;
    --yellow-light: #ffe26b;
    --green: #2f8f3a;
    --green2: #2aa334;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
    --text: #0b1b22;
}

body, html {
    padding:0 !important; margin:0 !important;
    background:var(--bg-main) !important;
    font-family:"Cairo",sans-serif !important;
    direction:rtl; color:var(--text); min-height:100vh;
}
header.navbar, .navbar, .top-navbar, footer, .web-footer { display:none !important; }
.page_content, .page-content, main, .main-section { margin:0 !important; padding:0 !important; }

.sr-topbar {
    display:flex !important; flex-direction:row !important;
    justify-content:space-between !important; align-items:center !important;
    padding:0 15px !important; height:65px !important;
    width:100% !important; box-sizing:border-box !important;
    direction:ltr !important;
    background:rgba(255,255,255,0.4) !important;
    backdrop-filter:blur(10px) !important;
    border-bottom:1px solid rgba(0,0,0,0.1) !important;
    position:fixed; top:0; left:0; right:0; z-index:1100;
}
.topbar-left  { display:flex !important; gap:8px !important; flex:none !important; order:1 !important; }
.topbar-right { display:flex !important; flex-direction:row !important; align-items:center !important; gap:12px !important; flex:none !important; order:2 !important; direction:rtl !important; }
.sr-title     { text-align:right !important; margin:0 !important; font-weight:900; font-size:16px; color:var(--text); font-family:"Cairo",sans-serif !important; }

.sr-btn-icon {
    background-color:var(--yellow-light) !important;
    border:1px solid rgba(0,0,0,0.2) !important;
    border-radius:999px !important; font-size:16px !important; font-weight:900 !important;
    cursor:pointer !important; width:40px !important; height:40px !important;
    display:flex !important; align-items:center !important; justify-content:center !important;
    box-shadow:var(--shadow) !important; margin:0 !important; color:var(--text) !important; padding:0 !important;
}

.sr-wrap    { max-width:1100px; margin:0 auto; padding:85px 14px 30px; }
.sr-filters { display:grid; gap:10px; margin-bottom:14px; }
.sr-row     { display:grid; grid-template-columns:1fr 1fr; gap:10px; }

.sr-pill {
    background:var(--yellow); border:1px solid rgba(0,0,0,.25);
    border-radius:999px; padding:10px 14px; box-shadow:var(--shadow);
    display:flex; align-items:center; justify-content:space-between; gap:10px;
}
.sr-pill label { font-weight:900; white-space:nowrap; margin-left:10px; min-width:60px; color:var(--text); }
.sr-pill select, .sr-pill input {
    flex:1; border:none; outline:none; background:transparent;
    font-family:"Cairo",sans-serif; font-weight:800; font-size:14px;
    text-align:right; cursor:pointer; color:var(--text);
}

.year-pill { border-radius:18px !important; padding:10px 14px !important; flex-wrap:wrap; }
#yearBtns  { display:flex; gap:6px; flex-wrap:wrap; justify-content:flex-end; flex:1; }
.yr-btn {
    border:1.5px solid rgba(0,0,0,0.25); border-radius:999px;
    padding:4px 14px; font-family:"Cairo",sans-serif;
    font-weight:900; font-size:13px; cursor:pointer;
    background:rgba(255,255,255,0.55); color:var(--text); transition:0.15s;
}
.yr-btn.active { background:var(--green); color:#fff; border-color:var(--green); }
.yr-btn:active { transform:scale(0.94); }

.agent-info-box {
    padding:12px; background:rgba(255,255,255,0.5);
    border-radius:12px; font-weight:900; text-align:center; color:var(--text); display:none;
}

.sr-actions { display:flex; gap:10px; flex-wrap:wrap; margin-top:5px; }
.sr-btn {
    border:none; cursor:pointer; border-radius:999px;
    padding:10px 20px; font-family:"Cairo",sans-serif;
    font-weight:900; box-shadow:var(--shadow);
    border:1px solid rgba(0,0,0,.25);
    background:var(--yellow-light); color:var(--text); transition:0.2s;
}
.sr-btn:active { transform:scale(0.95); }
.sr-btn.primary { background:var(--yellow); }
.sr-btn.print   { background:#ff7a7a; color:#fff; border-color:rgba(0,0,0,0.1); }

.sr-kpis {
    display:grid; grid-template-columns:1fr 1fr 1fr;
    gap:10px; margin:10px 0 12px;
}
.sr-kpi {
    background:rgba(255,255,255,.45);
    border:1px solid rgba(0,0,0,.12);
    border-radius:12px; padding:10px 14px;
    box-shadow:var(--shadow); backdrop-filter:blur(6px);
}
.sr-kpi .t { font-weight:700; color:#555; font-size:11px; margin-bottom:4px; }
.sr-kpi .v { font-weight:900; font-size:16px; color:var(--text); }

.sr-chart {
    margin-top:16px; background:rgba(255,255,255,.4);
    border:1px solid rgba(0,0,0,.15); border-radius:14px; padding:12px;
    box-shadow:var(--shadow); backdrop-filter:blur(6px);
}

.sr-table-wrap {
    border-radius:12px; overflow-x:auto;
    border:2px solid #555; box-shadow:var(--shadow);
    margin-top:10px; -webkit-overflow-scrolling:touch; background:#fff;
}
table { width:100%; border-collapse:collapse; min-width:600px; }

thead th {
    background:linear-gradient(180deg,var(--green2),var(--green)) !important;
    color:#fff !important; padding:10px 6px; font-weight:900; font-size:12px;
    border-left:1.5px solid #333 !important;
    border-bottom:1.5px solid #333 !important;
    text-align:center; white-space:nowrap;
}
tbody td {
    border-top:1.5px solid #555 !important;
    border-left:1.5px solid #555 !important;
    padding:8px 6px; font-weight:800; font-size:12px;
    text-align:center; white-space:nowrap; color:var(--text);
}
tbody tr:nth-child(odd)  td { background-color:var(--yellow-light) !important; }
tbody tr:nth-child(even) td { background-color:var(--bg-main) !important; }
tbody tr:hover { filter:brightness(0.95); }

td.name { text-align:right; min-width:180px; white-space:normal; }
td.num  { text-align:center; }

tfoot td {
    background:linear-gradient(180deg,var(--green2),var(--green)) !important;
    color:#fff !important; padding:10px 6px; font-weight:900;
    border-top:2px solid #333 !important;
    text-align:center; white-space:nowrap;
}

/* ── Qty cells ──────────────────────────────────────────────── */
td.qty-cell {
    background-color:rgba(47,143,58,0.10) !important;
    color:#1a5c22 !important;
    font-size:11px !important;
}
td.total-qty-cell {
    background-color:rgba(47,143,58,0.15) !important;
    color:#1a5c22 !important;
    font-weight:900 !important;
}
.sr-btn.excel {
    background: #217346;
    color: #fff;
    border-color: rgba(0,0,0,0.1);
}

javascript:
const API_USERS = "items-report-get-users";
const API_DATA  = "items-report-get-data";
const el    = (id) => document.getElementById(id);
const fmt   = (n)  => Number(n||0).toLocaleString(undefined, {minimumFractionDigits:2});
const fmtQty= (n)  => Number(n||0).toLocaleString(undefined, {minimumFractionDigits:0, maximumFractionDigits:2});
let chart = null;
let _lastData = null;

function init(){
    const year = new Date().getFullYear();
    el("srFrom").value = `${year}-01-01`;
    el("srTo").value   = `${year}-12-31`;

    document.querySelectorAll(".yr-btn").forEach(btn => {
        if(parseInt(btn.dataset.year) === year) btn.classList.add("active");
        btn.addEventListener("click", function(){
            document.querySelectorAll(".yr-btn").forEach(b => b.classList.remove("active"));
            this.classList.add("active");
            el("srFrom").value = `${this.dataset.year}-01-01`;
            el("srTo").value   = `${this.dataset.year}-12-31`;
            loadData();
        });
    });

    el("srRun").addEventListener("click", loadData);
    el("srExport").addEventListener("click", exportExcel);

    el("srDisplay").addEventListener("change", () => {
        if(_lastData) renderData(_lastData);
    });

    loadUsers();
}

function loadUsers(){
    el("srAgent").innerHTML = "<option>Loading...</option>";
    frappe.call({
        method: API_USERS,
        args: {},
        callback: (r) => {
            if(r.message) setupAgentDropdown(r.message);
            loadData();
        }
    });
}

function setupAgentDropdown(data){
    const sel = el("srAgent");
    sel.innerHTML = "";
    if(data.can_select){
        el("agentPill").style.display = "flex";
        el("agentInfo").style.display = "none";
        const optAll = document.createElement("option");
        optAll.value = "__ALL__"; optAll.text = "الكل";
        sel.appendChild(optAll);
        (data.users || []).forEach(u => {
            const opt = document.createElement("option");
            opt.value = u.id; opt.text = u.name;
            sel.appendChild(opt);
        });
    } else {
        el("agentPill").style.display = "none";
        el("agentInfo").style.display = "block";
        el("agentInfo").innerText = "المندوب: " + (data.current_user_name || "Me");
        const opt = document.createElement("option");
        opt.value = "__ALL__";
        sel.appendChild(opt);
    }
}

function loadData(){
    el("srRun").innerText = "⏳";
    frappe.call({
        method: API_DATA,
        args: {
            from_date: el("srFrom").value,
            to_date:   el("srTo").value,
            agent:     el("srAgent").value,
            status:    el("srStatus").value,
            location:  el("srLocation").value,
            city:      el("srCity").value,
            customer:  el("srCustomer").value,
            item:      el("srItem").value,
            group_by:  el("srGroupBy").value,
            source:    el("srSource").value
        },
        callback: (r) => {
            el("srRun").innerText = "تحديث";
            if(r.message) renderData(r.message);
        },
        error: (e) => {
            el("srRun").innerText = "تحديث";
            console.error(e);
        }
    });
}

function renderData(data){
    if(data.error){ frappe.msgprint(data.error); return; }
    _lastData = data;

    updateSelect("srLocation", data.options.regions);
    updateSelect("srCity",     data.options.cities);
    updateSelect("srCustomer", data.options.customers);
    updateSelect("srItem",     data.options.items);

    const k = data.kpis || {};
    el("srGrandBefore").innerText = fmt(k.total_before || 0);
    el("srGrandTotal").innerText  = fmt(k.total || 0);
    el("srGrandQty").innerText    = fmtQty(k.qty || 0);

    const months      = data.months || [];
    const displayMode = el("srDisplay").value;
    const showAmt     = displayMode === "amount" || displayMode === "both";
    const showQty     = displayMode === "qty"    || displayMode === "both";
    const groupLabel  = el("srGroupBy").options[el("srGroupBy").selectedIndex].text;

    let thHtml = `<th style="text-align:right">${groupLabel}</th>`;
    months.forEach(m => {
        if(showAmt) thHtml += `<th>${m}<br><small style="opacity:0.7;font-size:10px">قيمة</small></th>`;
        if(showQty) thHtml += `<th style="background:linear-gradient(180deg,#1a6f25,#145c1e) !important">${m}<br><small style="opacity:0.85;font-size:10px">كمية</small></th>`;
    });
    thHtml += `<th>الكمية</th><th>القيمة</th>`;
    el("srTh").innerHTML = thHtml;
    el("srTb").innerHTML = "";

    const colTotAmt = {};
    const colTotQty = {};
    months.forEach(m => { colTotAmt[m] = 0; colTotQty[m] = 0; });

    (data.rows || []).forEach(r => {
        months.forEach(m => {
            colTotAmt[m] += (r[m]           || 0);
            colTotQty[m] += (r["qty_" + m]  || 0);
        });

        const tr = document.createElement("tr");
        let nameHtml = `<div style="font-size:13px">${r.name}</div>`;
        if(r.sub_text) nameHtml += `<div style="font-size:11px;opacity:0.7">${r.sub_text}</div>`;

        let cells = `<td class="name">${nameHtml}</td>`;
        months.forEach(m => {
            if(showAmt) cells += `<td class="num">${fmt(r[m] || 0)}</td>`;
            if(showQty) cells += `<td class="num qty-cell">${fmtQty(r["qty_" + m] || 0)}</td>`;
        });
        cells += `<td class="num total-qty-cell">${fmtQty(r.total_qty)}</td>`;
        cells += `<td class="num">${fmt(r.total_amt)}</td>`;
        tr.innerHTML = cells;
        el("srTb").appendChild(tr);
    });

    let tfHtml = `<td class="name">Total</td>`;
    months.forEach(m => {
        if(showAmt) tfHtml += `<td class="num">${fmt(colTotAmt[m])}</td>`;
        if(showQty) tfHtml += `<td class="num">${fmtQty(colTotQty[m])}</td>`;
    });
    tfHtml += `<td class="num">${fmtQty(k.qty)}</td>`;
    tfHtml += `<td class="num">${fmt(k.total)}</td>`;
    el("srTf").innerHTML = tfHtml;

    if(chart) chart.destroy();
    if(data.chart && data.chart.values){
        chart = new Chart(el("srChart"), {
            type: 'bar',
            data: {
                labels:   data.chart.labels || months,
                datasets: [{ label:'Sales', data: data.chart.values, backgroundColor:'#2f8f3a' }]
            },
            options: { responsive:true, maintainAspectRatio:false }
        });
    }
}

function exportExcel(){
    el("srExport").innerText = "⏳";
    frappe.call({
        method: "items-report-export",
        args: {
            from_date: el("srFrom").value,
            to_date:   el("srTo").value,
            agent:     el("srAgent").value,
            status:    el("srStatus").value,
            location:  el("srLocation").value,
            city:      el("srCity").value,
            customer:  el("srCustomer").value,
            item:      el("srItem").value,
            group_by:  el("srGroupBy").value,
            source:    el("srSource").value
        },
        callback: (r) => {
            el("srExport").innerText = "تصدير Excel";
            if(!r.message){ frappe.msgprint("No response"); return; }
            if(r.message.error){ frappe.msgprint("Error: " + r.message.error); return; }

            const d          = r.message;
            const months     = d.months || [];
            const agents     = d.agents || [];
            const rows       = d.rows   || [];
            const displayMode= el("srDisplay").value;
            const showAmt    = displayMode === "amount" || displayMode === "both";
            const showQty    = displayMode === "qty"    || displayMode === "both";
            const groupLabel = el("srGroupBy").options[el("srGroupBy").selectedIndex].text;

            const wb = XLSX.utils.book_new();

            // ── SHEET 1: By Month ─────────────────────────────────────
            const s1 = [];
            const h1 = [groupLabel];
            months.forEach(m => {
                if(showAmt) h1.push(m + " قيمة");
                if(showQty) h1.push(m + " كمية");
            });
            h1.push("الكمية الكلية");
            h1.push("القيمة الكلية");
            s1.push(h1);

            const colAmt = {};
            const colQty = {};
            months.forEach(m => { colAmt[m] = 0; colQty[m] = 0; });
            let gAmt = 0, gQty = 0;

            rows.forEach(({key, data: rv}) => {
                const row = [key];
                months.forEach(m => {
                    const a = rv[m]          || 0;
                    const q = rv["qty_" + m] || 0;
                    colAmt[m] = colAmt[m] + a;
                    colQty[m] = colQty[m] + q;
                    if(showAmt) row.push(Math.round(a * 100) / 100);
                    if(showQty) row.push(Math.round(q * 100) / 100);
                });
                gQty = gQty + (rv.total_qty || 0);
                gAmt = gAmt + (rv.total_amt || 0);
                row.push(Math.round((rv.total_qty || 0) * 100) / 100);
                row.push(Math.round((rv.total_amt || 0) * 100) / 100);
                s1.push(row);
            });

            const tf1 = ["Grand Total"];
            months.forEach(m => {
                if(showAmt) tf1.push(Math.round(colAmt[m] * 100) / 100);
                if(showQty) tf1.push(Math.round(colQty[m] * 100) / 100);
            });
            tf1.push(Math.round(gQty * 100) / 100);
            tf1.push(Math.round(gAmt * 100) / 100);
            s1.push(tf1);

            const ws1 = XLSX.utils.aoa_to_sheet(s1);
            ws1["!cols"] = [{wch:40}].concat(h1.slice(1).map(() => ({wch:14})));
            XLSX.utils.book_append_sheet(wb, ws1, "By Month");

            // ── SHEET 2: By Agent ─────────────────────────────────────
            const s2  = [];
            const h2  = [groupLabel, ...agents, "Grand Total"];
            s2.push(h2);

            const agTot = {};
            agents.forEach(a => { agTot[a] = 0; });

            rows.forEach(({key, data: rv}) => {
                const row = [key];
                let rowTot = 0;
                agents.forEach(a => {
                    const v = rv["agent_" + a] || 0;
                    agTot[a] = agTot[a] + v;
                    rowTot   = rowTot   + v;
                    row.push(v ? Math.round(v * 100) / 100 : "");
                });
                row.push(Math.round(rowTot * 100) / 100);
                s2.push(row);
            });

            const tf2 = ["Grand Total"];
            let g2 = 0;
            agents.forEach(a => {
                const v = agTot[a];
                g2 = g2 + v;
                tf2.push(Math.round(v * 100) / 100);
            });
            tf2.push(Math.round(g2 * 100) / 100);
            s2.push(tf2);

            const ws2 = XLSX.utils.aoa_to_sheet(s2);
            ws2["!cols"] = [{wch:40}].concat(h2.slice(1).map(() => ({wch:18})));
            XLSX.utils.book_append_sheet(wb, ws2, "By Agent");

            // ── DOWNLOAD ──────────────────────────────────────────────
            XLSX.writeFile(wb, `items-report-${d.from_date}-to-${d.to_date}.xlsx`);
            frappe.show_alert({
                message:   `✅ تم تصدير ${rows.length} صنف × ${months.length} شهر`,
                indicator: "green"
            });
        },
        error: (e) => {
            el("srExport").innerText = "تصدير Excel";
            console.error(e);
        }
    });
}

function updateSelect(id, items){
    const sel = el(id);
    const currentVal = sel.value;
    sel.innerHTML = '<option value="__ALL__">الكل</option>';
    if(items && items.length > 0){
        items.forEach(i => {
            const opt = document.createElement("option");
            opt.value = i; opt.text = i;
            sel.appendChild(opt);
        });
        if(currentVal && currentVal !== "__ALL__" && items.includes(currentVal)){
            sel.value = currentVal;
        }
    }
}

