javascript:
/* =========================
   مركز الزبائن (المنطق الأصلي)
   + Enhancement:
   - Focus/click on empty search shows ALL my customers
   - Typing filters as before
   - NEW: If NEW customer created AND return_to exists => go Address (steps=2)
   ========================= */

var isEditMode = false;
var searchTimer = null;
var creationChain = false;
var currentUser = window.CURRENT_USER || "Guest";

// NEW
var RETURN_TO = "";

$(document).ready(function () {
  const urlParams = new URLSearchParams(window.location.search);
  RETURN_TO = urlParams.get("return_to") || "";

  $("#hidden_manager_id").val(currentUser);

  $("#search_input").on("input", function () {
    var val = $(this).val();
    clearTimeout(searchTimer);
    searchTimer = setTimeout(function () {
      runLiveSearch(val);
    }, 300);
  });

  $("#search_input").on("focus click", function () {
    if (!$(this).val()) runLiveSearch("__ALL__");
  });

  $(document).on("click", function (e) {
    if (!$(e.target).closest("#search_input, #search_dropdown").length) {
      $("#search_dropdown").hide();
    }
  });
});

function runLiveSearch(query) {
  var dropdown = $("#search_dropdown");
  var showAll = (query === "__ALL__");

  if (!showAll && (!query || query.length < 1)) {
    dropdown.hide();
    return;
  }

  var filtersArr = [["account_manager", "=", currentUser]];
  if (!showAll) {
    filtersArr.push(["customer_name", "like", "%" + query + "%"]);
  }

  var filters = encodeURIComponent(JSON.stringify(filtersArr));
  var fields = encodeURIComponent(
    JSON.stringify([
      "name",
      "customer_name",
      "customer_group",
      "territory",
      "account_manager",
      "posa_discount",
      "custom_customers_type",
      "customer_type"
    ])
  );

  fetch(`/api/resource/Customer?filters=${filters}&fields=${fields}&limit_page_length=50`)
    .then((r) => r.json())
    .then((d) => {
      var list = d.data || [];
      dropdown.empty();

      if (list.length > 0) {
        list.forEach((c) => {
          var displayName = c.customer_name || c.name;
          var item = $('<div class="wh-search-item">' + displayName + "</div>");

          item.click(() => {
            $("#search_input").val(displayName);
            dropdown.hide();
            loadCustomerData(c);
          });

          dropdown.append(item);
        });
        dropdown.show();
      } else dropdown.hide();
    })
    .catch((err) => {
      console.error("Live search error:", err);
      dropdown.hide();
    });
}

function loadCustomerData(data) {
  isEditMode = true;
  creationChain = false; // IMPORTANT: this is an edit path

  $("#mode_badge").text("وضع التعديل").css({ "background": "#fff7ed", "color": "#9a3412" });
  $("#btnSave").text("تحديث بيانات الزبون");

  $("#cust_name").prop("disabled", true).val(data.customer_name || data.name);
  $("#cust_group").val(data.customer_group);
  $("#cust_territory").val(data.territory);
  $("#hidden_manager_id").val(data.account_manager || currentUser);
  $("#cust_discount").val(data.posa_discount || 0);

  var customType = data.custom_customers_type || data.customer_type;
  if (customType) $("#cust_category").val(customType);

  $("#extra_actions_panel").show();

  if ($("#hidden_customer_id").length === 0) {
    $("<input>").attr({ type: "hidden", id: "hidden_customer_id" }).appendTo("body");
  }
  $("#hidden_customer_id").val(data.name || "");
}

function processForm() {
  var businessSelection = $("#cust_category").val();
  var standardType = businessSelection === "Pharmacy" ? "Individual" : "Company";

  var doc = {
    customer_name: $("#cust_name").val(),
    customer_group: $("#cust_group").val(),
    territory: $("#cust_territory").val(),
    account_manager: $("#hidden_manager_id").val() || currentUser,
    custom_customers_type: businessSelection,
    customer_type: standardType,
    posa_discount: parseFloat($("#cust_discount").val()) || 0
  };

  if (!doc.customer_name) {
    frappe.msgprint("اسم الزبون مطلوب");
    return;
  }

  $("#btnSave").text("جاري الحفظ...").prop("disabled", true);

  var url = "/api/resource/Customer";
  var method = isEditMode ? "PUT" : "POST";

  if (isEditMode) {
    var realId = ($("#hidden_customer_id").val() || "").trim() || doc.customer_name;
    url += "/" + encodeURIComponent(realId);
  } else {
    creationChain = true; // IMPORTANT: NEW customer flow
  }

  fetch(url, {
    method: method,
    headers: {
      "Content-Type": "application/json",
      "X-Frappe-CSRF-Token": frappe.csrf_token
    },
    body: JSON.stringify(doc)
  })
    .then((r) => r.json())
    .then((d) => {
      $("#btnSave")
        .text(isEditMode ? "تحديث بيانات الزبون" : "حفظ وإضافة التفاصيل ➔")
        .prop("disabled", false);

      if (!d.data) {
        console.error("Customer save error:", d);
        return;
      }

      frappe.msgprint("✅ تم حفظ بيانات الزبون بنجاح!");

      var customer_id = d.data.name;                     // REAL ID
      var cust_name = d.data.customer_name || d.data.name; // DISPLAY

      // ✅ NEW: if NEW customer created from sales => go Address first
      if (RETURN_TO && creationChain) {
        // steps=2 => Address then Contact then back to Sales
        var next =
          `/split_address?cust_name=${encodeURIComponent(cust_name)}` +
          `&customer_id=${encodeURIComponent(customer_id)}` +
          `&return_to=${encodeURIComponent(RETURN_TO)}` +
          `&steps=2`;
        window.location.href = next;
        return;
      }

      // ✅ If opened from sales but it was edit => return directly
      if (RETURN_TO && !creationChain) {
        var sep = RETURN_TO.indexOf("?") !== -1 ? "&" : "?";
        window.location.href =
          RETURN_TO + sep +
          "customer_id=" + encodeURIComponent(customer_id) +
          "&customer_name=" + encodeURIComponent(cust_name);
        return;
      }

      // Normal home behavior
      if (!isEditMode) loadCustomerData(d.data);
    })
    .catch((err) => {
      $("#btnSave")
        .text(isEditMode ? "تحديث بيانات الزبون" : "حفظ وإضافة التفاصيل ➔")
        .prop("disabled", false);
      console.error("Form error:", err);
    });
}

function goToModule(module) {
  var name = $("#cust_name").val();
  if (!name) return;

  let url = `/split_${module}?cust_name=` + encodeURIComponent(name);
  if (RETURN_TO) url += `&return_to=${encodeURIComponent(RETURN_TO)}`;
  window.location.href = url;
}

