(function () {
  // ================= CONFIG (ALLOWED METHODS ONLY) =================
  const API_META  = "lmt_inventory_meta";
  const API_ROWS  = "lmt_inventory_rows";
  const API_PRINT = "lmt_inventory_print_create";

  let LOGGED_USER = window.LOGGED_IN_USER || null;

  // masters
  let warehouses = []; // [{name}]
  let items = [];      // [{item_code,item_name,label}]

  // selection
  let selectedItemCode = "";
  let selectedItemLabel = "";
  let selectedWarehouses = []; // list of warehouse names
  let lastRows = [];

  // dom
  const el = (id) => document.getElementById(id);

  // ============= SAFE CALL (NO frappe.client, NO /api/resource) =============
  async function callApi(method, args) {
    const r = await frappe.call({ method, args });
    return r.message;
  }

  // ============= STATUS =============
  function setPill(text, bad = false) {
    const p = el("statusPill");
    if (!p) return;
    p.textContent = text;
    p.classList.toggle("bad", !!bad);
  }

  function setUser() {
    const u = (LOGGED_USER && LOGGED_USER !== "Guest") ? LOGGED_USER : "-";
    const uv = el("userView");
    if (uv) uv.textContent = u;
  }

  function fmtNow() {
    return new Date().toLocaleString();
  }

  // ============= DRAWER =============
  function toggleDrawer() {
    const d = el("drawer");
    const o = el("drawerOverlay");
    if (!d || !o) return;

    if (d.classList.contains("hidden")) {
      d.classList.remove("hidden");
      o.classList.remove("hidden");
    } else {
      closeDrawer();
    }
  }

  function closeDrawer() {
    const d = el("drawer");
    const o = el("drawerOverlay");
    if (!d || !o) return;
    d.classList.add("hidden");
    o.classList.add("hidden");
  }

  // ============= WAREHOUSE UI =============
  function renderWarehouses() {
    const box = el("warehousesBox");
    if (!box) return;

    box.innerHTML = "";

    if (!warehouses.length) {
      box.innerHTML = `<div class="items-empty">لا توجد مخازن</div>`;
      return;
    }

    warehouses.forEach(w => {
      const name = (w && w.name) ? String(w.name) : "";
      const safe = frappe.utils.escape_html(name);

      const row = document.createElement("label");
      row.className = "wh-row";
      row.innerHTML = `
        <input type="checkbox" value="${safe}" class="wh-chk">
        <span>${safe}</span>
      `;
      box.appendChild(row);
    });

    // apply selection state
    syncWarehouseChecks();
  }

  function syncWarehouseChecks() {
    const allChk = el("allWarehousesChk");
    const all = !!(allChk && allChk.checked);

    document.querySelectorAll(".wh-chk").forEach(chk => {
      chk.disabled = all;
      chk.checked = all ? false : selectedWarehouses.includes(chk.value);
    });
  }

  // ✅ MAIN FIX: If none selected -> treat as ALL
  function getWarehouseSelection() {
    const allChk = el("allWarehousesChk");
    if (allChk && allChk.checked) return ["__ALL__"];

    const out = [];
    document.querySelectorAll(".wh-chk").forEach(chk => {
      if (chk.checked) out.push(chk.value);
    });

    // If user selected none, default to ALL (required behavior)
    if (!out.length) return ["__ALL__"];

    return out;
  }

  // ============= ITEM MODAL =============
  function openItemModal() {
    const modal = el("listSelectModal");
    const search = el("listSelectSearch");
    if (!modal || !search) return;

    modal.style.display = "flex";
    search.value = "";
    renderItemList("");

    search.oninput = (e) => renderItemList((e.target && e.target.value) ? e.target.value : "");
  }

  function renderItemList(q) {
    const sc = el("listSelectScroller");
    if (!sc) return;

    sc.innerHTML = "";

    const term = (q || "").toLowerCase().trim();
    const list = term
      ? items.filter(x => (String(x.label || "")).toLowerCase().includes(term))
      : items;

    if (!list.length) {
      sc.innerHTML = `<div style="padding:15px;text-align:center;color:#999;">No results</div>`;
      return;
    }

    list.slice(0, 500).forEach(x => {
      const row = document.createElement("div");
      row.className = "select-list-row";
      row.innerHTML = `
        <div class="select-list-dot"></div>
        <div class="select-list-text">${frappe.utils.escape_html(String(x.label || ""))}</div>
      `;
      row.onclick = () => {
        selectedItemCode = String(x.item_code || "");
        selectedItemLabel = String(x.label || "");
        const ii = el("itemInput");
        if (ii) ii.value = selectedItemLabel;
        const modal = el("listSelectModal");
        if (modal) modal.style.display = "none";
      };
      sc.appendChild(row);
    });
  }

  // ============= TABLE RENDER =============
  function setTableEmpty(msg) {
    const tb = el("tbody");
    if (tb) tb.innerHTML = `<tr><td colspan="6" class="table-empty">${msg}</td></tr>`;

    const rc = el("rowsCountView");  if (rc) rc.textContent = "0";
    const ti = el("totalItemsView"); if (ti) ti.textContent = "0";
    const tq = el("totalQtyView");   if (tq) tq.textContent = "0";

    const bp = el("btnPrint");
    if (bp) bp.disabled = true;

    lastRows = [];
  }

  function renderRows(rows, totals) {
    lastRows = rows || [];

    if (!rows || !rows.length) {
      setTableEmpty("لا توجد نتائج حسب الفلاتر.");
      return;
    }

    const tb = el("tbody");
    if (!tb) return;

    tb.innerHTML = "";

    rows.forEach((r, i) => {
      const tr = document.createElement("tr");
      tr.innerHTML = `
        <td class="num">${i + 1}</td>
        <td class="text-right">
          <div class="bold">${frappe.utils.escape_html(String(r.item_name || r.item_code || ""))}</div>
          <div class="sub mono">${frappe.utils.escape_html(String(r.item_code || ""))}</div>
        </td>
        <td class="qty">${frappe.utils.escape_html(String(r.qty || 0))}</td>
        <td class="mono">${frappe.utils.escape_html(String(r.batch_no || "--"))}</td>
        <td class="mono">${frappe.utils.escape_html(String(r.expiry_date || "--"))}</td>
        <td class="mono">${frappe.utils.escape_html(String(r.warehouse || ""))}</td>
      `;
      tb.appendChild(tr);
    });

    const rc = el("rowsCountView");  if (rc) rc.textContent = String(rows.length);
    const ti = el("totalItemsView"); if (ti) ti.textContent = String((totals && totals.total_items) || rows.length);
    const tq = el("totalQtyView");   if (tq) tq.textContent = String((totals && totals.total_qty) || 0);

    const lr = el("lastRunView");
    if (lr) lr.textContent = fmtNow();

    const bp = el("btnPrint");
    if (bp) bp.disabled = false;
  }

  // ============= ACTIONS =============
  async function loadMeta() {
    setPill("تحميل...", false);
    try {
      const msg = await callApi(API_META, {});
      warehouses = (msg && msg.warehouses) || [];
      items = (msg && msg.items) || [];
      renderWarehouses();
      setPill("جاهز", false);
    } catch (e) {
      console.error(e);
      setPill("خطأ في تحميل البيانات", true);
      setTableEmpty("تعذر تحميل البيانات.");
    }
  }

    function buildFilters() {
      const whs = getWarehouseSelection();
      const hide_zero = !!(el("hideZeroChk") && el("hideZeroChk").checked);
      const sum_all_batches = !!(el("sumBatchesChk") && el("sumBatchesChk").checked);

      return {
        item_code: selectedItemCode || "",
        warehouses: whs,                      // list
        warehouses_json: JSON.stringify(whs), // string fallback
        sum_all_batches,
        hide_zero
      };
    }


  async function refresh() {
    setPill("جاري التحديث...", false);

    try {
      const msg = await callApi(API_ROWS, buildFilters());
      const rows = (msg && msg.rows) || [];
      const totals = (msg && msg.totals) || {};
      renderRows(rows, totals);
      setPill("تم", false);
    } catch (e) {
      console.error(e);
      setPill("فشل التحديث", true);
      setTableEmpty("حدث خطأ أثناء جلب التقرير.");
    }
  }

  async function printReport() {
    if (!lastRows.length) return;

    setPill("تجهيز الطباعة...", false);

    try {
      const whs = getWarehouseSelection();
      const payload = {
        item_code: selectedItemCode || "",
        warehouses: JSON.stringify(whs),
        hide_zero: !!(el("hideZeroChk") && el("hideZeroChk").checked)
      };

      // DO NOT send rows. Server must query using Serial/Batch Bundle to be consistent.
      const msg = await callApi(API_PRINT, payload);

      const doctype = msg && msg.doctype;
      const name = msg && msg.name;
      const format = "LMT Inventory Status (Arabic Pro)";

      if (!doctype || !name) {
        throw new Error("Print API did not return doctype/name");
      }

        const url =
          `/api/method/frappe.utils.print_format.download_pdf` +
          `?doctype=${encodeURIComponent(doctype)}` +
          `&name=${encodeURIComponent(name)}` +
          `&format=${encodeURIComponent(format)}`;

        window.open(url, "_blank");

      setPill("جاهز", false);
    } catch (e) {
      console.error(e);
      setPill("فشل الطباعة", true);
      alert("فشل الطباعة: " + (e.message || e));
    }
  }

  function clearFilters() {
    selectedItemCode = "";
    selectedItemLabel = "";

    const ii = el("itemInput");
    if (ii) ii.value = "";

    const allChk = el("allWarehousesChk");
    if (allChk) allChk.checked = false;

    selectedWarehouses = [];
    syncWarehouseChecks();

    const sb = el("sumBatchesChk");
    if (sb) sb.checked = true;

    const hz = el("hideZeroChk");
    if (hz) hz.checked = true;

    setTableEmpty("تم مسح الفلاتر. اضغط تحديث.");
    setPill("جاهز", false);
  }

  // ============= INIT =============
  function bindEvents() {
    const ii = el("itemInput");
    if (ii) ii.onclick = openItemModal;

    const allChk = el("allWarehousesChk");
    if (allChk) {
      allChk.addEventListener("change", () => {
        syncWarehouseChecks();
      });
    }

    // track manual warehouse selection
    document.addEventListener("change", (e) => {
      const t = e.target;
      if (t && t.classList && t.classList.contains("wh-chk")) {
        const value = t.value;
        if (t.checked) {
          if (!selectedWarehouses.includes(value)) selectedWarehouses.push(value);
        } else {
          selectedWarehouses = selectedWarehouses.filter(x => x !== value);
        }
      }
    });

    const br = el("btnRefresh");
    if (br) br.onclick = refresh;

    const bp = el("btnPrint");
    if (bp) bp.onclick = printReport;

    const bc = el("btnClear");
    if (bc) bc.onclick = clearFilters;
  }

  frappe.ready(() => {
    // run only for this route
    if (!window.location.pathname.includes("/inventory-status")) return;

    setUser();
    bindEvents();
    setTableEmpty("لا توجد بيانات. اضغط تحديث.");
    loadMeta();
  });

  // expose drawer globals used by HTML
  window.toggleDrawer = toggleDrawer;
  window.closeDrawer = closeDrawer;

})();

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');

:root { 
    --bg-main: #bfeaf4;
    --card: rgba(255, 255, 255, 0.4);
    --line: rgba(0, 0, 0, 0.15);
    --text: #0b1b22;
    --primary-blue: #004b80;
    --yellow: #ffd23c;
    --yellow-light: #ffe26b;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
}

* { box-sizing: border-box; }

/* --- Theme Force --- */
body, .page-container, .main-section, .appshell, .content, #appContent { 
    background-color: var(--bg-main) !important; 
    font-family: "Cairo", sans-serif !important;
    margin: 0;
    direction: rtl;
    text-align: right;
    padding-top: 85px !important; /* Pushed down to avoid hiding behind the fixed topbar */
    padding-bottom: 40px;
    min-height: 100vh;
}

header, footer, .navbar { display: none !important; }

/* ===== UNIFIED TOPBAR ===== */
.sr-topbar {
    display: flex !important; flex-direction: row !important; justify-content: space-between !important;
    align-items: center !important; padding: 0 15px !important; height: 65px !important;
    width: 100% !important; box-sizing: border-box !important; direction: ltr !important;
    background: rgba(255, 255, 255, 0.4) !important; backdrop-filter: blur(10px) !important;
    border-bottom: 1px solid rgba(0,0,0,0.1) !important; position: fixed; top: 0; left: 0; right: 0; z-index: 1100;
}
.topbar-left { display: flex !important; gap: 8px !important; flex: none !important; order: 1 !important; }
.topbar-right { display: flex !important; flex-direction: row !important; align-items: center !important; gap: 12px !important; flex: none !important; order: 2 !important; direction: rtl !important; }
.sr-title { text-align: right !important; margin: 0 !important; font-weight: 900; font-size: 16px; color: var(--text); font-family: "Cairo", sans-serif !important; }

.sr-btn-icon { 
    background-color: var(--yellow-light) !important; border: 1px solid rgba(0,0,0,0.2) !important; 
    border-radius: 999px !important; font-size: 16px !important; font-weight: 900 !important;
    cursor: pointer !important; width: 40px !important; height: 40px !important; 
    display: flex !important; align-items: center !important; justify-content: center !important; 
    box-shadow: var(--shadow) !important; margin: 0 !important; color: #0b1b22 !important; padding: 0 !important;
}

.wrap { max-width: 1040px; margin: 0 auto; padding: 16px; }

.card { 
    background: var(--card); 
    border: 1px solid var(--line); 
    border-radius: 14px; 
    padding: 20px; 
    margin-bottom: 20px; 
    box-shadow: var(--shadow); 
    backdrop-filter: blur(6px);
}

.grid2 { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
@media(max-width:768px){ .grid2{ grid-template-columns: 1fr; } }

.h1 { font-size: 22px; font-weight: 900; color: var(--text); }
.h2 { font-size: 18px; font-weight: 800; margin-bottom: 12px; color: var(--text); }

label { display: block; font-size: 13px; color: var(--text); margin-bottom: 6px; font-weight: 900; }

input, select, textarea { 
    width: 100%; 
    padding: 12px 15px; 
    border: 1px solid var(--line); 
    border-radius: 999px;
    background: var(--yellow-light); 
    font-family: "Cairo", sans-serif; 
    font-weight: 700;
    direction: rtl; 
    text-align: right; 
    outline: none;
    box-shadow: var(--shadow);
}
textarea { border-radius: 16px; }

button { 
    padding: 12px 24px; 
    border: 1px solid rgba(0,0,0,0.2); 
    border-radius: 999px; 
    background: var(--yellow); 
    color: var(--text); 
    font-weight: 900; 
    cursor: pointer; 
    font-family: "Cairo", sans-serif;
    box-shadow: var(--shadow);
    transition: transform 0.2s;
}

.flex-sb { display: flex; justify-content: space-between; align-items: center; }

.item { 
    padding: 16px; border: 1px solid var(--line); border-radius: 14px; 
    background: rgba(255,255,255,0.5); margin-bottom: 10px; cursor: pointer; box-shadow: var(--shadow);
}

.pill { padding: 4px 12px; border-radius: 999px; font-size: 12px; font-weight: 900; color: #fff; }
.pill.Open { background-color: #ef4444; }        
.pill.Resolved { background-color: #10b981; }    
.pill.Closed { background-color: #6b7280; }      
.pill.InProgress { background-color: #f59e0b; }

.tab-container { background: var(--yellow-light); padding: 4px; border-radius: 999px; display: inline-flex; gap: 4px; border: 1px solid var(--line); }
.tab-btn { background: transparent; color: var(--text); border: none; font-weight: 900; padding: 6px 16px; border-radius: 999px; font-size: 13px; cursor: pointer; }
.tab-btn.active { background: var(--yellow); box-shadow: var(--shadow); }

#msg { display: none; padding: 14px; background: var(--primary-blue); color: #fff; text-align: center; border-radius: 12px; margin-bottom: 16px; font-weight: 900; }

javascript:
(function(){
  function $(id){ return document.getElementById(id); }

  window.USER = "{{ frappe.session.user }}";
  var currentTicket = null;
  var currentView = "active";
  var selectedFile = null;

  // --- 1. File Selection (5MB Limit) ---
  window.handleFileSelect = function(input) {
    if (input.files.length === 0) return;
    var file = input.files[0];
    if (file.size > 5242880) {
        toast("File too large (Max 5MB)", false);
        input.value = "";
        selectedFile = null;
        return;
    }
    $("fileNameDisplay").innerText = file.name;
    selectedFile = file; 
  };

  function toast(msg, ok){
    var b = $("msg"); b.style.display="block"; b.innerText = msg;
    b.style.background = ok ? "#2f8f3a" : "#dc2626";
    window.scrollTo(0,0);
    setTimeout(() => { b.style.display="none"; }, 4000);
  }

  // --- 2. API Helpers (Warehouse Pattern) ---
  // Uses JSON for data to match your stable Server Script logic
  function apiPost(method, args) {
    return fetch("/api/method/" + method, {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
            "X-Frappe-CSRF-Token": frappe.csrf_token
        },
        body: JSON.stringify(args || {})
    }).then(function(r){ 
        if(!r.ok) throw new Error("Server Error: " + r.status);
        return r.json(); 
    });
  }

  // Native Frappe Upload logic - This handles the binary transfer correctly
  function uploadFileToTicket(file, doctype, docname) {
    var formData = new FormData();
    formData.append("file", file, file.name);
    formData.append("is_private", 0);
    formData.append("doctype", doctype);
    formData.append("docname", docname);

    return fetch("/api/method/upload_file", {
        method: "POST",
        body: formData,
        headers: { "X-Frappe-CSRF-Token": frappe.csrf_token }
    }).then(function(r){ return r.json(); });
  }

  // --- 3. Ticket Actions ---
  window.createTicket = async function(){
    var s = $("newSubject").value, d = $("newDesc").value, p = $("newPriority").value;
    if(!s || !d) return toast("Subject and Description required", false);

    var payload = { subject: s, description: d, priority: p, category: "General" };
    try {
        toast("Creating Ticket...", true);

        // Step 1: Create the record via your custom API
        var res = await apiPost("lmt_helpdesk_new_create_ticket", payload);

        if (res.message && res.message.name) {
            var ticketName = res.message.name;

            // Step 2: If a file is selected, upload it using the native Warehouse approach
            if (selectedFile) {
                toast("Uploading attachment...", true);
                var uploadRes = await uploadFileToTicket(selectedFile, "LMT Helpdesk Ticket", ticketName);

                // Intelligent Check: Verify if native upload returned success
                if (!uploadRes.message) throw new Error("Upload Failed");
            }

            toast("Success!", true);
            setTimeout(() => { location.reload(); }, 1000);
        } else {
            throw new Error(res.message || "Failed to create ticket");
        }
    } catch(e) { 
        console.error("Creation Failed:", e);
        toast(e.message, false); 
    }
  };

  // --- 4. Update Logic (Status, Assign, Comment) ---
  window.updateTicket = async function(action){
      var args = { name: currentTicket.name, action: action };
      if(action === "comment") { 
          args.note = $("replyText").value; 
          if(!args.note) return; 
      }
      else if(action === "status") args.val = $("adminStatus").value;
      else if(action === "assign") args.val = $("adminAssign").value;

      try {
          toast("Updating...", true);
          var res = await apiPost("lmt_helpdesk_new_update_ticket", args);
          if (res.message && res.message.ok) {
              toast("Updated successfully", true);
              if(action === "comment") $("replyText").value = "";
              openTicket(currentTicket.name); // Refresh view
              if(action === "status") loadMyTickets(); // Refresh list
          }
      } catch(e) { toast(e.message, false); }
  };
   // --- Tab Switching Logic ---
  window.setTab = function(view) {
      currentView = view;

      // Update button colors
      $("btnActive").className = (view === "active") ? "tab-btn active" : "tab-btn";
      $("btnArchive").className = (view === "archive") ? "tab-btn active" : "tab-btn";

      // Load the tickets for the selected tab
      loadMyTickets();
  };
  // --- 5. Navigation and Listing ---
  window.loadMyTickets = async function(){
    $("myList").innerHTML = "<div class='muted' style='text-align:center; padding:20px'>Loading...</div>";
    try {
        var r = await fetch("/api/method/lmt_helpdesk_new_list_tickets?view=" + currentView + "&_t=" + Date.now());
        var d = await r.json();
        var rows = d.message || [];
        var h = "";
        rows.forEach(r => {
            var sc = (r.status || "Open").replace(/\s/g, '');
            h += `<div class="item" onclick="openTicket('${r.name}')">
                    <div class="flex-sb">
                        <span style="font-weight:900; font-size:16px;">${r.subject}</span>
                        <span class="pill ${sc}">${r.status}</span>
                    </div>
                    <div class="muted" style="margin-top:8px;">${r.name} • 👤 <b>${r.raised_by_name || r.raised_by}</b></div>
                  </div>`;
        });
        $("myList").innerHTML = h || "<div class='muted' style='text-align:center; padding:20px'>No results</div>";
    } catch(e) { console.error("List Load Failed:", e); }
  };

  window.openTicket = async function(name){
      toast("Opening...", true);
      try {
          var r = await fetch("/api/method/lmt_helpdesk_new_get_ticket?name=" + name);
          var d = await r.json();
          var res = d.message;
          currentTicket = res.ticket;

          $("d_name").innerText = currentTicket.name;
          $("d_subject").innerText = currentTicket.subject;
          var sEl = $("d_status");
          sEl.innerText = currentTicket.status;
          sEl.className = "pill " + (currentTicket.status || "Open").replace(/\s/g, '');
          $("d_desc").innerText = currentTicket.description;

          // Show attachment if it exists
          if(currentTicket.attachment) {
              $("attachmentArea").style.display = "block";
              var isImg = /\.(jpg|jpeg|png|gif)$/i.test(currentTicket.attachment);
              if(isImg) {
                  $("d_attachment").innerHTML = `<img src="${currentTicket.attachment}" style="max-width:100%; border-radius:8px; cursor:pointer;" onclick="window.open(this.src)">`;
              } else {
                  $("d_attachment").innerHTML = `<a href="${currentTicket.attachment}" target="_blank" style="color:var(--primary-blue); font-weight:bold;">📎 Download Attachment</a>`;
              }
          } else { $("attachmentArea").style.display = "none"; }

          // Comments List
          var h = "";
          (res.updates || []).forEach(u => {
              h += `<div style="border-right:3px solid var(--yellow); padding-right:10px; margin-bottom:10px;">
                      <div class="muted" style="font-size:11px">${u.update_by}</div>
                      <div style="background:rgba(255,255,255,0.5); padding:8px; border-radius:8px; font-weight:700;">${u.note}</div>
                    </div>`;
          });
          $("updatesList").innerHTML = h;

          // Admin Panel visibility
          if(res.is_admin) {
              $("adminPanel").style.display = "block";
              $("adminStatus").value = currentTicket.status;
              var sel = $("adminAssign");
              sel.innerHTML = '<option value="">-- Select --</option>';
              (res.assignees || []).forEach(u => {
                  var opt = document.createElement("option");
                  opt.value = u.name; opt.text = u.full_name;
                  if(currentTicket.assigned_to === u.name) opt.selected = true;
                  sel.appendChild(opt);
              });
          } else { $("adminPanel").style.display = "none"; }

          $("viewList").style.display="none"; 
          $("viewDetail").style.display="block"; 
          window.scrollTo(0,0); 
          $("msg").style.display="none";
      } catch(e) { toast("Error opening ticket", false); }
  };

  window.showList = function(){ $("viewDetail").style.display="none"; $("viewList").style.display="block"; loadMyTickets(); window.scrollTo(0,0); };

  if(window.USER !== "Guest") loadMyTickets(); 
})();

