let selectedLeaveType = "";
let isHalfDay = 0;
let empDoc = null;
let leaveTypes = [];

$(document).ready(async function() {
    // Set default dates to today
    const today = new Date().toISOString().split("T")[0];
    $("#fromDate, #toDate").val(today);

    // Initial Data Fetch
    await getEmployeeData();
    await loadLeaveTypes();

    if (empDoc) {
        await loadLeaveBalance();
        await loadApplicationHistory();
    }

    // UI Listeners
    $("#leaveTypeInput").on("click", openLeaveModal);
    $("#halfDayYes").on("click", () => toggleHalfDay(1));
    $("#halfDayNo").on("click", () => toggleHalfDay(0));
    $("#btnSubmitLeave").on("click", submitLeaveRequest);
});

async function getEmployeeData() {
    try {
        const res = await fetch(`/api/resource/Employee?filters=[["user_id","=","${window.LOGGED_IN_USER}"]]&fields=["name","employee_name","company","leave_approver"]`);
        const data = await res.json();
        if (data.data && data.data.length > 0) {
            empDoc = data.data[0];
            $("#empNameFull").text(empDoc.employee_name);
            $("#approverName").text(empDoc.leave_approver || "غير محدد");
        } else {
            alert("خطأ: حسابك غير مرتبط بملف موظف.");
        }
    } catch (e) { console.error("Employee fetch failed", e); }
}

async function loadLeaveBalance() {
    try {
        const res = await fetch(`/api/resource/Leave Allocation?filters=[["employee","=","${empDoc.name}"],["docstatus","=",1]]&fields=["unused_leaves"]`);
        const data = await res.json();
        let total = 0;
        if (data.data) {
            data.data.forEach(alloc => total += alloc.unused_leaves);
        }
        $("#leaveBalance").text(`رصيد متبقي: ${total} يوم`);
    } catch (e) { console.error("Balance fetch failed", e); }
}

async function loadApplicationHistory() {
    try {
        const res = await fetch(`/api/resource/Leave Application?filters=[["employee","=","${empDoc.name}"]]&fields=["name","leave_type","from_date","to_date","total_leave_days","status"]&order_by=creation desc&limit_page_length=5`);
        const data = await res.json();
        const container = $("#historyContainer").empty();

        if (data.data && data.data.length > 0) {
            data.data.forEach(app => {
                let statusColor = app.status === "Approved" ? "#2e7d32" : (app.status === "Open" ? "#004b80" : "#d32f2f");
                container.append(`
                    <div class="item-row">
                        <div class="order-meta-row">
                            <div class="item-row-name">${app.leave_type}</div>
                            <div class="item-row-total">${app.total_leave_days} يوم</div>
                        </div>
                        <div class="order-meta-row sub-meta">
                            <div>${app.from_date} ⬅ ${app.to_date}</div>
                            <div style="color: ${statusColor}; font-weight: 900;">● ${app.status}</div>
                        </div>
                    </div>
                `);
            });
        } else {
            container.html('<div class="items-empty">لا يوجد سجل طلبات سابق</div>');
        }
    } catch (e) { console.error("History fetch failed", e); }
}

async function loadLeaveTypes() {
    try {
        const res = await fetch(`/api/resource/Leave Type?fields=["name"]`);
        const data = await res.json();
        leaveTypes = data.data.map(d => d.name);
    } catch (e) { console.error("Leave types failed", e); }
}

function openLeaveModal() {
    $("#listSelectModal").css("display", "flex");
    renderOptions(leaveTypes);
    $("#listSelectSearch").off().on("input", function() {
        const val = $(this).val().toLowerCase();
        renderOptions(leaveTypes.filter(t => t.toLowerCase().includes(val)));
    });
}

function renderOptions(list) {
    const container = $("#listSelectScroller").empty();
    list.forEach(item => {
        const row = $(`<div class="select-list-row"><div class="select-list-dot"></div><div class="select-list-text">${item}</div></div>`);
        row.on("click", () => {
            selectedLeaveType = item;
            $("#leaveTypeInput").val(item);
            $("#listSelectModal").hide();
        });
        container.append(row);
    });
}

function toggleHalfDay(val) {
    isHalfDay = val;
    $("#halfDayYes").toggleClass("active-sale", val === 1);
    $("#halfDayNo").toggleClass("active-sale", val === 0);
}

async function submitLeaveRequest() {
    if (!empDoc) return alert("بيانات الموظف غير محملة");
    if (!selectedLeaveType) return alert("يرجى اختيار نوع الإجازة");

    const btn = $("#btnSubmitLeave");
    btn.prop("disabled", true).text("جاري الإرسال...");

    const payload = {
        doctype: "Leave Application",
        employee: empDoc.name,
        company: empDoc.company,
        leave_approver: empDoc.leave_approver,
        leave_type: selectedLeaveType,
        from_date: $("#fromDate").val(),
        to_date: $("#toDate").val(),
        half_day: isHalfDay,
        reason: $("#reason").val() || "طلب عبر الموبايل",
        status: "Open",
        docstatus: 0
    };

    try {
        const response = await fetch("/api/resource/Leave Application", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
                "X-Frappe-CSRF-Token": window.CSRF_TOKEN
            },
            body: JSON.stringify(payload)
        });

        if (response.ok) {
            alert("✅ تم إرسال الطلب بنجاح");
            window.location.reload();
        } else {
            const err = await response.json();
            alert("خطأ: " + (err.message || "تأكد من الرصيد أو تواريخ الإجازة"));
        }
    } catch (e) {
        alert("فشل الاتصال بالخادم");
    } finally {
        btn.prop("disabled", false).text("حفظ وإرسال الطلب ✅");
    }
}

