    callback: (r) => {
      const resp = r.message || {};
      if (resp.status === "error") { frappe.msgprint(resp.message); return; }

      const sel = el("srAgent");
      sel.innerHTML = '<option value="">-- اختر المندوب --</option>';

      let users = Array.isArray(resp.data) ? resp.data : [];
      users.forEach(u => {
        const opt = document.createElement("option");
        opt.value = u.id;
        opt.text  = u.name;
        sel.appendChild(opt);
      });
    }
  });
}

function loadOrders() {
  const targetUser = el("srAgent").value;
  if (!targetUser) {
    el("srTb").innerHTML = '<tr><td colspan="5">اختر المندوب لعرض الطلبيات</td></tr>';
    return;
  }

  el("srTb").innerHTML = '<tr><td colspan="5">جاري التحميل...</td></tr>';

  frappe.call({
    method: API_ORDERS,
    args: { target_user: targetUser },
    callback: (r) => {
      const resp = r.message || {};
      if (resp.status === "error") { frappe.msgprint(resp.message); return; }

      let orders = Array.isArray(resp.data) ? resp.data : [];
      renderTable(orders);
    }
  });
}

function renderTable(orders) {
  const tbody = el("srTb");
  tbody.innerHTML = "";

  if (!orders || orders.length === 0) {
    tbody.innerHTML = '<tr><td colspan="5">لا يوجد طلبيات لهذا المندوب</td></tr>';
    return;
  }

  orders.forEach(o => {
    const tr = document.createElement("tr");
    const dateStr = frappe.datetime.str_to_user(o.transaction_date);

    let nameHtml = `<div style="font-size:13px; font-weight:900;">${o.name}</div>`;
    nameHtml += `<div style="font-size:11px; opacity:0.8">${o.customer_name}</div>`;

    tr.innerHTML = `
      <td class="name">${nameHtml}</td>
      <td>${dateStr}</td>
      <td><span class="sr-badge">${o.status || 'Unknown'}</span></td>
      <td style="font-weight:900;">${fmt(o.grand_total)}</td>
      <td><button class="sr-btn danger" onclick="confirmUnsubmit('${o.name}')">الغاء الطلب 🔄</button></td>
    `;
    tbody.appendChild(tr);
  });
}

function confirmUnsubmit(soName) {
  frappe.confirm(
    `هل أنت متأكد من الغاء الطلب ${soName}؟<br>سيتم مسح أي أوامر تسليم أو فواتير مرتبطة به، وسيتم إنشاء نسخة معدلة جديدة.`,
    () => executeUnsubmit(soName)
  );
}

function executeUnsubmit(soName) {
  frappe.call({
    method: API_ACTION,
    args: { so_name: soName },
    freeze: true,
    freeze_message: "جاري التنفيذ وحذف المرفقات...",
    callback: (r) => {
      const resp = r.message || {};

      if (resp.status === "error") { 
          frappe.msgprint({title: 'خطأ في النظام (System Error)', indicator: 'red', message: resp.message}); 
          loadOrders(); 
          return; 
      }

      if (resp.status === "success") {
        // THE FIX: Large, obvious confirmation modal instead of a tiny toast
        frappe.msgprint({
            title: 'تمت العملية بنجاح ✅',
            indicator: 'green',
            message: `تم الغاء الطلب وحذف أوامر التسليم المرتبطة به بنجاح!<br><br>تم إنشاء نسخة مسودة جديدة برقم:<br><b style="font-size:16px;">${resp.new_name}</b>`
        });

        // This will instantly refresh the table in the background
        loadOrders();
      }
    }
  });
}

frappe.ready(init);

