@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');

/* --- Reset ERPNext UI --- */
footer, .web-footer, .page-footer, header.navbar, .navbar, .page-breadcrumbs { display: none !important; }

:root { 
    --bg: #bfeaf4; 
