}
.sr-btn-icon { 
    border: 1px solid rgba(0,0,0,0.25); cursor: pointer; border-radius: 999px; 
    padding: 8px 12px; font-weight: 900; background: var(--yellow2); box-shadow: var(--shadow); color: #0b1b22;
}
.sr-title { font-weight: 900; font-size: 16px; flex: 1; color: #0b1b22; }

.sr-badge-msg { background: var(--green); color: white; padding: 2px 12px; border-radius: 999px; font-size: 11px; font-weight: 900; }

/* --- Containers & Cards --- */
.wh-container { max-width: 1200px; margin: 0 auto; padding: 20px; }

.wh-card { 
    background: rgba(255,255,255,0.4) !important; 
    border: 1px solid rgba(0,0,0,0.1) !important; 
    border-radius: 20px !important; 
    box-shadow: var(--shadow); 
