}

/* --- Filters --- */
.wh-filter-bar { padding: 15px; display: flex; flex-wrap: wrap; gap: 10px; align-items: center; border-bottom: 1px solid rgba(0,0,0,0.05); }

.sr-pill { 
    background: var(--yellow); border: 1px solid rgba(0,0,0,0.15); 
    border-radius: 999px; padding: 4px 16px; display: flex; align-items: center; box-shadow: var(--shadow);
}

.wh-input, .wh-select, .wh-input-date {
    flex: 1; border: none !important; background: transparent !important; 
