/* --- Tab Actions (Restored wh-btn for Click Functions) --- */
.wh-actions { padding: 15px; display: flex; gap: 10px; overflow-x: auto; white-space: nowrap; border-bottom: 1px solid rgba(0,0,0,0.05); }

.wh-btn { 
    border: 1px solid rgba(0,0,0,.1); cursor: pointer; border-radius: 999px; 
    padding: 10px 20px; font-family: "Cairo"; font-weight: 900; 
