}

.wh-btn.active { background: var(--green) !important; color: white !important; border-color: var(--green) !important; }

/* --- Table --- */
.wh-table { width: 100%; border-collapse: collapse; }
.wh-table th { text-align: right; padding: 12px; font-size: 12px; font-weight: 900; color: #0b1b22; opacity: 0.6; }
.wh-table td { padding: 15px 12px; border-bottom: 1px solid rgba(0,0,0,0.05); font-weight: 700; font-size: 13px; }

/* --- NEW ROW COLOR LOGIC --- */
/* Slightly transparent so the text remains readable */
.wh-table tr.row-draft td { background-color: rgba(239, 68, 68, 0.15) !important; }    /* Red for Draft */
.wh-table tr.row-submitted td { background-color: rgba(59, 130, 246, 0.15) !important; } /* Blue for Submitted */
.wh-table tr.row-delivered td { background-color: rgba(21, 128, 61, 0.2) !important; }   /* Dark Green for Delivered */

/* Status Badges */
.status-badge { padding: 4px 12px; border-radius: 999px; font-size: 11px; font-weight: 900; }
.st-NEW { background: #e0f2fe; color: #0284c7; }
.st-PICKING { background: #fef3c7; color: #d97706; }
.st-DISPATCHED { background: #dcfce7; color: #16a34a; }

/* --- Modals --- */
.wh-modal { 
    position: fixed; inset: 0; background: rgba(0,0,0,0.4); 
    display: none; justify-content: center; align-items: center; 
    z-index: 2000; backdrop-filter: blur(4px); 
}
.wh-modal-content { 
    background: var(--bg); width: 90%; max-width: 350px; padding: 25px; 
