javascript:
// --- SAFE SECURITY: LOCKOUT GUESTS ---
$(document).ready(function() {
    try {
        if (frappe.session.user === 'Guest') {
            window.location.href = '/login?redirect-to=/warehouse';
        } else {
            $('body').css('display', 'block');
        }
    } catch (e) {
        console.error("Security Check Failed:", e);
        $('body').css('display', 'block');
    }
});

// --- CONFIGURATION ---
var SO_STATUS_FIELD = "custom_warehouse_status";
var API_SET = "mark_printed_flags";
var API_GET = "get_print_status";
var API_UNDO_PICKING = "warehouse_undo_picking";

var allOrders = [];
var userMap = {}; 
var currentStatus = "NEW";

// --- API HELPERS ---
function apiGet(url, callback) {
    var noCacheUrl = url + (url.indexOf("?") === -1 ? "?" : "&") + "_t=" + new Date().getTime();
    fetch(noCacheUrl)
        .then(function(r){ return r.json(); })
        .then(function(d){ callback(d); })
        .catch(function(e){ console.error(e); });
}

function apiSetPrinted(doctype, name, field, callback) {
    var url = "/api/method/"+API_SET+"?doctype="+encodeURIComponent(doctype)+"&name="+encodeURIComponent(name)+"&fieldname="+field;
    apiGet(url, callback);
}

function apiPost(method, args) {
    return fetch("/api/method/" + method, {
        method: "POST",
        headers: {
            "Content-Type": "application/json",
            "X-Frappe-CSRF-Token": frappe.csrf_token
        },
        body: JSON.stringify(args || {})
    }).then(function(r){ return r.json(); });
}

// --- NEW FILE UPLOAD WITH CLIENT-SIDE RESIZING ---
function uploadFile(input, doctype, docname) {
    if (input.files.length === 0) return;
    var file = input.files[0];
    var label = $(input).parent();
    var originalText = label.html();

    // Helper function to handle the actual upload request
    function executeUpload(uploadBlob, fileName) {
        label.text("جاري الرفع...");
        var formData = new FormData();
        formData.append("file", uploadBlob, fileName);
        formData.append("is_private", 0);
        formData.append("doctype", doctype);
        formData.append("docname", docname);

        fetch("/api/method/upload_file", {
            method: "POST",
            body: formData,
            headers: { "X-Frappe-CSRF-Token": frappe.csrf_token }
        })
        .then(function(r){ return r.json(); })
        .then(function(d) {
            label.html(originalText);
            if (d.message) {
                var soName = (doctype === "Sales Order") ? docname : findOrderNameByDN(docname);
                fetchRowStatus(soName);

                if (currentStatus === "DISPATCHED" && doctype === "Sales Order" && soName) {
                    var order = findOrder(soName);
                    var dnName = order ? order.dn_name : null;
                    $("#msg").text("Creating Sales Invoice...");

                    apiPost("create_sales_invoice_after_upload_qa", { so_name: soName, dn_name: dnName })
                    .then(function(res) {
                        if (res && res.message && res.message.ok) {
                            $("#msg").text("Invoice: " + res.message.invoice);
                            setTimeout(function(){ fetchRowStatus(soName); }, 1200);
                        } else {
                            $("#msg").text("Failed to create invoice");
                            alert("Failed to create Sales Invoice");
                        }
                    })
                    .catch(function(e) {
                        $("#msg").text("Failed to create invoice");
                        alert("Failed to create Sales Invoice");
                    });
                }
            }
        })
        .catch(function(e){
            alert("فشل الرفع. الرجاء المحاولة مرة أخرى.");
            label.html(originalText);
        });
    }

    // Check if the file is an image
    if (file.type.match(/image.*/)) {
        label.text("جاري الضغط...");
        var reader = new FileReader();

        reader.onload = function(e) {
            var img = new Image();
            img.onload = function() {
                var canvas = document.createElement("canvas");
                // MAX PIXEL DIMENSIONS
                var MAX_WIDTH = 1200;
                var MAX_HEIGHT = 1200;
                var width = img.width;
                var height = img.height;

                // Calculate aspect ratio
                if (width > height) {
                    if (width > MAX_WIDTH) {
                        height *= MAX_WIDTH / width;
                        width = MAX_WIDTH;
                    }
                } else {
                    if (height > MAX_HEIGHT) {
                        width *= MAX_HEIGHT / height;
                        height = MAX_HEIGHT;
                    }
                }

                // Draw resized image
                canvas.width = width;
                canvas.height = height;
                var ctx = canvas.getContext("2d");
                ctx.drawImage(img, 0, 0, width, height);

                // Compress as JPEG at 70% quality
                canvas.toBlob(function(blob) {
                    // Extract original file name but ensure it uploads as .jpg
                    var originalName = file.name.replace(/\.[^/.]+$/, "");
                    executeUpload(blob, originalName + "_compressed.jpg");
                }, "image/jpeg", 0.7);
            };
            img.src = e.target.result;
        };
        reader.readAsDataURL(file);
    } else {
        // Fallback for PDFs or other docs (Limit to 5MB)
        if (file.size > 5 * 1024 * 1024) {
            alert("حجم الملف كبير جداً! الحد الأقصى للملفات غير المصورة هو 5 ميجابايت.");
            input.value = "";
            return;
        }
        executeUpload(file, file.name);
    }
}

// --- MAIN LOGIC ---
function loadList(status) {
    currentStatus = status || "NEW";
    $('.wh-btn').removeClass('active');
    $('#btn' + currentStatus).addClass('active');

    updateTableHeaders();
    $('#msg').text("جاري التحميل...");
    var selectedWH = $("#filterWarehouse").val();
    var payload = {
        status: currentStatus,
        date_from: $("#dateFrom").val(),
        date_to: $("#dateTo").val(),
        search: $("#searchInput").val(),
        owner: $("#filterUser").val() || "",
        warehouses: (selectedWH ? [selectedWH] : ["__ALL__"])
    };

    apiPost("lmt_warehouse_orders", payload)
        .then(function(res) {

            allOrders = (res && res.message && res.message.rows) ? res.message.rows : [];

            for (var i = 0; i < allOrders.length; i++) {
                allOrders[i].so_printed = 0; allOrders[i].dn_printed = 0;
                allOrders[i].picked = 0; allOrders[i].dispatched = 0; allOrders[i].delivered = 0;
                allOrders[i].dn_file_url = ""; allOrders[i].so_file_url = "";
                allOrders[i].dn_name = "";
            }

            fetchUserNames();
            updateFilterOptions();
            renderTable();

            $('#msg').text(allOrders.length + " طلب");
            allOrders.forEach(function(d) { fetchRowStatus(d.name); });
        })
        .catch(function(e){
            console.error(e);
            $('#msg').text("فشل التحميل");
        });

}

// --- Fetch user full names ---
function fetchUserNames() {
    var emailsToFetch = [];

    for (var i=0; i<allOrders.length; i++) {
        var email = allOrders[i].owner;
        if (email && !userMap[email]) {
            userMap[email] = email.split('@')[0];
            emailsToFetch.push(email);
        }
    }

    var uniqueEmails = emailsToFetch.filter(function(item, pos) {
        return emailsToFetch.indexOf(item) === pos;
    });

    if (uniqueEmails.length === 0) {
        updateFilterOptions();
        renderTable();
        return;
    }

    var filters = JSON.stringify([["name", "in", uniqueEmails]]);
    var fields = JSON.stringify(["name", "full_name"]);
    var url = "/api/resource/User?fields=" + encodeURIComponent(fields) +
              "&filters=" + encodeURIComponent(filters) +
              "&limit_page_length=200";

    apiGet(url, function(res) {
        if (res.data) {
            res.data.forEach(function(u) {
                if (u.full_name) userMap[u.name] = u.full_name;
            });
        }
        renderTable();
        updateFilterOptions();
    });
}

function updateTableHeaders() {
    var thead = $('.wh-table thead tr');
    thead.empty();
    thead.append(
        '<th>الطلب</th>' +
        '<th>العميل</th>' +
        '<th>مندوب المبيعات</th>' +
        '<th>المستودع</th>' +
        '<th>التاريخ</th>'
    );

    if (currentStatus === 'NEW') {
        thead.append(
            '<th style="text-align:center">ملف الفاتورة</th>' +
            '<th style="text-align:center">ملف امر التسليم</th>'
        );
    } else if (currentStatus === 'PICKING') {
        thead.append(
            '<th style="text-align:center">امر التسليم موقّع</th>' +
            '<th style="text-align:center">إجراء</th>'
        );
    } else if (currentStatus === 'DISPATCHED') {
        thead.append(
            '<th style="text-align:center">السائق</th>' +
            '<th style="text-align:center">التسليم</th>'
        );
    } else if (currentStatus === 'OVERVIEW') {
        thead.append(
            '<th style="text-align:center">الحالة</th>' +
            '<th style="text-align:center">الملفات</th>'
        );
    }
}

function fetchRowStatus(soName) {
    if (!soName) return;

    apiGet("/api/method/" + API_GET + "?so_name=" + encodeURIComponent(soName), function(res) {
        if (!res.message || !res.message.ok) return;

        var d = res.message;
        var order = findOrder(soName);

        if (order) {
            order.status = d.status;
            order.so_printed = d.so_printed;
            order.dn_name = d.dn_name;
            order.dn_printed = d.dn_printed;
            order.picked = d.picked;
            order.dispatched = d.dispatched;
            order.delivered = d.delivered;
            order.dn_file_url = d.dn_file_url;
            order.so_file_url = d.so_file_url;

            if (currentStatus !== 'OVERVIEW' && order.status && order.status !== currentStatus) {
                $("#tr-" + soName).fadeOut(500, function() { $(this).remove(); });
                var count = $("#rows tr").length - 1;
                if (count >= 0) $('#msg').text(count + " Orders");
                return;
            }

            var existingRow = $("#tr-" + soName);
            if (existingRow.length) {
                var rowClass = "";
                var ds = (typeof order.docstatus === "number") ? order.docstatus : parseInt(order.docstatus || "0", 10);
                if (order.delivered) {
                    rowClass = "row-delivered";
                } else if (ds === 1) {
                    rowClass = "row-submitted";
                } else if (ds === 0) {
                    rowClass = "row-draft";
                }

                existingRow.attr("class", rowClass);
            }

            updateRowUI(order);

            var hide = $("#hidePrinted").is(":checked");
            if (currentStatus === 'NEW' && hide && order.so_printed && order.dn_printed) $("#tr-" + soName).fadeOut();
            if (currentStatus === 'DISPATCHED' && order.delivered) $("#tr-" + soName).fadeOut();
        }
    });
}

function findOrder(name) {
    for (var i=0; i<allOrders.length; i++) {
        if (allOrders[i].name === name) return allOrders[i];
    }
    return null;
}
function findOrderNameByDN(dnName) {
    for (var i=0; i<allOrders.length; i++) {
        if (allOrders[i].dn_name === dnName) return allOrders[i].name;
    }
    return null;
}

function buildOrderCell(d) {
    var ds = (typeof d.docstatus === "number") ? d.docstatus : parseInt(d.docstatus || "0", 10);

    if (ds === 1) {
        return '<span class="so-link so-submitted">' +
               d.name + ' <span class="so-tag">(submitted)</span></span>';
    }

    var orderDateStr = (d.transaction_date || "").slice(0, 10); 
    var diffDays = 0;

    if (orderDateStr && orderDateStr.indexOf("-") > -1) {
        var p = orderDateStr.split("-");
        var od = new Date(parseInt(p[0],10), parseInt(p[1],10)-1, parseInt(p[2],10));
        var now = new Date();
        var today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        diffDays = Math.floor((today.getTime() - od.getTime()) / 86400000);
    }

    var cls = (diffDays > 2) ? "so-draft-old" : "so-draft-warn";

    var tip = (cls === "so-draft-old")
        ? ("Draft أقدم من يومين (" + diffDays + " يوم) — الرجاء إبلاغ المندوب لعمل Submit")
        : ("Draft جديد (" + diffDays + " يوم) — راجع المندوب إذا تأخر في Submit");

    return '<span class="so-link ' + cls + '" title="' + tip.replace(/"/g,'&quot;') + '">' +
           d.name + ' <span class="so-tag">(draft)</span></span>';
}

function renderTable() {
    var txt = $("#searchInput").val().toLowerCase();
    var wh = $("#filterWarehouse").val();
    var user = $("#filterUser").val();
    var hide = $("#hidePrinted").is(":checked");
    var dFrom = $("#dateFrom").val();
    var dTo = $("#dateTo").val();
    var tbody = $("#rows"); tbody.empty();

    if (!allOrders.length) {
        tbody.html('<tr><td colspan="7" style="text-align:center; padding:20px">لا توجد نتائج</td></tr>');
        return;
    }

    var html = "";
    for (var i = 0; i < allOrders.length; i++) {
        var d = allOrders[i];

        if (txt && d.name.toLowerCase().indexOf(txt) === -1 &&
            (!d.customer_name || d.customer_name.toLowerCase().indexOf(txt) === -1)) continue;

        if (wh && d.set_warehouse !== wh) continue;
        if (user && d.owner !== user) continue;
        if (dFrom && d.transaction_date < dFrom) continue;
        if (dTo && d.transaction_date > dTo) continue;

        if (currentStatus === 'NEW' && hide && d.so_printed && d.dn_printed) continue;
        if (currentStatus === 'DISPATCHED' && d.delivered) continue;

        var rowClass = "";
        var ds = (typeof d.docstatus === "number") ? d.docstatus : parseInt(d.docstatus || "0", 10);

        if (d.delivered) {
            rowClass = "row-delivered";
        } else if (ds === 1) {
            rowClass = "row-submitted";
        } else if (ds === 0) {
            rowClass = "row-draft";
        }

        html += '<tr id="tr-' + d.name + '" class="' + rowClass + '">';
        html += '<td data-label="Order">' + buildOrderCell(d) + '</td>';
        html += '<td data-label="Customer">' + (d.customer_name || '-') + '</td>';

        var displayName = userMap[d.owner] || d.owner || '-';
        html += '<td data-label="Sales Rep" style="font-size:12px; color:#555; font-weight:bold;">' + displayName + '</td>';

        html += '<td data-label="Whse">' + (d.set_warehouse || 'N/A') + '</td>';
        html += '<td data-label="Date">' + d.transaction_date + '</td>';

        if (currentStatus === 'NEW') {
            html += '<td data-label="SO" style="text-align:center" id="c1-' + d.name + '">' + buildSOCell(d) + '</td>';
            html += '<td data-label="DN" style="text-align:center" id="c2-' + d.name + '">' + buildDNCell(d) + '</td>';
        } else if (currentStatus === 'PICKING') {
            html += '<td data-label="File" style="text-align:center" id="c1-' + d.name + '">' + buildUploadCell(d, 'DN') + '</td>';
            html += '<td data-label="Action" style="text-align:center" id="c2-' + d.name + '">' + buildActionCell(d, 'PICK') + '</td>';
        } else if (currentStatus === 'DISPATCHED') {
            html += '<td data-label="Driver" style="text-align:center" id="c1-' + d.name + '">' + buildDriverCell(d) + '</td>';
            html += '<td data-label="Delivery" style="text-align:center" id="c2-' + d.name + '">' + buildDeliveryCell(d) + '</td>';
        } else if (currentStatus === 'OVERVIEW') {
            html += '<td data-label="Status" style="text-align:center" id="c1-' + d.name + '">' + buildStatusCell(d) + '</td>';
            html += '<td data-label="Files" style="text-align:center" id="c2-' + d.name + '">' + buildFilesCell(d) + '</td>';
        }

        html += '</tr>';
    }

    tbody.html(html);
}

function buildSOCell(d) {
    var link = "/api/method/frappe.utils.print_format.download_pdf?doctype=Sales Order&name=" + d.name + "&format=Draft Proforma&no_letterhead=0";
    var onclick = "markPrinted('Sales Order', '"+d.name+"', 'custom_log_1'); setTimeout(function(){ fetchRowStatus('"+d.name+"'); }, 1500);";
    return '<div class="wh-pdfcell"><a href="' + link + '" target="_blank" class="wh-pdflink" onclick="'+onclick+'">📄 SO</a></div>';
}

function buildDNCell(d) {
    if (!d.dn_name) return '-';
    var disabledClass = (!d.so_printed) ? "style='pointer-events:none; opacity:0.5;'" : "";
    var link = "/api/method/frappe.utils.print_format.download_pdf?doctype=Delivery Note&name=" + d.dn_name + "&format=Arabic Delivery Note Picklist&no_letterhead=1";
    var onclick = "markPrinted('Delivery Note', '"+d.dn_name+"', 'custom_log_1'); setTimeout(function(){ fetchRowStatus('"+d.name+"'); }, 1500);";
    return '<div class="wh-pdfcell" '+disabledClass+'><a href="' + link + '" target="_blank" class="wh-pdflink" onclick="'+onclick+'">📄 DN</a></div>';
}

function buildUploadCell(d, type) {
    var fileUrl = (type === 'DN') ? d.dn_file_url : d.so_file_url;
    var docName = (type === 'DN') ? d.dn_name : d.name;
    var docType = (type === 'DN') ? 'Delivery Note' : 'Sales Order';
    if (type === 'DN' && !docName) return 'لا يوجد DN';

    var html = '<div style="display:flex; flex-direction:column; gap:5px; align-items:center;">';

    if (fileUrl) {
        var freshLink = fileUrl + "?t=" + new Date().getTime();
        html += '<a href="'+freshLink+'" target="_blank" style="color:blue; font-size:11px; font-weight:bold;">👁 View File</a>';
    }

    html += '<label class="wh-btn wh-upload-btn" style="font-size:11px; padding:4px 8px; cursor:pointer;">📷 Upload';
    html += '<input type="file" style="display:none;" accept="image/*,application/pdf" onchange="uploadFile(this, \''+docType+'\', \''+docName+'\')">';
    html += '</label></div>';

    return html;
}

function buildActionCell(d, action) {
    if (action === 'PICK') {

        var undoBtn =
          '<button class="wh-btn" style="background:#ef4444; color:white; border:none;" '
        + 'onclick="showConfirmUndo(\''+d.name+'\')">↩ رجوع إلى جديد</button>';

        if (!d.dn_file_url) {
            return ''
              + '<div style="display:flex; gap:6px; justify-content:center; flex-wrap:wrap;">'
              +   '<button class="wh-btn" disabled style="opacity:0.5; background:#ccc;">بانتظار الملف</button>'
              +   undoBtn
              + '</div>';
        }

        return ''
          + '<div style="display:flex; gap:6px; justify-content:center; flex-wrap:wrap;">'
          +   '<button class="wh-btn" style="background:#10b981; color:white; border:none;" '
          +     'onclick="showConfirm(\''+d.name+'\', \'custom_log_2\', \'تم تجهيز البضاعة للتسليم؟\')">✔ Picked</button>'
          +   undoBtn
          + '</div>';
    }
}

function buildDriverCell(d) {
    var checked = d.dispatched ? "checked" : "";
    var disabled = d.dispatched ? "disabled" : "";
    return '<label class="wh-checkbox-label" style="justify-content:center"><input type="checkbox" '+checked+' '+disabled+' onclick="markStep(\''+d.name+'\', \'custom_log_3\')"> سلمت للسائق؟</label>';
}

function buildDeliveryCell(d) {
    if (!d.dispatched) {
        return '<span style="color:#9ca3af; font-size:12px; font-style:italic;">بانتظار الإرسال...</span>';
    }
    var uploadHtml = buildUploadCell(d, 'SO');
    var btnState = "disabled style='opacity:0.5; background:#ccc; cursor:not-allowed;'";
    var btnText = "Upload Invoice";
    if (d.so_file_url) { btnState = "style='background:#3b82f6; color:white; border:none; margin-top:5px;'"; btnText = "Delivered"; }

    return uploadHtml + '<button class="wh-btn" '+btnState+' onclick="showConfirm(\''+d.name+'\', \'custom_log_4\', \'Confirm Delivered?\')">'+btnText+'</button>';
}

function buildStatusCell(d) { return '<span class="status-badge st-'+(d.status||"NEW")+'">' + (d.status||"NEW") + '</span>'; }

function buildFilesCell(d) {
    var h = "";
    if (d.dn_file_url) h += '<a href="'+d.dn_file_url+'" target="_blank">📄 DN</a> ';
    if (d.so_file_url) h += '<a href="'+d.so_file_url+'" target="_blank">📄 INV</a>';
    return h || "-";
}

function updateRowUI(d) {
    var c1 = document.getElementById("c1-" + d.name);
    var c2 = document.getElementById("c2-" + d.name);
    if (!c1) return;

    if (currentStatus === 'NEW') { c1.innerHTML = buildSOCell(d); c2.innerHTML = buildDNCell(d); }
    else if (currentStatus === 'PICKING') { c1.innerHTML = buildUploadCell(d, 'DN'); c2.innerHTML = buildActionCell(d, 'PICK'); }
    else if (currentStatus === 'DISPATCHED') { c1.innerHTML = buildDriverCell(d); c2.innerHTML = buildDeliveryCell(d); }
    else if (currentStatus === 'OVERVIEW') { c1.innerHTML = buildStatusCell(d); c2.innerHTML = buildFilesCell(d); }
}

// --- ACTIONS & MODAL ---
var pendingAction = null;

function showConfirm(name, field, text) {
    $("#wh-modal-text").text(text);
    $("#wh-modal").css("display", "flex");
    pendingAction = { name: name, field: field };
}

function showConfirmUndo(soName) {
    $("#wh-modal-text").text("هل تريد إرجاع الطلب إلى (جديد) ومسح علامات الطباعة؟");
    $("#wh-modal").css("display", "flex");
    pendingAction = { name: soName, field: "__UNDO__" };
}

$("#wh-modal-cancel").click(function() {
    $("#wh-modal").hide();
    pendingAction = null;
});

$("#wh-modal-confirm").click(function() {
    if (pendingAction) {
        if (pendingAction.field === "__UNDO__") {
            undoPickingToNew(pendingAction.name);
        } else {
            markStep(pendingAction.name, pendingAction.field);
        }
        $("#wh-modal").hide();
    }
});

window.markPrinted = function(doctype, name, field) {
    apiSetPrinted(doctype, name, field, function(r) {});
};

window.markStep = function(soName, field) {
    apiSetPrinted("Sales Order", soName, field, function(res) {
        if (res.message && res.message.ok) {
            if ((field === 'custom_log_2' && currentStatus === 'PICKING') ||
                (field === 'custom_log_4' && currentStatus === 'DISPATCHED')) {
                $("#tr-" + soName).fadeOut();
            } else {
                fetchRowStatus(soName);
            }
        }
    });
};

function updateFilterOptions() {
    var whSelect = $("#filterWarehouse");
    var userSelect = $("#filterUser");
    var currentUser = userSelect.val();
    var currentWH = whSelect.val();

    whSelect.empty();
    whSelect.append('<option value="">كل المستودعات</option>');
    var seenWH = {};
    for (var i=0; i<allOrders.length; i++) {
        var w = allOrders[i].set_warehouse;
        if (w && !seenWH[w]) {
            seenWH[w] = true;
            whSelect.append('<option value="' + w + '">' + w + '</option>');
        }
    }
    if (currentWH) whSelect.val(currentWH);

    userSelect.empty();
    userSelect.append('<option value="">All Sales Reps</option>');

    var seenUser = {};
    for (var j=0; j<allOrders.length; j++) {
        var u = allOrders[j].owner;
        var name = userMap[u] || u;
        if (u && !seenUser[u]) {
            seenUser[u] = true;
            userSelect.append('<option value="' + u + '">' + name + '</option>');
        }
    }

    if (currentUser) userSelect.val(currentUser);

    $("#filterWarehouse, #filterUser").off("change").on("change", renderTable);
}

// --- INIT ---
$(document).ready(function() {
    var now = new Date();
    var past = new Date();
    past.setMonth(now.getMonth() - 3);

    var m = ("0"+(past.getMonth()+1)).slice(-2);
    var d = ("0"+past.getDate()).slice(-2);
    $("#dateFrom").val(past.getFullYear()+"-"+m+"-"+d);

    var m2 = ("0"+(now.getMonth()+1)).slice(-2);
    var d2 = ("0"+now.getDate()).slice(-2);
    $("#dateTo").val(now.getFullYear()+"-"+m2+"-"+d2);

    $("#searchInput").on("input", renderTable);
    $("#hidePrinted, #dateFrom, #dateTo").on("change", renderTable);
    $("#btnRefresh").on("click", function() { loadList(currentStatus); });

    $(".wh-btn").on("click", function() {
        if (this.id.indexOf('modal') === -1) {
            var id = $(this).attr("id").replace("btn", "");
            loadList(id);
        }
    });

    loadList("NEW");
});

// =====================
// UNDO: PICKING -> NEW
// =====================
window.undoPickingToNew = function(soName) {
    apiPost(API_UNDO_PICKING, { so_name: soName })
      .then(function(res){
          if (res && res.message && res.message.ok) {
              $("#msg").text("تم الإرجاع إلى جديد ✅");
              fetchRowStatus(soName);
              if (currentStatus === "PICKING") {
                  $("#tr-" + soName).fadeOut(300, function(){ $(this).remove(); });
              }
          } else {
              var err = (res && res.message && res.message.error) ? res.message.error : "Unknown error";
              alert("فشل الإرجاع إلى جديد\n" + err);
          }
      })
      .catch(function(e){
          console.error(e);
          alert("فشل الإرجاع إلى جديد");
      });
};

