@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');

/* CSS FIX: Applied writing-mode direction to :root to prevent w3c warnings */
:root { 
    --primary-blue: #004b80; 
    --bg-main: #bfeaf4;
    --yellow: #ffd23c;
    --yellow-light: #ffe26b;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
    direction: rtl; 
}

/* --- FORCE THEME ON ALL FRAPPE LAYERS --- */
body, .page-container, .main-section, .appshell, .content, #appContent { 
    background-color: #bfeaf4 !important; 
    font-family: "Cairo", sans-serif !important;
    min-height: 100vh;
    margin: 0; padding: 0;
}

/* Hide Default Nav/Footer */
footer, .web-footer, .page-footer, .footer-section, .navbar { display: none !important; }

/* ===== UNIFIED TOPBAR ===== */
.sr-topbar {
    display: flex !important;
    flex-direction: row !important;
    justify-content: space-between !important;
    align-items: center !important;
    padding: 0 15px !important;
    height: 65px !important;
    width: 100% !important;
    box-sizing: border-box !important;
    direction: ltr !important;
    background: rgba(255, 255, 255, 0.4) !important;
    backdrop-filter: blur(10px) !important;
    border-bottom: 1px solid rgba(0,0,0,0.1) !important;
    position: sticky;
    top: 0;
    z-index: 1100;
}
.topbar-left { display: flex !important; gap: 8px !important; flex: none !important; order: 1 !important; }
.topbar-right { display: flex !important; flex-direction: row !important; align-items: center !important; gap: 12px !important; flex: none !important; order: 2 !important; direction: rtl !important; }
.sr-title { text-align: right !important; margin: 0 !important; font-weight: 900; font-size: 16px; color: #111827; font-family: "Cairo", sans-serif !important; }

.sr-btn-icon { 
    background-color: var(--yellow-light) !important; 
    border: 1px solid rgba(0,0,0,0.2) !important; 
    border-radius: 999px !important; 
    font-size: 16px !important; 
    font-weight: 900 !important;
    cursor: pointer !important; 
    width: 40px !important; 
    height: 40px !important; 
    display: flex !important; 
    align-items: center !important; 
    justify-content: center !important; 
    box-shadow: var(--shadow) !important;
    margin: 0 !important;
    color: #0b1b22 !important;
}

/* --- LAYOUT & COMPONENTS --- */
.dashboard-shell { max-width: 1200px; margin: 0 auto; padding: 15px; }

.sr-btn-primary {
    background: var(--yellow);
    color: #0b1b22;
    border: 1px solid rgba(0,0,0,0.25);
    border-radius: 999px;
    padding: 10px 20px;
    font-family: "Cairo", sans-serif;
    font-weight: 900;
    cursor: pointer;
    box-shadow: var(--shadow);
    display: inline-flex; align-items: center; gap: 5px;
}

.btn { display: inline-flex; align-items: center; justify-content: center; gap: 6px; padding: 10px 20px; border-radius: 6px; font-size: 14px; font-weight: 900; cursor: pointer; border: none; font-family: "Cairo", sans-serif; }
.btn-primary, #btnSearch, #btnSaveRecord { background-color: var(--primary-blue) !important; color: white !important; }
.btn-primary:hover { filter: brightness(0.9); }
.btn-default { background: #fff !important; border: 1px solid #d1d5db !important; color: #374151 !important; font-weight: 900; }

.filter-card, .editor-card { background: rgba(255, 255, 255, 0.4); border: 1px solid rgba(0,0,0,0.1); border-radius: 14px; padding: 20px; box-shadow: var(--shadow); backdrop-filter: blur(6px); }
.filter-card { margin-bottom: 24px; }
.filter-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 16px; align-items: end; }
.control-group { display: flex; flex-direction: column; gap: 6px; margin-bottom: 12px; }
.control-group label { font-size: 13px; font-weight: 900; color: #0b1b22; text-align: right;}
.form-control { width: 100%; padding: 8px 15px; border: 1px solid rgba(0,0,0,0.2); border-radius: 999px; font-size: 14px; font-weight: 700; outline: none; box-sizing: border-box; height: 44px; font-family: "Cairo"; background: var(--yellow-light); }
.form-control:focus { background: #fff; border-color: var(--primary-blue); }
.form-control:disabled, .form-control[readonly] { opacity: 0.8; background: #f1f5f9; cursor: not-allowed; }
textarea.form-control { height: auto; border-radius: 14px; }

/* 5. RESULTS GRID */
.results-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(350px, 1fr)); gap: 16px; }
.mapping-card { background: #fff; border: 1px solid #e5e7eb; border-radius: 14px; padding: 16px; border-right: 6px solid #ddd; transition: transform 0.2s; cursor: pointer; box-shadow: var(--shadow); }
.mapping-card.active { border-right-color: #2f8f3a; }
.mapping-card.inactive { border-right-color: #ff4d4d; }
.card-title { font-weight: 900; font-size: 15px; margin-bottom: 8px; display: flex; justify-content: space-between; color: #0b1b22; }
.badge { background:#f1f5f9; padding:2px 8px; border-radius:999px; font-size:11px; font-weight:900; border: 1px solid #ccc;}

/* 6. MODAL STYLES */
.editor-overlay { position: fixed; top: 0; left: 0; right: 0; bottom: 0; background: rgba(0,0,0,0.6); z-index: 2000; display: flex; align-items: center; justify-content: center; backdrop-filter: blur(4px); }
.editor-card { width: 95%; max-width: 500px; max-height: 85vh; overflow-y: auto; display: flex; flex-direction: column; background: #fff; border-radius: 20px; }
.editor-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px; border-bottom: 1px solid #eee; padding-bottom: 10px; }
.btn-close { background: none; border: none; font-size: 20px; cursor: pointer; color: #999; font-weight: 900; }
.full-width { width: 100%; }

/* Status */
.status-indicator { display:inline-flex; align-items:center; gap:5px; margin-right:10px; font-weight: 800;}
.status-dot { width:8px; height:8px; border-radius:50%; background:#ccc; }
.status-dot.loading { background: #ffd23c; }
.status-dot.success { background: #2f8f3a; }

