frappe.ready(function() {
    window.lmt_current_docname = null;

    const els = {
        fCompany: document.getElementById('fCompany'),
        fKey: document.getElementById('fKey'),
        fActive: document.getElementById('fActive'),
        results: document.getElementById('results'),
        modal: document.getElementById('editorOverlay'),
        editorTitle: document.getElementById('editorTitle'),
        modalMsg: document.getElementById('modalMsg'),
        inpCompany: document.getElementById('inpCompany'),
        inpKey: document.getElementById('inpKey'),
        inpAccount: document.getElementById('inpAccount'),
        inpAccountSearch: document.getElementById('inpAccountSearch'),
        inpCostCenter: document.getElementById('inpCostCenter'),
        inpMoP: document.getElementById('inpMoP'),
        inpDesc: document.getElementById('inpDesc'),
        inpActive: document.getElementById('inpActive'),
        btnNew: document.getElementById('btnNew'),
        btnCloseModal: document.getElementById('btnCloseModal'),
        btnSaveRecord: document.getElementById('btnSaveRecord'),
        btnDeleteRecord: document.getElementById('btnDeleteRecord'),
        btnSearch: document.getElementById('btnSearch'),
        btnRefresh: document.getElementById('btnRefreshTop')
    };

    let allCompanies = [];
    let allMoPs = [];
    let cachedAccounts = [];

    async function init() {
        setGlobalStatus("جاري التحميل...", "loading");

        const r1 = await frappe.call({ method: "frappe.client.get_list", args: { doctype: "Company", fields: ["name"] } });
        allCompanies = r1.message || [];

        const r2 = await frappe.call({ method: "frappe.client.get_list", args: { doctype: "Mode of Payment", fields: ["name"] } });
        allMoPs = r2.message || [];

        populateSelect(els.fCompany, allCompanies, "name", "الكل");
        populateSelect(els.inpCompany, allCompanies, "name", "اختر...");
        populateSelect(els.inpMoP, allMoPs, "name", "اختر...");

        if (els.inpAccountSearch) {
            els.inpAccountSearch.addEventListener('input', () => {
                const q = (els.inpAccountSearch.value || "").trim().toLowerCase();
                const currentSelected = els.inpAccount.value || "";
                if (!q) { renderAccountOptions(cachedAccounts, currentSelected); return; }
                const filtered = cachedAccounts.filter(a => (a.name || "").toLowerCase().includes(q));
                renderAccountOptions(filtered, currentSelected);
            });
        }

        setGlobalStatus("جاهز", "success");
        runSearch();
    }

    async function runSearch() {
        setGlobalStatus("جاري البحث...", "loading");
        els.results.innerHTML = "";

        const filters = [];
        if (els.fCompany.value) filters.push(["company", "=", els.fCompany.value]);
        if (els.fKey.value) filters.push(["mapping_key", "like", `%${els.fKey.value}%`]);
        if (els.fActive.value !== "") filters.push(["is_active", "=", els.fActive.value]);

        try {
            const r = await frappe.call({
                method: "frappe.client.get_list",
                args: {
                    doctype: "GL Account Mapping",
                    fields: ["name", "mapping_key", "account", "company", "cost_center", "is_active", "priority"],
                    filters: filters,
                    order_by: "modified desc",
                    limit_page_length: 50
                }
            });
            renderResults(r.message || []);
            setGlobalStatus("تم", "success");
        } catch (e) {
            console.error(e);
            setGlobalStatus("خطأ", "loading");
        }
    }

    function renderResults(rows) {
        if (!rows.length) {
            els.results.innerHTML = `<div style="text-align:center; color:#999; grid-column:1/-1; padding:20px; font-weight:900;">لا توجد سجلات</div>`;
            return;
        }
        els.results.innerHTML = rows.map(r => `
            <div class="mapping-card ${r.is_active ? 'active' : 'inactive'}" data-name="${escapeHtml(r.name)}">
                <div class="card-title">
                    ${escapeHtml(r.mapping_key)}
                    <span class="badge">${r.is_active ? 'نشط' : 'متوقف'}</span>
                </div>
                <div style="font-size:12px; font-weight:700; line-height:1.6; color:#555;">
                    <div><b>الحساب:</b> ${escapeHtml(r.account)}</div>
                    <div><b>الشركة:</b> ${escapeHtml(r.company)}</div>
                    <div><b>مركز التكلفة:</b> ${escapeHtml(r.cost_center || '-')}</div>
                </div>
            </div>
        `).join('');
    }

    function resetModalMsg() {
        els.modalMsg.style.display = "none";
        els.modalMsg.textContent = "";
    }

    function openModalForNew() {
        window.lmt_current_docname = null; 

        // UNLOCKED FOR NEW RECORDS
        els.inpKey.readOnly = false;
        els.inpCompany.disabled = false;

        els.editorTitle.textContent = "إنشاء ربط جديد";
        els.btnDeleteRecord.style.display = "none";
        resetModalMsg();

        els.inpCompany.value = "";
        els.inpKey.value = "";
        els.inpAccount.innerHTML = "<option value=''>اختر الشركة أولاً</option>";
        cachedAccounts = [];
        if (els.inpAccountSearch) els.inpAccountSearch.value = "";
        els.inpCostCenter.value = "";
        els.inpMoP.value = "";
        els.inpDesc.value = "";
        els.inpActive.checked = true;

        els.modal.style.display = "flex";
    }

    async function openModalForEdit(docname) {
        window.lmt_current_docname = docname; 

        // UNLOCKED SO YOU CAN CHANGE THEM
        els.inpKey.readOnly = false;
        els.inpCompany.disabled = false;

        els.editorTitle.textContent = "تعديل الربط";
        els.btnDeleteRecord.style.display = "inline-flex";
        resetModalMsg();

        els.modal.style.display = "flex";
        showMsg("جاري تحميل السجل...", false);

        try {
            const r = await frappe.call({
                method: "frappe.client.get",
                args: { doctype: "GL Account Mapping", name: docname }
            });

            const doc = r.message;
            if (!doc) throw new Error("لم يتم العثور على السجل");

            els.inpCompany.value = doc.company || "";
            els.inpKey.value = doc.mapping_key || "";
            els.inpCostCenter.value = doc.cost_center || "";
            els.inpMoP.value = doc.mode_of_payment || "";
            els.inpDesc.value = doc.description || "";
            els.inpActive.checked = (doc.is_active ? true : false);

            await loadAccountsForCompany(doc.company, doc.account);
            resetModalMsg(); 
        } catch (e) {
            console.error(e);
            showMsg("حدث خطأ أثناء تحميل السجل. تأكد من صلاحيات القراءة.", true);
        }
    }

    function closeModal() {
        els.modal.style.display = "none";
        window.lmt_current_docname = null;
        resetModalMsg();
        els.btnSaveRecord.textContent = "حفظ السجل";
        els.btnSaveRecord.disabled = false;
    }

    els.btnNew.addEventListener('click', openModalForNew);
    els.btnCloseModal.addEventListener('click', closeModal);

    els.results.addEventListener('click', (ev) => {
        const card = ev.target.closest('.mapping-card');
        if (!card) return;
        const docname = card.getAttribute('data-name');
        if (!docname) return;
        openModalForEdit(docname);
    });

    async function loadAccountsForCompany(company, selectedAccount) {
        if (!company) {
            cachedAccounts = [];
            if (els.inpAccountSearch) els.inpAccountSearch.value = "";
            els.inpAccount.innerHTML = "<option value=''>اختر الشركة أولاً</option>";
            return;
        }

        els.inpAccount.innerHTML = "<option>جاري تحميل الحسابات...</option>";
        if (els.inpAccountSearch) els.inpAccountSearch.value = "";

        const r = await frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Account",
                filters: { company: company, is_group: 0 },
                fields: ["name"],
                limit_page_length: 500
            }
        });

        const accounts = r.message || [];
        cachedAccounts = accounts;
        renderAccountOptions(accounts, selectedAccount);
    }

    els.inpCompany.addEventListener('change', async function() {
        await loadAccountsForCompany(this.value, null);
    });

    // THE ULTIMATE FIX: Flat arguments explicitly pass Sandbox limits
    els.btnSaveRecord.addEventListener('click', async () => {

        const argsData = {
            docname: window.lmt_current_docname,
            company: els.inpCompany.value,
            mapping_key: els.inpKey.value,
            account: els.inpAccount.value,
            cost_center: els.inpCostCenter.value,
            mode_of_payment: els.inpMoP.value,
            description: els.inpDesc.value,
            is_active: els.inpActive.checked ? 1 : 0
        };

        if (!argsData.company || !argsData.mapping_key || !argsData.account) {
            showMsg("الرجاء تعبئة الحقول الإجبارية (*)", true);
            return;
        }

        els.btnSaveRecord.textContent = "جاري الحفظ...";
        els.btnSaveRecord.disabled = true;

        try {
            // Call our custom python API with flat parameters
            const response = await frappe.call({
                method: "save_gl_mapping_api_7",
                args: argsData
            });

            if(response.message && response.message.status === "success") {
                frappe.show_alert({ message: "تمت العملية بنجاح", indicator: 'green' });
                closeModal();
                runSearch();
            }

        } catch (e) {
            console.error(e);
            let err = "حدث خطأ غير متوقع.";
            if (e && e.message) err = e.message;
            showMsg(err, true);
            els.btnSaveRecord.textContent = "حفظ السجل";
            els.btnSaveRecord.disabled = false;
        }
    });

    els.btnDeleteRecord.addEventListener('click', async () => {
        const docnameToDelete = window.lmt_current_docname; 
        if (!docnameToDelete) return;

        frappe.confirm(
            "هل أنت متأكد أنك تريد حذف هذا السجل؟ لا يمكن التراجع.",
            async () => {
                try {
                    els.btnDeleteRecord.disabled = true;
                    els.btnDeleteRecord.textContent = "جاري الحذف...";
                    await frappe.call({
                        method: "frappe.client.delete",
                        args: { doctype: "GL Account Mapping", name: docnameToDelete }
                    });
                    frappe.show_alert({ message: "تم حذف السجل", indicator: "green" });
                    closeModal();  
                    runSearch();
                } catch (e) {
                    console.error(e);
                    showMsg("فشل الحذف. تأكد من صلاحيات Delete.", true);
                } finally {
                    els.btnDeleteRecord.disabled = false;
                    els.btnDeleteRecord.textContent = "حذف السجل";
                }
            }
        );
    });

    function populateSelect(el, list, field, placeholder) { el.innerHTML = `<option value="">${placeholder}</option>` + list.map(i => `<option value="${escapeHtml(i[field])}">${escapeHtml(i[field])}</option>`).join(''); }
    function renderAccountOptions(list, selected) { els.inpAccount.innerHTML = `<option value="">اختر الحساب...</option>` + (list || []).map(a => { const name = a.name || ""; const sel = (selected && name === selected) ? " selected" : ""; return `<option value="${escapeHtml(name)}"${sel}>${escapeHtml(name)}</option>`; }).join(''); }
    function setGlobalStatus(txt, type) { document.getElementById('statusText').textContent = txt; document.getElementById('statusDot').className = `status-dot ${type}`; }

    function showMsg(txt, isError) { els.modalMsg.style.display = "block"; els.modalMsg.textContent = txt; els.modalMsg.style.background = isError ? "#fee2e2" : "#dcfce7"; els.modalMsg.style.color = isError ? "#b91c1c" : "#15803d"; }
    function escapeHtml(str) { if (str === null || str === undefined) return ""; return String(str).replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;").replaceAll('"', "&quot;").replaceAll("'", "&#039;"); }

    els.btnSearch.addEventListener('click', runSearch);
    if(els.btnRefresh) els.btnRefresh.addEventListener('click', runSearch);

    init();
});

