javascript:
/* global frappe */

const VD = (() => {
  function el(id){ return document.getElementById(id); }

  function setStatus(msg, ok=true){
    const s = el("vd_status");
    s.className = "vd-status " + (ok ? "ok" : "err");
    s.textContent = msg || "";
  }

  function fmtDT(s){
    if (!s) return "";
    try { return new Date(s).toLocaleString(); } catch(e){ return String(s); }
  }

  function f3(x){
    const n = Number(x);
    if (!isFinite(n)) return "-";
    return n.toFixed(3);
  }

  function enc(s){ return encodeURIComponent(String(s || "")); }

  function setMapLinks(lat, lng){
    const g = el("vd_map_google");
    const a = el("vd_map_apple");
    g.href = `https://www.google.com/maps/search/?api=1&query=${lat},${lng}`;
    a.href = `http://maps.apple.com/?q=${lat},${lng}`;
    g.style.pointerEvents = "auto"; a.style.pointerEvents = "auto";
    g.style.opacity = "1"; a.style.opacity = "1";
    el("vd_map_hint").textContent = `Lat/Lng: ${f3(lat)}, ${f3(lng)}`;
  }

  function getFilters(){
    return {
      agent: el("f_agent").value || "",
      from_date: el("f_from").value || "",
      to_date: el("f_to").value || "",
      customer_q: (el("f_customer_q").value || "").trim()
    };
  }

  async function loadAgents(){
    setStatus("تحميل المندوبين...", true);
    const r = await frappe.call({ method: "lmt_visit_dashboard_get_agents" });
    const agents = (r.message && r.message.agents) ? r.message.agents : [];

    const sel = el("f_agent");
    sel.innerHTML = `<option value="">(الكل)</option>` + agents.map(a =>
      `<option value="${a.user}">${(a.full_name || a.user)}</option>`
    ).join("");

    setStatus("جاهز ✅", true);
  }

function buildVisitActions(v){
  const dt = "LMT Customer Visit";
  const dn = v.name;

  const pdfUrl  = `/printview?doctype=${enc(dt)}&name=${enc(dn)}&format=Standard&no_letterhead=0`;

  const photo = v.photo
    ? `<a class="vd-btn ghost" href="${v.photo}" target="_blank" rel="noopener">🖼️ الصورة</a>`
    : "";

  return `
    <div class="vd-actions">
      <button class="vd-btn primary" type="button" data-lat="${v.latitude}" data-lng="${v.longitude}">📍 فتح الخريطة</button>
      <a class="vd-btn ghost" href="${pdfUrl}" target="_blank" rel="noopener">🖨️ معاينة PDF</a>
      ${photo}
    </div>
  `;
}


  async function loadVisits(){
    const filters = getFilters();
    setStatus("تحميل الزيارات...", true);

    const r = await frappe.call({
      method: "lmt_visit_dashboard_get_visits",
      args: { filters }
    });

    const rows = (r.message && r.message.visits) ? r.message.visits : [];
    el("vd_count").textContent = String(rows.length);
    el("vd_range").textContent = (filters.from_date || "…") + " → " + (filters.to_date || "…");

    if (!rows.length){
      el("vd_list").innerHTML = `<div class="vd-item"><div class="vd-muted">لا توجد زيارات</div></div>`;
      setStatus("لا توجد نتائج", true);
      return;
    }

    el("vd_list").innerHTML = rows.map(v => {
      const cust = (v.customer_name || v.customer || "-");
      const agent = (v.sales_user_full_name || v.sales_user || "-");
      const dt = fmtDT(v.visit_datetime);
      const lat = f3(v.latitude);
      const lng = f3(v.longitude);
      const acc = (v.accuracy_m != null && v.accuracy_m !== "") ? `±${Math.round(Number(v.accuracy_m))}m` : "";
      const note = (v.notes || "").trim();

      return `
        <div class="vd-item">
          <div class="vd-item-top">
            <div>
              <div class="vd-item-title">${cust}</div>
              <div class="vd-item-sub">
                <span class="vd-chip">👤 ${agent}</span>
                <span class="vd-chip">🕒 ${dt}</span>
                <span class="vd-chip">📍 ${lat}, ${lng} ${acc ? "(" + acc + ")" : ""}</span>
              </div>
              ${note ? `<div class="vd-note">📝 ${note}</div>` : ``}
            </div>
          </div>

          ${buildVisitActions(v)}
        </div>
      `;
    }).join("");

    // wire map buttons
    Array.from(el("vd_list").querySelectorAll("button[data-lat][data-lng]")).forEach(btn => {
      btn.addEventListener("click", () => {
        const lat = btn.getAttribute("data-lat");
        const lng = btn.getAttribute("data-lng");
        if (lat && lng) setMapLinks(lat, lng);
      });
    });

    setStatus("تم ✅", true);
  }

  function clearFilters(){
    el("f_agent").value = "";
    el("f_customer_q").value = "";
    refresh();
  }

  async function refresh(){
    await loadVisits();
  }

  return { loadAgents, refresh, clearFilters };
})();

window.VD = VD;

window.addEventListener("load", async () => {
  el("vdUserName").textContent =
    (window.VISIT_DASH && window.VISIT_DASH.FULL_NAME) ||
    (window.VISIT_DASH && window.VISIT_DASH.USER) || "";

  const to = new Date();
  const from = new Date();
  from.setDate(from.getDate() - 7);
const pad = n => String(n).padStart(2, "0");

el("f_to").value = `${to.getFullYear()}-${pad(to.getMonth()+1)}-${pad(to.getDate())}`;
el("f_from").value = `${from.getFullYear()}-${pad(from.getMonth()+1)}-${pad(from.getDate())}`;


  await VD.loadAgents();
  await VD.refresh();
});

function el(id){ return document.getElementById(id); }

