/* Visits list */
.vp-list-head { display:flex; align-items:baseline; justify-content:space-between; gap:10px; }
.vp-list-title { font-weight:900; font-size:14px; color: var(--primary-blue); }
.vp-list-sub { font-size:12px; font-weight:700; color: #555; }
