.vp-vrow { border:1px solid rgba(0,0,0,0.1); border-radius:12px; padding:12px; margin-bottom:8px; background:rgba(255,255,255,0.7); box-shadow: var(--shadow); }
.vp-vtop { display:flex; justify-content:space-between; gap:10px; align-items:center; }
