}

.vp-modal-head{ display:flex; align-items:center; justify-content:space-between; gap:10px; margin-bottom:12px; }
.vp-modal-title{ font-weight:900; font-size:16px; color: var(--primary-blue); }
.vp-x{ border:none; background:#f1f1f1; padding:8px 15px; border-radius:999px; font-weight:900; cursor:pointer; font-size:13px; font-family: "Cairo"; }

.vp-modal-meta{ margin-top:8px; font-size:12px; font-weight: 700; color: #555; }

.vp-list{
  margin-top:10px; border:1px solid rgba(0,0,0,0.1); border-radius:14px;
  overflow:hidden; overflow-y:auto; -webkit-overflow-scrolling: touch; flex:1; background: #fafafa;
