javascript:
/* global frappe */
// 100% Original Logic Preserved. Only API endpoints updated to _1.

const VP = (() => {
  let lastGPS = null;
  let selectedCustomer = null;
  let searchTimer = null;

  function el(id){ return document.getElementById(id); }

  function setStatus(msg, ok=true){
    const s = el("vp_status");
    s.className = "vp-status " + (ok ? "ok" : "err");
    s.textContent = msg;
  }

  function escapeHtml(s){
    return String(s || "").replace(/[&<>"']/g, m => ({
      "&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#039;"
    }[m]));
  }

  function fmt3(x){
    const n = Number(x);
    if (!isFinite(n)) return "-";
    return n.toFixed(3);
  }

  function enableActions(){
    const hasCustomer = !!selectedCustomer;
    const hasGPS = !!lastGPS;

    el("btn_update_customer").disabled = !(hasCustomer && hasGPS);
    el("btn_create_visit").disabled = !(hasCustomer && hasGPS);
  }

  function openCustomerPicker(){
    el("cust_modal").style.display = "block";
    el("cust_search").value = "";
    renderCustomers([]);
    el("cust_count").textContent = "0";
    setTimeout(() => el("cust_search").focus(), 100);

    // initial load (empty search) - small
    fetchCustomers("");
  }

  function closeCustomerPicker(){
    el("cust_modal").style.display = "none";
  }

  async function fetchCustomers(q){
    const r = await frappe.call({
      method: "lmt_visit_get_customers_api_1",
      args: { q: q || "", limit: 200 }
    });

    const customers = (r.message && r.message.customers) ? r.message.customers : [];
    renderCustomers(customers);

    el("cust_count").textContent = String(customers.length);

    if (r.message && r.message.warning){
      setStatus(r.message.warning, false);
    }
  }

  function renderCustomers(list){
    const wrap = el("cust_list");
    if (!list.length){
      wrap.innerHTML = `<div class="vp-item"><div class="vp-item-title">لا توجد نتائج</div></div>`;
      return;
    }

    wrap.innerHTML = list.map(c => {
      const title = escapeHtml(c.customer_name || c.name);
      const sub = `${c.territory ? escapeHtml(c.territory) + " • " : ""}ID: ${escapeHtml(c.name)}`;
      return `
        <div class="vp-item" data-id="${escapeHtml(c.name)}" data-title="${title}">
          <div class="vp-item-title">${title}</div>
          <div class="vp-item-sub">${sub}</div>
        </div>
      `;
    }).join("");

    Array.from(wrap.querySelectorAll(".vp-item")).forEach(item => {
      item.addEventListener("click", async () => {
        const id = item.getAttribute("data-id");
        const title = item.getAttribute("data-title");
        if (!id) return;

        selectedCustomer = id;
        el("customer_id").value = id;
        el("customer_display").textContent = title;

        closeCustomerPicker();
        setStatus(`تم اختيار الزبون: ${title}`, true);

        enableActions();
        await loadVisits();
      });
    });
  }

  function updateMapLinks(lat, lng){
    el("map_google").href = `https://www.google.com/maps/search/?api=1&query=$${lat},${lng}`;
    el("map_apple").href = `http://maps.apple.com/?q=${lat},${lng}`;
  }

  function clearGPS(){
    lastGPS = null;
    el("gps_lat").textContent = "-";
    el("gps_lng").textContent = "-";
    el("gps_acc").textContent = "-";
    el("map_google").removeAttribute("href");
    el("map_apple").removeAttribute("href");
    enableActions();
  }

  function getGPS(){
    if (!navigator.geolocation){
      setStatus("الموقع غير مدعوم على هذا الجهاز.", false);
      return;
    }

    setStatus("جاري تحديد الموقع...", true);

    navigator.geolocation.getCurrentPosition((pos) => {
      lastGPS = { lat: pos.coords.latitude, lng: pos.coords.longitude, acc: pos.coords.accuracy };

      el("gps_lat").textContent = fmt3(lastGPS.lat);
      el("gps_lng").textContent = fmt3(lastGPS.lng);
      el("gps_acc").textContent = String(Math.round(lastGPS.acc || 0));

      updateMapLinks(lastGPS.lat, lastGPS.lng);
      setStatus("تم تحديد الموقع ✅", true);

      enableActions();
    }, (err) => {
      console.error(err);
      setStatus("خطأ في تحديد الموقع: " + (err.message || err.code), false);
      clearGPS();
    }, { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 });
  }

  async function updateCustomerLocation(){
    if (!selectedCustomer) { setStatus("اختر الزبون أولاً.", false); return; }
    if (!lastGPS) { setStatus("اضغط (جلب الموقع) أولاً.", false); return; }

    setStatus("جاري تحديث موقع الزبون...", true);

    const r = await frappe.call({
      method: "lmt_visit_update_customer_location_api_1",
      args: { customer: selectedCustomer, lat: lastGPS.lat, lng: lastGPS.lng, accuracy_m: lastGPS.acc }
    });

    if (r.message && r.message.ok) setStatus("تم تحديث موقع الزبون ✅", true);
    else setStatus((r.message && r.message.error) || "فشل تحديث موقع الزبون.", false);
  }

  function openCamera(){
    const inp = el("photo_input");
    inp.value = "";
    inp.accept = "image/*";
    inp.setAttribute("capture", "environment");
    inp.click();
  }

  function openGallery(){
    const inp = el("photo_input");
    inp.value = "";
    inp.accept = "image/*";
    inp.removeAttribute("capture");
    inp.click();
  }

  function bindPhotoPreview(){
    const inp = el("photo_input");
    inp.addEventListener("change", () => {
      const f = inp.files && inp.files[0];
      if (!f) return;
      const img = el("photo_preview");
      img.style.display = "block";
      img.src = URL.createObjectURL(f);
    });
  }

  async function uploadPhotoIfAny(){
    const f = el("photo_input").files && el("photo_input").files[0];
    if (!f) return "";

    const fd = new FormData();
    fd.append("file", f, f.name);
    fd.append("is_private", "0");

    const res = await fetch("/api/method/upload_file", {
      method: "POST",
      headers: { "X-Frappe-CSRF-Token": (window.VISIT_CFG && window.VISIT_CFG.CSRF) || "" },
      body: fd
    });

    const data = await res.json();
    const file_url = data && data.message && data.message.file_url;
    if (!file_url) throw new Error("Upload failed");
    return file_url;
  }

  function renderVisits(visits){
    const wrap = el("visit_list");

    if (!visits || !visits.length){
      wrap.innerHTML = `<div class="vp-empty">لا توجد زيارات</div>`;
      return;
    }

    wrap.innerHTML = visits.map(v => {
      const dt = v.visit_datetime ? new Date(v.visit_datetime).toLocaleString() : "";
      const lat = fmt3(v.latitude);
      const lng = fmt3(v.longitude);
      const acc = Math.round(Number(v.accuracy_m || 0));
      const notes = escapeHtml(v.notes || "");
      const map = (v.latitude && v.longitude)
        ? `https://www.google.com/maps/search/?api=1&query=$${v.latitude},${v.longitude}`
        : "";

      return `
        <div class="vp-vrow">
          <div class="vp-vtop">
            <div class="vp-vdt">${escapeHtml(dt)}</div>
            <div class="vp-vmeta">📍 ${lat}, ${lng} • ±${acc}m</div>
          </div>
          ${notes ? `<div class="vp-vnotes">${notes}</div>` : ``}
          <div class="vp-vactions">
            ${map ? `<a class="vp-btn ghost vp-mini" target="_blank" rel="noopener" href="${map}">📍 فتح الخريطة</a>` : ``}
            ${v.photo ? `<a class="vp-btn ghost vp-mini" target="_blank" rel="noopener" href="${escapeHtml(v.photo)}">🖼️ الصورة</a>` : ``}
          </div>
        </div>
      `;
    }).join("");
  }

async function loadVisits(){
  if (!selectedCustomer){
    el("visit_list_hint").textContent = "اختر زبون لعرض الزيارات";
    renderVisits([]);
    return;
  }

  el("visit_list_hint").textContent = "جاري تحميل الزيارات...";

  const filters = {
    customer: selectedCustomer,
  };

  const r = await frappe.call({
    method: "lmt_visit_client_get_my_visits",
    args: { filters: JSON.stringify(filters) }
  });

  const visits = (r.message && r.message.visits) ? r.message.visits : [];
  el("visit_list_hint").textContent = `آخر ${visits.length} زيارة`;
  renderVisits(visits);
}



  async function createVisit(){
    if (!selectedCustomer) { setStatus("اختر الزبون أولاً.", false); return; }
    if (!lastGPS) { setStatus("اضغط (جلب الموقع) أولاً.", false); return; }

    // Guard: button should already be disabled unless GPS exists
    el("btn_create_visit").disabled = true;

    setStatus("جاري رفع الصورة (إن وجدت)...", true);
    let photo_url = "";
    try { photo_url = await uploadPhotoIfAny(); }
    catch (e) { console.error(e); setStatus("فشل رفع الصورة.", false); enableActions(); return; }

    setStatus("جاري تسجيل الزيارة...", true);
    const notes = el("visit_notes").value || "";

    const r = await frappe.call({
      method: "lmt_visit_create_visit_api_1",
      args: { customer: selectedCustomer, lat: lastGPS.lat, lng: lastGPS.lng, accuracy_m: lastGPS.acc, notes, photo_url }
    });

    if (r.message && r.message.ok){
      const name = r.message.visit_name || "";
      const updated = r.message.updated ? " (تم التحديث)" : "";
      setStatus("تم تسجيل الزيارة ✅ " + name + updated, true);

      // reset form AFTER save
      el("visit_notes").value = "";
      el("photo_input").value = "";
      el("photo_preview").style.display = "none";
      el("photo_preview").src = "";

      // force new GPS next time (so button disables again)
      clearGPS();

      // refresh list so user sees it immediately
      await loadVisits();
    } else {
      setStatus((r.message && r.message.error) || "فشل تسجيل الزيارة.", false);
      enableActions();
    }
  }

  function bindUI(){
    // top user name
    const nameEl = el("vpUserName");
    if (nameEl) nameEl.textContent =
      (window.VISIT_CFG && window.VISIT_CFG.FULL_NAME) ||
      (window.VISIT_CFG && window.VISIT_CFG.USER) || "";

    // customer picker
    el("customer_open").addEventListener("click", openCustomerPicker);
    el("cust_close").addEventListener("click", closeCustomerPicker);
    el("cust_done").addEventListener("click", closeCustomerPicker);

    el("cust_search").addEventListener("input", (e) => {
      const q = e.target.value || "";
      if (searchTimer) clearTimeout(searchTimer);
      searchTimer = setTimeout(() => fetchCustomers(q), 250);
    });

    // buttons
    el("btn_gps").addEventListener("click", getGPS);
    el("btn_update_customer").addEventListener("click", updateCustomerLocation);
    el("btn_create_visit").addEventListener("click", createVisit);

    el("btn_camera").addEventListener("click", openCamera);
    el("btn_gallery").addEventListener("click", openGallery);

    bindPhotoPreview();
    enableActions();
  }

  return { bindUI };
})();

window.addEventListener("load", () => {
  VP.bindUI();
});

