@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');

:root { 
    --primary-blue: #004b80; 
    --bg-main: #bfeaf4;
    --yellow: #ffd23c;
    --yellow-light: #ffe26b;
    --green: #2f8f3a;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
    --text: #0b1b22;
}

* { box-sizing: border-box; }

body, .page-container, .main-section, .appshell, .content { 
    background-color: var(--bg-main) !important; 
    font-family: "Cairo", sans-serif !important;
    margin: 0; padding: 0; min-height: 100vh;
    direction: rtl;
}

header, footer, .web-footer, .navbar { display: none !important; }

/* ===== UNIFIED TOPBAR ===== */
.sr-topbar {
    display: flex !important; flex-direction: row !important; justify-content: space-between !important;
    align-items: center !important; padding: 0 15px !important; height: 65px !important;
    width: 100% !important; box-sizing: border-box !important; direction: ltr !important;
    background: rgba(255, 255, 255, 0.4) !important; backdrop-filter: blur(10px) !important;
    border-bottom: 1px solid rgba(0,0,0,0.1) !important; position: fixed; top: 0; left: 0; right: 0; z-index: 1100;
}
.topbar-left { display: flex !important; gap: 8px !important; flex: none !important; order: 1 !important; }
.topbar-right { display: flex !important; flex-direction: row !important; align-items: center !important; gap: 12px !important; flex: none !important; order: 2 !important; direction: rtl !important; }
.sr-title { text-align: right !important; margin: 0 !important; font-weight: 900; font-size: 16px; color: var(--text); font-family: "Cairo", sans-serif !important; }

.sr-btn-icon { 
    background-color: var(--yellow-light) !important; border: 1px solid rgba(0,0,0,0.2) !important; 
    border-radius: 999px !important; font-size: 16px !important; font-weight: 900 !important;
    cursor: pointer !important; width: 40px !important; height: 40px !important; 
    display: flex !important; align-items: center !important; justify-content: center !important; 
    box-shadow: var(--shadow) !important; margin: 0 !important; color: #0b1b22 !important; padding: 0 !important;
}

/* --- CARDS & UI --- */
.sr-wrap { max-width: 1100px; margin: 0 auto; padding: 85px 12px 30px; } /* 85px padding clears the fixed topbar */
.sr-card { 
    background: rgba(255, 255, 255, 0.4); border-radius: 14px; 
    padding: 18px; margin-bottom: 15px; backdrop-filter: blur(6px);
    border: 1px solid rgba(0,0,0,0.1); box-shadow: var(--shadow);
}

.sr-pill { 
    background: var(--yellow-light); border: 1px solid rgba(0,0,0,0.2); 
    border-radius: 999px; padding: 8px 16px; margin-bottom: 10px;
    display: flex; align-items: center; gap: 10px; box-shadow: var(--shadow);
}
.sr-pill label { font-weight: 900; font-size: 14px; color: var(--text); white-space: nowrap; margin: 0; }
.sr-pill select { flex: 1; border: none; background: transparent; font-family: "Cairo", sans-serif; font-weight: 800; font-size: 14px; color: var(--text); outline: none; direction: rtl; }

.sr-btn { 
    border: 1px solid rgba(0,0,0,0.2); cursor: pointer; border-radius: 999px; 
    padding: 10px 22px; font-family: "Cairo", sans-serif; font-weight: 900; 
    background: #fff; box-shadow: var(--shadow); color: var(--text); transition: 0.2s;
}
.sr-btn:active { transform: scale(0.95); }
.sr-btn.primary { background: var(--yellow); }

/* --- KPIS --- */
.kpis { display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; margin-top: 15px; }
.kpi { background: rgba(255,255,255,0.6); border-radius: 12px; padding: 12px 5px; text-align: center; border: 1px solid rgba(0,0,0,0.1); box-shadow: var(--shadow); }
.kpi-label { font-size: 12px; font-weight: 900; color: #444; }
.kpi-val { font-size: 15px; font-weight: 900; color: var(--primary-blue); margin-top: 6px; }

/* --- TABLE --- */
/* --- TABLE --- */
.table-wrap { 
    overflow: auto; 
    border: 2px solid #555; 
    border-radius: 12px; 
    background: white; 
    margin-top: 10px; 
}
table { width: 100%; border-collapse: collapse; min-width: 800px; }
th { 
    background: var(--green) !important; 
    color: white !important; 
    font-weight: 900; 
    padding: 14px 10px; 
    font-size: 14px; 
    border: 1.5px solid #333 !important; 
}
td { 
    border: 1.5px solid #555 !important; 
    padding: 12px 10px; 
    font-size: 13px; 
    text-align: center; 
    font-weight: 700; 
    color: var(--text); 
}

/* RESTORED ORIGINAL COLORFUL ROWS */
tbody tr { transition: filter 0.2s; }
tbody tr:nth-child(odd) { background-color: var(--yellow-light) !important; }
tbody tr:nth-child(even) { background-color: var(--bg-main) !important; }
tbody tr:hover { filter: brightness(0.95); }

.status-badge { display: inline-block; padding: 6px 14px; border-radius: 999px; font-weight: 900; font-size: 12px; border: 1px solid rgba(0,0,0,0.1); background: #fff; box-shadow: var(--shadow); color: var(--text); }
.hidden { display: none !important; }

javascript:
let L_DOC = null, C_AG = null;

const setSt = (t) => { document.getElementById("st").textContent = t; };
const fmt   = (x)  => Number(x || 0).toLocaleString(undefined, { minimumFractionDigits: 2 });

async function fJ(u) {
  const r = await fetch(u, { headers: { "X-Frappe-CSRF-Token": window.CSRF_TOKEN || "" } });
  const d = await r.json();
  if (!r.ok) throw new Error(d.exc || "Error");
  return d.message || d;
}

function reset() {
  L_DOC = null;
  ['bP', 'bD'].forEach(i => document.getElementById(i).classList.add('hidden'));
  document.getElementById("tb").innerHTML =
    "<tr><td colspan='8' style='padding:30px; background:transparent;'>الرجاء اختيار المندوب</td></tr>";
  ['kS', 'kC', 'kB'].forEach(i => document.getElementById(i).innerText = "0.00");
  setSt("Ready");
}

async function load() {
  try {
    const m = await fJ("/api/method/lmt_supervisor_agents_simple");
    const s = document.getElementById("ag_sel"),
          w = document.getElementById("ag_wrp"),
          i = document.getElementById("ag_inf");
    if (m.can_select_agent !== 1) {
      w.classList.add('hidden');
      i.classList.remove('hidden');
      C_AG = m.agents[0]?.user || window.CURRENT_USER;
      i.innerText = "المندوب: " + (m.agents[0]?.full_name || C_AG);
    } else {
      s.innerHTML = '<option value="">-- اختر --</option>';
      m.agents.forEach(a => {
        let o = document.createElement("option");
        o.value = a.user; o.innerText = a.full_name; s.appendChild(o);
      });
      s.onchange = e => C_AG = e.target.value;
    }
  } catch (e) { setSt("Error"); }
}

function buildRow(x) {
  const pct     = parseFloat(x.debt_percent  || 0);
  const pay     = parseFloat(x.pay_to_unblock || 0);
  const bal     = parseFloat(x.balance        || 0);
  const pctClr  = pct >= 60 ? '#ef4444' : pct >= 30 ? '#f97316' : '#16a34a';
  const payClr  = pay > 0   ? '#ef4444' : '#16a34a';
  const payTxt  = bal <= 0  ? '✓'       : (pay > 0 ? fmt(pay) : '✓');
  return `
    <tr>
      <td style="text-align:right; font-weight:900;">${x.customer}</td>
      <td>${fmt(x.sales)}</td>
      <td>${x.last_sale || "-"}</td>
      <td>${fmt(x.collect)}</td>
      <td>${x.last_collect || "-"}</td>
      <td style="color:var(--primary-blue); font-weight:900;">${fmt(x.balance)}</td>
      <td style="font-weight:900; color:${pctClr};">${fmt(x.debt_percent)}%</td>
      <td style="font-weight:900; color:${payClr};">${payTxt}</td>
    </tr>`;
}

async function gen() {
  if (!C_AG) return setSt("اختر مندوب");
  setSt("Loading...");
  try {
    const r = await fJ(
      "/api/method/lmt_generate_agent_simple_statement?sales_person=" +
      encodeURIComponent(C_AG) + "&_t=" + Date.now()
    );
    L_DOC = r.name || r.docname;
    ['bP', 'bD'].forEach(i => document.getElementById(i).classList.remove('hidden'));
    document.getElementById("kS").innerText = fmt(r.sum_simple_sales);
    document.getElementById("kC").innerText = fmt(r.sum_simple_collect);
    document.getElementById("kB").innerText = fmt(r.sum_balance);
    const rows30 = (r.rows_preview || []).slice(0, 30);
    document.getElementById("tb").innerHTML = rows30.map(buildRow).join('');
    setSt("Done ✓");
    sessionStorage.setItem("LMT_LAST_DOC",  L_DOC || "");
    sessionStorage.setItem("LMT_LAST_AGENT", C_AG || "");
    sessionStorage.setItem("LMT_LAST_KS",   String(r.sum_simple_sales   || 0));
    sessionStorage.setItem("LMT_LAST_KC",   String(r.sum_simple_collect || 0));
    sessionStorage.setItem("LMT_LAST_KB",   String(r.sum_balance        || 0));
    sessionStorage.setItem("LMT_LAST_ROWS", JSON.stringify(rows30));
  } catch (e) { setSt("Error"); }
}

let PDF_OBJ_URL = null;

function closePdfModal() {
  document.getElementById("pdfModal").classList.add("hidden");
  document.getElementById("pdfFrame").src = "about:blank";
  if (PDF_OBJ_URL) { URL.revokeObjectURL(PDF_OBJ_URL); PDF_OBJ_URL = null; }
}

async function openPdf() {
  if (!L_DOC) return;
  const url =
    `/api/method/frappe.utils.print_format.download_pdf` +
    `?doctype=${encodeURIComponent("LMT Agent Simple Statement")}` +
    `&name=${encodeURIComponent(L_DOC)}` +
    `&format=${encodeURIComponent("LMT Agent Simple Statement (Arabic)")}` +
    `&no_letterhead=0&_t=${Date.now()}`;
  try {
    setSt("Downloading...");
    const res = await fetch(url, {
      method: "GET",
      headers: { "X-Frappe-CSRF-Token": window.CSRF_TOKEN || "" },
      credentials: "include"
    });
    if (!res.ok) throw new Error("PDF fetch failed");
    const blobUrl = URL.createObjectURL(await res.blob());
    const a = document.createElement("a");
    a.href = blobUrl;
    a.download = (L_DOC ? L_DOC + ".pdf" : "statement.pdf");
    document.body.appendChild(a); a.click(); a.remove();
    setTimeout(() => URL.revokeObjectURL(blobUrl), 2000);
    setSt("Done ✓");
  } catch (e) {
    setSt("PDF Error");
    window.location.href = url;
  }
}

const oD = () => window.open(`/app/lmt-agent-simple-statement/${encodeURIComponent(L_DOC)}`, "_blank");

// ── Boot ──
if (window.CURRENT_USER === "Guest") {
  window.location.href = "/login";
} else {
  reset(); load();
  const lastDoc = sessionStorage.getItem("LMT_LAST_DOC");
  const lastAg  = sessionStorage.getItem("LMT_LAST_AGENT");
  if (lastDoc && lastAg) {
    L_DOC = lastDoc; C_AG = lastAg;
    document.getElementById("kS").innerText = fmt(sessionStorage.getItem("LMT_LAST_KS") || "0");
    document.getElementById("kC").innerText = fmt(sessionStorage.getItem("LMT_LAST_KC") || "0");
    document.getElementById("kB").innerText = fmt(sessionStorage.getItem("LMT_LAST_KB") || "0");
    try {
      const rows = JSON.parse(sessionStorage.getItem("LMT_LAST_ROWS") || "[]");
      if (Array.isArray(rows) && rows.length) {
        document.getElementById("tb").innerHTML = rows.map(buildRow).join('');
        ['bP', 'bD'].forEach(i => document.getElementById(i).classList.remove('hidden'));
        setSt("Restored");
      }
    } catch (e) {}
  }
}

