javascript:
const API_USERS = "sales-report-get-users";
const API_DATA  = "sales-report-get-data";
const el  = (id) => document.getElementById(id);
const fmt = (n)  => Number(n||0).toLocaleString(undefined, {minimumFractionDigits:2});
let chart = null;

function init(){
    const year = new Date().getFullYear();
    el("srFrom").value = `${year}-01-01`;
    el("srTo").value   = `${year}-12-31`;

    document.querySelectorAll(".yr-btn").forEach(btn => {
        if(parseInt(btn.dataset.year) === year) btn.classList.add("active");
        btn.addEventListener("click", function(){
            document.querySelectorAll(".yr-btn").forEach(b => b.classList.remove("active"));
            this.classList.add("active");
            el("srFrom").value = `${this.dataset.year}-01-01`;
            el("srTo").value   = `${this.dataset.year}-12-31`;
            loadData();
        });
    });

    el("srRun").addEventListener("click", loadData);
    loadUsers();
}

function loadUsers(){
    el("srAgent").innerHTML = "<option>Loading...</option>";
    frappe.call({
        method: API_USERS,
        args: {},
        callback: (r) => {
            if(r.message) setupAgentDropdown(r.message);
            loadData();
        }
    });
}

function setupAgentDropdown(data){
    const sel = el("srAgent");
    sel.innerHTML = "";
    if(data.can_select){
        el("agentPill").style.display = "flex";
        el("agentInfo").style.display = "none";
        const optAll = document.createElement("option");
        optAll.value = "__ALL__"; optAll.text = "الكل";
        sel.appendChild(optAll);
        (data.users || []).forEach(u => {
            const opt = document.createElement("option");
            opt.value = u.id; opt.text = u.name;
            sel.appendChild(opt);
        });
    } else {
        el("agentPill").style.display = "none";
        el("agentInfo").style.display = "block";
        el("agentInfo").innerText = "المندوب: " + (data.current_user_name || "Me");
        const opt = document.createElement("option");
        opt.value = "__ALL__";
        sel.appendChild(opt);
    }
}

function loadData(){
    el("srRun").innerText = "⏳";
    frappe.call({
        method: API_DATA,
        args: {
            from_date: el("srFrom").value,
            to_date:   el("srTo").value,
            agent:     el("srAgent").value,
            status:    el("srStatus").value,
            location:  el("srLocation").value,
            city:      el("srCity").value,
            customer:  el("srCustomer").value,
            group_by:  el("srGroupBy").value,
            source:    el("srSource").value
        },
        callback: (r) => {
            el("srRun").innerText = "تحديث";
            if(r.message) renderData(r.message);
        },
        error: (e) => {
            el("srRun").innerText = "تحديث";
            console.error(e);
        }
    });
}

function renderData(data){
    if(data.error){ frappe.msgprint(data.error); return; }

    updateSelect("srLocation", data.options.regions);
    updateSelect("srCity",     data.options.cities);
    updateSelect("srCustomer", data.options.customers);

    const k = data.kpis || {};
    el("srGrandBefore").innerText = fmt(k.total_before || 0);
    el("srGrandTotal").innerText  = fmt(k.total || 0);
    el("srOrdersCount").innerText = k.count || 0;

    const months = data.months || [];
    el("srTh").innerHTML = `<th style="text-align:right">الاسم</th>${months.map(m=>`<th>${m}</th>`).join('')}<th>Total</th>`;
    el("srTb").innerHTML = "";
    const colTot = {};
    months.forEach(m => colTot[m] = 0);

    (data.rows || []).forEach(r => {
        months.forEach(m => colTot[m] += (r[m] || 0));
        const tr = document.createElement("tr");
        let nameHtml = `<div style="font-size:13px">${r.name}</div>`;
        if(r.sub_text) nameHtml += `<div style="font-size:11px;opacity:0.7">${r.sub_text}</div>`;
        if(r.address)  nameHtml += `<div style="font-size:10px;color:#666">${r.address}</div>`;
        tr.innerHTML = `<td class="name">${nameHtml}</td>${months.map(m=>`<td class="num">${fmt(r[m])}</td>`).join('')}<td class="num">${fmt(r.total)}</td>`;
        el("srTb").appendChild(tr);
    });

    el("srTf").innerHTML = `<td class="name">Total</td>${months.map(m=>`<td class="num">${fmt(colTot[m])}</td>`).join('')}<td class="num">${fmt(k.total)}</td>`;

    if(chart) chart.destroy();
    if(data.chart && data.chart.values){
        chart = new Chart(el("srChart"), {
            type: 'bar',
            data: {
                labels:   data.chart.labels || months,
                datasets: [{ label:'Sales', data: data.chart.values, backgroundColor:'#2f8f3a' }]
            },
            options: { responsive:true, maintainAspectRatio:false }
        });
    }
}

function updateSelect(id, items){
    const sel = el(id);
    const currentVal = sel.value;
    sel.innerHTML = '<option value="__ALL__">الكل</option>';
    if(items && items.length > 0){
        items.forEach(i => {
            const opt = document.createElement("option");
            opt.value = i; opt.text = i;
            sel.appendChild(opt);
        });
        if(currentVal && currentVal !== "__ALL__" && items.includes(currentVal)){
            sel.value = currentVal;
        }
    }
}

frappe.ready(init);

