javascript:
let C_AG = null;

const setSt = function(t) { document.getElementById("st").textContent = t; };
const fmt = function(x) { return Number(x||0).toLocaleString(undefined, {minimumFractionDigits: 2}); };

// FIX: Dynamic CSRF Token Fetcher (Bypasses Jinja Cache completely)
function getCsrfToken() {
    if (window.frappe && frappe.csrf_token) return frappe.csrf_token;
    let meta = document.querySelector('meta[name="csrf-token"]');
    if (meta && meta.content) return meta.content;
    return "";
}

// Advanced Fetch Wrapper to handle GET & POST + Frappe error extraction safely
async function fJ(u, method, body) {
  if (!method) method = "GET";

  const opts = {
    method: method,
    headers: { 
        "X-Frappe-CSRF-Token": getCsrfToken(),
        "Content-Type": "application/json"
    }
  };

  if (body) opts.body = JSON.stringify(body);

  const r = await fetch(u, opts);
  const text = await r.text();

  if (!r.ok) {
    let errMsg = "حدث خطأ في النظام";
    try {
        const j = JSON.parse(text);
        if (j._server_messages) errMsg = JSON.parse(JSON.parse(j._server_messages)[0]).message;
        else if (j.exc) errMsg = "خطأ برمجي (راجع الـ Console)";
        else if (j.message) errMsg = j.message;
    } catch(e) {}
    throw new Error(errMsg);
  }

  try { 
      const j = JSON.parse(text);
      return j.message !== undefined ? j.message : (j.data !== undefined ? j.data : j); 
  } 
  catch(e) { return text; }
}

function reset(){
  document.getElementById("tb").innerHTML = "<tr><td colspan='5' style='padding:30px; background:transparent;'>الرجاء اختيار المندوب لعرض البيانات</td></tr>";
  document.getElementById("kC").innerText = "0";
  document.getElementById("kV").innerText = "0.00";
  setSt("مستعد");
}

async function load(){
  try {
    // 100% RELYING ON YOUR ORIGINAL ENDPOINT
    const m = await fJ("/api/method/lmt_supervisor_agents_simple");
    const s = document.getElementById("ag_sel");
    const w = document.getElementById("ag_wrp");
    const i = document.getElementById("ag_inf");

    if(m.can_select_agent !== 1){ 
      w.classList.add('hidden');
      i.classList.remove('hidden');
      C_AG = m.agents[0] ? m.agents[0].user : window.CURRENT_USER; 
      i.innerText = "المندوب: " + (m.agents[0] ? m.agents[0].full_name : C_AG);
    } else {
      s.innerHTML = '<option value="">-- اختر المندوب --</option><option value="__ALL__">🔍 كل المندوبين</opt>';
      m.agents.forEach(function(a) {
        let o = document.createElement("option");
        o.value = a.user;
        o.innerText = a.full_name;
        s.appendChild(o);
      });
      s.onchange = function(e) { C_AG = e.target.value; };
    }
  } catch(e){
    setSt("خطأ في جلب بيانات المناديب");
  }
}

async function gen(){
  if(!C_AG) return setSt("الرجاء اختيار مندوب");
  setSt("جاري التحميل...");

  try {
    // 100% RELYING ON YOUR ORIGINAL STANDARD FETCH LOGIC
    const filters = (C_AG === "__ALL__") 
      ? [["docstatus","=",0], ["is_return","=",1]] 
      : [["docstatus","=",0], ["is_return","=",1], ["owner","=",C_AG]];
    const fields = ["name","customer_name","posting_date","grand_total","update_stock"];
    const url = "/api/resource/Sales Invoice?filters=" + encodeURIComponent(JSON.stringify(filters)) + "&fields=" + encodeURIComponent(JSON.stringify(fields)) + "&limit_page_length=200&order_by=creation desc";

    const rows = await fJ(url) || [];

    document.getElementById("kC").innerText = rows.length;
    let totalVal = rows.reduce(function(sum, r) { return sum + (r.grand_total||0); }, 0);
    document.getElementById("kV").innerText = fmt(totalVal);

    if (rows.length === 0) {
      document.getElementById("tb").innerHTML = "<tr><td colspan='5' style='padding:30px; background:transparent;'>لا توجد مرتجعات معلقة (مسودة) لهذا المندوب</td></tr>";
      setSt("تم التحميل");
      return;
    }

    // Minifier-safe string concatenation
    document.getElementById("tb").innerHTML = rows.map(function(x) {
      return "<tr>" +
        "<td style='font-weight:900; color:var(--primary-blue); cursor:pointer; text-decoration: underline;' onclick='showPreview(\"" + x.name + "\")'>" + x.name + "</td>" +
        "<td style='font-weight:900;'>" + (x.customer_name || "") + "</td>" +
        "<td>" + (x.posting_date || "") + "</td>" +
        "<td style='font-weight:900; color:#ef4444;'>" + fmt(x.grand_total) + "</td>" +
        "<td>" +
          "<div style='display:flex; gap:6px; justify-content:center;'>" +
             "<button class='sr-btn primary' style='padding:6px 12px; font-size:12px;' onclick='processReturn(\"" + x.name + "\", " + x.update_stock + ")'>اعتماد 📦</button>" +
             "<button class='sr-btn' style='padding:6px 12px; font-size:12px; background:#ef4444; color:white; border:none;' onclick='cancelReturn(\"" + x.name + "\")'>إلغاء 🗑️</button>" +
          "</div>" +
        "</td>" +
      "</tr>";
    }).join("");

    setSt("تم التحديث");
  } catch(e){
    setSt("حدث خطأ");
  }
}

// === Show Preview Modal ===
async function showPreview(name) {
    const modal = document.getElementById('previewModal');
    const body = document.getElementById('previewBody');
    const title = document.getElementById('previewTitle');

    modal.classList.remove('hidden');
    body.innerHTML = "<div style='text-align:center; padding:30px; font-weight:800;'>جاري جلب تفاصيل المرتجع...</div>";
    title.innerText = "تفاصيل المرتجع: " + name;

    try {
        let docObj = await fJ("/api/resource/Sales Invoice/" + encodeURIComponent(name));
        let doc = docObj.data ? docObj.data : docObj; 

        let itemsArr = doc.items || [];
        let itemsHtml = itemsArr.map(function(i) {
            return "<tr>" +
                "<td style='text-align:right;'>" + (i.item_name || "") + "</td>" +
                "<td style='text-align:center;'>" + Math.abs(i.qty) + "</td>" +
                "<td style='text-align:center;'>" + fmt(i.rate) + "</td>" +
                "<td style='text-align:center;'>" + fmt(Math.abs(i.amount)) + "</td>" +
            "</tr>";
        }).join("");

        // Minifier-safe string concatenation
        let html = 
            "<div style='background:#f9f9f9; padding:10px; border-radius:8px; border:1px solid #eee; margin-bottom:10px; direction: rtl; text-align: right;'>" +
                "<div style='margin-bottom:8px; font-size:14px;'><strong style='color:var(--primary-blue);'>الزبون:</strong> " + (doc.customer_name || "") + "</div>" +
                "<div style='font-size:14px;'><strong style='color:var(--primary-blue);'>الملاحظات:</strong> " + (doc.remarks || "<span style='opacity:0.5;'>لا يوجد</span>") + "</div>" +
            "</div>" +
            "<div style='max-height: 40vh; overflow-y:auto; border-radius:8px; border: 1px solid #ccc; direction: rtl;'>" +
                "<table class='preview-table' style='margin-top:0;'>" +
                    "<thead style='position:sticky; top:0; z-index:10;'>" +
                        "<tr>" +
                            "<th style='text-align:right;'>الصنف</th>" +
                            "<th>الكمية</th>" +
                            "<th>السعر</th>" +
                            "<th>المجموع</th>" +
                        "</tr>" +
                    "</thead>" +
                    "<tbody>" +
                        itemsHtml +
                    "</tbody>" +
                "</table>" +
            "</div>" +
            "<div style='text-align:left; margin-top:15px; padding:10px; background:var(--yellow-light); border-radius:8px; border:1px solid rgba(0,0,0,0.1);'>" +
                "<strong style='font-size:16px;'>إجمالي المرتجع: <span style='color:#ef4444;'>" + fmt(Math.abs(doc.grand_total)) + "</span> د.ل</strong>" +
            "</div>";

        body.innerHTML = html;
    } catch(e) {
        body.innerHTML = "<div style='color:red; text-align:center; padding:20px; font-weight:800;'>⚠️ تعذر جلب التفاصيل:<br>" + e.message + "</div>";
    }
}

// === Cancel Return Draft ===
async function cancelReturn(invName) {
    if (!confirm("هل أنت متأكد من إلغاء وحذف المرتجع [" + invName + "] نهائياً؟")) return;

    setSt("جاري إلغاء " + invName + "...");
    try {
        await fJ("/api/method/sr_cancel_return_draft_7", "POST", { name: invName });
        alert("✅ تم حذف وإلغاء المرتجع [" + invName + "] بنجاح.");
        gen(); // Refresh table
    } catch(e) {
        alert("⚠️ خطأ أثناء الإلغاء:\n" + e.message);
        setSt("فشلت العملية");
    }
}

// === Process/Approve (Exactly your original working code) ===
async function processReturn(invName, hasStockUpdate) {
    if (!confirm("هل أنت متأكد من اعتماد المرتجع " + invName + " واسترجاع الكميات للمخزن؟")) return;

    setSt("جاري اعتماد " + invName + "...");
    try {
        // Step 1: Fetch Full Document
        let invDocObj = await fJ("/api/resource/Sales Invoice/" + encodeURIComponent(invName));
        let invDoc = invDocObj.data ? invDocObj.data : invDocObj;

        // Step 2+3: LMT script handles bundle + submit atomically
        setSt("جاري اعتماد المرتجع وتسوية المخزون...");
        await fJ("/api/method/lmt_create_return_dn_v1", "POST", { invoice_name: invName });

        alert("✅ تم اعتماد المرتجع [" + invName + "] بنجاح، وتم تسوية المخزون!");
        gen(); // Refresh table
    } catch(e) {
        alert("⚠️ خطأ أثناء الاعتماد:\n" + e.message);
        setSt("فشلت العملية");
    }
}

// Boot up
if (window.CURRENT_USER === "Guest") {
  window.location.href = "/login";
} else {
  reset();
  load();
}
</script>

