javascript:
(function () {
  "use strict";

  const ERPNEXT_BASE_URL = window.location.origin;
  const RETURN_PRINT_FORMAT = "Arabic Invoice"; 

  let DEFAULT_PRICE_LIST = "Standard Selling";
  let LOGGED_USER_EMAIL = null;
  let DEFAULT_WAREHOUSE = null;
  let LINKED_EMPLOYEE = null; 

  let MODE = "against_invoice"; 
  let selectedCustomerName = "";
  let selectedCustomerId = "";
  let selectedInvoiceName = "";
  let invoiceDoc = null;

  let customerMaster = [];
  let customerIdByName = {};

  let itemLabelByCode = {};
  let itemCodeByLabel = {};
  let warehouseItemLabels = [];
  let invoiceItemMap = {};

  let cart = [];
  let busy = false;

  let pickedItemCode = "";
  let pickedItemLabel = "";
  let pickedItemUom = "";
  let pickedItemName = "";
  let pickedItemRate = 0;
  let pickedRateEditable = true;

  // BATCH STATE
  let selectedBatchNo = null;
  let currentBatchLimit = 0;

  let lastCreatedReturnName = "";

  // EDIT & VIEW STATE
  let EDITING_RETURN_NAME = null;
  let VIEW_ONLY_MODE = false;

  // PAGINATION STATE
  let currentReturnOffset = 0;
  const RETURNS_LIMIT = 5;

  function el(id){ return document.getElementById(id); }

  function setStatus(msg, cls){
    const x = el("retStatus");
    if (!x) return;
    x.className = "ret-status ret-mt10 " + (cls || "");
    x.textContent = msg || "";
  }

  function getCsrfToken() {
    if (window.frappe && frappe.csrf_token) return frappe.csrf_token;
    const meta = document.querySelector('meta[name="csrf-token"]');
    return (meta && meta.content) ? meta.content : null;
  }

  function extractServerError(errObj, rawText) {
    try {
      if (errObj && errObj._raw) rawText = errObj._raw;
      if (rawText && typeof rawText === "string") {
        try {
          const j = JSON.parse(rawText);
          if (j && j._server_messages) {
            try {
              const arr = JSON.parse(j._server_messages);
              if (Array.isArray(arr) && arr.length) {
                const first = JSON.parse(arr[0]);
                if (first && first.message) return first.message;
              }
            } catch(_) {}
          }
          if (j && j.message && typeof j.message === "string") return j.message;
          if (j && j.exception) return j.exception;
        } catch(_) {}
      }
      if (errObj && errObj.message) return errObj.message;
    } catch(_) {}
    return "حدث خطأ غير معروف";
  }

  async function erpRequest(path, options = {}) {
    const headers = Object.assign({}, options.headers || {});
    if ((options.method || "GET") !== "GET") {
      headers["Content-Type"] = "application/json";
      headers["X-Frappe-CSRF-Token"] = getCsrfToken();
    }
    const url = path.startsWith("http") ? path : ERPNEXT_BASE_URL + path;
    const resp = await fetch(url, Object.assign({}, options, { headers, credentials: "include" }));
    const txt = await resp.text();
    if (!resp.ok) {
      const e = new Error(resp.statusText || "Request Failed");
      e._raw = txt;
      e._status = resp.status;
      throw e;
    }
    try { return JSON.parse(txt); } catch { return txt; }
  }

  function requireCustomer(){
    if (!selectedCustomerId) { setStatus("اختر الزبون أولاً", "warn"); return false; }
    return true;
  }

  function requireWarehouse(){
    if (!DEFAULT_WAREHOUSE) { setStatus("لا يوجد مخزن مربوط للمستخدم", "error"); return false; }
    return true;
  }

  async function loadDefaultsAndUser(){
    try {
      const gd = await erpRequest("/api/resource/Global Defaults/Global Defaults?fields=" + encodeURIComponent(JSON.stringify(["default_price_list"])));
      if (gd?.data?.default_price_list) DEFAULT_PRICE_LIST = gd.data.default_price_list;
    } catch (e) {}

    LOGGED_USER_EMAIL = window.CURRENT_USER || "{{ frappe.session.user }}";

    if(LOGGED_USER_EMAIL) {
        const u = await erpRequest("/api/resource/User/" + encodeURIComponent(LOGGED_USER_EMAIL) + "?fields=" + encodeURIComponent(JSON.stringify(["warehouse"])));
        DEFAULT_WAREHOUSE = (u?.data?.warehouse || null);

        try {
            const empReq = await erpRequest(`/api/resource/Employee?filters=[["user_id","=","${LOGGED_USER_EMAIL}"]]&fields=["name"]`);
            if (empReq?.data && empReq.data.length > 0) {
                LINKED_EMPLOYEE = empReq.data[0].name;
            }
        } catch(e) { console.warn("Could not fetch linked employee"); }
    }
    if (el("retWarehouseView")) el("retWarehouseView").textContent = DEFAULT_WAREHOUSE || "-";
  }

  async function loadCustomersFiltered(){
    const filters = LOGGED_USER_EMAIL ? `&filters=[["account_manager","=", "${LOGGED_USER_EMAIL}"]]` : "";
    const fields = JSON.stringify(["name", "customer_name"]);
    const cData = await erpRequest(`/api/resource/Customer?fields=${encodeURIComponent(fields)}${filters}&limit_page_length=9999`);

    customerMaster = [];
    customerIdByName = {};
    (cData.data || []).forEach(d => {
      const n = d.customer_name || d.name;
      customerMaster.push({ name: n, id: d.name });
      customerIdByName[n] = d.name;
    });
  }

  async function loadAllItemsMaster(){
    const iData = await erpRequest(`/api/resource/Item?fields=["name","item_name","disabled"]&filters=[["disabled","=",0]]&limit_page_length=3000`);
    (iData.data || []).forEach(d => {
      const label = d.name + (d.item_name ? " - " + d.item_name : "");
      itemLabelByCode[d.name] = label;
      itemCodeByLabel[label] = d.name;
    });
  }

  async function loadWarehouseItems(){
    if (!requireWarehouse()) return;
    const bData = await erpRequest(`/api/resource/Bin?fields=["item_code","actual_qty"]&filters=` + encodeURIComponent(JSON.stringify([
      ["warehouse","=", DEFAULT_WAREHOUSE]
    ])) + `&limit_page_length=5000`);

    const codes = new Set();
    (bData.data || []).forEach(b => { if (b.item_code) codes.add(b.item_code); });

    warehouseItemLabels = [];
    codes.forEach(code => warehouseItemLabels.push(itemLabelByCode[code] || code));
    warehouseItemLabels.sort((a,b)=> a.localeCompare(b, 'en'));
  }

  function setMode(m){
    MODE = m;
    document.querySelectorAll("#retMode .ret-seg-btn").forEach(b => b.classList.remove("active"));
    const btn = document.querySelector(`#retMode .ret-seg-btn[data-mode="${m}"]`);
    if (btn) btn.classList.add("active");

    if (el("retInvoiceRow")) el("retInvoiceRow").style.display = (m === "against_invoice") ? "" : "none";
    if (el("retNoInvoiceInfo")) el("retNoInvoiceInfo").style.display = (m === "no_invoice") ? "" : "none";

    selectedInvoiceName = "";
    invoiceDoc = null;
    invoiceItemMap = {};
    if (el("retInvoiceInput")) el("retInvoiceInput").value = "";

    clearPickedItem();
    cart = [];
    renderCart();
    setStatus("");
    lastCreatedReturnName = "";
    if (el("retPrint")) el("retPrint").disabled = true;
  }

  function clearPickedItem(){
    pickedItemCode = "";
    pickedItemLabel = "";
    pickedItemUom = "";
    pickedItemName = "";
    pickedItemRate = 0;
    pickedRateEditable = true;

    selectedBatchNo = null;
    currentBatchLimit = 0;

    if (el("retItemLabel")) el("retItemLabel").value = "";
    if (el("retItemQty")) el("retItemQty").value = "";
    if (el("retItemRate")) {
      el("retItemRate").value = "";
      if (!VIEW_ONLY_MODE) el("retItemRate").disabled = false;
    }
    if (el("retRateHint")) el("retRateHint").textContent = "—";

    if (el("retBatchContainer")) {
        el("retBatchContainer").innerHTML = "";
        el("retBatchContainer").style.display = "none";
    }
  }

  function renderPickList(container, list, onPick){
    container.innerHTML = "";
    if (!list.length) { container.innerHTML = `<div class="ret-empty">لا توجد بيانات</div>`; return; }
    list.forEach(txt => {
      const row = document.createElement("div");
      row.className = "ret-pick-row";
      row.textContent = txt;
      row.onclick = () => onPick(txt);
      container.appendChild(row);
    });
  }

  function openCustomerModal(){
    if (VIEW_ONLY_MODE) return;
    el("retCustomerModal").style.display = "flex";
    el("retCustomerSearch").value = "";

    const full = customerMaster.map(c => c.name);
    renderPickList(el("retCustomerList"), full, pickCustomer);

    el("retCustomerSearch").oninput = (e) => {
      const normalize = (str) => str.replace(/[أإآا]/g, 'ا').replace(/ة/g, 'ه').replace(/[يى]/g, 'ي');
      const q = normalize((e.target.value || "").toLowerCase().trim());
      const terms = q.split(/\s+/);

      renderPickList(el("retCustomerList"), full.filter(n => {
        const target = normalize(n.toLowerCase());
        return terms.every(t => target.includes(t));
      }), pickCustomer);
    };
  }

  function pickCustomer(name){
    selectedCustomerName = name;
    selectedCustomerId = customerIdByName[name] || "";
    el("retCustomerInput").value = name;
    selectedInvoiceName = "";
    invoiceDoc = null;
    invoiceItemMap = {};
    el("retInvoiceInput").value = "";
    clearPickedItem();
    cart = [];
    renderCart();
    setStatus("");
    lastCreatedReturnName = "";
    if (el("retPrint")) el("retPrint").disabled = true;
    closeCustomerModal();
  }

  function closeCustomerModal(){ el("retCustomerModal").style.display = "none"; }

  async function openInvoiceModal(){
    if (VIEW_ONLY_MODE) return;
    if (!requireCustomer()) return;
    el("retInvoiceModal").style.display = "flex";
    el("retInvoiceSearch").value = "";
    el("retInvoiceList").innerHTML = `<div class="ret-empty">جاري تحميل الفواتير...</div>`;

    const fields = JSON.stringify(["name","posting_date","grand_total"]);
    const filters = encodeURIComponent(JSON.stringify([
      ["customer","=", selectedCustomerId],
      ["docstatus","=", 1],
      ["is_return","=", 0]
    ]));

    const invData = await erpRequest(`/api/resource/Sales Invoice?fields=${encodeURIComponent(fields)}&filters=${filters}&order_by=posting_date desc&limit_page_length=200`);
    const raw = (invData.data || []).map(d => ({
      name: d.name,
      label: `${d.name} | ${d.posting_date || ""} | ${Number(d.grand_total || 0).toFixed(2)}`
    }));

    const labels = raw.map(x=>x.label);
    function pick(labelPicked){
      const chosen = raw.find(x => x.label === labelPicked);
      if (!chosen) return;
      selectedInvoiceName = chosen.name;
      el("retInvoiceInput").value = chosen.name;
      closeInvoiceModal();
      loadInvoiceAndBuildItemMap(chosen.name);
    }
    renderPickList(el("retInvoiceList"), labels, pick);
    el("retInvoiceSearch").oninput = (e) => {
      const q = (e.target.value || "").toLowerCase();
      renderPickList(el("retInvoiceList"), labels.filter(x => x.toLowerCase().includes(q)), pick);
    };
  }

  function closeInvoiceModal(){ el("retInvoiceModal").style.display = "none"; }

  async function loadInvoiceAndBuildItemMap(invName, keepCart = false){
    setStatus("جاري تحميل بيانات الفاتورة...", "info");
    const doc = await erpRequest(`/api/resource/Sales Invoice/${encodeURIComponent(invName)}`);
    const d = doc.data;
    if (!d || d.docstatus !== 1 || d.is_return) { setStatus("فاتورة غير صالحة", "error"); return; }
    if (d.customer !== selectedCustomerId) { setStatus("خطأ: الفاتورة ليست لهذا الزبون", "error"); selectedInvoiceName = ""; el("retInvoiceInput").value = ""; return; }

    invoiceDoc = d;
    invoiceItemMap = {};
    (d.items || []).forEach(row => {
          const code = row.item_code;
    invoiceItemMap[code] = {
        rate: Number(row.rate || 0),
        price_list_rate: Number(row.price_list_rate || row.rate || 0),
        discount_percentage: Number(row.discount_percentage || 0),
        discount_amount: Number(row.discount_amount || 0),
        net_rate: Number(row.net_rate || row.rate || 0),
        uom: row.uom || "",
            item_name: row.item_name || "",
            batch_no: row.batch_no || "",
            sales_invoice_item: row.name, 
            delivery_note: row.delivery_note || "",
            dn_detail: row.dn_detail || "",
            label: (itemLabelByCode[code] || (code + (row.item_name ? " - " + row.item_name : "")))
          };
        });

    if (!keepCart) {
        clearPickedItem();
        cart = [];
        renderCart();
        setStatus("تم تحميل الفاتورة. اختر الأصناف من قائمة الفاتورة.", "ok");
        // We only clear PDF button if we are NOT in View mode
        if (!VIEW_ONLY_MODE) {
            lastCreatedReturnName = "";
            if (el("retPrint")) el("retPrint").disabled = true;
        }
    }
  }

  function openItemModal(){
    if (VIEW_ONLY_MODE) return;
    if (!requireCustomer()) return;
    if (!requireWarehouse()) return;
    if (MODE === "against_invoice" && !selectedInvoiceName) { setStatus("اختر الفاتورة أولاً ثم اختر الأصناف", "warn"); return; }

    el("retItemModal").style.display = "flex";
    el("retItemSearch").value = "";

    let sourceLabels = [];
    if (MODE === "against_invoice") sourceLabels = Object.values(invoiceItemMap).map(x => x.label);
    else sourceLabels = warehouseItemLabels.slice();

    if (!sourceLabels.length) { el("retItemList").innerHTML = `<div class="ret-empty">لا توجد أصناف للعرض</div>`; return; }

    sourceLabels.sort((a,b)=> a.localeCompare(b, 'en'));
    const pick = (label) => { closeItemModal(); applyPickedItem(label); };
    renderPickList(el("retItemList"), sourceLabels, pick);

    el("retItemSearch").oninput = (e) => {
      const q = (e.target.value || "").toLowerCase();
      renderPickList(el("retItemList"), sourceLabels.filter(x => x.toLowerCase().includes(q)), pick);
    };
  }

  function closeItemModal(){ el("retItemModal").style.display = "none"; }

  async function fetchItemBatches(itemCode) {
    const container = el("retBatchContainer");
    if (!itemCode || !DEFAULT_WAREHOUSE) return;

    container.style.display = "block";
    container.innerHTML = `<div style="padding:10px;text-align:center;color:#666;">جاري فحص الدفعات (Batches)...</div>`;
    selectedBatchNo = null;
    currentBatchLimit = 0;

    try {
      const response = await erpRequest("/api/method/get_warehouse_batches", {
        method: "POST",
        body: JSON.stringify({ item_code: itemCode, warehouse: DEFAULT_WAREHOUSE })
      });
      renderBatchList(response.message || [], itemCode);
    } catch (e) {
      console.error(e);
      container.innerHTML = `<div style="padding:10px;text-align:center;color:red;">خطأ في جلب الدفعات</div>`;
    }
  }

  function renderBatchList(batches, itemCode) {
    const container = el("retBatchContainer");
    container.innerHTML = "";

    if (batches.length === 0) {
      container.innerHTML = `<div style="padding:15px; text-align:center; color:#999;">لا يوجد رصيد في المخزن المختار</div>`;
      return;
    }

    let activeBatchFound = false;
    const today = new Date().toISOString().split("T")[0];

    batches.forEach(b => {
      let inCart = cart.filter(i => i.item_code === itemCode && i.batch_no === b.name).reduce((sum, i) => sum + i.qty_pos, 0);
      let realAvailable = b.batch_qty - inCart;
      if (realAvailable < 0) realAvailable = 0;

      const displayBatchQty = (realAvailable > 100) ? "متوفر" : realAvailable;
      const row = document.createElement("div");
      row.className = "batch-row";
      const batchIdValue = b.name || "";
      let isDisabled = realAvailable === 0;

      if (realAvailable > 0 && !activeBatchFound) {
        activeBatchFound = true;
        row.classList.add("selected");
        selectedBatchNo = batchIdValue;
        currentBatchLimit = realAvailable;
        el("retItemQty").value = 1;
      }

      if (isDisabled) row.classList.add("disabled");

      let dateColor = (b.expiry_date && b.expiry_date < today) ? "#c00" : "#333";
      let dateText = b.expiry_date || "N/A";
      if (b.expiry_date && b.expiry_date < today) dateText += " (منتهي)";

      row.innerHTML = `
        <div class="batch-info">
          <div class="batch-date" style="color:${dateColor}">${dateText}</div>
          <div class="batch-id">${b.name || "<i>بدون دفعة</i>"}</div>
        </div>
        <div style="text-align:right;">
          <div class="batch-qty" style="color:${realAvailable > 0 ? '#2e7d32' : '#d32f2f'}">${displayBatchQty}</div>
        </div>
      `;

      row.onclick = () => {
        if (isDisabled) return;
        document.querySelectorAll("#retBatchContainer .batch-row").forEach(r => r.classList.remove("selected"));
        row.classList.add("selected");
        selectedBatchNo = batchIdValue;
        currentBatchLimit = realAvailable;
        el("retItemQty").value = 1;
      };

      container.appendChild(row);
    });
  }

  async function getCurrentRate(item_code){
    try {
      const p = await erpRequest(`/api/resource/Item Price?fields=["price_list_rate"]&filters=` + encodeURIComponent(JSON.stringify([
        ["item_code","=", item_code], ["price_list","=", DEFAULT_PRICE_LIST]
      ])) + `&limit_page_length=1`);
      if (p.data && p.data.length) return Number(p.data[0].price_list_rate || 0);
    } catch(e) {}
    try {
      const it = await erpRequest(`/api/resource/Item/${encodeURIComponent(item_code)}?fields=["standard_rate"]`);
      return Number(it.data.standard_rate || 0);
    } catch(e) {}
    return 0;
  }

  async function applyPickedItem(label){
    let code = itemCodeByLabel[label] || "";
    if (!code && MODE === "against_invoice") {
      const found = Object.entries(invoiceItemMap).find(([k,v]) => v.label === label);
      if (found) code = found[0];
    }
    if (!code) { setStatus("خطأ: لم يتم تحديد الصنف", "error"); return; }

    pickedItemCode = code;
    pickedItemLabel = label;

    if (MODE === "against_invoice") {
      const inv = invoiceItemMap[code];
      pickedItemName = inv?.item_name || "";
      pickedItemUom = inv?.uom || "";
      pickedItemRate = Number(inv?.rate || 0);
      pickedRateEditable = false;

      selectedBatchNo = inv?.batch_no || "";
      currentBatchLimit = 9999; 
      el("retBatchContainer").style.display = "none"; 

      el("retItemLabel").value = inv?.label || label;
      el("retItemRate").value = pickedItemRate;
      el("retItemRate").disabled = true;
      el("retRateHint").textContent = "السعر والكمية من الفاتورة";
    } else {
      pickedItemName = (label.split(" - ")[1] || "").trim();
      pickedItemUom = "";
      pickedItemRate = await getCurrentRate(code);
      pickedRateEditable = true;

      el("retItemLabel").value = itemLabelByCode[code] || label;
      el("retItemRate").value = pickedItemRate;
      el("retItemRate").disabled = false;
      el("retRateHint").textContent = "السعر قابل للتعديل";

      await fetchItemBatches(code);
    }

    el("retItemQty").value = 1;
  }

  function addPickedItemToCart(){
    if (VIEW_ONLY_MODE) return;
    if (!requireCustomer()) return;
    if (!requireWarehouse()) return;
    if (!pickedItemCode) return setStatus("اختر الصنف أولاً", "warn");

    const qty = Number(el("retItemQty").value || 0);
    if (!(qty > 0)) return setStatus("أدخل كمية صحيحة", "warn");

    if (MODE === "no_invoice") {
        const container = el("retBatchContainer");
        if (container.querySelector(".batch-row") && !selectedBatchNo) {
            return setStatus("الرجاء اختيار الدفعة (Batch) أولاً", "warn");
        }
        if (currentBatchLimit > 0 && qty > currentBatchLimit) {
            return setStatus(`الكمية المتاحة للدفعة هي ${currentBatchLimit} فقط`, "warn");
        }
    }

    const rate = Number(el("retItemRate").value || 0);
    if (!(rate >= 0)) return setStatus("أدخل سعر صحيح", "warn");

    cart.push({
      item_code: pickedItemCode,
      label: el("retItemLabel").value || pickedItemLabel,
      item_name: pickedItemName || "",
      uom: pickedItemUom || "",
      qty_pos: qty,
      rate: rate,
      batch_no: selectedBatchNo || "", 
      sales_invoice_item: MODE === "against_invoice" ? invoiceItemMap[pickedItemCode].sales_invoice_item : null,
      delivery_note: MODE === "against_invoice" ? invoiceItemMap[pickedItemCode].delivery_note : null,
      dn_detail: MODE === "against_invoice" ? invoiceItemMap[pickedItemCode].dn_detail : null,
      allow_rate_edit: pickedRateEditable,
      price_list_rate: MODE === "against_invoice" ? (invoiceItemMap[pickedItemCode].price_list_rate || 0) : 0,
      discount_percentage: MODE === "against_invoice" ? (invoiceItemMap[pickedItemCode].discount_percentage || 0) : 0,
      item_discount_amount: MODE === "against_invoice" ? (invoiceItemMap[pickedItemCode].discount_amount || 0) : 0
    });

    renderCart();
    clearPickedItem();
    setStatus("تمت إضافة الصنف للقائمة", "ok");
    // Ensure we don't accidentally clear the PDF button if it's currently active (like after saving a draft)
    if (!EDITING_RETURN_NAME) {
        lastCreatedReturnName = "";
        if (el("retPrint")) el("retPrint").disabled = true;
    }
  }

  function renderCart(){
    const box = el("retItems");
    box.innerHTML = "";

    if (!cart.length) {
      box.innerHTML = `<div class="ret-empty">لا توجد أصناف بعد</div>`;
      return;
    }

    cart.forEach((it, idx) => {
      const batchDisplay = it.batch_no ? `<span style="color:#2f8f3a; font-weight:900;">[${it.batch_no}]</span>` : "";

      // Determine disabled states based on View Mode
      let qtyDisabledStr = VIEW_ONLY_MODE ? "disabled" : "";
      let rateDisabledStr = (VIEW_ONLY_MODE || !it.allow_rate_edit) ? "disabled" : "";
      let removeBtnHtml = VIEW_ONLY_MODE ? "" : `<button class="btn-remove" type="button" data-idx="${idx}">حذف</button>`;

      box.insertAdjacentHTML("beforeend", `
        <div class="ret-item">
          <div class="ret-item-title">${it.label} ${batchDisplay}</div>
          <div class="ret-grid2">
            <div style="display:flex; flex-direction:column; align-items:center;">
              <span style="font-size:11px; font-weight:900;">الكمية</span>
              <input type="number" min="1" step="1" value="${Number(it.qty_pos || 1)}" class="inp" data-idx="${idx}" data-field="qty_pos" ${qtyDisabledStr}>
            </div>
            <div style="display:flex; flex-direction:column; align-items:center;">
              <span style="font-size:11px; font-weight:900;">السعر</span>
              <input type="number" min="0" step="0.01" value="${Number(it.rate || 0)}" class="inp" data-idx="${idx}" data-field="rate" ${rateDisabledStr}>
            </div>
          </div>
          ${removeBtnHtml}
        </div>
      `);
    });
  }

  function validate(){
    if (!selectedCustomerId) return "اختر الزبون أولاً";
    if (!DEFAULT_WAREHOUSE) return "لا يوجد مخزن مربوط للمستخدم";
    if (MODE === "against_invoice" && !selectedInvoiceName) return "اختر الفاتورة أولاً";
    if (!cart.length) return "أضف أصناف أولاً";
    return null;
  }

  async function createReturnDraft(){
    if (busy || VIEW_ONLY_MODE) return;
    const err = validate();
    if (err) { setStatus(err, "error"); return; }

    busy = true;
    const remarks = (el("retRemarks").value || "").trim();

    const doc = {
      doctype: "Sales Invoice",
      is_return: 1,
      customer: selectedCustomerId,
      selling_price_list: DEFAULT_PRICE_LIST,
      set_warehouse: DEFAULT_WAREHOUSE,
      remarks: remarks
    };

    if (LINKED_EMPLOYEE) {
        doc.employee = LINKED_EMPLOYEE;
    }

    if (MODE === "against_invoice") {
      doc.return_against = selectedInvoiceName;
      doc.update_outstanding_for_self = 0; 

      if (invoiceDoc) {
        doc.company = invoiceDoc.company;
        doc.currency = invoiceDoc.currency;
        doc.debit_to = invoiceDoc.debit_to;
        doc.cost_center = invoiceDoc.cost_center;
        doc.selling_price_list = invoiceDoc.selling_price_list || DEFAULT_PRICE_LIST;
        doc.update_stock = invoiceDoc.update_stock || 0;
        doc.additional_discount_percentage = invoiceDoc.additional_discount_percentage || 0;
        doc.discount_amount = invoiceDoc.discount_amount || 0;
        doc.apply_discount_on = invoiceDoc.apply_discount_on || "";
      }
    } else {
      doc.update_stock = 1;
    }

    doc.items = cart.map(it => {
      let row = {
          item_code: it.item_code,
          qty: -Math.abs(Number(it.qty_pos || 0)),
          rate: Number(it.rate || 0),
          batch_no: it.batch_no || null,
          warehouse: DEFAULT_WAREHOUSE
      };

       if (MODE === "against_invoice") {
          row.sales_invoice_item = it.sales_invoice_item;
          row.price_list_rate = it.price_list_rate || it.rate;
          row.discount_percentage = it.discount_percentage || 0;
          row.discount_amount = it.item_discount_amount || 0;
          if (it.delivery_note) row.delivery_note = it.delivery_note;
          if (it.dn_detail) row.dn_detail = it.dn_detail;
      }
      return row;
    });

    if (EDITING_RETURN_NAME) {
        setStatus("جاري تحديث المسودة...", "info");
        frappe.call({
            method: "sr_update_draft_return_24",
            args: { name: EDITING_RETURN_NAME, payload: JSON.stringify(doc) },
            callback: function(r) {
                busy = false;
                if (r.message && r.message.status === "success") {
                    lastCreatedReturnName = r.message.name;
                    setStatus(`✅ تم تحديث المسودة: ${lastCreatedReturnName}`, "ok");
                    if (el("retPrint")) el("retPrint").disabled = false;

                    EDITING_RETURN_NAME = null;
                    el("retCreate").textContent = "إنشاء المرتجع (مسودة)";

                    selectedInvoiceName = "";
                    invoiceDoc = null;
                    invoiceItemMap = {};
                    if (el("retInvoiceInput")) el("retInvoiceInput").value = "";
                    cart = [];
                    renderCart();
                    el("retRemarks").value = "";
                    fetchRecentReturns(false);
                } else {
                    setStatus("حدث خطأ في التحديث", "error");
                }
            },
            error: function(err) {
                busy = false;
                setStatus("حدث خطأ في التحديث", "error");
            }
        });
        return;
    }

    setStatus("جاري إنشاء المرتجع (مسودة)...", "info");
    try {
      const inserted = await erpRequest("/api/resource/Sales Invoice", {
        method: "POST",
        body: JSON.stringify(doc)
      });
      const createdName = inserted?.data?.name;
      if (!createdName) throw new Error("Insert failed");

      lastCreatedReturnName = createdName;
      setStatus(`✅ تم إنشاء المرتجع كمسودة: ${createdName}`, "ok");
      if (el("retPrint")) el("retPrint").disabled = false;

      selectedInvoiceName = "";
      invoiceDoc = null;
      invoiceItemMap = {};
      if (el("retInvoiceInput")) el("retInvoiceInput").value = "";
      cart = [];
      renderCart();
      el("retRemarks").value = "";
      busy = false;

      fetchRecentReturns(false);

    } catch (e) {
      console.error(e);
      busy = false;
      const msg = extractServerError(e, e?._raw);
      setStatus(msg, "error");
      try { frappe.msgprint({ title: "خطأ", indicator: "red", message: msg }); } catch(_) {}
    }
  }

  function openReturnPDF(){
    if (!lastCreatedReturnName) return setStatus("أنشئ المرتجع أولاً", "warn");
    const url = `/api/method/frappe.utils.print_format.download_pdf?doctype=Sales Invoice&name=${encodeURIComponent(lastCreatedReturnName)}&format=${encodeURIComponent(RETURN_PRINT_FORMAT)}&no_letterhead=0`;
    window.open(url, "_blank");
  }

  function resetAll(){
    VIEW_ONLY_MODE = false;
    selectedCustomerName = ""; selectedCustomerId = ""; selectedInvoiceName = "";
    invoiceDoc = null; invoiceItemMap = {}; cart = [];
    el("retCustomerInput").value = ""; el("retInvoiceInput").value = "";
    clearPickedItem(); el("retRemarks").value = ""; setStatus("");

    EDITING_RETURN_NAME = null;

    // Restore UI for Editing/Creating
    el("topbarTitle").textContent = "المرتجعات";
    el("retCreate").style.display = "block";
