  // TRIGGER A FRESH FORM
  window.startNewReturn = function() {
    resetAll();
    setStatus("تم فتح نموذج مرتجع جديد", "info");
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // PAGINATION API INTEGRATION
  window.fetchRecentReturns = function(append = false) {
    const listContainer = el("retRecentList");
    const btnMore = el("btnLoadMoreReturns");
    if (!listContainer) return;

    if (!append) {
        currentReturnOffset = 0;
        listContainer.innerHTML = '<div class="ret-empty">جاري التحميل...</div>';
        if (btnMore) btnMore.style.display = "none";
    } else {
        if (btnMore) btnMore.innerHTML = "جاري التحميل...";
    }

    if (window.frappe) {
        frappe.call({
            method: "sr_get_recent_returns_24",
            args: {
                offset: currentReturnOffset,
                limit: RETURNS_LIMIT
            },
            callback: function(r) {
                if (r.message && r.message.status === "success") {
                    const data = r.message.data;
                    renderRecentReturns(data, append);

                    currentReturnOffset += data.length;

                    if (btnMore) {
                        if (data.length === RETURNS_LIMIT) {
                            btnMore.style.display = "block";
                            btnMore.innerHTML = "عرض المزيد 🔽";
                        } else {
                            btnMore.style.display = "none";
                        }
                    }
                } else {
                    if (!append) listContainer.innerHTML = '<div class="ret-empty">تعذر تحميل القائمة</div>';
                    if (btnMore) btnMore.innerHTML = "عرض المزيد 🔽";
                }
            }
        });
    }
  };

  function renderRecentReturns(data, append) {
    const container = el("retRecentList");

    if (!append && (!data || data.length === 0)) {
        container.innerHTML = '<div class="ret-empty">لا توجد مرتجعات سابقة</div>';
        return;
    }

    let html = "";
    data.forEach(d => {
        let statusBadge = "";
        let btnAction = "";

        if (d.docstatus === 0) {
            statusBadge = '<span style="background:#fef08a; color:#854d0e; padding:2px 8px; border-radius:12px; font-size:11px; font-weight:900;">مسودة</span>';
            // false = isEdit
            btnAction = `<button class="sr-btn" style="padding:4px 12px; font-size:12px;" onclick="loadReturnDocument('${d.name}', false)">تعديل ✏️</button>`;
        } else if (d.docstatus === 1) {
            statusBadge = '<span style="background:#bbf7d0; color:#166534; padding:2px 8px; border-radius:12px; font-size:11px; font-weight:900;">معتمد</span>';
            // true = isViewOnly
            btnAction = `<button class="sr-btn" style="padding:4px 12px; font-size:12px;" onclick="loadReturnDocument('${d.name}', true)">عرض 👁️</button>`;
        } else {
            statusBadge = '<span style="background:#fecaca; color:#991b1b; padding:2px 8px; border-radius:12px; font-size:11px; font-weight:900;">ملغي</span>';
            // true = isViewOnly
            btnAction = `<button class="sr-btn" style="padding:4px 12px; font-size:12px;" onclick="loadReturnDocument('${d.name}', true)">عرض 👁️</button>`;
        }

        html += `
        <div class="ret-item" style="margin-bottom:10px; padding: 12px !important;">
            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;">
                <span style="font-weight:900; font-size:13px;">${d.name}</span>
                ${statusBadge}
            </div>
            <div style="font-size:11px; color:#666; margin-bottom:8px; opacity:0.8;">${d.customer_name || 'غير محدد'} | ${d.posting_date || ''}</div>
            <div style="display:flex; justify-content:space-between; align-items:center;">
                <span style="font-weight:900; color:var(--green); font-size:14px;">${Number(d.grand_total).toFixed(2)} د.ل</span>
                ${btnAction}
            </div>
        </div>`;
    });

    if (append) {
        if (container.querySelector('.ret-empty')) {
            container.innerHTML = html;
        } else {
            container.insertAdjacentHTML('beforeend', html);
        }
    } else {
        container.innerHTML = html;
    }
  }

  // UNIFIED IN-PAGE LOADER (Handles both Edit and Read-Only View)
  window.loadReturnDocument = function(name, isReadOnly) {
    VIEW_ONLY_MODE = isReadOnly;
    setStatus(isReadOnly ? "جاري تحميل المرتجع للعرض..." : "جاري تحميل المسودة للتعديل...", "info");
    window.scrollTo({ top: 0, behavior: 'smooth' });

    frappe.call({
        method: "sr_get_return_doc_24",
        args: { name: name },
        callback: function(r) {
            if (r.message && r.message.status === "success") {
                const doc = r.message.doc;

                // 1. FIRST process the mode so it clears whatever it needs to clear
                if (doc.return_against) {
                    setMode("against_invoice");
                    selectedInvoiceName = doc.return_against;
                    el("retInvoiceInput").value = selectedInvoiceName;
                    loadInvoiceAndBuildItemMap(selectedInvoiceName, true); // true = keep cart
                } else {
                    setMode("no_invoice");
                }

                // 2. NOW assign our specific document variables (so setMode doesn't wipe them)
                EDITING_RETURN_NAME = doc.name;
                lastCreatedReturnName = doc.name; // Critical for PDF to work!

                selectedCustomerId = doc.customer;
                selectedCustomerName = doc.customer_name;
                el("retCustomerInput").value = selectedCustomerName;
                el("retRemarks").value = doc.remarks || "";

                // 3. Toggle UI based on Read-Only Mode
                if (VIEW_ONLY_MODE) {
                    el("topbarTitle").textContent = "عرض: " + doc.name;
                    el("retCreate").style.display = "none"; // Hide Save button
                    el("retAddItemContainer").style.display = "none"; // Hide entire add item block
                    el("retChooseCustomer").style.display = "none";
                    el("retChooseInvoice").style.display = "none";
                    el("retRemarks").disabled = true;
                    el("retMode").style.pointerEvents = "none";
                    el("retMode").style.opacity = "0.6";
                    el("retReset").textContent = "إغلاق العرض";

                    // Unlock the print button
                    if (el("retPrint")) {
                        el("retPrint").disabled = false;
                        el("retPrint").removeAttribute("disabled");
                    }
                } else {
                    el("topbarTitle").textContent = "تحديث: " + doc.name;
                    el("retCreate").style.display = "block";
                    el("retCreate").textContent = "تحديث المسودة: " + doc.name;
                    el("retAddItemContainer").style.display = "block";
                    el("retChooseCustomer").style.display = "block";
                    el("retChooseInvoice").style.display = "block";
                    el("retRemarks").disabled = false;
                    el("retMode").style.pointerEvents = "auto";
                    el("retMode").style.opacity = "1";
                    el("retReset").textContent = "إلغاء";

                    // Unlock the print button for Edit mode too since it's a saved draft
                    if (el("retPrint")) {
                        el("retPrint").disabled = false;
                        el("retPrint").removeAttribute("disabled");
                    }
                }

                // 4. Reconstruct the cart array
                cart = doc.items.map(it => {
                    let code = it.item_code;
                    return {
                        item_code: code,
                        label: itemLabelByCode[code] || code,
                        item_name: it.item_name || "",
                        uom: it.uom || "",
                        qty_pos: Math.abs(it.qty),
                        rate: it.rate,
                        batch_no: it.batch_no || "",
                        sales_invoice_item: it.sales_invoice_item || null,
                        delivery_note: it.delivery_note || null,
                        dn_detail: it.dn_detail || null,
                        allow_rate_edit: true,
                        price_list_rate: it.price_list_rate || it.rate || 0,
                        discount_percentage: it.discount_percentage || 0,
                        item_discount_amount: it.discount_amount || 0
                    };
                });

                renderCart();
                setStatus(isReadOnly ? "المرتجع في وضع العرض فقط (Read Only)." : "تم تحميل المسودة للتعديل.", "ok");
            } else {
                setStatus("حدث خطأ أثناء تحميل المرتجع", "error");
            }
        }
    });
  }

  function bind(){
    el("retMode").addEventListener("click", function(e){
      if (VIEW_ONLY_MODE) return;
      const b = e.target.closest(".ret-seg-btn");
      if (!b) return;
      setMode(b.getAttribute("data-mode"));
    });

    el("retChooseCustomer").onclick = openCustomerModal;
    el("retCustomerInput").onclick = openCustomerModal;
    el("retCloseCustomerModal").onclick = closeCustomerModal;

    el("retChooseInvoice").onclick = openInvoiceModal;
    el("retInvoiceInput").onclick = openInvoiceModal;
    el("retCloseInvoiceModal").onclick = closeInvoiceModal;

    el("retChooseItem").onclick = openItemModal;
    el("retItemLabel").onclick = openItemModal;
    el("retCloseItemModal").onclick = closeItemModal;

    el("retAddItem").onclick = addPickedItemToCart;

    el("retItems").addEventListener("input", function(e){
      if (VIEW_ONLY_MODE) return;
      const inp = e.target.closest(".inp");
      if (!inp) return;
      const idx = Number(inp.getAttribute("data-idx"));
      const field = inp.getAttribute("data-field");
      const val = Number(inp.value || 0);
      if (!cart[idx]) return;
      cart[idx][field] = val;

      // If user starts editing an existing draft, lock the print button until they save
      if (EDITING_RETURN_NAME) {
          lastCreatedReturnName = "";
          if (el("retPrint")) el("retPrint").disabled = true;
      }
    });

    el("retItems").addEventListener("click", function(e){
      if (VIEW_ONLY_MODE) return;
      const rm = e.target.closest(".btn-remove");
      if (!rm) return;
      const idx = Number(rm.getAttribute("data-idx"));
      cart.splice(idx, 1);
      renderCart();

      // If user deletes an item from an existing draft, lock the print button until they save
      if (EDITING_RETURN_NAME) {
          lastCreatedReturnName = "";
          if (el("retPrint")) el("retPrint").disabled = true;
      }
    });

    el("retCreate").onclick = createReturnDraft;
    el("retPrint").onclick = openReturnPDF;
    el("retReset").onclick = resetAll;

    setMode("against_invoice");
    renderCart();
    setStatus("", "");
  }

  (async function init(){
    try {
      await loadDefaultsAndUser();
      await loadCustomersFiltered();
      await loadAllItemsMaster();
      await loadWarehouseItems();
      bind();
      fetchRecentReturns(false);
    } catch (e) {
      console.error(e);
      const msg = extractServerError(e, e?._raw);
      setStatus(msg || "خطأ أثناء تحميل البيانات", "error");
    }
  })();

})();

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');

/* --- System Reset --- */
footer, .web-footer, .navbar, .page-breadcrumbs, header.navbar { display: none !important; }

:root { 
    --bg: #bfeaf4; 
    --yellow: #ffd23c; 
    --yellow2: #ffe26b; 
    --green: #2f8f3a; 
    --shadow: 0 10px 30px rgba(0,0,0,.08); 
    --panel: rgba(255, 255, 255, 0.4);
}

body { 
    direction: rtl; 
    background-color: var(--bg) !important; 
    font-family: "Cairo", sans-serif !important; 
    margin: 0; 
    color: #0b1b22;
}

/* --- Topbar Fix --- */
.sr-topbar { 
    position: sticky; top: 0; z-index: 1100; 
    display: flex !important;
    flex-direction: row !important; 
    justify-content: space-between !important; 
    align-items: center !important; 
    padding: 10px 15px !important; 
    background: var(--panel) !important; 
    border-bottom: 1px solid rgba(0, 0, 0, 0.1) !important; 
    backdrop-filter: blur(10px); 
    height: 60px;
    width: 100% !important;
    box-sizing: border-box !important;
    direction: ltr !important; 
}

/* Ensure the title stays on the right and keeps Arabic text direction */
.sr-title { 
    font-weight: 900; 
    font-size: 16px; 
    flex: none !important; 
    text-align: right !important; 
    direction: rtl !important; 
}

/* Group the buttons together on the left */
.sr-btn-icon-group { 
    display: flex !important; 
    gap: 8px !important; 
    flex: none !important;
}

.sr-btn-icon { 
    border: 1px solid rgba(0,0,0,0.2); cursor: pointer; border-radius: 999px; 
    padding: 8px 12px; font-weight: 900; background: var(--yellow2); box-shadow: var(--shadow); color: #0b1b22;
}

/* --- Containers --- */
.sr-wrap { max-width: 900px; margin: 0 auto; padding: 15px; }
.ret-card { 
    background: var(--panel) !important; 
    border: 1px solid rgba(0,0,0,0.1) !important; 
    border-radius: 20px; padding: 15px; box-shadow: var(--shadow); 
}
.ret-mt12 { margin-top: 12px; }

/* --- Inputs & Pills --- */
.wh-label { display: block; margin-bottom: 6px; font-size: 13px; font-weight: 900; color: #0b1b22; text-align: right; padding-right: 10px; }
.sr-pill { 
    background: var(--yellow); border: 1px solid rgba(0,0,0,0.15); 
    border-radius: 999px; padding: 4px 16px; display: flex; align-items: center; box-shadow: var(--shadow);
}
.sr-input-transparent {
    flex: 1; border: none !important; background: transparent !important; 
    font-family: Cairo !important; font-weight: 800; font-size: 14px; 
    outline: none; height: 38px; color: #0b1b22;
}
.ret-mini-hint { font-size: 11px; font-weight: 700; color: #0b1b22; opacity: 0.6; margin-top: 4px; padding-right: 15px; }

/* --- Buttons --- */
.sr-btn { 
    border: 1px solid rgba(0,0,0,0.2); cursor: pointer; border-radius: 999px; 
    padding: 12px 20px; font-family: "Cairo"; font-weight: 900; 
    background: #fff; color: #0b1b22; box-shadow: var(--shadow); flex: 1;
}
.sr-btn.primary { background: var(--yellow2); }
.ret-actions { display: flex; gap: 10px; }

/* --- Metric Card --- */
.ret-metric { 
    background-color: var(--green) !important;
    border-radius: 20px !important;
    padding: 25px !important;
    text-align: center !important;
    color: #ffffff !important;
    border: none !important;
}
.ret-metric #totalVal,
.ret-metric .ret-title,
.ret-metric #countVal {
    color: #ffffff !important;
}

/* --- Status --- */
.ret-status { padding: 12px 14px; border-radius: 14px; font-weight: 900; }
.ret-status.info { background: rgba(2,132,199,0.15); border:1px solid rgba(2,132,199,0.25); }
.ret-status.ok { background: rgba(16,185,129,0.15); border:1px solid rgba(16,185,129,0.25); }
.ret-status.warn { background: rgba(245,158,11,0.15); border:1px solid rgba(245,158,11,0.25); }
.ret-status.error { background: rgba(239,68,68,0.15); border:1px solid rgba(239,68,68,0.25); }

/* --- List Items --- */
.ret-item { 
    background: var(--panel) !important;
    border: 1px solid rgba(0,0,0,0.08) !important; 
    border-radius: 20px !important;
    padding: 18px !important;
    margin-top: 12px; 
    margin-bottom: 15px !important;
    box-shadow: 0 8px 20px rgba(0,0,0,0.06) !important;
}
.ret-item-title { font-weight: 900; font-size: 14px; color: #0b1b22; }
.cash-border { border-right: 8px solid var(--green) !important; }
.cheque-border { border-right: 8px solid #0288d1 !important; }

.account-pill {
    display: inline-block; padding: 4px 10px; border-radius: 999px;
    background: var(--bg); border: 1px solid rgba(0,0,0,0.1);
    color: #0b1b22; font-weight: 800; font-size: 11px;
}

/* --- Modals --- */
.modal-overlay { 
    position: fixed; inset: 0; background: rgba(0,0,0,0.4); 
    display: flex; justify-content: center; align-items: flex-start !important; 
    padding-top: 0 !important; z-index: 2000; backdrop-filter: blur(4px); 
}
.select-list-box { 
    background: var(--bg); width: 100%; height: 100vh !important; 
    margin-top: 0 !important; border-radius: 0 0 24px 24px; padding: 15px; 
    display: flex; flex-direction: column; overflow: hidden; 
}
.select-list-scroller { flex: 1; overflow-y: auto; padding: 10px 0; }
.modal-btn-cancel { text-align: center; margin-top: 15px; color: #666; font-weight: 700; cursor: pointer; }

/* Modal Rows */
.ret-modal-list div, .ret-pick-row { 
    background: var(--yellow); margin-bottom: 8px; border-radius: 999px; 
    padding: 12px 18px; font-weight: 800; border: 1px solid rgba(0,0,0,0.1); 
    display: flex; align-items: center; justify-content: space-between; 
}

.hidden { display: none !important; }
.ret-empty { padding: 30px; text-align: center; font-weight: 800; opacity: 0.5; }

@media (max-width: 640px) { .ret-grid2 { grid-template-columns: 1fr; } }

/* --- Collection list buttons --- */
#collectionList .ret-item .ret-actions,
#collectionList .ret-item div[style*="display: flex"],
#collectionList .ret-actions {
    display: flex !important;
    gap: 12px !important;
    margin-top: 15px !important;
    width: 100% !important;
}

#collectionList .ret-item button,
#collectionList .ret-item .ret-btn,
#collectionList .ret-btn {
    flex: 1 !important;
    background-color: var(--green) !important;
    color: #ffffff !important;
    border: none !important;
    border-radius: 999px !important;
    padding: 12px 18px !important;
    font-family: 'Cairo', sans-serif !important;
    font-weight: 900 !important;
    font-size: 14px !important;
    cursor: pointer !important;
    box-shadow: 0 4px 12px rgba(47, 143, 58, 0.2) !important;
    transition: all 0.2s ease !important;
}
#collectionList .ret-item button:active {
    transform: scale(0.97) !important;
    filter: brightness(0.9) !important;
}
#collectionList .ret-item button:nth-child(2) { opacity: 0.9 !important; }
#collectionList .ret-item .btn-download {
  background-color: #ef4444 !important;
  box-shadow: 0 4px 12px rgba(239,68,68,0.18) !important;
}

