// ================= CONFIG =================
  const ERPNEXT_BASE_URL = window.location.origin;

  // Current filter state
  let selectedEmployeeId = "";
  let selectedEmployeeLabel = "الكل";

  // Modal temp selection
  let pendingPickId = "";
  let pendingPickLabel = "";

  // Employee master list: [{id,label,email}]
  let employeeList = [];
  let emailToName = {};

  // ============= API HELPERS =============
  function getCsrfToken() {
    if (window.frappe && frappe.csrf_token) return frappe.csrf_token;
    const meta = document.querySelector('meta[name="csrf-token"]');
    return (meta && meta.content) ? meta.content : (window.CSRF_TOKEN || null);
  }

  async function erpRequest(path, options = {}) {
    const headers = Object.assign({}, options.headers || {});
    const method = (options.method || "GET").toUpperCase();

    if (method !== "GET") {
      headers["Content-Type"] = "application/json";
      headers["X-Frappe-CSRF-Token"] = getCsrfToken();
    }

    const url = path.startsWith("http") ? path : (ERPNEXT_BASE_URL + path);
    const resp = await fetch(url, Object.assign({}, options, {
      headers,
      credentials: "include"
    }));

    const txt = await resp.text();
    let data;
    try { data = JSON.parse(txt); } catch { data = txt; }

    if (!resp.ok) {
      let msg = resp.statusText;
      if (data && typeof data === "object") {
        msg = data.exception || data.message || data._server_messages || resp.statusText;
      }
      throw new Error(msg);
    }

    return data;
  }

  function esc(s) {
    if (window.frappe && frappe.utils && frappe.utils.escape_html) {
      return frappe.utils.escape_html(s == null ? "" : String(s));
    }
    return (s == null ? "" : String(s)).replace(/[&<>"']/g, c => ({
      "&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"
    }[c]));
  }

  function fmtCurrency(amt) {
    const n = Number(amt || 0);
    if (window.format_currency) return window.format_currency(n, "LYD");
    return n.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + " LYD";
  }

  // ============= STATUS BOX =============
  function showStatus(type, msg) {
    const box = document.getElementById("statusBox");
    box.className = "ret-status ret-mt12 " + (type || "info");
    box.style.display = "block";
    box.textContent = msg || "";
  }
  function hideStatus() {
    const box = document.getElementById("statusBox");
    box.style.display = "none";
    box.textContent = "";
  }

  // ============= FILTER HELPERS =============
  function setHints() {
    const pt = document.getElementById("typeSelect").value || "";
    document.getElementById("typeHint").textContent = pt ? pt : "الكل";

    const emp = selectedEmployeeLabel || "الكل";
    document.getElementById("employeeHint").textContent = emp;
    document.getElementById("employeePickerText").textContent = emp;
  }

  function getFilters() {
    return {
      employee: selectedEmployeeId || "",
      payment_type: document.getElementById("typeSelect").value || ""
    };
  }

  // ============= EMPLOYEE MODAL =============
  function openEmployeeModal() {
    pendingPickId = selectedEmployeeId;
    pendingPickLabel = selectedEmployeeLabel;

    document.getElementById("employeeSearch").value = "";
    renderEmployeeList(employeeList);
    document.getElementById("employeeModal").classList.remove("hidden");
    document.getElementById("employeeSearch").focus();
  }

  function closeEmployeeModal() {
    document.getElementById("employeeModal").classList.add("hidden");
  }

  function renderEmployeeList(list) {
    const scroller = document.getElementById("employeeScroller");
    scroller.innerHTML = "";

    if (!list.length) {
      scroller.innerHTML = `<div class="ret-empty" style="margin:6px;">لا يوجد بيانات</div>`;
      return;
    }

    list.forEach(emp => {
      const row = document.createElement("div");
      row.className = "ret-pick-row";

      const isActive = (pendingPickId === emp.id);
      row.style.borderColor = isActive ? "#cfe2ff" : "#eee";
      row.style.background = isActive ? "#f2f7ff" : "#fff";

      row.innerHTML = `
        <div style="font-weight:800;">${esc(emp.label)}</div>
        <div style="font-size:11px; opacity:.65; margin-top:2px;">${esc(emp.id)}</div>
      `;

      row.onclick = () => {
        selectedEmployeeId = emp.id;
        selectedEmployeeLabel = emp.label;
        closeEmployeeModal();
        setHints();
        refreshList();
      };

      scroller.appendChild(row);
    });
  }

  async function loadEmployeesOnce() {
    const r = await erpRequest("/api/method/get_active_employees_for_filter", {
      method: "POST",
      body: JSON.stringify({})
    });

    const rows = (r.message || []);
    employeeList = rows.map(x => ({
      id: x.name,
      label: x.employee_name ? x.employee_name : x.name,
      email: x.user_id
    }));

    emailToName = {};
    employeeList.forEach(e => {
      if (e.email) emailToName[e.email] = e.label;
    });
  }

  // ============= PDF DOWNLOAD (iOS safe) =============
  async function downloadDebtPdf(docname, btnEl) {
    if (!docname) return;

    const url =
      `/api/method/frappe.utils.print_format.download_pdf?doctype=${encodeURIComponent("LMT Debt Collection")}` +
      `&name=${encodeURIComponent(docname)}` +
      `&format=${encodeURIComponent("Standard")}` +
      `&no_letterhead=0&_t=${Date.now()}`;

    const oldTxt = btnEl ? btnEl.textContent : "";
    try {
      if (btnEl) { btnEl.disabled = true; btnEl.textContent = "..."; }
      showStatus("info", "⬇️ جاري تنزيل PDF ...");

      const res = await fetch(url, {
        method: "GET",
        headers: { "X-Frappe-CSRF-Token": getCsrfToken() || "" },
        credentials: "include"
      });

      if (!res.ok) throw new Error("PDF fetch failed");

      const blob = await res.blob();
      const blobUrl = URL.createObjectURL(blob);

      const a = document.createElement("a");
      a.href = blobUrl;
      a.download = `${docname}.pdf`;
      document.body.appendChild(a);
      a.click();
      a.remove();

      setTimeout(() => URL.revokeObjectURL(blobUrl), 2000);
      showStatus("ok", "✅ تم تنزيل PDF");
    } catch (e) {
      console.error(e);
      showStatus("error", "❌ فشل تنزيل PDF");
      window.location.href = url;
    } finally {
      if (btnEl) { btnEl.disabled = false; btnEl.textContent = oldTxt; }
    }
  }

  // ============= LIST RENDER =============
  function renderEntries(entries) {
    const list = document.getElementById("collectionList");
    const empty = document.getElementById("emptyState");

    list.innerHTML = "";
    empty.classList.add("hidden");

    if (!entries || !entries.length) {
      empty.classList.remove("hidden");
      return;
    }

    entries.forEach(d => {

      if (d.action_type === "خصم تسوية") return;

      const borderClass = (d.payment_type === "نقد") ? "cash-border" : "cheque-border";
      const bank = d.bank ? d.bank : "غير محدد";
      const receipt = d.receipt_no ? ` | واصل: ${esc(d.receipt_no)}` : "";

      const isDraw = (d.action_type === "سحب");
      const agentDisplay = emailToName[d.agent_name] || d.agent_name;
      const typeLabel = isDraw ? "سحب (Draw)" : "تحصيل (Collect)";
      const typeColor = isDraw ? "#d32f2f" : "#2e7d32";

      let displayName = esc(d.customer);
      if (!d.customer || d.customer === "بدون اسم") {
        displayName = `<span style="color:#555; font-weight:600;">👤 ${esc(d.agent_name)}</span>`;
      }

      const item = document.createElement("div");
      item.className = `ret-item ${borderClass}`;
      item.innerHTML = `
        <div class="ret-item-title" style="display:flex; justify-content:space-between; align-items:center;">
          <div style="display:flex; align-items:center; gap:8px;">
            <span style="font-size:10px; color:${typeColor}; border:1px solid ${typeColor}; padding:2px 6px; border-radius:4px; font-weight:bold;">
              ${typeLabel}
            </span>
            <span>${displayName}</span>
          </div>
          <span style="font-weight:900;">${fmtCurrency(d.amount)}</span>
        </div>

        <div class="ret-item-sub">
          ${esc(d.payment_type || "")} | ${esc(d.name)}${receipt}
        </div>

        <div class="ret-item-sub" style="margin-top:4px;">
          👤 ${esc(agentDisplay)}
        </div>

        <div class="ret-mini-hint" style="margin-top:6px;">
          <span class="account-pill">الحساب: ${esc(bank)}</span>
        </div>

        <div class="ret-actions ret-mt10">
          <button class="ret-btn ret-small btn-download" type="button" data-name="${esc(d.name)}">تحميل/معاينة PDF</button>
          <button class="ret-btn ret-primary ret-small btn-verify" type="button" data-name="${esc(d.name)}">اعتماد وقفل</button>
        </div>
      `;
      list.appendChild(item);
    });

    list.querySelectorAll(".btn-verify").forEach(btn => {
      btn.onclick = () => verifyAndLock(btn.getAttribute("data-name"), btn);
    });

    list.querySelectorAll(".btn-download").forEach(btn => {
      btn.onclick = () => downloadDebtPdf(btn.getAttribute("data-name"), btn);
    });
  }

  // ============= DATA LOAD =============
  async function refreshList() {
    setHints();
    hideStatus();

    const list = document.getElementById("collectionList");
    const totalVal = document.getElementById("totalVal");
    const countVal = document.getElementById("countVal");

    list.innerHTML = `<div class="ret-empty">جاري التحميل...</div>`;
    totalVal.textContent = "0.00";
    countVal.textContent = "0 سجلات";

    try {
      const filters = getFilters();

      const r = await erpRequest("/api/method/get_collection_staging_data_qa", {
        method: "POST",
        body: JSON.stringify({
          employee: filters.employee || "",
          payment_type: filters.payment_type || ""
        })
      });

      const msg = r.message || {};
      const entries = msg.entries || [];
      const total = (msg.totals && msg.totals.total) || 0;

      totalVal.textContent = fmtCurrency(total);
      countVal.textContent = `${entries.length} سجلات`;

      renderEntries(entries);

    } catch (e) {
      console.error(e);
      showStatus("error", "خطأ: " + (e.message || "Unknown"));
      list.innerHTML = `<div class="ret-empty">تعذر تحميل البيانات</div>`;
    }
  }

  // ============= VERIFY AND LOCK =============
  async function verifyAndLock(docname, btnEl) {
    if (!docname) return;
    if (!window.confirm("ترحيل القيد وقفل السجل؟")) return;

    const oldTxt = btnEl.textContent;
    btnEl.disabled = true;
    btnEl.textContent = "...";

    try {
      const r = await erpRequest("/api/method/verify_collection_api_qa", {
        method: "POST",
        body: JSON.stringify({ docname })
      });

      const msg = r.message || {};
      let statusMsg = "✅ تم الترحيل"
        + (msg.journal_entry ? (" | JE: " + msg.journal_entry) : "")
        + (msg.settlement_journal_entry ? (" | Settlement: " + msg.settlement_journal_entry) : "");

      showStatus("ok", statusMsg);
      await refreshList();

    } catch (e) {
      console.error(e);
      showStatus("error", "❌ فشل: " + (e.message || "Unknown"));
    } finally {
      btnEl.disabled = false;
      btnEl.textContent = oldTxt;
    }
  }

  // ============= INIT =============
  document.addEventListener("DOMContentLoaded", async () => {
    document.getElementById("typeSelect").addEventListener("change", refreshList);
    document.getElementById("btnRefresh").onclick = refreshList;

    document.getElementById("btnClearFilters").onclick = () => {
      selectedEmployeeId = "";
      selectedEmployeeLabel = "الكل";
      document.getElementById("typeSelect").value = "";
      setHints();
      refreshList();
    };

    document.getElementById("btnPickEmployee").onclick = openEmployeeModal;
    document.getElementById("btnEmployeeClose").onclick = closeEmployeeModal;

    document.getElementById("employeeModal").addEventListener("click", (e) => {
      if (e.target && e.target.id === "employeeModal") closeEmployeeModal();
    });

    document.getElementById("btnEmployeeAll").onclick = () => {
      pendingPickId = "";
      pendingPickLabel = "الكل";
      renderEmployeeList(employeeList);
    };

    document.getElementById("btnEmployeeDone").onclick = () => {
      selectedEmployeeId = pendingPickId || "";
      selectedEmployeeLabel = pendingPickLabel || "الكل";
      closeEmployeeModal();
      setHints();
      refreshList();
    };

    document.getElementById("employeeSearch").oninput = (e) => {
      const q = (e.target.value || "").trim().toLowerCase();
      if (!q) return renderEmployeeList(employeeList);

      const filtered = employeeList.filter(x =>
        (x.label || "").toLowerCase().includes(q) ||
        (x.id || "").toLowerCase().includes(q)
      );
      renderEmployeeList(filtered);
    };

    setHints();

    try {
      await loadEmployeesOnce();
    } catch (e) {
      console.error("Employee load error", e);
      showStatus("warn", "⚠️ لم يتم تحميل قائمة المندوبين (تحقق من Server Script get_active_employees_for_filter).");
    }

    refreshList();
  });

