@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');
@import url("/assets/libyan_modern_trading/css/lmt_vars.css");

:root {
    --bg-main: #bfeaf4; --card: rgba(255,255,255,0.4); --line: rgba(0,0,0,0.15);
    --text: #0b1b22; --primary-blue: #004b80; --yellow: #ffd23c; --yellow-light: #ffe26b;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
}
body, .page-container, .layout-main-section, .content, .page-content, .main-section, .appshell { background-color: var(--bg-main) !important; font-family:"Cairo",sans-serif !important; }
header.navbar, .page-head, .standard-sidebar, .sticky-header { display:none !important; }
.layout-main-section { padding-top:0 !important; margin-top:0 !important; }
* { box-sizing:border-box; }
.wrap { max-width:820px; margin:0 auto; padding:80px 16px 40px 16px; }
.lmt-topbar { position:fixed; top:0; left:0; right:0; height:60px; background-color:var(--bg-main) !important; border-bottom:1px solid var(--line); display:flex; align-items:center; padding:0 16px; gap:10px; z-index:100; direction:ltr; }
.icon-btn { background:var(--yellow-light); border:1px solid var(--line); border-radius:999px; padding:8px 14px; font-size:16px; cursor:pointer; box-shadow:var(--shadow); font-family:"Cairo",sans-serif; font-weight:900; }
.card { background:var(--card); border:1px solid var(--line); border-radius:14px; padding:20px; margin-bottom:20px; box-shadow:var(--shadow); backdrop-filter:blur(6px); direction:rtl; }
.grid2 { display:grid; grid-template-columns:1fr 1fr; gap:16px; }
.grid3 { display:grid; grid-template-columns:1fr 1fr 1fr; gap:16px; }
.h1 { font-size:22px; font-weight:900; color:var(--text); margin-bottom:4px; }
.h2 { font-size:18px; font-weight:800; margin-bottom:12px; color:var(--text); }
.muted { font-size:13px; opacity:0.6; font-weight:700; }
label { display:block; font-size:13px; color:var(--text); margin-bottom:6px; font-weight:900; }
input, select { width:100%; padding:12px 15px; border:1px solid var(--line); border-radius:999px; background:var(--yellow-light); font-weight:700; text-align:right; outline:none; box-shadow:var(--shadow); color:var(--text); font-family:"Cairo",sans-serif !important; }
button { padding:12px 24px; border:1px solid rgba(0,0,0,0.2); border-radius:999px; background:var(--yellow); color:var(--text); font-weight:900; cursor:pointer; box-shadow:var(--shadow); transition:transform 0.2s; font-family:"Cairo",sans-serif !important; }
button:active { transform:scale(0.95); }
.action-btn { width:100%; height:42px; display:flex; align-items:center; justify-content:center; border-radius:12px !important; border:none; font-weight:600; font-size:13px; color:white; cursor:pointer; box-shadow:var(--shadow); transition:transform 0.2s; font-family:"Cairo",sans-serif; }
.action-btn:active { transform:scale(0.95); }
.action-btn.indigo { background:#6366f1; }
.action-btn.purple { background:#8b5cf6; }
.action-btn.orange { background:#f59e0b; }
.action-btn.red    { background:#ef4444; }
.flex-sb { display:flex; justify-content:space-between; align-items:center; }
.pill { padding:4px 12px; border-radius:999px; font-size:12px; font-weight:900; color:#fff; }
.pill.Closed { background-color:#ef4444; }
.pill.Active  { background-color:#10b981; }
#msg { display:none; padding:14px; background:var(--primary-blue); color:#fff; text-align:center; border-radius:12px; margin-bottom:16px; font-weight:900; }
footer, .footer-subscribe, .web-footer { display:none !important; }
body { background-color:#d1e9ff !important; min-height:100vh; }
.modal-content { background-color:var(--bg-main) !important; border-radius:14px !important; border:1px solid var(--line) !important; box-shadow:var(--shadow) !important; color:var(--text) !important; font-family:"Cairo",sans-serif !important; direction:rtl !important; }
.modal-header  { border-bottom:1px solid var(--line) !important; background-color:transparent !important; }
.modal-title   { font-weight:900 !important; color:var(--text) !important; }
.modal-body    { font-weight:700 !important; color:var(--text) !important; }
.modal-footer  { border-top:1px solid var(--line) !important; background-color:transparent !important; }
.modal-footer .btn         { padding:10px 24px !important; border-radius:999px !important; font-family:"Cairo",sans-serif !important; font-weight:900 !important; box-shadow:var(--shadow) !important; border:1px solid rgba(0,0,0,0.2) !important; }
.modal-footer .btn-primary { background-color:var(--yellow) !important; color:var(--text) !important; }
.modal-footer .btn-default { background-color:var(--yellow-light) !important; color:var(--text) !important; }
.modal-footer .btn:active  { transform:scale(0.95) !important; }

