frappe.ready(function() {

    $('body').off('click','#btnDelete').on('click','#btnDelete', function() {
        frappe.confirm('Are you sure? This will delete ALL Process Payment Reconciliation records.', function() {
            handleEngineAction('delete_all');
        });
    });

    $('body').off('click','#btnResetCursor').on('click','#btnResetCursor', function() {
        frappe.confirm('Reset GL cursor? Next run will re-scan all GL entries from the beginning.', function() {
            handleEngineAction('reset_cursor');
        });
    });

    $('body').off('click','#btnRefreshMain').on('click','#btnRefreshMain', function() { loadData(); });
    $('body').off('click','#btnSave').on('click','#btnSave', function() { saveData(); });
    $('body').off('click','#btnStop').on('click','#btnStop', function() { emergencyControl('stop'); });
    $('body').off('click','#btnStart').on('click','#btnStart', function() { emergencyControl('start'); });
    $('body').off('click','#btnSeed').on('click','#btnSeed', function() { handleEngineAction('seed'); });
    $('body').off('click','#btnAutoCreate').on('click','#btnAutoCreate', function() { handleEngineAction('auto_create'); });
    $('body').off('click','#btnRunNow').on('click','#btnRunNow', function() { runEngineNow(); });

    loadData();
});

function loadData() {
    var btn = $('#btnRefreshMain');
    btn.css('opacity', 0.5);
    frappe.call({
        method: 'payment_control_api_15',
        args: { action: 'get_status' },
        callback: function(r) {
            btn.css('opacity', 1);
            var d = r.data || r.message;
            if (!d) return;
            $('#confAuto').val(d.auto);
            $('#confType').val(d.type);
            $('#confQueue').val(d.queue);
            $('#confTrigger').val(d.trigger);
            $('#pendingCount').text(d.pending_ppr != null ? d.pending_ppr : '-');
            $('#submittedCount').text(d.submitted_ppr != null ? d.submitted_ppr : '-');
            $('#glCursor').text(d.gl_cursor || 'Not set');
            var lr = d.sched_last_run || d.last_run;
            $('#lastCheck').text(lr ? frappe.datetime.str_to_user(lr) : 'Never Run');
            if (parseInt(d.auto) === 1) {
                $('#statusPill').text('Active').css('background','#10b981');
            } else {
                $('#statusPill').text('Paused').css('background','#ef4444');
            }
        }
    });
}

function saveData() {
    var btn = $('#btnSave'), oldText = btn.text();
    btn.text('Saving...').prop('disabled', true);
    frappe.call({
        method: 'payment_control_api_15',
        args: {
            action: 'update_settings',
            auto:    $('#confAuto').val(),
            type:    $('#confType').val(),
            queue:   $('#confQueue').val(),
            trigger: $('#confTrigger').val()
        },
        callback: function(r) {
            btn.text(oldText).prop('disabled', false);
            if (!r.exc && !r.error) {
                showMsg(r.message || 'Configuration Updated', '#10b981');
                loadData();
            } else {
                showMsg('Error: ' + (r.error || 'Unknown'), '#ef4444');
            }
        }
    });
}

function emergencyControl(act) {
    frappe.call({
        method: 'stop_start_payment_control_api_15',
        args: { action: act },
        callback: function(r) {
            showMsg(r.message || r.error, act === 'stop' ? '#ef4444' : '#10b981');
            loadData();
        }
    });
}

function handleEngineAction(actionType) {
    frappe.call({
        method: 'ppr_engine_actions_api_15',
        args: { action: actionType },
        freeze: true,
        freeze_message: 'Processing...',
        callback: function(r) {
            if (r.message && !r.error) {
                frappe.show_alert({ message: r.message, indicator: 'green' });
                loadData();
            } else {
                frappe.msgprint({ title: 'Error', message: r.error || 'Unknown error', indicator: 'red' });
            }
        }
    });
}

function runEngineNow() {
    frappe.call({
        method: 'ppr_scheduler_v15',
        freeze: true,
        freeze_message: 'Running reconciliation engine...',
        callback: function(r) {
            var d = r.message || {};
            if (d.status === 'success') {
                frappe.msgprint({
                    title: 'Engine Run Complete',
                    indicator: 'green',
                    message:
                        'GL rows processed: <b>' + d.rows_processed + '</b><br>' +
                        'PPR records created: <b>' + d.created + '</b><br>' +
                        'Skipped (no credit): <b>' + d.skipped_no_credit + '</b><br>' +
                        'Skipped (no open invoice): <b>' + d.skipped_no_invoice + '</b><br>' +
                        'Cursor: <b>' + (d.cursor || 'N/A') + '</b>'
                });
                loadData();
            } else if (d.status === 'skipped') {
                frappe.show_alert({ message: 'Skipped: ' + d.reason, indicator: 'orange' });
            } else {
                frappe.msgprint({ title: 'Engine Error', message: JSON.stringify(d), indicator: 'red' });
            }
        }
    });
}

function showMsg(text, bg) {
    var msg = $('#msg');
    msg.text(text).css({ background: bg, color: 'white', padding: '10px', 'border-radius': '8px', 'margin-bottom': '15px' }).slideDown();
    setTimeout(function() { msg.slideUp(); }, 4000);
}

async function lmt_download_pdf_one_call(url, filename) {
  const res = await fetch(url, {
    method: "GET",
    headers: { "X-Frappe-CSRF-Token": (window.CSRF_TOKEN || ""), "Accept": "application/pdf" },
    credentials: "include"
  });
  if (!res.ok) { const t = await res.text().catch(() => ""); throw new Error("PDF failed: " + res.status + " " + t); }
  const blob    = await res.blob();
  const blobUrl = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = blobUrl; a.download = filename || "statement.pdf";
  document.body.appendChild(a); a.click(); a.remove();
  setTimeout(() => { try { window.open(blobUrl, "_blank"); } catch(e) {} }, 300);
  setTimeout(() => URL.revokeObjectURL(blobUrl), 8000);
}

const PAYMENT_DISPLAY = {
  "Cash":          "نقد",
  "Cheque":        "صك",
  "Bank Draft":    "صك",
  "Wire Transfer": "تحويل",
  "POS terminal":  "ماكينة نقاط بيع",
  "Credit Card":   "تحويل"
};

var currentUser = window.CURRENT_USER || "Guest";
var searchTimer = null;

document.addEventListener("DOMContentLoaded", function () {
  document.getElementById("from_date").value = "2022-01-01";
  document.getElementById("to_date").value   = new Date().toISOString().split('T')[0];

  var si = document.getElementById("search_input");
  var dd = document.getElementById("search_dropdown");

  si.addEventListener("focus", () => { si.select(); runSearch("__ALL__"); dd.style.display = "block"; });
  si.addEventListener("click", () => { si.select(); runSearch("__ALL__"); dd.style.display = "block"; });
  si.addEventListener("input", () => {
    document.getElementById("hidden_customer_id").value = "";
    clearTimeout(searchTimer);
    searchTimer = setTimeout(() => runSearch(si.value), 300);
  });

  function runSearch(val) {
    var filters = [["account_manager", "=", currentUser]];
    if (val && val !== "__ALL__") filters.push(["customer_name", "like", "%" + val + "%"]);
    fetch("/api/resource/Customer?fields=" + encodeURIComponent(JSON.stringify(["name","customer_name"])) +
          "&filters=" + encodeURIComponent(JSON.stringify(filters)) + "&limit_page_length=500")
      .then(r => r.json())
      .then(d => {
        dd.innerHTML = "";
        (d.data || []).forEach(c => {
          var item = document.createElement("div");
          item.className = "stmt-search-item";
          item.textContent = c.customer_name;
          item.onclick = () => {
            si.value = c.customer_name;
            document.getElementById("hidden_customer_id").value = c.name;
            dd.style.display = "none";
            loadStatement();
          };
          dd.appendChild(item);
        });
        dd.style.display = (d.data && d.data.length) ? "block" : "none";
      })
      .catch(() => { dd.style.display = "none"; });
  }

  document.getElementById("btnLoad").onclick  = loadStatement;
  document.getElementById("btnReload").onclick = loadStatement;

  document.getElementById("btnStatementPdf").onclick = async function() {
    var cid = document.getElementById("hidden_customer_id").value;
    if (!cid) return alert("اختر زبون أولاً");
    var f = document.getElementById("from_date").value || "2022-01-01";
    var t = document.getElementById("to_date").value   || new Date().toISOString().split('T')[0];
    const pdfUrl =
      "/api/method/frappe.utils.print_format.download_pdf" +
      "?doctype=" + encodeURIComponent("Customer") +
      "&name="    + encodeURIComponent(cid) +
      "&format="  + encodeURIComponent("Customer_Running_Balance") +
      "&no_letterhead=0&print_with_attachments=0" +
      "&from_date=" + encodeURIComponent(f) +
      "&to_date="   + encodeURIComponent(t) +
      "&_t=" + Date.now();
    const customerLabel = (si.value || cid).trim();
    const safeName = customerLabel.replace(/[\/\\:*?"<>|]+/g, "_");
    const filename = "Statement_" + safeName + "_" + f + "_to_" + t + ".pdf";
    const old = this.textContent;
    this.disabled = true; this.textContent = "...";
    try {
      await lmt_download_pdf_one_call(pdfUrl, filename);
    } catch (e) {
      console.error(e); alert("فشل تنزيل PDF");
      window.open(pdfUrl, "_blank");
    } finally {
      this.disabled = false; this.textContent = old;
    }
  };

  document.addEventListener("click", (e) => {
    if (!e.target.closest("#search_input") && !e.target.closest("#search_dropdown"))
      dd.style.display = "none";
  });
});

function fetchOpeningFromGL(customerKey, fromDate, toDate) {
  var url = "/api/method/lmt_opening_balance_customer" +
            "?customer="  + encodeURIComponent(customerKey || "") +
            "&from_date=" + encodeURIComponent(fromDate    || "") +
            "&to_date="   + encodeURIComponent(toDate      || "");
  return fetch(url, {
    method: "GET", credentials: "include",
    headers: { "Accept": "application/json", "X-Frappe-CSRF-Token": (window.CSRF_TOKEN || "") }
  })
  .then(r => r.json())
  .then(d => {
    var msg = (d && d.message) ? d.message : {};
    return { opening: parseFloat(msg.opening || 0) || 0, journal_entries: msg.journal_entries || [] };
  })
  .catch(() => ({ opening: 0, journal_entries: [] }));
}

function loadStatement() {
  var cid = document.getElementById("hidden_customer_id").value;
  var t   = document.getElementById("to_date").value;
  var f   = "2000-01-01";
  if (!cid) return;
  document.getElementById("kpiStatus").textContent = "جاري التحميل...";

  fetchOpeningFromGL(cid, f, t).then(gl => {
    Promise.all([
      fetch("/api/resource/Sales%20Invoice?filters=" +
            encodeURIComponent(JSON.stringify([["customer","=",cid],["docstatus","<",2],["posting_date",">=",f],["posting_date","<=",t]])) +
            "&fields=" + encodeURIComponent(JSON.stringify(["name","posting_date","grand_total"])))
        .then(r => r.json()),

      fetch("/api/resource/Payment%20Entry?filters=" +
            encodeURIComponent(JSON.stringify([["party","=",cid],["docstatus","<",2],["posting_date",">=",f],["posting_date","<=",t]])) +
            "&fields=" + encodeURIComponent(JSON.stringify(["name","posting_date","paid_amount","reference_no","mode_of_payment"])))
        .then(r => r.json()),

      fetch("/api/resource/LMT%20Debt%20Collection?filters=" +
            encodeURIComponent(JSON.stringify([["customer","=",cid],["docstatus","<",2]])) +
            "&fields=" + encodeURIComponent(JSON.stringify(["name","payment_type","mode_of_payment","receipt_no","bank"])) +
            "&limit_page_length=2000")
        .then(r => r.json())
    ])
    .then(res => {

      // ── BUILD debtMap ──────────────────────────────────────────
      // THE FIX: if payment_type is POS → use bank field, strip " - S"
      // Otherwise → use PAYMENT_DISPLAY as before
      var debtMap = {};
      (res[2].data || []).forEach(d => {
        var rawType = d.payment_type || d.mode_of_payment || "";
        var displayLbl;

        if (rawType === "ماكينة نقاط بيع" || rawType === "POS terminal") {
          // Use actual bank account name, strip company suffix
          displayLbl = (d.bank || "ماكينة نقاط بيع").replace(/ - \S+$/, "").trim();
        } else {
          displayLbl = PAYMENT_DISPLAY[rawType] || rawType || "نقد";
        }

        if (d.receipt_no) debtMap[String(d.receipt_no)] = displayLbl;
        debtMap[d.name] = displayLbl;
      });

      var timeline = [];

      (res[0].data || []).forEach(i => {
        timeline.push({ date: i.posting_date, inv: i.name, sale: parseFloat(i.grand_total || 0), pay: 0, ref: "", type: "فاتورة" });
      });

      (res[1].data || []).forEach(p => {
        var ref = String(p.reference_no || "").trim();
        // Lookup: receipt_no match first, then DEBT name, then PE mode_of_payment
        var label = debtMap[ref] || debtMap[p.name] || PAYMENT_DISPLAY[p.mode_of_payment] || p.mode_of_payment || "نقد";
        timeline.push({ date: p.posting_date, inv: p.name, sale: 0, pay: parseFloat(p.paid_amount || 0), ref: ref, type: label });
      });

      (gl.journal_entries || []).forEach(j => {
        var net     = parseFloat(j.net || 0) || 0;
        var remark  = j.user_remark || "";
        var lremark = remark.toLowerCase();
        var rowType = "قيد يومية";
        if (lremark.includes("migration") || lremark.includes("opening") || remark.includes("افتتاحي"))
          rowType = "رصيد افتتاحي";
        var displayRef = remark.includes("واصل:") ? remark.split("واصل:")[1].trim() : (j.cheque_no || j.reference_no || "");
        timeline.push({ date: j.posting_date, inv: j.voucher_no || "", sale: net > 0 ? net : 0, pay: net < 0 ? (-net) : 0, ref: displayRef, type: rowType });
      });

      timeline.sort((a, b) => (b.date || "").localeCompare(a.date || ""));

      var totalSales = 0, totalPaid = 0, runningBalance = parseFloat(gl.opening || 0);
      timeline.forEach(r => { totalSales += (r.sale || 0); totalPaid += (r.pay || 0); runningBalance += ((r.sale || 0) - (r.pay || 0)); });
      var kpiBal = runningBalance;

      var html = "";
      timeline.forEach(r => {
        var displayBal = runningBalance;
        html += "<tr>" +
          "<td>" + (r.date || "")                    + "</td>" +
          "<td>" + (r.inv  || "")                    + "</td>" +
          "<td>" + (r.sale ? r.sale.toFixed(2) : "") + "</td>" +
          "<td>" + (r.ref  || "")                    + "</td>" +
          "<td>" + (r.pay  ? r.pay.toFixed(2)  : "") + "</td>" +
          "<td>" + (r.type || "")                    + "</td>" +
          "<td>" + displayBal.toFixed(2)             + "</td>" +
        "</tr>";
        runningBalance = runningBalance - (r.sale || 0) + (r.pay || 0);
      });

      document.getElementById("tbody").innerHTML = html ||
        '<tr><td colspan="7" style="padding:40px;text-align:center;">لا توجد بيانات</td></tr>';
      document.getElementById("kpiSales").textContent  = totalSales.toFixed(2);
      document.getElementById("kpiPaid").textContent   = totalPaid.toFixed(2);
      document.getElementById("kpiBal").textContent    = kpiBal.toFixed(2);
      document.getElementById("kpiStatus").textContent = "جاهز";
    })
    .catch(err => {
      console.error(err);
      document.getElementById("kpiStatus").textContent = "خطأ";
    });
  });
}

