@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');
:root{
  --bg:#bfeaf4;
  --card:rgba(255,255,255,0.4);
  --text:#0b1b22;
  --muted:#6b7280;
  --border:rgba(0,0,0,0.15);
  --primary:#ffd23c;
  --yellow-light:#ffe26b;
  --danger:#ff7a7a;
  --warn:#f59e0b;
  --ok:#2f8f3a;
  --shadow:0 10px 30px rgba(0,0,0,.08);
  --radius:16px;
}
.hidden{display:none!important;}
body,.page-container,.main-section,.appshell,.content,#appContent{background-color:var(--bg)!important;font-family:"Cairo",sans-serif!important;min-height:100vh;}
footer,.web-footer,.page-footer,.footer-section,header,.navbar{display:none!important;}
.mobile-topbar{position:sticky;top:0;z-index:1000;background:rgba(255,255,255,0.35)!important;backdrop-filter:blur(6px)!important;border-bottom:1px solid var(--border)!important;padding:10px 12px;display:flex;align-items:center;justify-content:space-between;direction:rtl;}
.topbar-right,.topbar-left{display:flex;align-items:center;gap:10px;}
.topbar-text{font-weight:900;font-size:16px;color:var(--text);font-family:"Cairo",sans-serif;}
.icon-btn{background-color:var(--yellow-light)!important;border:1px solid var(--border)!important;border-radius:999px!important;padding:10px 12px;font-weight:900;line-height:1;min-height:42px;width:42px;display:flex;align-items:center;justify-content:center;box-shadow:var(--shadow);cursor:pointer;}
.drawer-overlay{position:fixed;inset:0;background:rgba(0,0,0,.35);z-index:1200;}
.drawer{position:fixed;top:0;right:0;height:100vh;width:82%;max-width:360px;background:#fff;z-index:1300;border-left:1px solid var(--border);box-shadow:var(--shadow);display:flex;flex-direction:column;}
.drawer-header{display:flex;align-items:center;justify-content:space-between;padding:12px;border-bottom:1px solid var(--border);background:var(--primary);}
