.drawer-action{width:100%;padding:12px;border-radius:14px;border:1px solid var(--border);background:#fff;font-weight:900;text-align:right;font-family:"Cairo",sans-serif;}
.panel-overlay{position:fixed;inset:0;background:rgba(0,0,0,.35);z-index:1400;}
.side-panel{position:fixed;top:0;right:0;height:100vh;width:88%;max-width:420px;background:#fff;z-index:1500;border-left:1px solid var(--border);box-shadow:var(--shadow);display:flex;flex-direction:column;}
.panel-header{display:flex;align-items:center;justify-content:space-between;padding:12px;border-bottom:1px solid var(--border);}
