.panel-body{padding:12px;overflow:auto;}
.modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:1600;}
.modal{position:fixed;left:50%;top:50%;transform:translate(-50%,-50%);width:min(92vw,520px);max-height:82vh;overflow:auto;background:#fff;border:1px solid var(--border);border-radius:18px;box-shadow:var(--shadow);z-index:1700;direction:rtl;}
.modal-header{display:flex;align-items:center;justify-content:space-between;padding:12px;border-bottom:1px solid var(--border);background:var(--ok);color:#fff;}
.modal-title{font-weight:900;font-family:"Cairo",sans-serif;}
.modal-body{padding:12px;}
.modal-footer{display:flex;gap:10px;flex-wrap:wrap;padding:12px;border-top:1px solid var(--border);}
.split-acc-page{padding:14px;background:var(--bg);direction:rtl;}
.card{background:var(--card);border:1px solid var(--border);border-radius:var(--radius);box-shadow:var(--shadow);padding:14px;margin-bottom:12px;backdrop-filter:blur(6px);}
.header-card .hint{margin-top:10px;color:var(--text);line-height:1.6;font-size:14px;opacity:0.8;}
