.badge.ok{background:rgba(47,143,58,0.15);border-color:var(--ok);color:var(--ok);}
.badge.warn{background:rgba(245,158,11,.12);border-color:rgba(245,158,11,.28);color:#b45309;}
.badge.err{background:rgba(220,38,38,.10);border-color:var(--danger);color:var(--danger);}
.badge.busy{background:rgba(11,94,215,.10);border-color:rgba(11,94,215,.25);color:var(--primary);}
.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
