.recent-item.submitted{border-color:var(--ok);background:rgba(47,143,58,0.05);}
.recent-top{display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:6px;}
.recent-name{font-weight:900;color:var(--text);font-family:"Cairo",sans-serif;}
