javascript:
(function () {
  let __ACC_ACCOUNTS = [];
  let __ACC_DIMS = [];

  // ── Drawer ──────────────────────────────────────────────
  window.__acc_toggleDrawer = function () {
    document.getElementById("drawer")?.classList.toggle("hidden");
    document.getElementById("drawerOverlay")?.classList.toggle("hidden");
  };
  window.__acc_closeDrawer = function () {
    document.getElementById("drawer")?.classList.add("hidden");
    document.getElementById("drawerOverlay")?.classList.add("hidden");
  };

  function $(id){ return document.getElementById(id); }
  function v(id){ return (($(id)?.value || "").trim()); }
  function setV(id,val){ if($(id)) $(id).value = val ?? ""; }

  function escapeHtml(s){
    return (s||"").replace(/[&<>"']/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
  }

  function setBadge(text, cls) {
    const el = $("statusBadge");
    if (!el) return;
    el.textContent = text || "";
    el.classList.remove("ok","warn","err","busy");
    el.classList.add(cls);
  }
  const STATUS = {
    ok:   t => setBadge(t || "جاهز",    "ok"),
    warn: t => setBadge(t || "تنبيه",   "warn"),
    err:  t => setBadge(t || "خطأ",     "err"),
    busy: t => setBadge(t || "جارٍ...", "busy")
  };

  function showResult(html, type){
    const box = $("resultBox");
    if (!box) return;
    box.classList.remove("hidden","ok","warn","err");
    box.classList.add(type || "ok");
    box.innerHTML = html;
  }
  function clearResult(){
    const box = $("resultBox");
    if (!box) return;
    box.classList.add("hidden");
    box.innerHTML = "";
  }

  // ── Robust API call with timeout ─────────────────────────
  function call(method, args, timeoutMs=45000){
    return new Promise((resolve, reject) => {
      let done = false;
      const timer = setTimeout(() => {
        if (done) return; done = true;
        reject(new Error("Timeout من السيرفر"));
      }, timeoutMs);

      frappe.call({
        method, args: args || {},
        callback: (r) => {
          if (done) return;
          clearTimeout(timer);
          if (r && r.exc) { done = true; reject(new Error("Server Error")); return; }
          done = true; resolve(r);
        },
        error: () => {
          if (done) return;
          clearTimeout(timer); done = true;
          reject(new Error("HTTP/Network Error"));
        }
      });
    });
  }

  // ✅ Fixed submit — uses custom server script (bypasses stale modified timestamp)
  // frappe.client.submit sends client-side modified from page load → TimestampMismatchError
  // Our script fetches fresh from DB by name only — no timestamp comparison possible
  async function submitDoc(doctype, name){
    if (doctype === "Journal Entry") {
      const r = await call("je_submit_by_name_57", { name });
      const resp = r.message || {};
      if (resp.status === "error") throw new Error(resp.message);
      return r;
    }
    return call("frappe.client.submit", { doc: { doctype, name } });
  }

  function todayStr(){
    const d = new Date();
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`;
  }
  function webLink(name){ return `/split-accounting-57?open=${encodeURIComponent(name)}`; }

  // ── Panels / Modal ───────────────────────────────────────
  function openCommittedPanel(){
    $("committedOverlay")?.classList.remove("hidden");
    $("committedPanel")?.classList.remove("hidden");
    window.__acc_closeDrawer();
    loadCommittedList();
  }
  function closeCommittedPanel(){
    $("committedOverlay")?.classList.add("hidden");
    $("committedPanel")?.classList.add("hidden");
  }
  function openDetailModal(html, footer){
    // Remove any previous dynamic detail modal
    const prev = document.getElementById("dynDetailModal");
    if (prev) prev.remove();

    const wrap = document.createElement("div");
    wrap.id = "dynDetailModal";
    wrap.style.cssText = "position:fixed;inset:0;z-index:9999;display:flex;align-items:center;justify-content:center;padding:16px;background:rgba(0,0,0,0.45);";
    wrap.innerHTML = `
      <div style="background:#fff;border-radius:18px;width:min(92vw,520px);max-height:82vh;overflow:auto;box-shadow:0 8px 32px rgba(0,0,0,.18);direction:rtl;">
        <div class="modal-header" style="display:flex;align-items:center;justify-content:space-between;padding:12px;border-bottom:1px solid var(--border);background:var(--ok);color:#fff;border-radius:18px 18px 0 0;">
          <div style="font-weight:900;font-family:'Cairo',sans-serif;">تفاصيل القيد</div>
          <button type="button" id="btnCloseDetail" style="background:none;border:none;color:#fff;font-size:22px;cursor:pointer;line-height:1;">✕</button>
        </div>
        <div id="detailBody" style="padding:12px;">${html}</div>
        <div id="detailFooter" style="display:flex;gap:10px;flex-wrap:wrap;padding:12px;border-top:1px solid var(--border);">${footer || ""}</div>
      </div>`;
    document.body.appendChild(wrap);
    // Close on overlay click
    wrap.addEventListener("click", e => { if (e.target === wrap) closeDetailModal(); });
    // Close button
    const closeBtn = document.getElementById("btnCloseDetail");
    if (closeBtn) closeBtn.onclick = closeDetailModal;
  }
  function closeDetailModal(){
    const el = document.getElementById("dynDetailModal");
    if (el) el.remove();
  }

  // ── Loaders ──────────────────────────────────────────────
  async function loadCompanies(){
    const sel = $("company");
    sel.innerHTML = "";

    // Get user default company via server script (bypasses permission check)
    let userDefault = "";
    try {
      const rd = await call("je_get_defaults_57", {});
      userDefault = (rd.message && rd.message.company) || "";
      console.log("[JE] userDefault company:", userDefault);
    } catch(e) { console.warn("[JE] je_get_defaults_57 failed:", e.message); }

    // Fetch all companies
    const r = await call("frappe.client.get_list", { doctype:"Company", fields:["name"], limit_page_length:50 });
    const list = (r.message || []).map(x => x.name);
    list.forEach(n => sel.appendChild(new Option(n,n)));

    // Pick: user default > first
    const picked = (userDefault && list.includes(userDefault)) ? userDefault : (list[0] || "");
    if (picked) { sel.value = picked; window.__COMPANY = picked; }
    if (list.length <= 1) $("companyWrap").style.display = "none";
    console.log("[JE] company picked:", picked);
  }

  async function loadAccounts(company){
    const da = $("debit_account"), ca = $("credit_account");
    da.innerHTML = ""; ca.innerHTML = "";
    da.appendChild(new Option("اختر حساب مدين","",true,true));
    ca.appendChild(new Option("اختر حساب دائن","",true,true));

    try {
      // Role-based: call je_get_user_accounts_57
      const r = await call("je_get_user_accounts_57", { company });
      const resp = r.message || {};
      const debitList  = resp.debit_accounts  || [];
      const creditList = resp.credit_accounts || [];

      __ACC_ACCOUNTS = debitList;
      debitList.forEach(a  => da.appendChild(new Option(a, a)));
      creditList.forEach(a => ca.appendChild(new Option(a, a)));

      // Store filtered cost centers for loadCostCenters to use
      window.__ALLOWED_CC = resp.allowed_cost_centers || [];

      // Auto-select if only one credit account
      if (creditList.length === 1) ca.value = creditList[0];
      // Auto-select if only one cost center
      if (window.__ALLOWED_CC.length === 1) setV("cost_center", window.__ALLOWED_CC[0]);

      // Submit button visibility
      window.__CAN_SUBMIT = resp.can_submit || false;
      if (window.__CAN_SUBMIT) {
        $("btnSubmit") && ($("btnSubmit").style.display = "");
      }

    } catch(e) {
      // Fallback: load all accounts like v26 (so page still works)
      console.warn("je_get_user_accounts_57 failed, falling back:", e);
      const r2 = await call("frappe.client.get_list", {
        doctype:"Account", fields:["name"],
        filters:{ company, is_group:0, disabled:0 }, limit_page_length:2000
      });
      __ACC_ACCOUNTS = (r2.message || []).map(x => x.name);
      __ACC_ACCOUNTS.forEach(a => {
        da.appendChild(new Option(a, a));
        ca.appendChild(new Option(a, a));
      });
    }
  }

  async function loadCostCenters(company){
    const cc = $("cost_center");
    cc.innerHTML = "";
    cc.appendChild(new Option("— (اختياري) —","",true,true));

    // If we have a filtered list from role-based accounts, use it
    if (window.__ALLOWED_CC && window.__ALLOWED_CC.length > 0) {
      window.__ALLOWED_CC.forEach(name => cc.appendChild(new Option(name, name)));
    } else {
      // Fallback: load all cost centers (accountant or no restriction)
      const r = await call("frappe.client.get_list", {
        doctype:"Cost Center", fields:["name"],
        filters:{ company, is_group:0, disabled:0 }, limit_page_length:500
      });
      (r.message || []).forEach(x => cc.appendChild(new Option(x.name, x.name)));
    }
  }

  async function loadMoP(){
    const r = await call("frappe.client.get_list", {
      doctype:"Mode of Payment", fields:["name"], filters:{enabled:1}, limit_page_length:200
    });
    const mop = $("mode_of_payment");
    mop.innerHTML = "";
    mop.appendChild(new Option("— (اختياري) —","",true,true));
    const mopTrans = {
      "Cash": "نقدي",
      "Bank Draft": "حوالة بنكية",
      "Cheque": "شيك",
      "Credit Card": "بطاقة ائتمان",
      "POS terminal": "نقطة بيع",
      "Wire Transfer": "تحويل بنكي",
      "Bank Transfer": "تحويل بنكي",
    };
    (r.message || []).forEach(x => {
      const label = mopTrans[x.name] || x.name;
      mop.appendChild(new Option(label, x.name));
    });
  }

  async function loadDimensions(){
    const wrap = $("dimsWrap"), container = $("dimensionsContainer");
    container.innerHTML = ""; wrap.style.display = "none"; __ACC_DIMS = [];
    let dims = [];
    try {
      const r = await call("frappe.client.get_list", {
        doctype:"Accounting Dimension", fields:["name","document_type","fieldname","disabled"],
        filters:{ disabled:0 }, limit_page_length:50
      });
      dims = r.message || [];
    } catch(e){
      // User lacks permission to read Accounting Dimension — skip silently
      return;
    }
    if (!dims.length) return;
    wrap.style.display = "block"; __ACC_DIMS = dims;
    for (const d of dims){
      const field = document.createElement("div"); field.className = "field";
      const label = document.createElement("label"); label.textContent = d.name; field.appendChild(label);
      const sel = document.createElement("select"); sel.id = "dim__" + d.fieldname; field.appendChild(sel);
      container.appendChild(field);
      try {
        const items = await loadDimensionOptions(d.document_type);
        sel.appendChild(new Option("— (اختياري) —","",true,true));
        items.forEach(it => sel.appendChild(new Option(it.label, it.value)));
      } catch(e){
        // Skip this dimension if options can't be loaded
        sel.appendChild(new Option("— (اختياري) —","",true,true));
      }
    }
  }

  async function loadDimensionOptions(doctype){
    const preferred = { "Employee":["name","employee_name","employee_number"], "Customer":["name","customer_name"] };
    const fieldsTry = preferred[doctype] || ["name","title","full_name"];
    let rows = [];
    try {
      const r = await call("frappe.client.get_list", { doctype, fields:fieldsTry, limit_page_length:500 });
      rows = r.message || [];
    } catch(e) {
      const r2 = await call("frappe.client.get_list", { doctype, fields:["name"], limit_page_length:500 });
      rows = r2.message || [];
    }
    return rows.map(r => {
      const name = r.name;
      if (doctype === "Employee"){
        const en = r.employee_name || "", eno = r.employee_number || "";
        return { value:name, label:(eno&&en)?`${eno} - ${en}`:(en?`${en} (${name})`:name) };
      }
      const t = r.customer_name || r.title || r.full_name || "";
      return { value:name, label:t?`${t} (${name})`:name };
    });
  }

  // ── Split lines ──────────────────────────────────────────
  function splitCount(){ return document.querySelectorAll("#splitLines .split-line").length; }
  function updateDebitVisibility(){ $("debitWrap").style.display = splitCount() > 0 ? "none" : ""; }

  function splitLineTemplate(){
    return `<div class="split-line">
      <div class="split-row">
        <div class="field"><label>حساب (مدين)</label><select class="sl_account"></select></div>
        <div class="field"><label>المبلغ</label><input class="sl_amount" type="number" step="0.01" placeholder="0.00"></div>
        <div class="field"><label>مركز التكلفة</label><select class="sl_cc"></select></div>
        <div class="field"><label>ملاحظة</label><input class="sl_remark" type="text" placeholder="اختياري"></div>
      </div>
      <div class="split-actions"><button type="button" data-action="remove-line">🗑 حذف</button></div>
    </div>`;
  }

  function recalcSplit(){
    const total = parseFloat(v("amount") || "0") || 0;
    let sum = 0;
    document.querySelectorAll("#splitLines .split-line").forEach(line => {
      sum += parseFloat(line.querySelector(".sl_amount")?.value || "0") || 0;
    });
    $("splitSum").textContent = sum.toFixed(2);
    $("splitRemain").textContent = (total - sum).toFixed(2);
    updateDebitVisibility();
  }

  async function addSplitLine(){
    const host = $("splitLines");
    const wrap = document.createElement("div"); wrap.innerHTML = splitLineTemplate();
    const line = wrap.firstElementChild; host.appendChild(line);
    const selAcc = line.querySelector(".sl_account");
    selAcc.appendChild(new Option("اختر حساب","",true,true));
    __ACC_ACCOUNTS.forEach(a => selAcc.appendChild(new Option(a,a)));
