  // ── Build JE doc ─────────────────────────────────────────
  function collectHeaderDims(){
    const dims = {};
    document.querySelectorAll("#dimensionsContainer select").forEach(sel => {
      const id = sel.id || "";
      if (!id.startsWith("dim__")) return;
      const fn = id.replace("dim__","");
      const vv = (sel.value || "").trim();
      if (vv) dims[fn] = vv;
    });
    return dims;
  }

  function buildJE(){
    const company = v("company"), posting_date = v("posting_date");
    const total = parseFloat(v("amount") || "0");
    const debit_header = v("debit_account"), credit_account = v("credit_account");
    const cost_center_header = v("cost_center"), mode_of_payment = v("mode_of_payment");
    const remark = v("remark"), entry_type = v("entry_type");

    const companyFinal = company || window.__COMPANY || "الشركة الليبية الحديثة";
    if (!companyFinal) throw new Error("الشركة غير محددة");
    if (!posting_date) throw new Error("اختر التاريخ");
    if (!total || total <= 0) throw new Error("أدخل مبلغ صحيح");
    if (!credit_account) throw new Error("اختر الحساب الدائن");

    const headerDims = collectHeaderDims();
    let finalRemark = remark || "";
    if (mode_of_payment) finalRemark = (finalRemark ? finalRemark + " | " : "") + "طريقة الدفع: " + mode_of_payment;

    const splitLines = Array.from(document.querySelectorAll("#splitLines .split-line"));
    const hasSplit = splitLines.length > 0;
    const accounts = [];

    if (hasSplit){
      let debSum = 0;
      splitLines.forEach(line => {
        const acc = (line.querySelector(".sl_account")?.value || "").trim();
        const amt = parseFloat(line.querySelector(".sl_amount")?.value || "0") || 0;
        const cc  = (line.querySelector(".sl_cc")?.value || "").trim();
        const rmk = (line.querySelector(".sl_remark")?.value || "").trim();
        if (!acc || amt <= 0) return;
        debSum += amt;
        accounts.push({ account:acc, debit_in_account_currency:amt, credit_in_account_currency:0,
          cost_center:cc||cost_center_header||undefined, user_remark:rmk||remark||undefined, ...headerDims });
      });
      if (!accounts.length) throw new Error("أضف بند واحد على الأقل");
      if (Math.abs(debSum - total) > 0.009) throw new Error(`مجموع البنود (${debSum.toFixed(2)}) لا يساوي الإجمالي (${total.toFixed(2)})`);
      accounts.push({ account:credit_account, debit_in_account_currency:0, credit_in_account_currency:total,
        cost_center:cost_center_header||undefined, user_remark:remark||undefined, ...headerDims });
    } else {
      if (!debit_header) throw new Error("اختر الحساب المدين أو استخدم التفصيل");
      if (debit_header === credit_account) throw new Error("المدين والدائن لا يمكن أن يكونا نفس الحساب");
      accounts.push({ account:debit_header, debit_in_account_currency:total, credit_in_account_currency:0,
        cost_center:cost_center_header||undefined, user_remark:remark||undefined, ...headerDims });
      accounts.push({ account:credit_account, debit_in_account_currency:0, credit_in_account_currency:total,
        cost_center:cost_center_header||undefined, user_remark:remark||undefined, ...headerDims });
    }

    var doc = {
      doctype:"Journal Entry",
      voucher_type: entry_type === "TRANSFER" ? "Bank Entry" : "Journal Entry",
      company: companyFinal, posting_date,
      remark: finalRemark || undefined,
      accounts
    };
    if (entry_type === "TRANSFER") {
      var chequeNo = v("cheque_no");
      var chequeDate = v("cheque_date");
      if (!chequeNo) throw new Error("أدخل رقم المرجع / الشيك");
      doc.cheque_no = chequeNo;
      doc.cheque_date = chequeDate || posting_date;
    }
    return doc;
  }

