  // Save / Submit new JE
  async function saveJE(submit){
    if (submit && !window.__CAN_SUBMIT) return;
    clearResult();
    STATUS.busy(submit ? "جارٍ الاعتماد..." : "جارٍ الحفظ...");
    try {
      const doc = buildJE();
      let name;

      // If editing an existing draft — delete old and insert updated
      if (window.__EDIT_DRAFT_NAME) {
        const editName = window.__EDIT_DRAFT_NAME;
        // Delete the old draft first
        await call("je_delete_draft_57", { name: editName });
        // Insert updated doc
        const ins = await call("frappe.client.insert", { doc });
        name = ins.message && ins.message.name;
        if (!name) throw new Error("فشل تحديث القيد");
        window.__EDIT_DRAFT_NAME = null;
      } else {
        const ins = await call("frappe.client.insert", { doc });
        name = ins.message && ins.message.name;
        if (!name) throw new Error("فشل إنشاء القيد");
      }

      if (submit){
        await submitDoc("Journal Entry", name);
      }

      STATUS.ok(submit ? "تم الاعتماد" : "تم الحفظ");
      showResult(
        `<div><b>تم ${submit ? "اعتماد" : "حفظ"} القيد</b></div>
         <div class="mono">${escapeHtml(name)}</div>
         <div style="margin-top:8px;">
           <a target="_blank" href="/app/journal-entry/${encodeURIComponent(name)}">ERPNext</a> |
           <a target="_blank" href="${webLink(name)}">فتح في الويب</a>
         </div>`, "ok"
      );

      clearForm();
      await loadDraftsToday();
      if (submit) await loadCommittedList();
      return name;

    } catch(e) {
      STATUS.err("فشل");
      showResult("<b>خطأ:</b> " + escapeHtml(e.message || String(e)), "err");
      throw e;
    }
  }

