  async function editDraft(name){
    STATUS.busy("جارٍ تحميل القيد...");
    try {
      const r = await call("frappe.client.get", { doctype:"Journal Entry", name });
      const doc = r.message;
      if (!doc || doc.docstatus !== 0) throw new Error("القيد غير موجود أو تم اعتماده");
      document.querySelector(".form-card")?.scrollIntoView({ behavior:"smooth" });
      if (doc.company)      setV("company", doc.company);
      if (doc.posting_date) setV("posting_date", doc.posting_date);
      if (doc.voucher_type) {
        setV("entry_type", doc.voucher_type === "Bank Entry" ? "TRANSFER" : "EXPENSE");
        var show = doc.voucher_type === "Bank Entry";
        $("refNoWrap").style.display = show ? "" : "none";
        $("refDateWrap").style.display = show ? "" : "none";
        if (doc.cheque_no) setV("cheque_no", doc.cheque_no);
        if (doc.cheque_date) setV("cheque_date", doc.cheque_date);
      }
      if (doc.remark)       setV("remark", doc.remark);
      await loadAccounts(doc.company || window.__COMPANY);
      const lines = doc.accounts || [];
      const creditLine = lines.find(l => Number(l.credit_in_account_currency||0) > 0);
      const debitLines = lines.filter(l => Number(l.debit_in_account_currency||0) > 0);
      if (creditLine){
        setV("credit_account", creditLine.account);
        if (creditLine.cost_center) setV("cost_center", creditLine.cost_center);
      }
      const total = creditLine ? Number(creditLine.credit_in_account_currency) : 0;
      if (total) setV("amount", total.toFixed(2));
      clearSplitLines();
      if (debitLines.length === 1){
        setV("debit_account", debitLines[0].account);
        recalcSplit();
      } else {
        for (const dl of debitLines){
          const line = addSplitLine();
          const accSel = line.querySelector(".sl_account");
          const amtInp = line.querySelector(".sl_amount");
          const remInp = line.querySelector(".sl_remark");
          if (accSel) accSel.value = dl.account;
          if (amtInp) amtInp.value = Number(dl.debit_in_account_currency).toFixed(2);
          if (remInp && dl.user_remark) remInp.value = dl.user_remark;
        }
        recalcSplit();
      }
    window.__EDIT_DRAFT_NAME = name;
      if ($("btnSubmit")) $("btnSubmit").style.display = "none";
      STATUS.ok("تم تحميل القيد — عدّل وأعد الحفظ");
    } catch(e) {
      STATUS.err("خطأ");
      showResult("<b>فشل تحميل القيد:</b> " + escapeHtml(e.message || String(e)), "err");
    }
  }

  function clearForm(){
    setV("amount",""); setV("debit_account",""); setV("credit_account","");
    setV("cost_center",""); setV("mode_of_payment",""); setV("remark","");
    setV("cheque_no",""); setV("cheque_date","");
    document.querySelectorAll("#dimensionsContainer select").forEach(s => s.value = "");
    clearSplitLines(); clearResult(); STATUS.ok("جاهز");
    window.__EDIT_DRAFT_NAME = null;
    if (window.__CAN_SUBMIT && $("btnSubmit")) $("btnSubmit").style.display = "";
  }

  async function onCompanyChanged(){
    const company = v("company") || window.__COMPANY || "";
    if (company) window.__COMPANY = company;
    STATUS.busy("تحميل...");
    await loadAccounts(company);
    await loadCostCenters(company);
    await loadDimensions();
    STATUS.ok("جاهز");
    recalcSplit();
  }

  function getOpenParam(){
    try { return (new URL(window.location.href).searchParams.get("open") || "").trim(); }
    catch(e){ return ""; }
  }

  // ── Event wiring ─────────────────────────────────────────
  // Sync cash account <-> cost center selection
  function syncFromCredit(){
    const creditVal = v("credit_account"); // e.g. "الخزينة النقدية الخمس - S"
    const cc = $("cost_center");
    if (!creditVal || !cc) return;
    // Find cost center whose name is substring of selected credit account value
    for (let i = 0; i < cc.options.length; i++){
      const opt = cc.options[i];
      if (!opt.value) continue;
      // cost_center_name is inside the full name e.g. "001 - الخمس - S"
      // extract the middle part OR just check if cc name contains the branch
      // We match: creditVal contains cc.text's cost_center portion
      // Simplest: check if any word of cc option text appears in creditVal
      const ccName = opt.text; // full name like "001 - الخمس - S"
      // Extract cost_center_name: split by " - " and take middle parts
      const parts = ccName.split(" - ");
      const ccShort = parts.length >= 2 ? parts.slice(1, -1).join(" - ") : ccName;
      if (creditVal.includes(ccShort) && ccShort.length > 1){
        cc.value = opt.value;
        return;
      }
    }
  }

  function syncFromCC(){
    const ccFull = v("cost_center"); // e.g. "001 - الخمس - S"
    const cr = $("credit_account");
    if (!ccFull || !cr) return;
    // Extract short name from cost center full name
    const parts = ccFull.split(" - ");
    const ccShort = parts.length >= 2 ? parts.slice(1, -1).join(" - ") : ccFull;
    if (!ccShort || ccShort.length <= 1) return;
    // Find credit account whose value contains ccShort
    for (let i = 0; i < cr.options.length; i++){
      const opt = cr.options[i];
      if (!opt.value) continue;
      if (opt.value.includes(ccShort)){
        cr.value = opt.value;
        return;
      }
    }
  }

  function wire(){
    $("btnOpenCommitted").addEventListener("click", openCommittedPanel);
    $("btnCloseCommitted").addEventListener("click", closeCommittedPanel);
    $("committedOverlay").addEventListener("click", closeCommittedPanel);

    $("btnClear").addEventListener("click", clearForm);
    $("btnSaveDraft").addEventListener("click", () => saveJE(false));
    $("btnSubmit").addEventListener("click", () => saveJE(true));

    $("btnAddLine").addEventListener("click", () => addSplitLine());
    $("btnClearSplit").addEventListener("click", clearSplitLines);
    $("btnAutoSplitEqual").addEventListener("click", () => {
      const total = parseFloat(v("amount") || "0") || 0;
      const lines = document.querySelectorAll("#splitLines .split-line");
      if (!lines.length || !total) return;
      const each = total / lines.length;
      lines.forEach(l => { const a = l.querySelector(".sl_amount"); if(a) a.value = each.toFixed(2); });
      recalcSplit();
    });
    $("amount").addEventListener("input", recalcSplit);
    $("entry_type").addEventListener("change", function(){ var show = this.value === "TRANSFER"; $("refNoWrap").style.display = show ? "" : "none"; $("refDateWrap").style.display = show ? "" : "none"; });

    wireSplitDelegation();

    // Sync cash <-> cost center on change
    $("credit_account").addEventListener("change", syncFromCredit);
    $("cost_center").addEventListener("change", syncFromCC);

    // Draft list actions: commit or delete
    $("draftList").addEventListener("click", async ev => {
      const commitBtn = ev.target.closest?.("[data-action='commit']");
      if (commitBtn){ await commitDraft(commitBtn.getAttribute("data-name")); return; }
      const editBtn = ev.target.closest?.("[data-action='edit-draft']");
      if (editBtn){ editDraft(editBtn.getAttribute("data-name")); return; }
      const deleteBtn = ev.target.closest?.("[data-action='delete-draft']");
      if (deleteBtn){ await deleteDraft(deleteBtn.getAttribute("data-name")); }
    });

    // Committed list actions: open detail or cancel+delete
    $("committedList").addEventListener("click", async ev => {
      const viewJEBtn = ev.target.closest?.("[data-action='view-je']");
      if (viewJEBtn){ viewJE(viewJEBtn.getAttribute("data-name")); return; }
      const openBtn = ev.target.closest?.("[data-action='open']");
      if (openBtn){ await openJEDetail(openBtn.getAttribute("data-name")); return; }
      const delBtn = ev.target.closest?.("[data-action='cancel-delete']");
      if (delBtn){ await cancelAndDelete(delBtn.getAttribute("data-name")); }
    });

    $("company").addEventListener("change", () => onCompanyChanged());
  }

  // ── Init ─────────────────────────────────────────────────
  frappe.ready(async function(){
    try {
      if (!frappe.session || frappe.session.user === "Guest"){
        window.location.href = "/login?redirect-to=/split-accounting-57";
        return;
      }

      setDefaultDate();
      wire();

      STATUS.busy("تحميل...");
      await loadCompanies();
      await loadMoP();
      await onCompanyChanged();
      await loadDraftsToday();

      STATUS.ok("جاهز");

      const openName = getOpenParam();
      if (openName){ await openJEDetail(openName); }

    } catch(e) {
      STATUS.err("خطأ");
      showResult("<b>فشل:</b> " + escapeHtml(e.message || String(e)), "err");
    }
  });

})();

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');
header.navbar,.navbar,.top-navbar,footer,.web-footer{display:none !important}
body{padding:0 !important;margin:0 !important;background:#bfeaf4;font-family:"Cairo",sans-serif;direction:rtl;color:#0b1b22}
.page_content,.page-content,main,.main-section{margin:0 !important;padding:0 !important}
:root{--yellow:#ffd23c;--yellow2:#ffe26b;--green:#2f8f3a;--green2:#2aa334;--shadow:0 4px 16px rgba(0,0,0,.1);--red:#e53935}
.sr-topbar{position:sticky;top:0;z-index:50;display:flex;gap:8px;align-items:center;padding:10px 12px;background:rgba(255,255,255,.35);border-bottom:1px solid rgba(0,0,0,.15);backdrop-filter:blur(6px)}
.sr-btn-icon{border:none;cursor:pointer;border-radius:999px;padding:8px 12px;font-weight:900;font-size:15px;box-shadow:var(--shadow);background:var(--yellow2);border:1px solid rgba(0,0,0,.2)}
.sr-title{font-weight:900;font-size:16px;margin-right:auto;margin-left:8px}
