.edx-bigbtn:hover{ background: rgba(17,24,39,.04); }
.edx-bigbtn-main{ font-weight: 1000; font-size: 18px; }
.edx-bigbtn-sub{ color: var(--muted); font-size: 12px; margin-top:4px; }
.edx-bigbtn-badge{
  font-size: 11px;
  font-weight: 900;
  margin-top: 8px;
  min-height: 16px;
}

.edx-manage-head{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:10px;
  margin-bottom: 10px;
}
.edx-back{
  border:1px solid var(--line);
  background: var(--btn);
  border-radius: 12px;
  padding: 10px 12px;
  cursor:pointer;
  font-weight: 900;
}
.edx-back:hover{ background: var(--btn2); }
.edx-manage-title{ font-weight: 1000; }

/* --- Flagged list (v2) --- */
.edx-flagged{
  margin-bottom: 14px;
  border: 1px solid var(--line);
  border-radius: 14px;
  overflow: hidden;
}
.edx-flagged-head{
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 12px;
  background: rgba(17,24,39,.04);
  border-bottom: 1px solid var(--line);
}
.edx-flagged-title{ font-weight: 900; font-size: 13px; }
.edx-flagged-count{
  background: var(--bad);
  color: #fff;
  font-weight: 900;
  font-size: 11px;
  padding: 2px 10px;
  border-radius: 99px;
  min-width: 20px;
  text-align: center;
}
.edx-flagged-list{
  max-height: 260px;
  overflow-y: auto;
}
.edx-flagged-loading{
  padding: 12px;
  text-align: center;
  color: var(--muted);
  font-size: 12px;
}
.edx-flagged-row{
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 12px;
  border-bottom: 1px solid rgba(0,0,0,.06);
  cursor: pointer;
  transition: background .15s;
}
.edx-flagged-row:hover{ background: rgba(17,24,39,.04); }
.edx-flagged-row:last-child{ border-bottom: none; }
.edx-flagged-row-right{ display: flex; align-items: center; gap: 8px; }
.edx-flagged-dot{
  display: inline-block;
  width: 8px; height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}
.edx-flagged-name{ font-weight: 900; font-size: 13px; }
.edx-flagged-sub{ font-size: 11px; color: var(--muted); margin-top: 1px; }
.edx-flagged-status{
  font-size: 11px;
  font-weight: 900;
  color: var(--muted);
  white-space: nowrap;
}

.edx-label{
  display:block;
  font-size: 12px;
  color: var(--muted);
  margin-bottom: 6px;
}
.edx-input{
  width:100%;
  padding: 12px 12px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: #fff;
  outline: none;
}
.edx-help{ margin-top:6px; font-size:11px; color:var(--muted); }

.edx-searchbox{ position:relative; }

.edx-dd{
  position:absolute;
  left:0; right:0;
  top: calc(100% + 6px);
  z-index: 9999;
  border:1px solid var(--line);
  background:#fff;
  border-radius: 14px;
  overflow:hidden;
  max-height: 280px;
  overflow-y:auto;
  box-shadow: 0 12px 30px rgba(0,0,0,.15);
}
.edx-dd-item{
  padding: 10px 12px;
  border-bottom: 1px solid rgba(0,0,0,.06);
  cursor:pointer;
}
.edx-dd-item:hover{ background: rgba(17,24,39,.04); }
.edx-dd-main{ font-weight: 900; font-size: 13px; }
.edx-dd-sub{ font-size: 11px; color: var(--muted); margin-top:2px; }

.edx-selected{ margin-top: 12px; }
.edx-selected-title{ font-weight: 900; font-size: 12px; margin-bottom: 8px; }
.edx-selected-box{
  border: 1px solid rgba(0,0,0,.08);
  background: rgba(17,24,39,.02);
  border-radius: 14px;
  padding: 10px;
  min-height: 52px;
}
.edx-empty{ color: var(--muted); font-size: 12px; }

.edx-chip{
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:10px;
  padding: 10px 12px;
  border-radius: 14px;
  border: 1px solid rgba(0,0,0,.10);
  background: rgba(17,24,39,.04);
}
.edx-chip-name{ font-weight: 1000; }
.edx-chip-sub{ font-size: 12px; color: var(--muted); margin-top:2px; }
.edx-chip-x{
  width:32px;height:32px;border-radius:12px;
  border:1px solid rgba(0,0,0,.10);
  background: rgba(17,24,39,.06);
  cursor:pointer;
}

.edx-actions{
  display:flex;
  gap:10px;
  margin-top: 12px;
}
.edx-btn{
  flex:1;
  padding: 12px 12px;
  border-radius: 14px;
  border: 1px solid var(--line);
  background: var(--btn);
  cursor:pointer;
  font-weight: 1000;
}
.edx-btn:hover{ background: var(--btn2); }

.edx-btn.danger{
  border-color: rgba(220,38,38,.35);
  background: rgba(220,38,38,.10);
  color: #991b1b;
}

.edx-info{
  margin-top: 12px;
  border: 1px solid rgba(0,0,0,.08);
  background: rgba(17,24,39,.02);
  border-radius: 14px;
  padding: 10px;
}
.edx-info-title{ font-weight: 900; font-size: 12px; margin-bottom: 4px; }
.edx-info-text{ color: var(--muted); font-size: 12px; line-height: 1.5; }

@media (max-width: 720px){
  .edx-choice{ grid-template-columns: 1fr; }
}

javascript:
(function () {
  var API_FLAGGED = "edx_get_flagged_records_2";

  function isGuest() {
    try {
      if (typeof frappe !== "undefined" && frappe.session && frappe.session.user) {
        return frappe.session.user === "Guest";
      }
      return window.LOGGED_IN_USER === "Guest";
    } catch (e) { return false; }
  }

  function $(id){ return document.getElementById(id); }
  function setMsg(t){ $("msg").textContent = t || ""; }

  function esc(s){
    return String(s || "")
      .replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;")
      .replaceAll('"',"&quot;").replaceAll("'","&#039;");
  }

  function call(method, args){
    return new Promise(function(resolve, reject) {
      frappe.call({
        method: method,
        args: args,
        callback: function(r) { resolve(r); },
        error: function(e) { reject(e); }
      });
    });
  }

  function get_list(doctype, fields, filters, limit){
    return call("frappe.client.get_list", {
      doctype: doctype,
      fields: fields,
      filters: filters,
      limit_page_length: limit || 20,
      order_by: "modified desc"
    }).then(function(r) {
      return (r && r.message) ? r.message : [];
    });
  }

  function get_value(doctype, name, fieldname){
    return call("frappe.client.get_value", {
      doctype: doctype,
      filters: { name: name },
      fieldname: fieldname
    }).then(function(r) {
      return (r && r.message) ? r.message[fieldname] : null;
    });
  }

  function debounce(fn, ms){
    var t = null;
    return function(){
      var args = arguments;
      var self = this;
      clearTimeout(t);
      t = setTimeout(function(){ fn.apply(self, args); }, ms);
    };
  }

  // -------------------------------
  // State
  // -------------------------------
  var STATE = {
    mode: null,
    selected: null
  };

  function showHome(){
    $("homeView").classList.remove("hidden");
    $("manageView").classList.add("hidden");
    STATE.mode = null;
    clearSelection();
    setMsg("جاهز");
    loadHomeBadges();
  }

  // --- HOME BADGES (v2 new) ---
  function loadHomeBadges() {
    Promise.all([
      call(API_FLAGGED, { mode: "Customer" }),
      call(API_FLAGGED, { mode: "Sales Person" }),
      call(API_FLAGGED, { mode: "Exception" })
    ]).then(function(results) {
      var cc = (results[0] && results[0].message && results[0].message.data) ? results[0].message.data.length : 0;
      var cs = (results[1] && results[1].message && results[1].message.data) ? results[1].message.data.length : 0;
      var ce = (results[2] && results[2].message && results[2].message.data) ? results[2].message.data.length : 0;

      $("badgeCustomer").textContent     = cc ? cc + " معطل 🔴" : "";
      $("badgeSalesPerson").textContent  = cs ? cs + " معطل 🔴" : "";
      $("badgeException").textContent    = ce ? ce + " مستثنى 🟡" : "";
    }).catch(function(e) { console.warn("badges:", e); });
  }

  function showManage(mode){
    STATE.mode = mode;
    $("homeView").classList.add("hidden");
    $("manageView").classList.remove("hidden");

    if (mode === "Customer") {
      $("manageTitle").textContent = "إدارة العملاء";
      $("searchLabel").textContent = "بحث عن عميل";
      $("searchInput").placeholder = "ابدأ كتابة اسم العميل...";
      $("btnEnable").textContent = "تفعيل";
      $("btnDisable").textContent = "تعطيل";
    } else if (mode === "Exception") {
      $("manageTitle").textContent = "استثناء التحصيل";
      $("searchLabel").textContent = "بحث عن زبون لاستثنائه";
      $("searchInput").placeholder = "ابدأ كتابة اسم الزبون...";
      $("btnEnable").textContent = "تفعيل الاستثناء ✅";
      $("btnDisable").textContent = "إلغاء الاستثناء ❌";
    } else {
      $("manageTitle").textContent = "إدارة مندوبي المبيعات";
      $("searchLabel").textContent = "بحث عن مندوب مبيعات";
      $("searchInput").placeholder = "ابدأ كتابة اسم المندوب...";
      $("btnEnable").textContent = "تفعيل";
      $("btnDisable").textContent = "تعطيل";
    }

    $("searchInput").value = "";
    hideDropdown();
    clearSelection();
    setMsg("جاهز");

    loadFlaggedList(mode);

    $("searchInput").focus();
    loadSuggestions("");
  }

  // -------------------------------
  // FLAGGED LIST (v2 new)
  // -------------------------------
  function loadFlaggedList(mode) {
    var section = $("flaggedSection");
    var list = $("flaggedList");
    var ftitle = $("flaggedTitle");
    var fcount = $("flaggedCount");

    section.classList.add("hidden");
    list.innerHTML = '<div class="edx-flagged-loading">جاري التحميل...</div>';

    call(API_FLAGGED, { mode: mode }).then(function(r) {
      var resp = (r && r.message) ? r.message : {};
      if (resp.status !== "ok") return;

      var data = resp.data || [];
      if (data.length === 0) {
        section.classList.add("hidden");
        return;
      }

      if (mode === "Customer") {
        ftitle.textContent = "العملاء المعطلون";
      } else if (mode === "Sales Person") {
        ftitle.textContent = "المندوبون المعطلون";
      } else {
        ftitle.textContent = "العملاء المستثنون";
      }

      fcount.textContent = data.length;

      var html = "";
      for (var i = 0; i < data.length; i++) {
        var item = data[i];
        var dot = (mode === "Exception") ? "var(--warn)" : "var(--bad)";
        var statusTxt = (mode === "Exception") ? "مستثنى" : "معطل";
        html += '<div class="edx-flagged-row" data-name="' + esc(item.name) + '" data-label="' + esc(item.label) + '">'
              +   '<div class="edx-flagged-row-right">'
              +     '<span class="edx-flagged-dot" style="background:' + dot + '"></span>'
              +     '<div>'
              +       '<div class="edx-flagged-name">' + esc(item.label) + '</div>'
              +       (item.sub ? '<div class="edx-flagged-sub">' + esc(item.sub) + '</div>' : '')
              +     '</div>'
              +   '</div>'
              +   '<div class="edx-flagged-status">' + statusTxt + '</div>'
              + '</div>';
      }

      list.innerHTML = html;
      section.classList.remove("hidden");

      list.querySelectorAll(".edx-flagged-row").forEach(function(row) {
        row.addEventListener("click", function() {
          var name = this.getAttribute("data-name");
          var label = this.getAttribute("data-label");
          pickSelection(name, label);
        });
      });

    }).catch(function(e) {
      console.error("flagged:", e);
      section.classList.add("hidden");
    });
  }

  // -------------------------------
  // Dropdown (same as original)
  // -------------------------------
  function hideDropdown(){ $("dropdown").classList.add("hidden"); }

  function showDropdown(items){
    var dd = $("dropdown");
    if (!items.length) {
      dd.innerHTML = '<div class="edx-dd-item"><div class="edx-dd-main">لا توجد نتائج</div></div>';
      dd.classList.remove("hidden");
      return;
    }

    dd.innerHTML = items.map(function(it) {
      return '<div class="edx-dd-item" data-name="' + esc(it.name) + '" data-label="' + esc(it.label || it.name) + '">'
        + '<div class="edx-dd-main">' + esc(it.label || it.name) + '</div>'
        + (it.sub ? '<div class="edx-dd-sub">' + esc(it.sub) + '</div>' : '')
        + '</div>';
    }).join("");

    dd.classList.remove("hidden");

    dd.querySelectorAll(".edx-dd-item").forEach(function(row) {
      row.addEventListener("pointerdown", function(ev) {
        ev.preventDefault();
        var name = row.getAttribute("data-name");
        var label = row.getAttribute("data-label");
        pickSelection(name, label);
        hideDropdown();
        $("searchInput").value = "";
      });
    });
  }

  // -------------------------------
  // Suggestions (same as original)
  // -------------------------------
  function loadSuggestions(txt){
    var q = (txt || "").trim();
    if (!STATE.mode) return;

    setMsg("جاري البحث...");

    var items = [];
    var isCustomer = (STATE.mode === "Customer" || STATE.mode === "Exception");

    if (isCustomer) {
      var f = ["name","customer_name","customer_group","territory"];
      var p1 = get_list("Customer", f, q ? [["name","like","%"+q+"%"]] : [], 20);
      var p2 = q ? get_list("Customer", f, [["customer_name","like","%"+q+"%"]], 20) : Promise.resolve([]);

      Promise.all([p1, p2]).then(function(results) {
        var seen = {};
        results[0].concat(results[1]).forEach(function(d) {
          if (seen[d.name]) return;
          seen[d.name] = true;
          items.push({
            name: d.name,
            label: d.customer_name || d.name,
            sub: [d.name, d.customer_group, d.territory].filter(Boolean).join(" • ")
          });
        });
        showDropdown(items.slice(0, 20));
        setMsg("جاهز");
      }).catch(function(e) {
        console.error(e);
        hideDropdown();
        setMsg("فشل البحث (تحقق من الصلاحيات).");
      });

    } else {
      var f2 = ["name","sales_person_name","is_group"];
      var p3 = get_list("Sales Person", f2, q ? [["name","like","%"+q+"%"]] : [], 20);
      var p4 = q ? get_list("Sales Person", f2, [["sales_person_name","like","%"+q+"%"]], 20) : Promise.resolve([]);

      Promise.all([p3, p4]).then(function(results) {
        var seen = {};
        results[0].concat(results[1]).forEach(function(d) {
          if (seen[d.name]) return;
          seen[d.name] = true;
          items.push({
            name: d.name,
            label: d.sales_person_name || d.name,
            sub: [d.name, (d.is_group ? "مجموعة" : "فرد")].filter(Boolean).join(" • ")
          });
        });
        showDropdown(items.slice(0, 20));
        setMsg("جاهز");
      }).catch(function(e) {
        console.error(e);
        hideDropdown();
        setMsg("فشل البحث (تحقق من الصلاحيات).");
      });
    }
  }

  // -------------------------------
  // Selection + status (same as original)
  // -------------------------------
  function clearSelection(){
    STATE.selected = null;
    $("selectedBox").innerHTML = '<div class="edx-empty" id="selectedEmpty">لا يوجد تحديد.</div>';
    $("infoBox").innerHTML = '<div class="edx-info-title">الحالة</div><div class="edx-info-text">اختر سجل لعرض الحالة.</div>';
  }

  function renderSelection(sel){
    $("selectedBox").innerHTML = '<div class="edx-chip">'
      + '<div>'
      +   '<div class="edx-chip-name">' + esc(sel.label) + '</div>'
      +   '<div class="edx-chip-sub">' + esc(sel.name) + ' • ' + esc(sel.doctype) + '</div>'
      + '</div>'
      + '<button class="edx-chip-x" id="btnRemoveSel" title="إزالة">×</button>'
      + '</div>';

    $("btnRemoveSel").addEventListener("click", clearSelection);

    var dot, txt;
    if (STATE.mode === "Exception") {
      dot = sel.enabled ? "var(--warn)" : "var(--bad)";
      txt = sel.enabled ? "مستثنى من الحظر ✅" : "لا يوجد استثناء ❌";
    } else {
      dot = sel.enabled ? "var(--good)" : "var(--bad)";
      txt = sel.enabled ? "مفعل" : "معطل";
    }

    $("infoBox").innerHTML = '<div class="edx-info-title">الحالة</div>'
      + '<div class="edx-info-text">'
      +   '<span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:' + dot + ';margin-left:8px;"></span>'
      +   '<b>' + esc(txt) + '</b>'
      + '</div>'
      + '<div class="edx-info-text" style="margin-top:6px;">'
      +   'فتح في النظام: '
      +   '<a href="/app/' + (sel.doctype === "Customer" ? "customer" : "sales-person") + '/' + encodeURIComponent(sel.name) + '" target="_blank">' + esc(sel.name) + '</a>'
      + '</div>';
  }

  function pickSelection(name, label){
    if (!STATE.mode) return;

    setMsg("جاري تحميل الحالة...");

    var doctype = (STATE.mode === "Exception") ? "Customer" : STATE.mode;

    if (doctype === "Customer" && STATE.mode === "Exception") {
      get_value("Customer", name, "custom_collect_exception").then(function(exc) {
        var enabled = (exc === 1 || exc === true || exc === "1");
        STATE.selected = { doctype: doctype, name: name, label: label || name, enabled: enabled };
        renderSelection(STATE.selected);
        setMsg("جاهز");
      }).catch(function(e) {
        console.error(e);
        setMsg("فشل تحميل الحالة (تحقق من الصلاحيات).");
      });
    } else if (doctype === "Customer") {
      get_value("Customer", name, "disabled").then(function(disabled) {
        var enabled = !(disabled === 1 || disabled === true || disabled === "1");
        STATE.selected = { doctype: doctype, name: name, label: label || name, enabled: enabled };
        renderSelection(STATE.selected);
        setMsg("جاهز");
      }).catch(function(e) {
        console.error(e);
        setMsg("فشل تحميل الحالة (تحقق من الصلاحيات).");
      });
    } else {
      get_value("Sales Person", name, "enabled").then(function(en) {
        var enabled = !!en;
        STATE.selected = { doctype: doctype, name: name, label: label || name, enabled: enabled };
        renderSelection(STATE.selected);
        setMsg("جاهز");
      }).catch(function(e) {
        get_value("Sales Person", name, "disabled").then(function(dis) {
          var enabled = !(dis === 1 || dis === true || dis === "1");
          STATE.selected = { doctype: doctype, name: name, label: label || name, enabled: enabled };
          renderSelection(STATE.selected);
          setMsg("جاهز");
        }).catch(function(e2) {
          console.error(e2);
          setMsg("فشل تحميل الحالة (تحقق من الصلاحيات).");
        });
      });
    }
  }

  // -------------------------------
  // Enable/Disable (same as original)
  // -------------------------------
  function setCustomerEnabled(name, enabledBool){
    return call("frappe.client.set_value", {
      doctype: "Customer", name: name,
      fieldname: "disabled",
      value: enabledBool ? 0 : 1
    });
  }

  function setSalesPersonEnabled(name, enabledBool){
    return call("frappe.client.set_value", {
      doctype: "Sales Person", name: name,
      fieldname: "enabled",
      value: enabledBool ? 1 : 0
    }).catch(function() {
      return call("frappe.client.set_value", {
        doctype: "Sales Person", name: name,
        fieldname: "disabled",
        value: enabledBool ? 0 : 1
      });
    });
  }

  function applyToggle(enable){
    if (!STATE.selected) { setMsg("اختر سجل أولاً."); return; }

    var sel = STATE.selected;
    setMsg((enable ? "جاري التفعيل" : "جاري التعطيل") + ": " + sel.name + " ...");

    var action;
    if (STATE.mode === "Exception") {
      action = call("frappe.client.set_value", {
        doctype: "Customer", name: sel.name,
        fieldname: "custom_collect_exception",
        value: enable ? 1 : 0
      });
    } else if (sel.doctype === "Customer") {
      action = setCustomerEnabled(sel.name, enable);
    } else {
      action = setSalesPersonEnabled(sel.name, enable);
    }

    action.then(function() {
      pickSelection(sel.name, sel.label);
      loadFlaggedList(STATE.mode);
      setMsg("تم ✅");
    }).catch(function(e) {
      console.error(e);
      setMsg("فشل التحديث (تحقق من الصلاحيات/Workflow).");
    });
  }

  // -------------------------------
  // Init
  // -------------------------------
  frappe.ready(function () {
    if (isGuest()) {
      window.location.href = "/login?redirect-to=/enable-disable_2";
      return;
    }

    // nav buttons use inline onclick

    $("chooseCustomer").addEventListener("click", function() { showManage("Customer"); });
    $("chooseSalesPerson").addEventListener("click", function() { showManage("Sales Person"); });
    $("chooseException").addEventListener("click", function() { showManage("Exception"); });
    $("btnBack").addEventListener("click", showHome);

    $("searchInput").addEventListener("focus", function() { loadSuggestions(""); });
    $("searchInput").addEventListener("input", debounce(function(e) {
      loadSuggestions(e.target.value || "");
    }, 200));

    document.addEventListener("pointerdown", function(e) {
      var dd = $("dropdown");
      var sb = $("searchInput");
      if (dd.classList.contains("hidden")) return;
      if (dd.contains(e.target) || sb.contains(e.target)) return;
      hideDropdown();
    });

    $("btnEnable").addEventListener("click", function() { applyToggle(true); });
    $("btnDisable").addEventListener("click", function() { applyToggle(false); });

    showHome();
  });

})();

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');

footer, .web-footer, .page-footer, .footer-section { display: none !important; }

:root { 
    --primary-blue: #004b80; 
    --bg-main: #bfeaf4;
    --yellow: #ffd23c;
    --yellow-light: #ffe26b;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
}

body { direction: rtl; background: var(--bg-main) !important; font-family: "Cairo", sans-serif !important; margin: 0; padding: 0; }

/* ===== Topbar + Drawer ===== */
.mobile-topbar { position: fixed; top: 0; left: 0; right: 0; height: 50px; background: rgba(255, 255, 255, 0.35) !important; backdrop-filter: blur(6px) !important; border-bottom: 1px solid rgba(0,0,0,0.15) !important; display: flex; justify-content: space-between; align-items: center; padding: 0 12px; z-index: 1100; box-shadow: var(--shadow); }
.topbar-right, .topbar-left { display: flex; align-items: center; gap: 6px; }
.topbar-text { font-weight: 900; font-size: 15px; color: #0b1b22; }
.icon-btn { background-color: var(--yellow-light) !important; border: 1px solid rgba(0,0,0,0.25) !important; border-radius: 999px !important; font-size: 16px; cursor: pointer; color: #333; width: 38px; height: 38px; display: flex; align-items: center; justify-content: center; padding: 0; box-shadow: var(--shadow); }

.drawer { position: fixed; top: 0; right: 0; width: 280px; height: 100%; background: white; z-index: 1201; box-shadow: -2px 0 10px rgba(0,0,0,0.15); display: flex; flex-direction: column; text-align: right; transition: 0.3s; }
.drawer.hidden, .drawer-overlay.hidden { display: none !important; }
.drawer-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: 1200; }
.drawer-header { padding: 24px 16px; background: var(--yellow); border-bottom: 1px solid rgba(0,0,0,0.1); }
.drawer-title { font-weight: 900; font-size: 16px; }
.drawer-sub { font-size: 12px; color: #666; margin-top: 4px; font-weight: 700; }
.drawer-item { display: block; padding: 14px 16px; border-bottom: 1px solid #f0f0f0; color: #333; text-decoration: none; font-size: 14px; font-weight: 700; }
.drawer-footer { margin-top: auto; padding: 10px; }
.drawer-logout { color: #d32f2f; font-weight: 900; text-decoration: none; display:block; text-align:center; padding: 16px; border-top: 1px solid #eee; }

/* ===== Page Body ===== */
.order-form-body { padding: 62px 12px 100px 12px; }
.meta-container { background: rgba(255, 255, 255, 0.4); backdrop-filter: blur(6px); padding: 12px; border-radius: 14px; border: 1px solid rgba(0,0,0,0.1); margin-bottom: 15px; box-shadow: var(--shadow); }
.order-meta-row { display: flex; justify-content: space-between; font-size: 12px; font-weight: 900; align-items: center; }
.sub-meta { margin-top: 6px; font-size: 11px; color: #444; font-weight: 700; }
.status-pill { background: var(--yellow-light); color: #0b1b22; padding: 2px 12px; border-radius: 999px; font-size: 10px; font-weight: 900; border: 1px solid rgba(0,0,0,0.1); }
.status-pill.submitted { background:#eaf7ee; color:#2e7d32; }

.mobile-form-group { margin-bottom: 15px; }
.mobile-form-label { display: block; margin-bottom: 6px; font-size: 12px; font-weight: 900; color: #0b1b22; }
.mobile-form-input { width: 100%; height: 44px; padding: 0 15px; border-radius: 999px; border: 1px solid rgba(0,0,0,0.2); font-size: 14px; font-weight: 700; background: var(--yellow-light); }

/* ===== Items ===== */
.items-container { background: rgba(255, 255, 255, 0.4); border: 1px solid rgba(0,0,0,0.1); border-radius: 14px; padding: 4px; min-height: 60px; box-shadow: var(--shadow); }
.items-empty { text-align: center; color: #444; font-size: 13px; padding: 20px; font-weight: 700; }
.item-row { display: flex; flex-direction: column; border-bottom: 1px solid rgba(0,0,0,0.05); padding: 12px 8px; }
.item-row-name { font-size: 13px; font-weight: 900; color: #212529; }
.item-row-sub { font-size: 12px; color:#444; margin-top: 4px; font-weight: 700; }
.item-row-badges { display: flex; gap: 8px; align-items: center; margin-top: 8px; }
.item-row-badge { background: var(--yellow-light); color: #0b1b22; padding: 2px 10px; border-radius: 999px; font-size: 11px; font-weight: 900; }
.item-delete { color: #fa5252; padding: 4px; font-size: 18px; margin-right: 8px; cursor:pointer; }

.add-item-btn { width: 100%; background: var(--yellow); color: #0b1b22; border: 1px solid rgba(0,0,0,0.2); padding: 12px; border-radius: 999px; margin-top: 12px; font-weight: 900; font-size: 14px; box-shadow: var(--shadow); }

/* ===== Bottom bar ===== */
.mobile-bottom-bar { position: fixed; bottom: 0; left: 0; right: 0; background: rgba(255, 255, 255, 0.4); backdrop-filter: blur(6px); border-top: 1px solid rgba(0,0,0,0.1); padding: 12px; display: flex; gap: 8px; z-index: 1000; box-shadow: var(--shadow); }
.bottom-bar-btn { flex: 1; height: 42px; border: 1px solid rgba(0,0,0,0.2); background: var(--yellow-light); border-radius: 999px; font-weight: 900; font-size: 12px; color: #0b1b22; display: flex; align-items: center; justify-content: center; }
.bottom-bar-btn-primary { background: var(--yellow); border: 1px solid rgba(0,0,0,0.3); }
.bottom-bar-btn-success { background: #2e7d32; color: #fff; border: none; }

/* ===== Modals ===== */
.modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.6); display: none; justify-content: center; align-items: center; z-index: 2000; backdrop-filter: blur(4px); }
.modal-box { background: #fff; width: 92%; max-width: 420px; padding: 18px; border-radius: 16px; text-align: right; box-shadow: 0 10px 25px rgba(0,0,0,0.2); }
.modal-title { text-align: center; font-weight: 900; font-size: 16px; margin-bottom: 14px; color: #212529; }

.qty-row { display:flex; align-items:center; justify-content:center; }
.qty-btn { width: 44px; height: 44px; border-radius: 999px; background: var(--yellow); color: #0b1b22; border: 1px solid rgba(0,0,0,0.2); font-size: 20px; font-weight: 900; cursor:pointer; }
.qty-input { flex: 1; max-width: 100px; height: 44px; text-align: center; margin: 0 12px; border: 1px solid rgba(0,0,0,0.2); border-radius: 999px; font-weight: 900; background: var(--yellow-light); }

.modal-footer-row { display: flex; gap: 10px; margin-top: 16px; }
.modal-footer-btn { flex: 1; height: 44px; border-radius: 999px; font-weight: 900; font-size: 14px; border: 1px solid rgba(0,0,0,0.2); }
.modal-footer-cancel { background: #f1f3f5; color: #495057; }
.modal-footer-save { background: var(--yellow); color: #0b1b22; }

/* Search list */
.select-list-box { background: #fff; width: 95%; max-height: 85vh; padding: 16px; border-radius: 16px; display: flex; flex-direction: column; box-shadow: 0 15px 35px rgba(0,0,0,0.3); }
.select-list-title { font-weight: 900; font-size: 16px; text-align:center; }
.select-list-search { width: 100%; height: 44px; padding: 0 15px; border: 1px solid rgba(0,0,0,0.2); border-radius: 999px; font-size: 14px; margin-top: 12px; background: var(--yellow-light); font-weight: 700; }
.select-list-scroller { overflow-y: auto; flex: 1; margin: 12px 0; border: 1px solid #f1f3f5; border-radius: 10px; }
.select-list-row { padding: 14px 12px; border-bottom: 1px solid #f1f3f5; display: flex; align-items: center; cursor: pointer; gap: 10px; }
.select-list-text { font-size: 14px; color: #212529; font-weight:900; }
.select-list-done-btn { background: var(--yellow); color: #0b1b22; border: 1px solid rgba(0,0,0,0.2); padding: 10px 24px; border-radius: 999px; font-weight: 900; cursor:pointer; }

/* Batches */
.batch-list-container { max-height: 190px; overflow-y: auto; border: 1px solid #eee; border-radius: 10px; background: #fcfcfc; }
.batch-row { display: flex; align-items: center; padding: 10px; border-bottom: 1px solid #f1f1f1; gap: 10px; cursor:pointer; }
.batch-row.selected { background: #f0f7ff; border-right: 4px solid var(--primary-blue); }
.batch-date { font-weight: 900; font-size: 13px; color: #212529; }
.batch-qty { font-size: 12px; font-weight: 900; color: #2b8a3e; background: #ebfbee; padding: 2px 8px; border-radius: 6px; }

/* Frappe Search Fix */
input[placeholder*="بحث"]{ height: 56px !important; font-size: 18px !important; padding: 12px 14px !important; border-radius: 12px !important; font-family: "Cairo", sans-serif; font-weight: 700; }
