javascript:
// ================= CONFIG =================
const ERPNEXT_BASE_URL = window.location.origin;

let LOGGED_USER_EMAIL = (window.LOGGED_IN_USER && window.LOGGED_IN_USER !== "{{ frappe.session.user }}")
  ? window.LOGGED_IN_USER
  : null;

// Current doc
let currentName = null;
let currentDoc = null;

// Warehouses
let warehouseList = [];
let fromWarehouse = "";
let toWarehouse = "";

// Items master & qty by warehouse
let itemMaster = [];
let itemCodeByLabel = {};
let itemLabelByCode = {};
let itemQtyByCode = {}; // based on SELECTED fromWarehouse

// Cart items
// Each item: {code, name, qty, batch_no, expiry_date, s_warehouse, t_warehouse}
let currentItems = [];

// Modal state
let editingItemIndex = null;
let currentBatchLimit = 0;

// ============= COOKIE / CSRF HELPERS =============
function getCookie(name) {
  const value = "; " + document.cookie;
  const parts = value.split("; " + name + "=");
  if (parts.length === 2) return parts.pop().split(";").shift();
  return null;
}

function getCsrfToken() {
  if (window.frappe && frappe.csrf_token) return frappe.csrf_token;
  if (typeof window.CSRF_TOKEN === "string" && window.CSRF_TOKEN && window.CSRF_TOKEN !== "{{ csrf_token }}") return window.CSRF_TOKEN;
  const meta = document.querySelector('meta[name="csrf-token"]');
  if (meta && meta.content && meta.content !== "{{ csrf_token }}") return meta.content;
  const cookieNames = ["csrf_token", "X-Frappe-CSRF-Token", "frappe-csrf-token"];
  for (const n of cookieNames) {
    const v = getCookie(n);
    if (v) return v;
  }
  return null;
}

// ============= ERP REQUEST =============
async function erpRequest(path, options = {}) {
  const url = path.startsWith("http") ? path : ERPNEXT_BASE_URL + path;
  const headers = Object.assign({}, options.headers || {});
  const method  = (options.method || "GET").toUpperCase();

  if (method !== "GET") {
    headers["Content-Type"] = "application/json";
    const token = getCsrfToken();
    if (token) headers["X-Frappe-CSRF-Token"] = token;
  }

  const resp = await fetch(url, Object.assign({}, options, { method, headers, credentials: "include" }));
  const txt = await resp.text();
  if (!resp.ok) {
    console.error("ERPNext error:", resp.status, txt);
    const err = new Error("Status " + resp.status);
    err.responseBody = txt;
    throw err;
  }
  try { return JSON.parse(txt); } catch { return txt; }
}

// ============= UI HELPERS =============
function setStatusPill(docstatus) {
  const pill = document.getElementById("orderStatusPill");
  if (!pill) return;
  pill.classList.remove("submitted", "cancelled");

  if (docstatus === 1) {
    pill.textContent = "معتمد";
    pill.classList.add("submitted");
  } else if (docstatus === 2) {
    pill.textContent = "ملغي";
    pill.classList.add("cancelled");
  } else {
    pill.textContent = "مسودة";
  }
}

function isLocked() {
  if (!currentDoc) return false;
  return Number(currentDoc.docstatus || 0) !== 0;
}

function goBackToList() {
  window.location.href = "/Material-Transfer";
}

function getParam(name) {
  const u = new URLSearchParams(window.location.search);
  return u.get(name);
}

// ============= DRAWER =============
function toggleDrawer() {
  const d = document.getElementById("drawer");
  const o = document.getElementById("drawerOverlay");
  if (d.classList.contains("hidden")) {
    d.classList.remove("hidden");
    o.classList.remove("hidden");
  } else {
    closeDrawer();
  }
}
function closeDrawer() {
  document.getElementById("drawer").classList.add("hidden");
  document.getElementById("drawerOverlay").classList.add("hidden");
}

// ============= LOAD MASTERS =============
async function ensureLoggedUser() {
  if (!LOGGED_USER_EMAIL || LOGGED_USER_EMAIL === "Guest") {
    const who = await erpRequest("/api/method/frappe.auth.get_logged_user");
    LOGGED_USER_EMAIL = (who.message || who || "").trim();
  }
  document.getElementById("userView").textContent = LOGGED_USER_EMAIL || "-";
}

async function loadWarehouses() {
  const resp = await erpRequest(`/api/resource/Warehouse?fields=["name","warehouse_name","disabled","is_group"]&filters=` +
    encodeURIComponent(JSON.stringify([["disabled","=",0],["is_group","=",0]])) +
    `&limit_page_length=5000`);

  warehouseList = (resp.data || []).map(w => w.name);
}

async function loadItemsMaster() {
  itemMaster = [];
  itemCodeByLabel = {};
  itemLabelByCode = {};

  const iData = await erpRequest(`/api/resource/Item?fields=["name","item_name","disabled"]&filters=` +
    encodeURIComponent(JSON.stringify([["disabled","=",0]])) +
    `&limit_page_length=5000`);

  (iData.data || []).forEach(d => {
    const label = d.name + (d.item_name ? " - " + d.item_name : "");
    itemMaster.push(label);
    itemCodeByLabel[label] = d.name;
    itemLabelByCode[d.name] = label;
  });
}

async function loadQtyForWarehouse(wh) {
  itemQtyByCode = {};
  if (!wh) return;

  // IMPORTANT: No FEFO blocking, just show qty by Bin for FROM warehouse
  const bData = await erpRequest(`/api/resource/Bin?fields=["item_code","actual_qty"]&filters=` +
    encodeURIComponent(JSON.stringify([["warehouse","=", wh]])) +
    `&limit_page_length=5000`);

  (bData.data || []).forEach(b => itemQtyByCode[b.item_code] = b.actual_qty);
}

// ============= LIST SELECT MODAL =============
function openListModal(type) {
  if (isLocked()) return;

  const modal = document.getElementById("listSelectModal");
  const search = document.getElementById("listSelectSearch");
  modal.style.display = "flex";
  search.value = "";

  if (type === "fromWarehouse") {
    document.getElementById("listSelectTitle").textContent = "اختيار مخزن (من)";
    renderListOptions(warehouseList, "fromWarehouse");
    search.oninput = (e) => renderListOptions(
      warehouseList.filter(n => n.toLowerCase().includes(e.target.value.toLowerCase())),
      "fromWarehouse"
    );
  }

  if (type === "toWarehouse") {
    document.getElementById("listSelectTitle").textContent = "اختيار مخزن (إلى)";
    renderListOptions(warehouseList, "toWarehouse");
    search.oninput = (e) => renderListOptions(
      warehouseList.filter(n => n.toLowerCase().includes(e.target.value.toLowerCase())),
      "toWarehouse"
    );
  }

  if (type === "item") {
    if (!fromWarehouse) {
      alert("اختار مخزن (من) أولاً");
      modal.style.display = "none";
      return;
    }
    document.getElementById("listSelectTitle").textContent = "اختيار الصنف";
    renderListOptions(itemMaster, "item");
    search.oninput = (e) => renderListOptions(
      itemMaster.filter(n => n.toLowerCase().includes(e.target.value.toLowerCase())),
      "item"
    );
  }
}

function renderListOptions(list, type) {
  const scroller = document.getElementById("listSelectScroller");
  scroller.innerHTML = "";

  if (!list.length) {
    scroller.innerHTML = `<div style="padding:15px;text-align:center;color:#999;">No results</div>`;
    return;
  }

  list.forEach(txt => {
    const row = document.createElement("div");
    row.className = "select-list-row";

    let dotColor = "#2e7d32";
    let extraHtml = "";

    if (type === "item") {
      const code = itemCodeByLabel[txt];
      const qty = Number(itemQtyByCode[code] || 0);

      // color based on qty
      if (qty <= 0) dotColor = "#c62828";
      else if (qty <= 9) dotColor = "#f57c00";
      else if (qty <= 99) dotColor = "#fbc02d";
      else dotColor = "#2e7d32";

      extraHtml = `<div class="select-list-extra">${qty}</div>`;
    }

    row.innerHTML = `
      <div class="select-list-dot" style="background:${dotColor}"></div>
      <div class="select-list-text">${txt}</div>
      ${extraHtml}
    `;

    row.onclick = async () => {
      if (type === "fromWarehouse") {
        fromWarehouse = txt;
        document.getElementById("fromWarehouseInput").value = txt;

        // Refresh qty lookup when FROM warehouse changes
        await loadQtyForWarehouse(fromWarehouse);

        // If items already exist, update their s_warehouse (and keep t_warehouse)
        currentItems = currentItems.map(it => ({
          ...it,
          s_warehouse: fromWarehouse,
          t_warehouse: toWarehouse || it.t_warehouse || ""
        }));
        renderItems();
      }

      if (type === "toWarehouse") {
        toWarehouse = txt;
        document.getElementById("toWarehouseInput").value = txt;

        // Update items t_warehouse
        currentItems = currentItems.map(it => ({
          ...it,
          s_warehouse: fromWarehouse || it.s_warehouse || "",
          t_warehouse: toWarehouse
        }));
        renderItems();
      }

      if (type === "item") {
        document.getElementById("itemNameInput").value = txt;
        const code = itemCodeByLabel[txt];
        await fetchItemBatches(code, null);
        updateQtyHint();
      }

      document.getElementById("listSelectModal").style.display = "none";
    };

    scroller.appendChild(row);
  });
}

// ============= BATCH FETCH (SERVER SCRIPT) =============
async function fetchItemBatches(itemCode, preSelectedBatch = null) {
  const container = document.getElementById("batchListContainer");
  currentBatchLimit = 0;

  if (!itemCode) {
    container.innerHTML = `<div class="batch-placeholder">Select an item</div>`;
    return;
  }
  if (!fromWarehouse) {
    container.innerHTML = `<div class="batch-placeholder" style="color:#c00;">اختار مخزن (من) أولاً</div>`;
    return;
  }

  container.innerHTML = `<div class="batch-placeholder" style="color:#666;">Scanning warehouse stock...</div>`;

  try {
    // Uses your existing method from split-sales
    const response = await erpRequest("/api/method/get_warehouse_batches", {
      method: "POST",
      body: JSON.stringify({ item_code: itemCode, warehouse: fromWarehouse })
    });

    const batches = response.message || [];
    renderBatchList(batches, preSelectedBatch, itemCode);
  } catch (e) {
    console.error("Batch fetch error", e);
    container.innerHTML = `<div class="batch-placeholder" style="color:#c00;">Error fetching batches</div>`;
  }
}

function renderBatchList(batches, preSelected, itemCode) {
  const container = document.getElementById("batchListContainer");
  container.innerHTML = "";

  // IMPORTANT: "show all batches" - no FEFO blocking
  if (!batches.length) {
    container.innerHTML = `<div class="batch-placeholder">لا يوجد رصيد لهذا الصنف في ${fromWarehouse}</div>`;
    currentBatchLimit = 0;
    return;
  }

  const today = new Date().toISOString().split("T")[0];

  batches.forEach((b, idx) => {
    // qty in batch returned by server (b.batch_qty)
    // For transfer: we still prevent picking more than available for that batch
    // (no FEFO sorting/locking, just availability)
    let inCart = 0;
    currentItems.forEach((it, cartIdx) => {
      if (it.code === itemCode && it.batch_no === (b.name || "")) {
        if (editingItemIndex === null || editingItemIndex !== cartIdx) inCart += Number(it.qty || 0);
      }
    });

    let available = Number(b.batch_qty || 0) - inCart;
    if (available < 0) available = 0;

    const row = document.createElement("div");
    row.className = "batch-row";
    row.setAttribute("data-batch-id", b.name || "");
    row.setAttribute("data-expiry-date", b.expiry_date || "");
    row.setAttribute("data-limit", available);

    const isDisabled = available <= 0;
    if (isDisabled) row.classList.add("disabled");

    // selection logic
    const shouldSelect =
      (preSelected && preSelected === b.name) ||
      (!preSelected && idx === 0 && available > 0);

    if (shouldSelect && !isDisabled) {
      row.classList.add("selected");
      currentBatchLimit = available;
      document.getElementById("qtyInput").value = 1;
    }

    let dateColor = (b.expiry_date && b.expiry_date < today) ? "#c00" : "#333";
    let dateText = b.expiry_date || "N/A";
    if (b.expiry_date && b.expiry_date < today) dateText += " (Expired)";

    row.innerHTML = `
      <div class="batch-radio"></div>
      <div class="batch-info">
        <div class="batch-date" style="color:${dateColor}">${dateText}</div>
        <div class="batch-id">${b.name || "<i>(Generic)</i>"}</div>
      </div>
      <div style="text-align:left;">
        <div class="batch-qty">${available}</div>
        ${inCart > 0 ? `<div style="font-size:10px;color:#999;margin-top:4px;">(In Cart: ${inCart})</div>` : ""}
      </div>
    `;

    row.onclick = () => {
      if (isDisabled) return;
      document.querySelectorAll(".batch-row").forEach(r => r.classList.remove("selected"));
      row.classList.add("selected");
      currentBatchLimit = Number(row.getAttribute("data-limit") || 0);
      document.getElementById("qtyInput").value = 1;
      updateQtyHint();
    };

    container.appendChild(row);
  });

  updateQtyHint();
}

function updateQtyHint() {
  const hint = document.getElementById("qtyHint");
  if (!hint) return;

  const selectedRow = document.querySelector(".batch-row.selected");
  if (!selectedRow) {
    hint.textContent = "";
    return;
  }
  const limit = Number(selectedRow.getAttribute("data-limit") || 0);
  hint.textContent = `الحد الأقصى من هذه الدفعة: ${limit}`;
}

// ============= ITEMS RENDER =============
function renderItems() {
  const con = document.getElementById("itemsContainer");
  con.innerHTML = "";
  if (!currentItems.length) {
    con.innerHTML = `<div class="items-empty">لا توجد أصناف مضافة</div>`;
    return;
  }

  currentItems.forEach((it, idx) => {
    const row = document.createElement("div");
    row.className = "item-row";

    const exp = it.expiry_date ? it.expiry_date : "(Generic)";
    const batch = it.batch_no ? it.batch_no : "(Generic)";
    const swh = it.s_warehouse || fromWarehouse || "-";
    const twh = it.t_warehouse || toWarehouse || "-";

    row.innerHTML = `
      <div class="item-row-name">${it.name}</div>
      <div class="item-row-sub">
        Batch: <b>${batch}</b> | Exp: <b style="color:#e67e22">${exp}</b>
      </div>
      <div class="item-row-sub">
        From: <b>${swh}</b> | To: <b>${twh}</b>
      </div>
      <div class="item-row-badges">
        <span class="item-row-badge">× ${it.qty}</span>
        <span class="item-delete" onclick="event.stopPropagation(); deleteItem(${idx})">✕</span>
      </div>
    `;

    row.onclick = () => { if (!isLocked()) openItemModal(idx); };
    con.appendChild(row);
  });
}

function deleteItem(idx) {
  if (isLocked()) return;
  currentItems.splice(idx, 1);
  renderItems();
}

// ============= ITEM MODAL =============
async function openItemModal(idx = null) {
  if (isLocked()) return;
  if (!fromWarehouse || !toWarehouse) {
    alert("اختار (من مخزن) و (إلى مخزن) أولاً");
    return;
  }

  editingItemIndex = idx;
  document.getElementById("itemModal").style.display = "flex";

  if (idx !== null) {
    const it = currentItems[idx];
    document.getElementById("itemNameInput").value = it.name;
    document.getElementById("qtyInput").value = it.qty || 1;

    await fetchItemBatches(it.code, it.batch_no || null);

    // ensure selected batch -> limit
    const selected = document.querySelector(`.batch-row[data-batch-id="${CSS.escape(it.batch_no || "")}"]`);
    if (selected) {
      document.querySelectorAll(".batch-row").forEach(r => r.classList.remove("selected"));
      selected.classList.add("selected");
      currentBatchLimit = Number(selected.getAttribute("data-limit") || 0);
    }
    updateQtyHint();
  } else {
    document.getElementById("itemNameInput").value = "";
    document.getElementById("qtyInput").value = 1;
    document.getElementById("batchListContainer").innerHTML = `<div class="batch-placeholder">اختر صنفاً أولاً</div>`;
    currentBatchLimit = 0;
    updateQtyHint();
  }
}

function closeItemModal() {
  document.getElementById("itemModal").style.display = "none";
}

function clampQtyToLimit() {
  const qtyEl = document.getElementById("qtyInput");
  let qty = Number(qtyEl.value || 0);
  if (qty < 1) qty = 1;

  if (currentBatchLimit > 0 && qty > currentBatchLimit) {
    qty = currentBatchLimit;
  }
  qtyEl.value = qty;
}

// ============= SAVE / SUBMIT / DELETE =============
function validateBeforeSave() {
  if (!fromWarehouse) return "اختار مخزن (من)";
  if (!toWarehouse) return "اختار مخزن (إلى)";
  if (fromWarehouse === toWarehouse) return "لا يمكن أن يكون (من) و (إلى) نفس المخزن";
  if (!currentItems.length) return "أضف صنفاً واحداً على الأقل";
  return null;
}

function buildStockEntryDoc() {
  // Stock Entry (Material Transfer)
  return {
    doctype: "Stock Entry",
    purpose: "Material Transfer",
    stock_entry_type: "Material Transfer",
    posting_date: document.getElementById("postingDate").value,
    remarks: document.getElementById("remarksInput").value || "",
    items: currentItems.map(it => ({
      item_code: it.code,
      qty: Number(it.qty || 0),
      batch_no: it.batch_no || null,
      s_warehouse: it.s_warehouse || fromWarehouse,
      t_warehouse: it.t_warehouse || toWarehouse
    }))
  };
}

async function saveDoc() {
  if (isLocked()) return alert("Locked");

  const err = validateBeforeSave();
  if (err) return alert(err);

  const btn = document.getElementById("btnSave");
  btn.textContent = "Saving...";
  btn.disabled = true;

  try {
    const doc = buildStockEntryDoc();
    let resp;

    if (currentName) {
      resp = await erpRequest(`/api/resource/Stock Entry/${encodeURIComponent(currentName)}`, {
        method: "PUT",
        body: JSON.stringify(doc)
      });
    } else {
      resp = await erpRequest(`/api/resource/Stock Entry`, {
        method: "POST",
        body: JSON.stringify(doc)
      });
    }

    const savedName = (resp.data && resp.data.name) ? resp.data.name : (resp.name || null);
    if (savedName) currentName = savedName;

    // Reload the saved doc to sync UI
    await loadExistingDoc(currentName);

    alert("✅ Saved!");
    // IMPORTANT: fallback to main list page after save (your request)
    window.location.href = "/Material-Transfer";
  } catch (e) {
    console.error(e);
    alert("Error: " + (e.message || e));
    btn.textContent = "حفظ";
    btn.disabled = false;
  }
}

async function submitDoc() {
  if (!currentName) {
    await saveDoc();
    return;
  }
  if (isLocked()) return alert("Already submitted");

  if (!confirm("اعتماد التحويل؟")) return;

  try {
    await erpRequest(`/api/resource/Stock Entry/${encodeURIComponent(currentName)}`, {
      method: "PUT",
      body: JSON.stringify({ docstatus: 1 })
    });

    alert("✅ Submitted!");
    window.location.href = "/Material-Transfer";
  } catch (e) {
    console.error(e);
    alert("فشل الاعتماد: " + (e.message || e));
  }
}

async function deleteDoc() {
  if (!currentName) return;
  if (isLocked()) return alert("Cannot delete submitted document");

  if (!confirm("حذف التحويل؟")) return;

  try {
    await erpRequest(`/api/resource/Stock Entry/${encodeURIComponent(currentName)}`, {
      method: "DELETE"
    });
    alert("✅ Deleted!");
    window.location.href = "/Material-Transfer";
  } catch (e) {
    console.error(e);
    alert("فشل الحذف: " + (e.message || e));
  }
}

function openPdf() {
  if (!currentName) return;

  // your custom Print Format name (must match exactly in ERPNext)
  const fmt = "Arabic Transfer Invoice";

  window.open(
    `/api/method/frappe.utils.print_format.download_pdf?doctype=Stock%20Entry&name=${encodeURIComponent(currentName)}&format=${encodeURIComponent(fmt)}`,
    "_blank"
  );
}


async function amendDoc() {
  if (!currentName || !currentDoc) return;
  if (Number(currentDoc.docstatus) !== 1) return alert("Only submitted documents can be amended");

  if (!confirm("سيتم إلغاء التحويل الحالي وإنشاء نسخة جديدة للتعديل. متأكد؟")) return;

  const amendBtn = document.getElementById("btnAmend");
  if (amendBtn) { amendBtn.textContent = "جاري..."; amendBtn.disabled = true; }

  try {
    const resp = await erpRequest("/api/method/stock_entry_amend", {
      method: "POST",
      body: JSON.stringify({ name: currentName })
    });

    const newName = resp.message && resp.message.new_name ? resp.message.new_name : (resp.new_name || null);
    if (newName) {
      alert("✅ تم إنشاء نسخة معدّلة: " + newName);
      window.location.href = "/stock-movement?name=" + encodeURIComponent(newName);
    } else {
      alert("✅ تم الإلغاء. أعد تحميل الصفحة.");
      location.reload();
    }
  } catch (e) {
    console.error(e);
    let errMsg = e.message || e;
    try {
      if (e.responseBody) {
        const errData = JSON.parse(e.responseBody);
        if (errData._server_messages) {
          const msgs = JSON.parse(errData._server_messages);
          // Get the last message (our Arabic one)
          const last = JSON.parse(msgs[msgs.length - 1] || "{}");
          errMsg = last.message || errMsg;
        }
      }
    } catch(x) {}
    alert(errMsg);
    if (amendBtn) { amendBtn.textContent = "✏️ تعديل"; amendBtn.disabled = false; }
  }
}

// ============= LOAD EXISTING =============
function pickWarehousesFromDoc(doc) {
  // Try doc fields, else infer from first item
  let fw = doc.from_warehouse || "";
  let tw = doc.to_warehouse || "";

  if ((!fw || !tw) && Array.isArray(doc.items) && doc.items.length) {
    fw = fw || (doc.items[0].s_warehouse || "");
    tw = tw || (doc.items[0].t_warehouse || "");
  }
  return { fw, tw };
}

async function loadExistingDoc(name) {
  const enriched = await erpRequest(`/api/method/get_ste_enriched?name=${encodeURIComponent(name)}`);
  const enrichedItems = (enriched.message || {}).items || [];
  const o = await erpRequest(`/api/resource/Stock Entry/${encodeURIComponent(name)}`);
  const d = o.data || o;
  d.items = (d.items || []).map((row, i) => {
    const e = enrichedItems[i] || {};
    return Object.assign(row, { batch_no: e.batch_no || "", expiry_date: e.expiry_date || "" });
  });

  currentDoc = d;
  currentName = d.name;

  document.getElementById("docNameView").textContent = d.name || "-";
  setStatusPill(Number(d.docstatus || 0));

  // fill meta
  const posting = d.posting_date || d.posting_time ? (d.posting_date || "") : (d.posting_date || "");
  if (posting) document.getElementById("postingDate").value = posting;

  document.getElementById("remarksInput").value = d.remarks || "";

  // Warehouses
  const { fw, tw } = pickWarehousesFromDoc(d);
  fromWarehouse = fw || "";
  toWarehouse = tw || "";

  document.getElementById("fromWarehouseInput").value = fromWarehouse;
  document.getElementById("toWarehouseInput").value = toWarehouse;

  // load qty for selected fromWarehouse (fix: qty + item selection)
  await loadQtyForWarehouse(fromWarehouse);

  // items
  currentItems = (d.items || []).map(row => ({
    code: row.item_code,
    name: itemLabelByCode[row.item_code] || row.item_name || row.item_code,
    qty: Number(row.qty || 0),
    batch_no: row.batch_no || "",
    expiry_date: row.custom_manual_expiry_date || row.expiry_date || "", // depends on your server payload
    s_warehouse: row.s_warehouse || fromWarehouse,
    t_warehouse: row.t_warehouse || toWarehouse
  }));

  renderItems();

  // buttons
  const ds = Number(d.docstatus || 0);
  if (ds === 0) {
    document.getElementById("btnDelete").style.display = "flex";
    document.getElementById("btnSubmit").style.display = "flex";
    document.getElementById("btnPrint").style.display = "none";
  } else if (ds === 1) {
    document.getElementById("btnDelete").style.display = "none";
    document.getElementById("btnSubmit").style.display = "none";
    document.getElementById("btnPrint").style.display = "flex";
    let amendBtn = document.getElementById("btnAmend");
    if (!amendBtn) {
      amendBtn = document.createElement("button");
      amendBtn.id = "btnAmend";
      amendBtn.className = "action-btn";
      amendBtn.style.cssText = "background:#e67e22;color:#fff;border:none;padding:10px 20px;border-radius:8px;font-size:15px;cursor:pointer;display:flex;align-items:center;gap:6px;";
      amendBtn.innerHTML = "✏️ تعديل";
      amendBtn.onclick = amendDoc;
      document.getElementById("btnPrint").parentElement.appendChild(amendBtn);
    }
    amendBtn.style.display = "flex";
  } else {
    document.getElementById("btnDelete").style.display = "none";
    document.getElementById("btnSubmit").style.display = "none";
    document.getElementById("btnPrint").style.display = "flex";
    let amendBtn = document.getElementById("btnAmend");
    if (amendBtn) amendBtn.style.display = "none";
  }
}

function setupNewDocDefaults() {
  const today = new Date().toISOString().split("T")[0];
  document.getElementById("postingDate").value = today;
  document.getElementById("docNameView").textContent = "جديد";
  setStatusPill(0);
  document.getElementById("btnDelete").style.display = "none";
  document.getElementById("btnSubmit").style.display = "none";
  document.getElementById("btnPrint").style.display = "none";
}

// ============= INIT =============
async function init() {
  await ensureLoggedUser();
  await loadWarehouses();
  await loadItemsMaster();

  const name = getParam("name");
  if (name) {
    await loadExistingDoc(name);
  } else {
    setupNewDocDefaults();

    // OPTIONAL: try default warehouse from user like split-sales (if exists)
    // If you want: auto-set from warehouse to user's warehouse
    try {
      const u = await erpRequest("/api/resource/User/" + encodeURIComponent(LOGGED_USER_EMAIL) +
        "?fields=" + encodeURIComponent(JSON.stringify(["warehouse"])));
      const wh = (u.data && u.data.warehouse) ? u.data.warehouse : null;
      if (wh) {
        fromWarehouse = wh;
        document.getElementById("fromWarehouseInput").value = wh;
        await loadQtyForWarehouse(fromWarehouse);
      }
    } catch (e) {
      console.warn("No default warehouse found for user", e);
    }
  }

  // Bind UI
  document.getElementById("fromWarehouseInput").onclick = () => openListModal("fromWarehouse");
  document.getElementById("toWarehouseInput").onclick = () => openListModal("toWarehouse");

  document.getElementById("addItemBtn").onclick = () => openItemModal(null);
  document.getElementById("itemNameInput").onclick = () => openListModal("item");

  document.getElementById("qtyPlusBtn").onclick = () => { const q = document.getElementById("qtyInput"); q.value = Number(q.value || 0) + 1; clampQtyToLimit(); };
  document.getElementById("qtyMinusBtn").onclick = () => { const q = document.getElementById("qtyInput"); q.value = Math.max(1, Number(q.value || 0) - 1); clampQtyToLimit(); };
  document.getElementById("qtyInput").addEventListener("input", clampQtyToLimit);

  document.getElementById("cancelItemBtn").onclick = closeItemModal;

  document.getElementById("saveItemBtn").onclick = () => {
    const label = document.getElementById("itemNameInput").value;
    if (!label) return alert("اختار الصنف");

    const code = itemCodeByLabel[label];
    const selectedRow = document.querySelector(".batch-row.selected");

    if (!selectedRow) return alert("اختار الدفعة");

    const batchNo = selectedRow.getAttribute("data-batch-id") || "";
    const expDate = selectedRow.getAttribute("data-expiry-date") || "";
    const limit = Number(selectedRow.getAttribute("data-limit") || 0);

    let qty = Number(document.getElementById("qtyInput").value || 0);
    if (qty < 1) qty = 1;
    if (limit > 0 && qty > limit) qty = limit;

    const item = {
      code,
      name: label,
      qty,
      batch_no: batchNo,
      expiry_date: expDate,
      s_warehouse: fromWarehouse,
      t_warehouse: toWarehouse
    };

    if (editingItemIndex !== null) currentItems[editingItemIndex] = item;
    else currentItems.push(item);

    closeItemModal();
    renderItems();
  };

  document.getElementById("btnSave").onclick = saveDoc;
  document.getElementById("btnSubmit").onclick = submitDoc;
  document.getElementById("btnDelete").onclick = deleteDoc;
  document.getElementById("btnPrint").onclick = openPdf;
}

document.addEventListener("DOMContentLoaded", init);

// expose globals used by HTML
window.toggleDrawer = toggleDrawer;
window.closeDrawer = closeDrawer;
window.goBackToList = goBackToList;

