@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');
header.navbar, .navbar, .top-navbar, footer, .web-footer { display:none !important; }
body { padding:0 !important; margin:0 !important; background:#bfeaf4; font-family:"Cairo",sans-serif; direction:rtl; color:#0b1b22; }
.page_content, .page-content, main, .main-section { margin:0 !important; padding:0 !important; }
:root {
  --bg:#bfeaf4; --yellow:#ffd23c; --yellow2:#ffe26b;
  --green:#2f8f3a; --green2:#2aa334;
  --shadow:0 10px 30px rgba(0,0,0,.08);
  --red:#ff4d4d; --blue:#1a73e8;
}

/* ── Topbar ── */
.sr-topbar {
  position:sticky; top:0; z-index:50;
  display:flex; align-items:center; justify-content:space-between;
  flex-direction:row;
  padding:10px 12px;
  background:rgba(255,255,255,.35);
  border-bottom:1px solid rgba(0,0,0,.15);
  backdrop-filter:blur(6px);
}
.sr-title { font-weight:900; font-size:16px; margin:0; }
.topbar-icons { display:flex; gap:8px; align-items:center; }
.sr-btn-icon {
  border:none; cursor:pointer; border-radius:999px;
  padding:8px 14px; font-weight:900; font-size:14px;
  box-shadow:var(--shadow); border:1px solid rgba(0,0,0,.25);
  background:var(--yellow2); font-family:"Cairo",sans-serif;
}
.sr-btn-icon#saveBtn {
  background:var(--green2); color:#fff;
  font-size:13px; padding:8px 16px;
}
.sr-btn-icon:active { transform:scale(0.95); }

/* ── Wrap ── */
.sr-wrap { max-width:1000px; margin:0 auto; padding:12px 14px 40px; }

/* ── Filters ── */
.sr-filters { display:grid; grid-template-columns:1fr auto; gap:10px; margin-bottom:10px; }
.sr-pill {
  background:var(--yellow); border:1px solid rgba(0,0,0,.25);
  border-radius:999px; padding:10px 16px;
  box-shadow:var(--shadow);
  display:flex; align-items:center; justify-content:space-between; gap:10px;
}
.sr-pill label { font-weight:900; white-space:nowrap; min-width:50px; }
.sr-pill select {
  flex:1; border:none; outline:none; background:transparent;
  font-family:"Cairo",sans-serif; font-weight:800; font-size:14px;
  text-align:right; cursor:pointer;
}

/* ── Summary bar ── */
.sr-summary {
  display:flex; gap:12px; flex-wrap:wrap;
  background:rgba(255,255,255,.4);
  border:1px solid rgba(0,0,0,.15);
  border-radius:12px; padding:8px 16px;
  margin-bottom:10px; font-weight:900; font-size:13px;
}
.sr-summary span {
  background:var(--yellow2); border-radius:999px;
  padding:4px 12px; border:1px solid rgba(0,0,0,.15);
}

/* ── Table ── */
.sr-table-wrap {
  border-radius:14px; overflow-x:auto;
  border:1px solid rgba(0,0,0,.25);
  box-shadow:var(--shadow);
  -webkit-overflow-scrolling:touch;
}
table { width:100%; border-collapse:collapse; background:rgba(255,255,255,.15); min-width:480px; }
thead th {
  background:linear-gradient(180deg,var(--green2),var(--green));
  color:#fff; padding:10px 8px; font-weight:900; font-size:13px;
  border-left:1px solid rgba(255,255,255,.25);
  text-align:center; white-space:nowrap;
}
tbody td {
  background:var(--yellow);
  border-top:1px solid rgba(0,0,0,.18);
  border-left:1px solid rgba(0,0,0,.12);
  padding:6px 8px; font-weight:900; font-size:13px;
  text-align:center; white-space:nowrap;
}
tbody tr:nth-child(even) td { background:#ffe16a; }
td.item-name { text-align:right; white-space:normal; min-width:200px; font-size:12px; }

tfoot td {
  background:linear-gradient(180deg,var(--green2),var(--green));
  color:#fff; padding:10px 8px; font-weight:900; font-size:14px;
  border-top:2px solid rgba(0,0,0,.25); text-align:center;
}

/* ── Editable inputs ── */
.tgt-input {
  width:100%; min-width:90px; max-width:140px;
  border:none; border-radius:8px;
  padding:5px 8px; text-align:center;
  font-family:"Cairo",sans-serif; font-weight:900; font-size:13px;
  background:rgba(255,255,255,.7);
  border:1px solid rgba(0,0,0,.2);
  outline:none; box-sizing:border-box;
}
.tgt-input:focus { background:#fff; border-color:var(--blue); box-shadow:0 0 0 2px rgba(26,115,232,.2); }
.tgt-input.changed { background:#fff3cd; border-color:#e6a817; }

javascript:
const API_SP      = "sat_get_sales_persons";
const API_TARGETS = "sat_get_targets";
const API_SAVE    = "sat_save_targets";

const el  = (id) => document.getElementById(id);
const fmt = (n)  => Number(n || 0).toLocaleString('ar-LY', {minimumFractionDigits: 0, maximumFractionDigits: 0});

let currentRows = [];

function init() {
  loadSalesPersons();
  el("srAgent").addEventListener("change", loadTargets);
  el("srFY").addEventListener("change", loadTargets);
}

function loadSalesPersons() {
  frappe.call({
    method: API_SP,
    callback: (r) => {
      const resp = r.message || {};
      if (resp.status === "error") { frappe.msgprint(resp.message); return; }
      const sel = el("srAgent");
      sel.innerHTML = '<option value="">-- اختر المندوب --</option>';
      (resp.data || []).forEach(u => {
        const opt = document.createElement("option");
        opt.value = u.name;
        opt.text  = u.name;
        sel.appendChild(opt);
      });
    }
  });
}

function loadTargets() {
  const sp = el("srAgent").value;
  const fy = el("srFY").value;

  if (!sp) {
    el("srTb").innerHTML = '<tr><td colspan="4">اختر المندوب لعرض المستهدفات</td></tr>';
    el("saveBtn").style.display    = "none";
    el("summaryBar").style.display = "none";
    el("srFoot").style.display     = "none";
    currentRows = [];
    return;
  }

  el("srTb").innerHTML = '<tr><td colspan="4">جاري التحميل...</td></tr>';
  el("saveBtn").style.display = "none";

  frappe.call({
    method: API_TARGETS,
    args: { sales_person: sp, fiscal_year: fy },
    callback: (r) => {
      const resp = r.message || {};
      if (resp.status === "error") { frappe.msgprint(resp.message); return; }
      currentRows = resp.data || [];
      renderTable(currentRows);
    }
  });
}

function renderTable(rows) {
  const tbody = el("srTb");
  tbody.innerHTML = "";

  if (!rows || rows.length === 0) {
    tbody.innerHTML = '<tr><td colspan="4">لا توجد مستهدفات لهذا المندوب</td></tr>';
    el("summaryBar").style.display = "none";
    el("srFoot").style.display     = "none";
    return;
  }

  rows.forEach((row, i) => {
    const displayName = (row.item_group || "").replace(/^group-/, "");
    const price = parseFloat(row.item_price || 0);
    const qty   = parseFloat(row.target_qty || 0);

    // Auto-calculate amount on load if price exists
    if (price > 0 && qty > 0) {
      row.target_amount = qty * price;
    }

    const tr = document.createElement("tr");
    tr.innerHTML = `
      <td>${i + 1}</td>
      <td class="item-name">
        ${displayName}
        ${price ? `<div style="font-size:10px;opacity:0.6;font-weight:600;">سعر الوحدة: ${fmt(price)}</div>` : ''}
      </td>
      <td>
        <input class="tgt-input" type="number" min="0"
          id="qty_${i}" value="${qty}"
          oninput="onInputChange(this, ${i}, 'target_qty')" />
      </td>
      <td>
        <input class="tgt-input" type="number" min="0"
          id="amt_${i}" value="${row.target_amount || 0}"
          oninput="onInputChange(this, ${i}, 'target_amount')" />
      </td>
    `;
    tbody.appendChild(tr);
  });

  updateSummary();
  el("summaryBar").style.display = "flex";
  el("srFoot").style.display     = "";
  el("saveBtn").style.display    = "";
}

function onInputChange(input, idx, field) {
  const val = parseFloat(input.value) || 0;
  currentRows[idx][field] = val;
  input.classList.add("changed");

  // Auto-calculate amount when qty changes
  if (field === "target_qty") {
    const price = parseFloat(currentRows[idx].item_price || 0);
    if (price > 0) {
      const calcAmt = val * price;
      currentRows[idx].target_amount = calcAmt;
      const amtInput = document.getElementById(`amt_${idx}`);
      if (amtInput) {
        amtInput.value = calcAmt.toFixed(0);
        amtInput.classList.add("changed");
      }
    }
  }

  updateSummary();
}

function updateSummary() {
  let totalQty = 0, totalAmt = 0;
  currentRows.forEach(r => {
    totalQty += parseFloat(r.target_qty    || 0);
    totalAmt += parseFloat(r.target_amount || 0);
  });

  el("sumItems").textContent  = `${currentRows.length} صنف`;
  el("sumQty").textContent    = `الكمية: ${fmt(totalQty)}`;
  el("sumAmount").textContent = `المبلغ: ${fmt(totalAmt)}`;
  el("footQty").textContent   = fmt(totalQty);
  el("footAmt").textContent   = fmt(totalAmt);
}

function saveTargets() {
  const sp = el("srAgent").value;
  const fy = el("srFY").value;

  if (!sp) { frappe.msgprint("اختر المندوب أولاً"); return; }
  if (!currentRows.length) { frappe.msgprint("لا توجد بيانات للحفظ"); return; }

  const payload = currentRows.map(r => ({
    item_group    : r.item_group,
    target_qty    : parseFloat(r.target_qty    || 0),
    target_amount : parseFloat(r.target_amount || 0),
  }));

  frappe.call({
    method: API_SAVE,
    args: {
      sales_person : sp,
      fiscal_year  : fy,
      targets      : JSON.stringify(payload),
    },
    freeze: true,
    freeze_message: "جاري الحفظ...",
    callback: (r) => {
      const resp = r.message || {};
      if (resp.status === "error") {
        frappe.msgprint({ title: "خطأ", indicator: "red", message: resp.message });
        return;
      }
      document.querySelectorAll(".tgt-input.changed").forEach(inp => inp.classList.remove("changed"));
      frappe.msgprint({ title: "تم الحفظ ✅", indicator: "green", message: `تم حفظ ${resp.updated} مستهدف بنجاح` });
    }
  });
}

frappe.ready(init);

