javascript:
const API_SP     = "sat_get_sales_persons";
const API_REPORT = "sar_get_achievement";
const API_MY_SP  = "sar_get_my_sales_person";

const el  = (id) => document.getElementById(id);
const fmt = (n)  => Number(n || 0).toLocaleString('ar-LY', {minimumFractionDigits: 0, maximumFractionDigits: 0});
const pct = (a, t) => t > 0 ? Math.round((a / t) * 100) : 0;

let fixedSalesPerson = null;  // used in self-view mode

function init() {
  frappe.call({
    method: API_MY_SP,
    callback: (r) => {
      const resp = r.message || {};

      if (resp.status === "self") {
        // Self view — hide dropdown, store sales person, auto-load
        fixedSalesPerson = resp.sales_person;
        el("agentPill").style.display = "none";
        el("selfBadge").style.display = "flex";
        el("selfName").textContent    = resp.sales_person;
        el("srFY").addEventListener("change", loadReport);
        loadReport();

      } else if (resp.status === "no_access") {
        el("srTb").innerHTML = `<tr><td colspan="7" style="color:red;font-size:15px;padding:20px;">
          🚫 ${resp.message || "ليس لديك صلاحية"}
        </td></tr>`;
        el("agentPill").style.display = "none";
        el("fyPill").style.display    = "none";

      } else {
        // manager or unknown → full dropdown
        loadSalesPersons();
        el("srAgent").addEventListener("change", loadReport);
        el("srFY").addEventListener("change", loadReport);
      }
    },
    error: () => {
      // fallback to full dropdown if script missing
      loadSalesPersons();
      el("srAgent").addEventListener("change", loadReport);
      el("srFY").addEventListener("change", loadReport);
    }
  });
}

// ── Load Sales Persons (managers only) ───────────────────────────────────────
function loadSalesPersons() {
  frappe.call({
    method: API_SP,
    callback: (r) => {
      const resp = r.message || {};
      if (resp.status === "error") { frappe.msgprint(resp.message); return; }
      const sel = el("srAgent");
      sel.innerHTML = '<option value="">-- اختر المندوب --</option>';
      (resp.data || []).forEach(u => {
        const opt = document.createElement("option");
        opt.value = u.name;
        opt.text  = u.name;
        sel.appendChild(opt);
      });
    }
  });
}

// ── Load Report ───────────────────────────────────────────────────────────────
function loadReport() {
  // In self-view use fixedSalesPerson, in manager view use dropdown
  const sp = fixedSalesPerson || el("srAgent").value;
  const fy = el("srFY").value;

  if (!sp) {
    el("srTb").innerHTML = '<tr><td colspan="7">اختر المندوب لعرض التقرير</td></tr>';
    el("summaryBar").style.display = "none";
    el("srFoot").style.display     = "none";
    return;
  }

  el("srTb").innerHTML = '<tr><td colspan="7">جاري التحميل...</td></tr>';
  el("summaryBar").style.display = "none";
  el("srFoot").style.display     = "none";

  frappe.call({
    method: API_REPORT,
    args: { sales_person: sp, fiscal_year: fy },
    callback: (r) => {
      const resp = r.message || {};
      if (resp.status === "error") { frappe.msgprint(resp.message); return; }
      renderTable(resp.data || []);
    }
  });
}

// ── Render Table ──────────────────────────────────────────────────────────────
function renderTable(rows) {
  const tbody = el("srTb");
  tbody.innerHTML = "";

  if (!rows || rows.length === 0) {
    tbody.innerHTML = '<tr><td colspan="7">لا توجد بيانات لهذا المندوب</td></tr>';
    el("summaryBar").style.display = "none";
    el("srFoot").style.display     = "none";
    return;
  }

  let totalTgtQty = 0, totalTgtAmt = 0;
  let totalAchQty = 0, totalAchAmt = 0;

  rows.forEach((row, i) => {
    const displayName = (row.item_group || "").replace(/^group-/, "");
    const tgtQty = parseFloat(row.target_qty      || 0);
    const tgtAmt = parseFloat(row.target_amount   || 0);
    const achQty = parseFloat(row.achieved_qty    || 0);
    const achAmt = parseFloat(row.achieved_amount || 0);
    const pctAmt = pct(achAmt, tgtAmt);
    const barPct = Math.min(pctAmt, 100);

    totalTgtQty += tgtQty; totalTgtAmt += tgtAmt;
    totalAchQty += achQty; totalAchAmt += achAmt;

    const cls      = pctAmt >= 100 ? "high" : pctAmt >= 50 ? "medium" : "low";
    const barColor = pctAmt >= 100 ? "#2aa334" : pctAmt >= 50 ? "#ff8c00" : "#ff4d4d";

    const tr = document.createElement("tr");
    tr.innerHTML = `
      <td>${i + 1}</td>
      <td class="item-name">${displayName}</td>
      <td>${fmt(tgtQty)}</td>
      <td>${fmt(tgtAmt)}</td>
      <td>${fmt(achQty)}</td>
      <td>${fmt(achAmt)}</td>
      <td>
        <div class="ach-bar-wrap">
          <div class="ach-bar-bg">
            <div class="ach-bar-fill" style="width:${barPct}%; background:${barColor};"></div>
          </div>
          <span class="ach-pct ${cls}">${pctAmt}%</span>
        </div>
      </td>
    `;
    tbody.appendChild(tr);
  });

  const totalPct = pct(totalAchAmt, totalTgtAmt);
  const footCls  = totalPct >= 100 ? "#2aa334" : totalPct >= 50 ? "#ff8c00" : "#ff4d4d";

  el("footTgtQty").textContent = fmt(totalTgtQty);
  el("footTgtAmt").textContent = fmt(totalTgtAmt);
  el("footAchQty").textContent = fmt(totalAchQty);
  el("footAchAmt").textContent = fmt(totalAchAmt);
  el("footPct").innerHTML      = `<span style="color:${footCls};">${totalPct}%</span>`;
  el("srFoot").style.display   = "";

  el("sumItems").textContent  = `${rows.length} صنف`;
  el("sumTgtQty").textContent = `المستهدف (ك): ${fmt(totalTgtQty)}`;
  el("sumTgtAmt").textContent = `المستهدف (م): ${fmt(totalTgtAmt)}`;
  el("sumAchQty").textContent = `المحقق (ك): ${fmt(totalAchQty)}`;
  el("sumAchAmt").textContent = `المحقق (م): ${fmt(totalAchAmt)}`;
  el("sumPct").textContent    = `${totalPct}%`;
  el("summaryBar").style.display = "flex";
}

frappe.ready(init);

