javascript:
var allBins    = [];
var allBatches = [];
var allDetails = [];
var showZero   = false;
var showBatch  = false;
var showDetails = false;

function fmt(n) {
    if (!n && n !== 0) return '0';
    return Number(n).toLocaleString('en');
}

function loadData() {
    document.getElementById('saTb').innerHTML =
        '<tr><td colspan="3" class="loading-row">⏳ جاري التحميل...</td></tr>';
    document.getElementById('sumItems').textContent = 'جاري التحميل...';
    document.getElementById('sumTotal').textContent = '';
    frappe.call({
        method: 'lmt_stock_availability_v3',
        callback: function(r) {
            if (!r || !r.message) {
                document.getElementById('saTb').innerHTML =
                    '<tr><td colspan="3" class="loading-row">⚠️ فشل تحميل البيانات</td></tr>';
                return;
            }
            allBins    = r.message.bins    || [];
            allBatches = r.message.batches || [];
            allDetails = r.message.details || [];
            var wSel   = document.getElementById('filterWarehouse');
            var prevWH = wSel.value;
            wSel.innerHTML = '<option value="">الكل</option>';
            (r.message.warehouses || []).forEach(function(w) {
                var o = document.createElement('option');
                o.value = w; o.textContent = w;
                if (w === prevWH) o.selected = true;
                wSel.appendChild(o);
            });
            applyFilters();
        }
    });
}

function applyFilters() {
    var wh   = document.getElementById('filterWarehouse').value;
    var srch = (document.getElementById('filterItem').value || '').trim().toLowerCase();
    if (showBatch && showDetails) { applyDetailsFilters(wh, srch); }
    else if (showBatch)           { applyExpiryFilters(wh, srch);  }
    else                          { applyNormalFilters(wh, srch);  }
}

/* ── NORMAL MODE ── */
function applyNormalFilters(wh, srch) {
    var filtered = allBins;
    if (wh) filtered = filtered.filter(function(b){ return b.warehouse === wh; });
    var totals = {}, names = {};
    filtered.forEach(function(b) {
        totals[b.item_code] = (totals[b.item_code] || 0) + (b.qty || 0);
        names[b.item_code]  = b.item_name;
    });
    var rows = Object.keys(totals).map(function(code) {
        return { item_code: code, item_name: names[code] || code, total_qty: totals[code] };
    });
    if (!showZero) rows = rows.filter(function(r){ return r.total_qty > 0; });
    if (srch) rows = rows.filter(function(r){
        return (r.item_name + ' ' + r.item_code).replace(/\s+/g, ' ').toLowerCase()
               .indexOf(srch.replace(/\s+/g, ' ')) !== -1;
    });
    rows.sort(function(a, b){ return b.total_qty - a.total_qty; });
    setHead3();
    renderNormal(rows);
}

function renderNormal(rows) {
    var tb = document.getElementById('saTb');
    if (!rows.length) {
        tb.innerHTML = '<tr><td colspan="3" class="loading-row">لا توجد بيانات</td></tr>';
        document.getElementById('sumItems').textContent = '0 صنف';
        document.getElementById('sumTotal').textContent = 'الإجمالي: 0';
        return;
    }
    var totalQty = rows.reduce(function(s, r){ return s + r.total_qty; }, 0);
    document.getElementById('sumItems').textContent = rows.length + ' صنف';
    document.getElementById('sumTotal').textContent = 'الإجمالي: ' + fmt(totalQty);
    tb.innerHTML = rows.map(function(r, i) {
        return '<tr' + (r.total_qty === 0 ? ' class="qty-zero"' : '') + '>'
            + '<td>' + (i + 1) + '</td>'
            + '<td class="col-name">' + (r.item_name || r.item_code) + '</td>'
            + '<td>' + fmt(r.total_qty) + '</td>'
            + '</tr>';
    }).join('');
}

/* ── EXPIRY MODE ── */
/* source: allBatches (tabBatch — all items, total qty, NO warehouse filter) */
function applyExpiryFilters(wh, srch) {
    var filtered = allBatches;
    /* warehouse filter intentionally not applied here —
       tabBatch has no per-warehouse breakdown */
    var key_qty = {}, key_name = {}, key_exp = {};
    filtered.forEach(function(b) {
        var k = b.item_code + '|||' + (b.expiry_date || '');
        key_qty[k]  = (key_qty[k]  || 0) + (b.qty || 0);
        key_name[k] = b.item_name;
        key_exp[k]  = b.expiry_date || '';
    });
    var rows = Object.keys(key_qty).map(function(k) {
        return {
            item_code:   k.split('|||')[0],
            item_name:   key_name[k],
            expiry_date: key_exp[k],
            total_qty:   key_qty[k]
        };
    });
    if (!showZero) rows = rows.filter(function(r){ return r.total_qty > 0; });
    if (srch) rows = rows.filter(function(r){
        return (r.item_name + ' ' + r.item_code).replace(/\s+/g, ' ').toLowerCase()
               .indexOf(srch.replace(/\s+/g, ' ')) !== -1;
    });
    rows.sort(function(a, b){
        var nc = a.item_name.localeCompare(b.item_name, 'ar');
        if (nc !== 0) return nc;
        if (a.expiry_date < b.expiry_date) return -1;
        if (a.expiry_date > b.expiry_date) return  1;
        return 0;
    });
    setHead4();
    renderExpiry(rows);
}

function renderExpiry(rows) {
    var tb    = document.getElementById('saTb');
    var today = new Date().toISOString().slice(0, 10);
    if (!rows.length) {
        tb.innerHTML = '<tr><td colspan="4" class="loading-row">لا توجد بيانات</td></tr>';
        document.getElementById('sumItems').textContent = '0 سطر';
        document.getElementById('sumTotal').textContent = 'الإجمالي: 0';
        return;
    }
    var totalQty = rows.reduce(function(s, r){ return s + r.total_qty; }, 0);
    document.getElementById('sumItems').textContent = rows.length + ' سطر';
    document.getElementById('sumTotal').textContent = 'الإجمالي: ' + fmt(totalQty);
    tb.innerHTML = rows.map(function(r, i) {
        var cls = [];
        if (r.total_qty === 0)                      cls.push('qty-zero');
        if (r.expiry_date && r.expiry_date < today) cls.push('expired');
        return '<tr' + (cls.length ? ' class="' + cls.join(' ') + '"' : '') + '>'
            + '<td>' + (i + 1) + '</td>'
            + '<td class="col-name">' + (r.item_name || r.item_code) + '</td>'
            + '<td class="col-expiry">' + (r.expiry_date || '-') + '</td>'
            + '<td>' + fmt(r.total_qty) + '</td>'
            + '</tr>';
    }).join('');
}

/* ── DETAILS MODE ── */
/* source: allDetails (SBB — exact per-warehouse per-batch, warehouse filter works) */
function applyDetailsFilters(wh, srch) {
    var filtered = allDetails;
    if (wh) filtered = filtered.filter(function(b){ return b.warehouse === wh; });
    if (!showZero) filtered = filtered.filter(function(b){ return (b.qty || 0) > 0; });
    if (srch) filtered = filtered.filter(function(b){
        return (b.item_name + ' ' + b.item_code).replace(/\s+/g, ' ').toLowerCase()
               .indexOf(srch.replace(/\s+/g, ' ')) !== -1;
    });
    filtered.sort(function(a, b){
        var nc = (a.item_name || '').localeCompare(b.item_name || '', 'ar');
        if (nc !== 0) return nc;
        if ((a.expiry_date || '') < (b.expiry_date || '')) return -1;
        if ((a.expiry_date || '') > (b.expiry_date || '')) return  1;
        return (a.warehouse || '').localeCompare(b.warehouse || '');
    });
    setHeadDetails();
    renderDetails(filtered);
}

function renderDetails(rows) {
    var tb    = document.getElementById('saTb');
    var today = new Date().toISOString().slice(0, 10);
    if (!rows.length) {
        tb.innerHTML = '<tr><td colspan="5" class="loading-row">لا توجد بيانات</td></tr>';
        document.getElementById('sumItems').textContent = '0 سطر';
        document.getElementById('sumTotal').textContent = 'الإجمالي: 0';
        return;
    }
    var totalQty = rows.reduce(function(s, r){ return s + (r.qty || 0); }, 0);
    document.getElementById('sumItems').textContent = rows.length + ' سطر';
    document.getElementById('sumTotal').textContent = 'الإجمالي: ' + fmt(totalQty);
    tb.innerHTML = rows.map(function(r, i) {
        var cls = [];
        if ((r.qty || 0) === 0)                         cls.push('qty-zero');
        if (r.expiry_date && r.expiry_date < today)     cls.push('expired');
        return '<tr' + (cls.length ? ' class="' + cls.join(' ') + '"' : '') + '>'
            + '<td>' + (i + 1) + '</td>'
            + '<td class="col-name">' + (r.item_name || r.item_code) + '</td>'
            + '<td class="col-expiry">' + (r.expiry_date || '-') + '</td>'
            + '<td class="col-warehouse">' + (r.warehouse || '-') + '</td>'
            + '<td>' + fmt(r.qty || 0) + '</td>'
            + '</tr>';
    }).join('');
}

/* ── HEAD HELPERS ── */
function setHead3() {
    var el = document.querySelector('#saTable thead');
    if (!el) return;
    el.innerHTML = '<tr>'
        + '<th style="width:40px">#</th>'
        + '<th class="col-name">وصف الصنف</th>'
        + '<th style="width:130px">إجمالي المتاح</th>'
        + '</tr>';
}
function setHead4() {
    var el = document.querySelector('#saTable thead');
    if (!el) return;
    el.innerHTML = '<tr>'
        + '<th style="width:40px">#</th>'
        + '<th class="col-name">وصف الصنف</th>'
        + '<th style="width:120px">تاريخ الانتهاء</th>'
        + '<th style="width:110px">الكمية</th>'
        + '</tr>';
}
function setHeadDetails() {
    var el = document.querySelector('#saTable thead');
    if (!el) return;
    el.innerHTML = '<tr>'
        + '<th style="width:40px">#</th>'
        + '<th class="col-name">وصف الصنف</th>'
        + '<th style="width:120px">تاريخ الانتهاء</th>'
        + '<th class="col-warehouse">المخزن</th>'
        + '<th style="width:110px">الكمية</th>'
        + '</tr>';
}

/* ── TOGGLES ── */
function toggleShowZero() {
    showZero = !showZero;
    var btn = document.getElementById('btnShowZero');
    btn.classList.toggle('active', showZero);
    btn.textContent = (showZero ? '☑' : '☐') + ' إظهار الكميات الصفرية';
    applyFilters();
}

function toggleShowBatch() {
    showBatch = !showBatch;
    var btn = document.getElementById('btnShowBatch');
    btn.classList.toggle('active', showBatch);
    btn.textContent = (showBatch ? '☑' : '☐') + ' عرض تواريخ الانتهاء';
    var detBtn = document.getElementById('btnShowDetails');
    detBtn.style.display = showBatch ? '' : 'none';
    if (!showBatch && showDetails) {
        showDetails = false;
        detBtn.classList.remove('active');
        detBtn.textContent = '☐ عرض تفاصيل المخازن';
    }
    applyFilters();
}

function toggleShowDetails() {
    showDetails = !showDetails;
    var btn = document.getElementById('btnShowDetails');
    btn.classList.toggle('active', showDetails);
    btn.textContent = (showDetails ? '☑' : '☐') + ' عرض تفاصيل المخازن';
    applyFilters();
}

/* ── RESET ── */
function resetFilters() {
    document.getElementById('filterWarehouse').value = '';
    document.getElementById('filterItem').value = '';
    if (showZero) {
        showZero = false;
        var b = document.getElementById('btnShowZero');
        b.classList.remove('active');
        b.textContent = '☐ إظهار الكميات الصفرية';
    }
    if (showBatch) {
        showBatch = false;
        var b = document.getElementById('btnShowBatch');
        b.classList.remove('active');
        b.textContent = '☐ عرض تواريخ الانتهاء';
    }
    if (showDetails) {
        showDetails = false;
        var b = document.getElementById('btnShowDetails');
        b.classList.remove('active');
        b.textContent = '☐ عرض تفاصيل المخازن';
    }
    document.getElementById('btnShowDetails').style.display = 'none';
    applyFilters();
}

