css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@600;700;800;900&display=swap');
:root {
  --yellow:#FFD700; --yellow2:#FFF3B0; --yellow3:#fff8d6;
  --green:#1a7a4a;  --green2:#2ea86b;  --red:#dc2626;
  --shadow:0 2px 8px rgba(0,0,0,.15);  --radius:12px;
}
*{box-sizing:border-box;margin:0;padding:0;}
body{font-family:'Cairo',sans-serif;direction:rtl;font-weight:700;}

/* Topbar */
.im-topbar{display:flex;justify-content:space-between;align-items:center;
  padding:10px 16px;position:sticky;top:0;z-index:100;box-shadow:var(--shadow);}
.im-topbar-left{display:flex;gap:6px;}
.im-topbar-right{display:flex;align-items:center;gap:10px;}
.im-topbar-title{font-size:17px;font-weight:900;color:white;}
.im-badge-msg{background:rgba(255,255,255,.25);border-radius:999px;padding:3px 12px;
  font-size:12px;color:white;font-weight:700;}
.im-btn-icon{background:rgba(255,255,255,.2);border:1px solid rgba(255,255,255,.3);
  border-radius:999px;padding:6px 12px;font-size:14px;cursor:pointer;color:white;
  font-family:'Cairo',sans-serif;}
.im-btn-icon:active{transform:scale(.95);}

/* Wrap */
.im-wrap{max-width:1200px;margin:0 auto;padding:12px 14px 40px;}

/* Tabs */
.im-tabs{display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap;}
.im-tab{flex:1;min-width:110px;background:var(--yellow2);border:1px solid rgba(0,0,0,.2);
  border-radius:999px;padding:9px 12px;font-family:'Cairo',sans-serif;font-weight:900;
  font-size:13px;cursor:pointer;box-shadow:var(--shadow);text-align:center;transition:all .2s;}
.im-tab.active{background:var(--green2);color:white;border-color:var(--green);}

/* Filters */
.im-filters{display:flex;gap:10px;margin-bottom:12px;flex-wrap:wrap;align-items:center;}
.im-pill{background:var(--yellow);border:1px solid rgba(0,0,0,.2);border-radius:999px;
  padding:8px 16px;box-shadow:var(--shadow);display:flex;align-items:center;gap:8px;
  flex:1;min-width:180px;}
.im-input{border:none;outline:none;background:transparent;font-family:'Cairo',sans-serif;
  font-weight:800;font-size:14px;width:100%;text-align:right;direction:rtl;}
.im-input::placeholder{font-weight:600;color:#888;}
.im-select{border:none;outline:none;background:transparent;font-family:'Cairo',sans-serif;
  font-weight:800;font-size:14px;width:100%;direction:rtl;cursor:pointer;}
.im-pill-row{display:flex;gap:8px;align-items:center;flex-wrap:wrap;}
.im-filter-btn{background:var(--yellow2);border:1px solid rgba(0,0,0,.2);border-radius:999px;
  padding:7px 16px;font-family:'Cairo',sans-serif;font-weight:900;font-size:13px;
  cursor:pointer;box-shadow:var(--shadow);}
.im-filter-btn.active{background:var(--green2);color:white;border-color:var(--green);}
.im-btn-add{background:var(--green2);color:white;border:none;border-radius:999px;
  padding:8px 18px;font-family:'Cairo',sans-serif;font-weight:900;font-size:13px;
  cursor:pointer;box-shadow:var(--shadow);white-space:nowrap;}
.im-btn-add:active{transform:scale(.95);}

/* Table */
.im-table-wrap{border-radius:var(--radius);overflow-x:auto;
  border:1px solid rgba(0,0,0,.2);box-shadow:var(--shadow);}
.im-empty{padding:40px;text-align:center;color:#888;font-weight:700;}
table.im-table{width:100%;border-collapse:collapse;min-width:400px;}
table.im-table thead th{background:linear-gradient(180deg,var(--green2),var(--green));
  color:white;padding:10px;font-weight:900;font-size:13px;
  border-left:1px solid rgba(255,255,255,.2);text-align:center;white-space:nowrap;}
table.im-table tbody td{background:var(--yellow);border-top:1px solid rgba(0,0,0,.15);
  border-left:1px solid rgba(0,0,0,.1);padding:8px 10px;font-weight:700;
  font-size:13px;text-align:center;}
table.im-table tbody tr:nth-child(even) td{background:#ffe16a;}
table.im-table tbody tr.im-row-disabled td{opacity:.5;}
table.im-table tbody tr.im-row-archived td{background:#f0f0f0;}
table.im-table tbody tr.im-row-archived:nth-child(even) td{background:#e8e8e8;}

/* Price layout */
.im-panel-top{display:flex;gap:14px;align-items:flex-start;}
.im-price-sidebar{width:240px;min-width:200px;flex-shrink:0;
  background:rgba(255,255,255,.5);border:1px solid rgba(0,0,0,.15);
  border-radius:var(--radius);box-shadow:var(--shadow);padding:10px;
  max-height:72vh;overflow-y:auto;}
.im-sidebar-header{display:flex;justify-content:space-between;align-items:center;
  font-weight:900;font-size:14px;margin-bottom:10px;padding-bottom:8px;
  border-bottom:2px solid rgba(0,0,0,.1);}
.im-price-list-items{display:flex;flex-direction:column;gap:6px;}
.im-pl-item{padding:9px 12px;border-radius:10px;cursor:pointer;
  border:1px solid rgba(0,0,0,.12);background:var(--yellow2);
  font-size:13px;font-weight:800;transition:all .15s;}
.im-pl-item:hover{background:var(--yellow);}
.im-pl-item.active{background:var(--green2);color:white;border-color:var(--green);}
.im-pl-item.archived{background:#f0f0f0;color:#888;font-size:12px;}
.im-pl-count{font-size:11px;opacity:.7;display:block;margin-top:2px;}
.im-pl-section-label{font-size:11px;font-weight:900;color:#888;
  text-transform:uppercase;padding:8px 4px 2px;letter-spacing:.5px;}
.im-price-main{flex:1;min-width:0;}
.im-price-main-header{display:flex;justify-content:space-between;align-items:center;
  margin-bottom:12px;flex-wrap:wrap;gap:8px;background:rgba(255,255,255,.4);
  border:1px solid rgba(0,0,0,.12);border-radius:var(--radius);padding:10px 14px;}
.im-price-info{display:flex;align-items:center;gap:10px;flex-wrap:wrap;}
.im-price-name-badge{font-size:15px;font-weight:900;}
.im-status-badge{border-radius:999px;padding:3px 12px;font-size:12px;font-weight:900;}
.im-status-badge.active{background:var(--green2);color:white;}
.im-status-badge.archived{background:#9ca3af;color:white;}
.im-price-actions{display:flex;gap:8px;flex-wrap:wrap;}
.im-btn-sm{border-radius:999px;padding:6px 14px;font-family:'Cairo',sans-serif;
  font-weight:900;font-size:12px;cursor:pointer;border:1px solid rgba(0,0,0,.15);
  box-shadow:var(--shadow);}
.im-btn-refresh{background:var(--yellow);}
.im-btn-copy{background:#3b82f6;color:white;border:none;}

/* Table action buttons */
.im-tbl-btn{border-radius:6px;padding:4px 10px;font-family:'Cairo',sans-serif;
  font-weight:900;font-size:12px;cursor:pointer;border:1px solid rgba(0,0,0,.15);margin:0 2px;}
.im-tbl-btn-edit{background:#fef3c7;}
.im-tbl-btn-enable{background:#d1fae5;}
.im-tbl-btn-disable{background:#fee2e2;}

/* Modals */
.im-modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:1000;
  display:flex;align-items:center;justify-content:center;padding:16px;}
.im-modal{background:white;border-radius:16px;padding:24px;width:100%;
  max-width:440px;box-shadow:0 20px 60px rgba(0,0,0,.3);
  font-family:'Cairo',sans-serif;direction:rtl;}
.im-modal-lg{max-width:580px;}
.im-modal h3{font-size:18px;font-weight:900;margin-bottom:16px;color:var(--green);}
.im-modal p{font-weight:700;margin-bottom:16px;color:#444;}
.im-modal-actions{display:flex;gap:10px;justify-content:flex-end;margin-top:20px;}
.im-btn-cancel{background:#f3f4f6;border:1px solid #d1d5db;border-radius:999px;
  padding:8px 20px;font-family:'Cairo',sans-serif;font-weight:900;cursor:pointer;}
.im-btn-confirm{background:var(--green2);color:white;border:none;border-radius:999px;
  padding:8px 20px;font-family:'Cairo',sans-serif;font-weight:900;cursor:pointer;}

/* Form */
.im-form-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
.im-form-group{display:flex;flex-direction:column;gap:4px;}
.im-form-group label{font-size:12px;font-weight:900;color:#555;}
.im-form-input{border:1px solid #d1d5db;border-radius:8px;padding:8px 12px;
  font-family:'Cairo',sans-serif;font-weight:700;font-size:14px;
  direction:rtl;outline:none;width:100%;}
.im-form-input:focus{border-color:var(--green2);}

/* Expired batch highlight */
.im-expired{color:#dc2626;font-weight:900;}

@media(max-width:640px){
  .im-panel-top{flex-direction:column;}
  .im-price-sidebar{width:100%;max-height:180px;}
  .im-form-grid{grid-template-columns:1fr;}
}

javascript:
$(document).ready(function() {
    if (frappe.session.user === 'Guest') {
        window.location.href = '/login?redirect-to=/item-mgmt-1';
        return;
    }
    document.getElementById('imConfirmBtn').addEventListener('click', function() {
        if (pendingConfirm) { pendingConfirm(); closeConfirm(); }
    });
    switchTab('price');
});

var currentTab = 'price';
var currentPriceList = null;
var currentPriceListEnabled = false;
var allPriceItems = [];
var allItems = [];
var currentItemFilter = 'all';
var pendingConfirm = null;
var editingItemCode = null;
var editingPriceItem = null;

// ── Tab ───────────────────────────────────────────────────────
function switchTab(tab) {
    currentTab = tab;
    document.querySelectorAll('.im-tab').forEach(function(b){ b.classList.remove('active'); });
    document.getElementById('tab-' + tab).classList.add('active');
    document.querySelectorAll('.im-panel').forEach(function(p){ p.style.display = 'none'; });
    document.getElementById('panel-' + tab).style.display = 'block';
    if (tab === 'price')   loadPriceLists();
    if (tab === 'items')   loadItems();
    if (tab === 'batches') loadBatches();
    if (tab === 'serials') loadSerials();
}

function setMsg(t){ document.getElementById('imMsg').textContent = t; }

// ── API ───────────────────────────────────────────────────────
function apiPost(method, args) {
    return fetch('/api/method/' + method, {
        method: 'POST',
        headers: {'Content-Type':'application/json','X-Frappe-CSRF-Token': frappe.csrf_token},
        body: JSON.stringify(args || {})
    }).then(function(r){ return r.json(); });
}
function escQ(s){ return (s||'').replace(/\\/g,'\\\\').replace(/'/g,"\\'"); }

// ══ PRICE LISTS ════════════════════════════════════════════════
function loadPriceLists() {
    setMsg('جاري التحميل...');
    apiPost('lmt_im_price_lists', {}).then(function(res) {
        if (!res.message || !res.message.ok) { setMsg('خطأ: ' + ((res.message && res.message.error) || '')); return; }
        renderPriceListSidebar(res.message.data);
        setMsg(res.message.data.length + ' قائمة');
    });
}

function renderPriceListSidebar(lists) {
    var active   = lists.filter(function(l){ return l.enabled; });
    var archived = lists.filter(function(l){ return !l.enabled; });
    var html = '';
    if (active.length) {
        html += '<div class="im-pl-section-label">نشطة</div>';
        active.forEach(function(l) {
            var cls = currentPriceList === l.name ? ' active' : '';
            var type = l.selling && l.buying ? '🔄' : l.selling ? '💰 مبيعات' : '🛒 مشتريات';
            html += '<div class="im-pl-item' + cls + '" onclick="selectPriceList(\'' + escQ(l.name) + '\',true)">'
                  + l.name + '<span class="im-pl-count">' + type + ' · ' + l.item_count + ' صنف</span></div>';
        });
    }
    if (archived.length) {
        html += '<div class="im-pl-section-label">الأرشيف</div>';
        archived.forEach(function(l) {
            var cls = 'archived' + (currentPriceList === l.name ? ' active' : '');
            html += '<div class="im-pl-item ' + cls + '" onclick="selectPriceList(\'' + escQ(l.name) + '\',false)">'
                  + l.name + '<span class="im-pl-count">' + l.item_count + ' صنف · مؤرشف</span></div>';
        });
    }
    document.getElementById('priceListSidebar').innerHTML = html || '<div class="im-empty">لا توجد قوائم</div>';
}

function selectPriceList(name, enabled) {
    currentPriceList = name;
    currentPriceListEnabled = enabled;
    document.getElementById('priceMainHeader').style.display = 'flex';
    document.getElementById('priceListNameLabel').textContent = name;
    var badge = document.getElementById('priceListStatusBadge');
    badge.textContent = enabled ? 'نشطة' : 'مؤرشفة';
    badge.className = 'im-status-badge ' + (enabled ? 'active' : 'archived');
    var actDiv = document.getElementById('priceActions');
    actDiv.innerHTML = enabled
        ? '<button class="im-btn-sm im-btn-copy" onclick="confirmCopyPriceList(\'' + escQ(name) + '\')">📋 نسخ وترقية</button>'
        : '<span style="font-size:12px;color:#9ca3af;">مؤرشفة — قراءة فقط</span>';
    document.getElementById('priceSearchPill').style.display = 'flex';
    setMsg('جاري التحميل...');
    apiPost('lmt_im_price_list_items', {price_list: name}).then(function(res) {
        if (!res.message || !res.message.ok) {
            var err = (res.message && res.message.error) ? res.message.error : JSON.stringify(res);
            document.getElementById('priceTableWrap').innerHTML = '<div class="im-empty" style="color:red;font-size:11px;">' + err + '</div>';
            return;
        }
        allPriceItems = res.message.data;
        document.getElementById('priceListItemCount').textContent = allPriceItems.length + ' صنف';
        renderPriceTable(allPriceItems);
        setMsg(allPriceItems.length + ' صنف');
    });
}

function filterPriceItems() {
    var q = document.getElementById('priceSearch').value.toLowerCase();
    if (!q) { renderPriceTable(allPriceItems); return; }
    var f = allPriceItems.filter(function(p){
        return (p.item_code||'').toLowerCase().indexOf(q) !== -1 ||
               (p.item_name||'').toLowerCase().indexOf(q) !== -1;
    });
    renderPriceTable(f);
}

function renderPriceTable(items) {
    if (!items.length) {
        document.getElementById('priceTableWrap').innerHTML = '<div class="im-empty">لا توجد أصناف</div>'; return;
    }
    var editable = currentPriceListEnabled;
    var html = '<table class="im-table"><thead><tr><th>#</th><th>كود الصنف</th><th>اسم الصنف</th><th>وحدة</th><th>السعر</th>';
    if (editable) html += '<th>تعديل</th>';
    html += '</tr></thead><tbody>';
    items.forEach(function(p, i) {
        var rc = editable ? '' : ' class="im-row-archived"';
        html += '<tr' + rc + '><td>' + (i+1) + '</td><td>' + (p.item_code||'') + '</td>'
              + '<td>' + (p.item_name||'') + '</td>'
              + '<td>' + (p.uom||'') + '</td>'
              + '<td><strong>' + (p.price_list_rate||0) + '</strong></td>';
        if (editable)
            html += '<td><button class="im-tbl-btn im-tbl-btn-edit" onclick="openPriceEdit(\''
                  + escQ(p.item_code) + '\',\'' + escQ(p.item_name||'') + '\',' + (p.price_list_rate||0) + ')">✏ تعديل</button></td>';
        html += '</tr>';
    });
    html += '</tbody></table>';
    document.getElementById('priceTableWrap').innerHTML = html;
}

function confirmCopyPriceList(name) {
    showConfirm('نسخ قائمة الأسعار',
        'سيتم أرشفة "' + name + '" وإنشاء نسخة جديدة نشطة. هل تريد المتابعة؟',
        function(){ doCopyPriceList(name); });
}
function doCopyPriceList(name) {
    setMsg('جاري النسخ...');
    apiPost('lmt_im_copy_price_list', {price_list_name: name}).then(function(res) {
        if (res.message && res.message.ok) {
            setMsg('✅ ' + res.message.archive_name + ' → نسخة جديدة (' + res.message.copied + ' صنف)');
            currentPriceList = null;
            document.getElementById('priceMainHeader').style.display = 'none';
            document.getElementById('priceSearchPill').style.display = 'none';
            document.getElementById('priceTableWrap').innerHTML = '<div class="im-empty">اختر قائمة من القائمة الجانبية</div>';
            loadPriceLists();
        } else {
            alert('فشل: ' + (res.message && res.message.error ? res.message.error : ''));
            setMsg('خطأ');
        }
    });
}

function openPriceEdit(item_code, item_name, rate) {
    editingPriceItem = item_code;
    document.getElementById('priceEditItemName').textContent = item_code + (item_name ? ' — ' + item_name : '');
    document.getElementById('fNewPrice').value = rate;
    document.getElementById('priceEditModal').style.display = 'flex';
}
function closePriceEdit(){ document.getElementById('priceEditModal').style.display = 'none'; editingPriceItem = null; }
function savePriceEdit() {
    var r = parseFloat(document.getElementById('fNewPrice').value);
    if (isNaN(r) || r < 0) { alert('السعر غير صحيح'); return; }
    setMsg('جاري الحفظ...');
    apiPost('lmt_im_update_price', {price_list: currentPriceList, item_code: editingPriceItem, new_rate: r})
    .then(function(res) {
        closePriceEdit();
        if (res.message && res.message.ok) {
            for (var i = 0; i < allPriceItems.length; i++) {
                if (allPriceItems[i].item_code === editingPriceItem) { allPriceItems[i].price_list_rate = r; break; }
            }
            filterPriceItems();
            setMsg('✅ تم تحديث السعر');
        } else {
            alert('فشل: ' + (res.message && res.message.error ? res.message.error : ''));
        }
    });
}

// ══ ITEMS ══════════════════════════════════════════════════════
function loadItems() {
    setMsg('جاري التحميل...');
    apiPost('lmt_im_items', {search: document.getElementById('itemSearch').value, filter: currentItemFilter})
    .then(function(res) {
        if (!res.message || !res.message.ok) { setMsg('خطأ: ' + ((res.message && res.message.error)||'')); return; }
        allItems = res.message.data;
        renderItemsTable(allItems);
        setMsg(allItems.length + ' صنف');
    });
}
function setItemFilter(f) {
    currentItemFilter = f;
    document.querySelectorAll('.im-filter-btn').forEach(function(b){ b.classList.remove('active'); });
    var map = {all:'All', active:'Active', disabled:'Disabled'};
    document.getElementById('itemFilter' + map[f]).classList.add('active');
    loadItems();
}
function renderItemsTable(items) {
    if (!items.length) {
        document.getElementById('itemsTableWrap').innerHTML = '<div class="im-empty">لا توجد نتائج</div>'; return;
    }
    var html = '<table class="im-table"><thead><tr><th>كود الصنف</th><th>اسم الصنف</th>'
             + '<th>المجموعة</th><th>وحدة</th><th>مخزني</th><th>الحالة</th><th>إجراء</th>'
             + '</tr></thead><tbody>';
    items.forEach(function(item) {
        var rc = item.disabled ? ' class="im-row-disabled"' : '';
        html += '<tr' + rc + '>'
              + '<td>' + (item.item_code||'') + '</td>'
              + '<td>' + (item.item_name||'') + '</td>'
              + '<td>' + (item.item_group||'') + '</td>'
              + '<td>' + (item.stock_uom||'') + '</td>'
              + '<td>' + (item.is_stock_item ? '✅' : '—') + '</td>'
              + '<td>' + (item.disabled
                  ? '<span style="color:#dc2626;font-weight:900;">معطّل</span>'
                  : '<span style="color:#16a34a;font-weight:900;">نشط</span>') + '</td>'
              + '<td>'
              + '<button class="im-tbl-btn im-tbl-btn-edit" onclick="openItemModal(\'' + escQ(item.item_code) + '\')">✏</button>'
              + (item.disabled
                  ? '<button class="im-tbl-btn im-tbl-btn-enable" onclick="toggleItem(\'' + escQ(item.item_code) + '\',0)">✅ تفعيل</button>'
                  : '<button class="im-tbl-btn im-tbl-btn-disable" onclick="toggleItem(\'' + escQ(item.item_code) + '\',1)">🚫 تعطيل</button>')
              + '</td></tr>';
    });
    html += '</tbody></table>';
    document.getElementById('itemsTableWrap').innerHTML = html;
}
function openItemModal(item_code) {
    editingItemCode = item_code;
    document.getElementById('itemModalTitle').textContent = item_code ? 'تعديل صنف' : 'صنف جديد';
    if (item_code) {
        var item = null;
        for (var i = 0; i < allItems.length; i++) { if (allItems[i].item_code === item_code) { item = allItems[i]; break; } }
        if (item) {
            document.getElementById('fItemCode').value = item.item_code;
            document.getElementById('fItemCode').disabled = true;
            document.getElementById('fItemName').value = item.item_name||'';
            document.getElementById('fItemGroup').value = item.item_group||'';
            document.getElementById('fUOM').value = item.stock_uom||'';
            document.getElementById('fIsStock').value = item.is_stock_item ? '1' : '0';
            document.getElementById('fIsSales').value = item.is_sales_item ? '1' : '0';
        }
    } else {
        document.getElementById('fItemCode').value = '';
        document.getElementById('fItemCode').disabled = false;
        document.getElementById('fItemName').value = '';
        document.getElementById('fItemGroup').value = 'All Item Groups';
        document.getElementById('fUOM').value = 'Nos';
        document.getElementById('fIsStock').value = '1';
        document.getElementById('fIsSales').value = '1';
    }
    document.getElementById('itemModal').style.display = 'flex';
}
function closeItemModal(){ document.getElementById('itemModal').style.display = 'none'; editingItemCode = null; }
function saveItem() {
    var ic = document.getElementById('fItemCode').value.trim();
    var inn = document.getElementById('fItemName').value.trim();
    if (!ic || !inn) { alert('كود الصنف والاسم مطلوبان'); return; }
    setMsg('جاري الحفظ...');
    apiPost('lmt_im_save_item', {
        item_code: ic, item_name: inn,
        item_group: document.getElementById('fItemGroup').value.trim(),
        uom: document.getElementById('fUOM').value.trim(),
        is_stock_item: document.getElementById('fIsStock').value,
        is_sales_item: document.getElementById('fIsSales').value,
        is_new: editingItemCode ? '0' : '1'
    }).then(function(res) {
        closeItemModal();
        if (res.message && res.message.ok) { setMsg('✅ تم الحفظ'); loadItems(); }
        else { alert('فشل: ' + (res.message && res.message.error ? res.message.error : '')); setMsg('خطأ'); }
    });
}
function toggleItem(item_code, disabled) {
    showConfirm('تأكيد',
        (disabled ? 'تعطيل' : 'تفعيل') + ' الصنف "' + item_code + '"؟',
        function() {
            apiPost('lmt_im_toggle_item', {item_code: item_code, disabled: disabled}).then(function(res) {
                if (res.message && res.message.ok) { setMsg('✅ تم'); loadItems(); }
                else alert('فشل: ' + (res.message && res.message.error ? res.message.error : ''));
            });
        });
}

// ══ BATCHES ════════════════════════════════════════════════════
function loadBatches() {
    setMsg('جاري التحميل...');
    apiPost('lmt_im_batches', {search: document.getElementById('batchItemSearch').value})
    .then(function(res) {
        if (!res.message || !res.message.ok) { setMsg('خطأ: ' + ((res.message && res.message.error)||'')); return; }
        var batches = res.message.data;
        renderBatchesTable(batches);
        setMsg(batches.length + ' دفعة');
    });
}
function renderBatchesTable(batches) {
    if (!batches.length) {
        document.getElementById('batchesTableWrap').innerHTML = '<div class="im-empty">لا توجد دفعات</div>'; return;
    }
    var today = new Date(); today.setHours(0,0,0,0);
    var html = '<table class="im-table"><thead><tr><th>رقم الدفعة</th><th>كود الصنف</th>'
             + '<th>اسم الصنف</th><th>تاريخ الانتهاء</th><th>تاريخ التصنيع</th><th>الكمية</th>'
             + '</tr></thead><tbody>';
    batches.forEach(function(b) {
        var expCls = '';
        if (b.expiry_date && new Date(b.expiry_date) < today) expCls = ' class="im-expired"';
        html += '<tr><td>' + (b.name||'') + '</td><td>' + (b.item||'') + '</td>'
              + '<td>' + (b.item_name||'') + '</td>'
              + '<td' + expCls + '>' + (b.expiry_date||'—') + '</td>'
              + '<td>' + (b.manufacturing_date||'—') + '</td>'
              + '<td>' + (b.batch_qty||0) + '</td></tr>';
    });
    html += '</tbody></table>';
    document.getElementById('batchesTableWrap').innerHTML = html;
}
function openBatchModal() {
    ['fBatchItem','fBatchId','fBatchExpiry','fBatchMfg'].forEach(function(id){ document.getElementById(id).value = ''; });
    document.getElementById('batchModal').style.display = 'flex';
}
function closeBatchModal(){ document.getElementById('batchModal').style.display = 'none'; }
function saveBatch() {
    var bid = document.getElementById('fBatchId').value.trim();
    var bitem = document.getElementById('fBatchItem').value.trim();
    if (!bid || !bitem) { alert('رقم الدفعة والصنف مطلوبان'); return; }
    setMsg('جاري الحفظ...');
    apiPost('lmt_im_save_batch', {
        batch_id: bid, item_code: bitem,
        expiry_date: document.getElementById('fBatchExpiry').value,
        manufacturing_date: document.getElementById('fBatchMfg').value
    }).then(function(res) {
        closeBatchModal();
        if (res.message && res.message.ok) { setMsg('✅ تم إنشاء الدفعة'); loadBatches(); }
        else { alert('فشل: ' + (res.message && res.message.error ? res.message.error : '')); setMsg('خطأ'); }
    });
}

// ══ SERIALS ════════════════════════════════════════════════════
function loadSerials() {
    setMsg('جاري التحميل...');
    apiPost('lmt_im_serial_nos', {
        search: document.getElementById('serialItemSearch').value,
        status: document.getElementById('serialStatus').value
    }).then(function(res) {
        if (!res.message || !res.message.ok) { setMsg('خطأ: ' + ((res.message && res.message.error)||'')); return; }
        var serials = res.message.data;
        renderSerialsTable(serials);
        setMsg(serials.length + ' رقم تسلسلي');
    });
}
function renderSerialsTable(serials) {
    if (!serials.length) {
        document.getElementById('serialsTableWrap').innerHTML = '<div class="im-empty">لا توجد أرقام تسلسلية</div>'; return;
    }
    var html = '<table class="im-table"><thead><tr><th>الرقم التسلسلي</th><th>كود الصنف</th>'
             + '<th>اسم الصنف</th><th>الحالة</th><th>المستودع</th><th>تاريخ الإنشاء</th>'
             + '</tr></thead><tbody>';
    serials.forEach(function(s) {
        html += '<tr><td>' + (s.name||'') + '</td><td>' + (s.item_code||'') + '</td>'
              + '<td>' + (s.item_name||'') + '</td><td>' + (s.status||'') + '</td>'
+ '<td>' + (s.warehouse||'—') + '</td><td>' + (s.creation||'—') + '</td></tr>';
    });
    html += '</tbody></table>';
    document.getElementById('serialsTableWrap').innerHTML = html;
}

// ══ CONFIRM MODAL ══════════════════════════════════════════════
function showConfirm(title, text, onConfirm) {
    document.getElementById('imConfirmTitle').textContent = title;
    document.getElementById('imConfirmText').textContent = text;
    pendingConfirm = onConfirm;
    document.getElementById('imConfirmModal').style.display = 'flex';
}
function closeConfirm(){ document.getElementById('imConfirmModal').style.display = 'none'; pendingConfirm = null; }

main_section_html:
{% set lmt_settings = frappe.db.get_value('LMT Mobile Menu Item',
    {'route': 'webpage_colors_and_tilte'},
    ['background_color', 'grid_background_color'], as_dict=True) %}

{% if lmt_settings %}
<style id="lmt-dynamic-sync">
    .navbar, #navbar, .navbar-default { display: none !important; }
    .sr-topbar, .topbar, .wk-topbar { background-color: {{ lmt_settings.background_color }} !important; }
    body, .appshell, .content, .wk-app { background-color: {{ lmt_settings.grid_background_color }} !important; }
    .appshell, .wk-app { margin-top: 0 !important; padding-top: 0 !important; }
</style>
{% endif %}

<meta name="csrf-token" content="{{ csrf_token }}">
<script>
  window.CSRF_TOKEN   = "{{ csrf_token }}";
  window.CURRENT_USER = "{{ frappe.session.user }}";
</script>

<link href="https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap" rel="stylesheet">

<style>
  header.navbar, .navbar, footer, .web-footer { display: none !important; }
  :root {
    --bg:     #bfeaf4;
    --yellow: #ffd23c;
    --yellow2:#ffe26b;
    --green:  #2f8f3a;
    --red:    #dc2626;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
  }
  body { direction: rtl; background-color: var(--bg) !important; font-family: "Cairo", sans-serif !important; margin: 0; color: #0b1b22; }

  /* ── Layout ─────────────────────────────────────── */
  .stmt-app    { min-height: 100vh; padding-top: 70px; padding-bottom: 40px; }

  /* ── Top-bar ─────────────────────────────────────── */
  .stmt-topbar {
    position: fixed; top: 0; right: 0; left: 0; height: 60px;
    background: rgba(255,255,255,0.4) !important;
    border-bottom: 1px solid rgba(0,0,0,0.1) !important;
    backdrop-filter: blur(10px);
    display: flex !important; flex-direction: row !important;
    align-items: center !important; justify-content: space-between !important;
    padding: 0 15px !important; z-index: 1100;
    direction: ltr !important;
  }
  .stmt-topbar-right { display: flex !important; flex: none !important; order: 1 !important; gap: 8px !important; }
  .stmt-topbar-left  { display: flex !important; flex-direction: row !important; align-items: center !important;
                        gap: 12px !important; flex: none !important; order: 2 !important; direction: rtl !important; }
  .stmt-header-text  { margin: 0 !important; text-align: right; }
  .stmt-title        { font-weight: 900; font-size: 16px; color: #0b1b22; line-height: 1.2; }
  .stmt-desc         { font-size: 10px; color: #0b1b22; font-weight: 700; opacity: 0.7; }
  .sr-btn-icon {
    border: 1px solid rgba(0,0,0,0.2); cursor: pointer; border-radius: 999px;
    font-weight: 900; background: var(--yellow2); box-shadow: var(--shadow);
    color: #0b1b22; font-size: 16px; height: 40px; width: 40px;
    display: flex; align-items: center; justify-content: center;
  }

  /* ── Cards & fields ──────────────────────────────── */
  .stmt-card  {
    background: rgba(255,255,255,0.4) !important;
    border: 1px solid rgba(0,0,0,0.1) !important;
    border-radius: 20px; box-shadow: var(--shadow); padding: 15px; margin: 12px;
  }
  .stmt-label { color: #0b1b22; font-size: 12px; font-weight: 900; margin-bottom: 6px; padding-right: 8px; }

  /* ── Role badge ──────────────────────────────────── */
  .role-badge {
    display: inline-block; border-radius: 999px; padding: 3px 14px;
    font-size: 11px; font-weight: 900; margin-bottom: 10px;
  }
  .role-badge.admin      { background: #ffd23c; color: #0b1b22; }
  .role-badge.supervisor { background: #2f8f3a; color: #fff;    }
  .role-badge.none       { background: #dc2626; color: #fff;    }

  /* ── Pills / inputs ──────────────────────────────── */
  .sr-pill {
    background: var(--yellow); border: 1px solid rgba(0,0,0,0.15);
    border-radius: 999px; padding: 4px 16px;
    display: flex; align-items: center; box-shadow: var(--shadow); position: relative;
  }
  .stmt-input {
    width: 100%; border: none !important; background: transparent !important;
    font-family: "Cairo" !important; font-weight: 800; font-size: 14px;
    outline: none; height: 38px; color: #0b1b22; text-align: right;
  }
  input[type="date"].stmt-input { direction: ltr; text-align: left; }

  /* Sales-user select */
  .stmt-select {
    width: 100%; border: none !important; background: transparent !important;
    font-family: "Cairo" !important; font-weight: 800; font-size: 14px;
    outline: none; height: 38px; color: #0b1b22; text-align: right;
    cursor: pointer;
    -webkit-appearance: none; appearance: none;
  }

  /* ── Dropdown ────────────────────────────────────── */
  .stmt-dd {
    position: absolute; top: 100%; right: 5%; left: 5%;
    max-height: 250px; overflow-y: auto;
    background: #fff; border: 1px solid var(--green);
    border-radius: 15px; z-index: 2000; box-shadow: var(--shadow);
  }
  .stmt-search-item { padding: 12px; cursor: pointer; font-weight: 800; border-bottom: 1px solid #f0f0f0; font-size: 13px; }
  .stmt-search-item:hover { background: var(--bg); }

  /* ── Grid ────────────────────────────────────────── */
  .stmt-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-top: 12px; }

  /* ── KPIs ────────────────────────────────────────── */
  .stmt-kpis { display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; }
  .stmt-kpi  { border-radius: 15px; padding: 12px; background: #fff; border: 1px solid rgba(0,0,0,0.05); box-shadow: 0 4px 10px rgba(0,0,0,0.03); }
  .stmt-kpi-label { font-size: 11px; font-weight: 800; opacity: 0.6; }
  .stmt-kpi-val   { font-size: 16px; font-weight: 900; direction: ltr; text-align: left; color: var(--green); }

  /* ── Table ───────────────────────────────────────── */
  .stmt-tablewrap { overflow-x: auto; background: #fff; border-radius: 15px; border: 1px solid rgba(0,0,0,0.05); }
  .stmt-table { width: 100%; border-collapse: collapse; min-width: 700px; table-layout: fixed; }
  .stmt-table colgroup col:nth-child(1) { width: 11%; }
  .stmt-table colgroup col:nth-child(2) { width: 18%; }
  .stmt-table colgroup col:nth-child(3) { width: 12%; }
  .stmt-table colgroup col:nth-child(4) { width: 10%; }
  .stmt-table colgroup col:nth-child(5) { width: 12%; }
  .stmt-table colgroup col:nth-child(6) { width: 14%; }
  .stmt-table colgroup col:nth-child(7) { width: 13%; }
  .stmt-table th { background: #f8fafc; font-weight: 900; color: #0b1b22; font-size: 12px; padding: 12px 6px; border-bottom: 2px solid rgba(0,0,0,0.08); border-left: 1px solid rgba(0,0,0,0.06); text-align: center; white-space: nowrap; }
  .stmt-table td { padding: 10px 6px; text-align: center; border-bottom: 1px solid rgba(0,0,0,0.05); border-left: 1px solid rgba(0,0,0,0.04); font-size: 12px; font-weight: 700; word-break: break-word; }
  .stmt-table tbody tr:nth-child(even) td { background: #fafafa; }
  .stmt-table tbody tr:hover td { background: #f0fdf4; }

  /* ── Button ──────────────────────────────────────── */
  .stmt-btn { width: 100%; background: var(--green) !important; color: #fff !important; border: none; padding: 14px; border-radius: 999px; font-weight: 900; cursor: pointer; margin-top: 15px; font-family: 'Cairo'; font-size: 15px; box-shadow: 0 6px 15px rgba(47,143,58,0.3); }
  .stmt-btn:active { transform: scale(0.98); }
  .stmt-btn:disabled { opacity: 0.5; cursor: not-allowed; }

  /* ── Access-denied screen ────────────────────────── */
  .stmt-denied { text-align: center; padding: 60px 20px; }
  .stmt-denied-icon { font-size: 60px; margin-bottom: 16px; }
  .stmt-denied h2   { font-weight: 900; font-size: 20px; color: var(--red); }
  .stmt-denied p    { font-size: 14px; opacity: 0.7; }
</style>

<!-- ════════════════════════════════════════════════════════ -->
<!--  HTML SKELETON                                          -->
<!-- ════════════════════════════════════════════════════════ -->
<div class="stmt-app">

  <!-- Top-bar -->
  <div class="stmt-topbar">
    <div class="stmt-topbar-right">
      <button class="sr-btn-icon" onclick="location.href='/mobile-home'">🏠</button>
      <button class="sr-btn-icon" id="btnReload">⟳</button>
      <button class="sr-btn-icon" onclick="history.back()">⬅</button>
      <button class="sr-btn-icon" id="btnStatementPdf"
              style="background:#dc2626;color:white;border:none;width:auto;padding:0 14px;border-radius:999px;font-size:13px;font-weight:900;">PDF</button>
    </div>
    <div class="stmt-topbar-left">
      <div class="stmt-header-text">
        <div class="stmt-title">كشف حساب رئيسي</div>
        <div class="stmt-desc" id="topbarRoleDesc">جاري التحقق من الصلاحيات...</div>
      </div>
    </div>
  </div>

  <!-- Access-denied placeholder (hidden by default) -->
  <div id="deniedBlock" class="stmt-denied" style="display:none;">
    <div class="stmt-denied-icon">🔒</div>
    <h2>غير مصرح بالوصول</h2>
    <p>ليس لديك صلاحية <strong>admin_show_statement</strong> أو <strong>supervisor_show_statement</strong></p>
  </div>

  <!-- Main content (hidden until role confirmed) -->
  <div id="mainContent" style="display:none;">

    <!-- Filter card -->
    <div class="stmt-card">

      <!-- Role badge -->
      <div id="roleBadge" class="role-badge">—</div>

      <!-- Sales-user picker -->
      <div class="stmt-field" style="margin-bottom:12px;">
        <div class="stmt-label">👤 اختر مندوب المبيعات</div>
        <div class="sr-pill">
          <select id="salesUserSelect" class="stmt-select">
            <option value="">— اختر مندوباً —</option>
          </select>
        </div>
      </div>

      <!-- Customer search -->
      <div class="stmt-field">
        <div class="stmt-label">🔍 بحث عن زبون</div>
        <div class="sr-pill">
          <input id="search_input" class="stmt-input" placeholder="اكتب اسم الصيدلية..." autocomplete="off">
          <div id="search_dropdown" class="stmt-dd" style="display:none;"></div>
        </div>
        <input type="hidden" id="hidden_customer_id">
        <input type="hidden" id="hidden_customer_name">
      </div>

      <!-- Date range -->
      <div class="stmt-grid">
        <div class="stmt-field">
          <div class="stmt-label">من تاريخ</div>
          <div class="sr-pill"><input id="from_date" class="stmt-input" type="date"></div>
        </div>
        <div class="stmt-field">
          <div class="stmt-label">إلى تاريخ</div>
          <div class="sr-pill"><input id="to_date" class="stmt-input" type="date"></div>
        </div>
      </div>

      <button id="btnLoad" class="stmt-btn">تحديث البيانات</button>
    </div>

    <!-- KPIs -->
    <div class="stmt-card">
      <div class="stmt-kpis">
        <div class="stmt-kpi"><div class="stmt-kpi-label">إجمالي البيع</div><div class="stmt-kpi-val" id="kpiSales">0.00</div></div>
        <div class="stmt-kpi"><div class="stmt-kpi-label">إجمالي التحصيل</div><div class="stmt-kpi-val" id="kpiPaid">0.00</div></div>
        <div class="stmt-kpi"><div class="stmt-kpi-label">الرصيد النهائي</div><div class="stmt-kpi-val" id="kpiBal" style="color:#0b1b22">0.00</div></div>
        <div class="stmt-kpi"><div class="stmt-kpi-label">الحالة</div><div class="stmt-kpi-val" id="kpiStatus" style="font-size:12px">جاهز</div></div>
      </div>
    </div>

    <!-- Table -->
    <div class="stmt-card" style="margin-bottom:30px;">
      <div class="stmt-tablewrap">
        <table class="stmt-table">
          <colgroup><col><col><col><col><col><col><col></colgroup>
          <thead>
            <tr>
              <th>التاريخ</th><th>البيان</th><th>البيع</th>
              <th>الإيصال</th><th>التحصيل</th><th>النوع</th><th>الرصيد</th>
            </tr>
          </thead>
          <tbody id="tbody">
            <tr><td colspan="7" style="padding:40px;text-align:center;">اختر مندوباً ثم زبوناً</td></tr>
          </tbody>
        </table>
      </div>
    </div>

  </div><!-- /mainContent -->
</div><!-- /stmt-app -->

<!-- ════════════════════════════════════════════════════════ -->
<!--  JAVASCRIPT                                             -->
<!-- ════════════════════════════════════════════════════════ -->
<script>
/* ── Constants ─────────────────────────────────────────── */
const PAYMENT_DISPLAY = {
  "Cash":          "نقد",
  "Cheque":        "صك",
  "Bank Draft":    "صك",
  "Wire Transfer": "تحويل",
  "POS terminal":  "ماكينة نقاط بيع",
  "Credit Card":   "تحويل"
};

const CSRF        = window.CSRF_TOKEN   || "";
const CURRENT_USER= window.CURRENT_USER || "Guest";

/* state */
let selectedSalesUser = "";   // user_id of chosen sales rep
let searchTimer = null;

/* ── PDF helper ─────────────────────────────────────────── */
async function lmt_download_pdf_one_call(url, filename) {
  const res = await fetch(url, {
    method: "GET",
    headers: { "X-Frappe-CSRF-Token": CSRF, "Accept": "application/pdf" },
    credentials: "include"
  });
  if (!res.ok) {
    const t = await res.text().catch(() => "");
    throw new Error("PDF failed: " + res.status + " " + t);
  }
  const blob    = await res.blob();
  const blobUrl = URL.createObjectURL(blob);
  const a       = document.createElement("a");
  a.href = blobUrl; a.download = filename || "statement.pdf";
  document.body.appendChild(a); a.click(); a.remove();
  setTimeout(() => { try { window.open(blobUrl, "_blank"); } catch(e){} }, 300);
  setTimeout(() => URL.revokeObjectURL(blobUrl), 8000);
}

/* ── Role check & init ──────────────────────────────────── */
document.addEventListener("DOMContentLoaded", async function () {

  /* default dates */
  document.getElementById("from_date").value = "2022-01-01";
  document.getElementById("to_date").value   = new Date().toISOString().split("T")[0];

  /* 1. Fetch current user's roles */
  let userRoles = [];
  try {
    const r = await fetch(
      "/api/method/master_account_statement_get_user_roles",
      { headers: { "X-Frappe-CSRF-Token": CSRF, "Accept": "application/json" }, credentials: "include" }
    );
    const d = await r.json();
    userRoles = d.message || [];
  } catch(e) { console.error("Role fetch error:", e); }

  const isAdmin      = userRoles.includes("admin_show_statement");
  const isSupervisor = userRoles.includes("supervisor_show_statement");

  if (!isAdmin && !isSupervisor) {
    document.getElementById("deniedBlock").style.display  = "block";
    document.getElementById("topbarRoleDesc").textContent = "غير مصرح";
    return;
  }

  /* show main UI */
  document.getElementById("mainContent").style.display = "block";

  /* Role badge */
  const badge = document.getElementById("roleBadge");
  if (isAdmin) {
    badge.textContent = "🔑 مدير النظام – admin_show_statement";
    badge.className   = "role-badge admin";
    document.getElementById("topbarRoleDesc").textContent = "صلاحية: مدير (جميع المندوبين)";
  } else {
    badge.textContent = "👁 مشرف – supervisor_show_statement";
    badge.className   = "role-badge supervisor";
    document.getElementById("topbarRoleDesc").textContent = "صلاحية: مشرف (مندوبوك فقط)";
  }

  /* 2. Load sales users into dropdown */
  await loadSalesUsers();

  /* 3. Wire up customer search */
  const si = document.getElementById("search_input");
  const dd = document.getElementById("search_dropdown");

  si.addEventListener("focus", () => { si.select(); runCustomerSearch("__ALL__"); dd.style.display = "block"; });
  si.addEventListener("click", () => { si.select(); runCustomerSearch("__ALL__"); dd.style.display = "block"; });
  si.addEventListener("input", () => {
    document.getElementById("hidden_customer_id").value   = "";
    document.getElementById("hidden_customer_name").value = "";
    clearTimeout(searchTimer);
    searchTimer = setTimeout(() => runCustomerSearch(si.value), 300);
  });

  document.getElementById("salesUserSelect").addEventListener("change", function() {
    selectedSalesUser = this.value;
    /* clear customer selection when rep changes */
    si.value = "";
    document.getElementById("hidden_customer_id").value   = "";
    document.getElementById("hidden_customer_name").value = "";
    dd.style.display = "none";
    document.getElementById("tbody").innerHTML =
      '<tr><td colspan="7" style="padding:40px;text-align:center;">اختر زبوناً</td></tr>';
    resetKPIs();
  });

  document.getElementById("btnLoad").onclick   = loadStatement;
  document.getElementById("btnReload").onclick  = loadStatement;

  /* PDF button */
  document.getElementById("btnStatementPdf").onclick = async function() {
    const cid  = document.getElementById("hidden_customer_id").value;
    const cname= document.getElementById("hidden_customer_name").value ||
                 document.getElementById("search_input").value;
    if (!cid) return alert("اختر زبوناً أولاً");
    const f = document.getElementById("from_date").value || "2022-01-01";
    const t = document.getElementById("to_date").value   || new Date().toISOString().split("T")[0];
    const pdfUrl =
      "/api/method/frappe.utils.print_format.download_pdf" +
      "?doctype=" + encodeURIComponent("Customer") +
      "&name="    + encodeURIComponent(cid) +
      "&format="  + encodeURIComponent("Customer_Running_Balance") +
      "&no_letterhead=0&print_with_attachments=0" +
      "&from_date=" + encodeURIComponent(f) +
      "&to_date="   + encodeURIComponent(t) +
      "&_t=" + Date.now();
    const safeName = cname.replace(/[\/\\:*?"<>|]+/g, "_");
    const filename = "Statement_" + safeName + "_" + f + "_to_" + t + ".pdf";
    const old = this.textContent;
    this.disabled = true; this.textContent = "...";
    try {
      await lmt_download_pdf_one_call(pdfUrl, filename);
    } catch(e) {
      console.error(e); alert("فشل تنزيل PDF");
      window.open(pdfUrl, "_blank");
    } finally {
      this.disabled = false; this.textContent = old;
    }
  };

  document.addEventListener("click", (e) => {
    if (!e.target.closest("#search_input") && !e.target.closest("#search_dropdown"))
      dd.style.display = "none";
  });
});

/* ── Load sales users into <select> ─────────────────────── */
async function loadSalesUsers() {
  const sel = document.getElementById("salesUserSelect");
  sel.innerHTML = '<option value="">— جاري التحميل... —</option>';
  try {
    const r = await fetch(
      "/api/method/master_account_statement_get_sales_users",
      { headers: { "X-Frappe-CSRF-Token": CSRF, "Accept": "application/json" }, credentials: "include" }
    );
    const d = await r.json();
    const list = d.message || [];
    sel.innerHTML = '<option value="">— اختر مندوباً —</option>';
    list.forEach(u => {
      const opt = document.createElement("option");
      opt.value       = u.user_id;           /* Frappe user_id */
      opt.textContent = u.sales_person_name || u.user_id;
      opt.dataset.spName = u.sales_person_name || "";
      sel.appendChild(opt);
    });
    if (list.length === 0) {
      sel.innerHTML = '<option value="">لا يوجد مندوبون متاحون</option>';
    }
  } catch(e) {
    console.error("Sales users fetch error:", e);
    sel.innerHTML = '<option value="">خطأ في تحميل المندوبين</option>';
  }
}

/* ── Customer search (filtered by selected sales user) ───── */
function runCustomerSearch(val) {
  if (!selectedSalesUser) {
    const dd = document.getElementById("search_dropdown");
    dd.innerHTML = '<div class="stmt-search-item">⚠ اختر مندوباً أولاً</div>';
    dd.style.display = "block";
    return;
  }
  const dd = document.getElementById("search_dropdown");
  const filters = [["account_manager", "=", selectedSalesUser]];
  if (val && val !== "__ALL__") filters.push(["customer_name", "like", "%" + val + "%"]);
  fetch("/api/resource/Customer?fields=" +
        encodeURIComponent(JSON.stringify(["name","customer_name"])) +
        "&filters=" + encodeURIComponent(JSON.stringify(filters)) +
        "&limit_page_length=500")
    .then(r => r.json())
    .then(d => {
      dd.innerHTML = "";
      (d.data || []).forEach(c => {
        const item = document.createElement("div");
        item.className   = "stmt-search-item";
        item.textContent = c.customer_name;
        item.onclick = () => {
          document.getElementById("search_input").value          = c.customer_name;
          document.getElementById("hidden_customer_id").value    = c.name;
          document.getElementById("hidden_customer_name").value  = c.customer_name;
          dd.style.display = "none";
          loadStatement();
        };
        dd.appendChild(item);
      });
      dd.style.display = (d.data && d.data.length) ? "block" : "none";
    })
    .catch(() => { dd.style.display = "none"; });
}

/* ── Opening balance from GL ────────────────────────────── */
function fetchOpeningFromGL(customerKey, fromDate, toDate) {
  const url = "/api/method/lmt_opening_balance_customer" +
              "?customer="  + encodeURIComponent(customerKey || "") +
              "&from_date=" + encodeURIComponent(fromDate    || "") +
              "&to_date="   + encodeURIComponent(toDate      || "");
  return fetch(url, {
    method: "GET", credentials: "include",
    headers: { "Accept": "application/json", "X-Frappe-CSRF-Token": CSRF }
  })
  .then(r => r.json())
  .then(d => {
    const msg = (d && d.message) ? d.message : {};
    return { opening: parseFloat(msg.opening || 0) || 0, journal_entries: msg.journal_entries || [] };
  })
  .catch(() => ({ opening: 0, journal_entries: [] }));
}

/* ── Reset KPIs ─────────────────────────────────────────── */
function resetKPIs() {
  document.getElementById("kpiSales").textContent  = "0.00";
  document.getElementById("kpiPaid").textContent   = "0.00";
  document.getElementById("kpiBal").textContent    = "0.00";
  document.getElementById("kpiStatus").textContent = "جاهز";
}

/* ── Load statement ─────────────────────────────────────── */
function loadStatement() {
  const cid = document.getElementById("hidden_customer_id").value;
  const t   = document.getElementById("to_date").value;
  const f   = "2000-01-01";
  if (!cid) { alert("اختر زبوناً أولاً"); return; }
  if (!selectedSalesUser) { alert("اختر مندوباً أولاً"); return; }

  document.getElementById("kpiStatus").textContent = "جاري التحميل...";

  fetchOpeningFromGL(cid, f, t).then(gl => {
    Promise.all([
      /* Sales Invoices */
      fetch("/api/resource/Sales%20Invoice?filters=" +
            encodeURIComponent(JSON.stringify([
              ["customer","=",cid],["docstatus","=",1],
              ["posting_date",">=",f],["posting_date","<=",t]
            ])) +
            "&fields=" + encodeURIComponent(JSON.stringify(["name","posting_date","grand_total","is_return"])))
        .then(r => r.json()),

      /* Payment Entries */
      fetch("/api/resource/Payment%20Entry?filters=" +
            encodeURIComponent(JSON.stringify([
              ["party","=",cid],["docstatus","<",2],
              ["posting_date",">=",f],["posting_date","<=",t]
            ])) +
            "&fields=" + encodeURIComponent(JSON.stringify(
              ["name","posting_date","paid_amount","reference_no","mode_of_payment"])))
        .then(r => r.json()),

      /* Debt collection metadata */
      fetch("/api/resource/LMT%20Debt%20Collection?filters=" +
            encodeURIComponent(JSON.stringify([["customer","=",cid],["docstatus","<",2]])) +
            "&fields=" + encodeURIComponent(JSON.stringify(
              ["name","payment_type","mode_of_payment","receipt_no","bank"])) +
            "&limit_page_length=2000")
        .then(r => r.json())
    ])
    .then(res => {
      /* Build debtMap: receipt_no / name → display label */
      const debtMap = {};
      (res[2].data || []).forEach(d => {
        const rawType = d.payment_type || d.mode_of_payment || "";
        let displayLbl;
        if (rawType === "ماكينة نقاط بيع" || rawType === "POS terminal") {
          displayLbl = (d.bank || "ماكينة نقاط بيع").replace(/ - \S+$/, "").trim();
        } else {
          displayLbl = PAYMENT_DISPLAY[rawType] || rawType || "نقد";
        }
        if (d.receipt_no) debtMap[String(d.receipt_no)] = displayLbl;
        debtMap[d.name] = displayLbl;
      });

      const timeline = [];

      /* Invoices */
        (res[0].data || []).forEach(i => {
          const gt = parseFloat(i.grand_total || 0);
          if (i.is_return) {
            timeline.push({ date: i.posting_date, inv: i.name, sale: 0, pay: Math.abs(gt), ref: "", type: "ترجيع" });
          } else {
            timeline.push({ date: i.posting_date, inv: i.name, sale: gt, pay: 0, ref: "", type: "فاتورة" });
          }
        });

      /* Payments */
      (res[1].data || []).forEach(p => {
        const ref   = String(p.reference_no || "").trim();
        const label = debtMap[ref] || debtMap[p.name] || PAYMENT_DISPLAY[p.mode_of_payment] || p.mode_of_payment || "نقد";
        timeline.push({ date: p.posting_date, inv: p.name, sale: 0, pay: parseFloat(p.paid_amount || 0), ref, type: label });
      });

      /* Journal entries */
      (gl.journal_entries || []).forEach(j => {
        const net     = parseFloat(j.net || 0) || 0;
        const remark  = j.user_remark || "";
        const lremark = remark.toLowerCase();
        let rowType = "قيد يومية";
        if (lremark.includes("migration") || lremark.includes("opening") || remark.includes("افتتاحي"))
          rowType = "رصيد افتتاحي";
        const displayRef = remark.includes("واصل:") ? remark.split("واصل:")[1].trim() : (j.cheque_no || j.reference_no || "");
        timeline.push({ date: j.posting_date, inv: j.voucher_no || "", sale: net > 0 ? net : 0, pay: net < 0 ? (-net) : 0, ref: displayRef, type: rowType });
      });

      /* Sort newest first */
      timeline.sort((a, b) => (b.date || "").localeCompare(a.date || ""));

      /* Compute totals */
      let totalSales = 0, totalPaid = 0, runningBalance = parseFloat(gl.opening || 0);
      timeline.forEach(r => { totalSales += (r.sale || 0); totalPaid += (r.pay || 0); runningBalance += ((r.sale || 0) - (r.pay || 0)); });
      const kpiBal = runningBalance;

      /* Build rows (running balance decreases as we go down) */
      let html = "";
      timeline.forEach(r => {
        const displayBal = runningBalance;
        html += "<tr>" +
          "<td>" + (r.date || "")                    + "</td>" +
          "<td>" + (r.inv  || "")                    + "</td>" +
          "<td>" + (r.sale ? r.sale.toFixed(2) : "") + "</td>" +
          "<td>" + (r.ref  || "")                    + "</td>" +
          "<td>" + (r.pay  ? r.pay.toFixed(2)  : "") + "</td>" +
          "<td>" + (r.type || "")                    + "</td>" +
          "<td>" + displayBal.toFixed(2)             + "</td>" +
        "</tr>";
        runningBalance = runningBalance - (r.sale || 0) + (r.pay || 0);
      });

      document.getElementById("tbody").innerHTML = html ||
        '<tr><td colspan="7" style="padding:40px;text-align:center;">لا توجد بيانات</td></tr>';
      document.getElementById("kpiSales").textContent  = totalSales.toFixed(2);
      document.getElementById("kpiPaid").textContent   = totalPaid.toFixed(2);
      document.getElementById("kpiBal").textContent    = kpiBal.toFixed(2);
      document.getElementById("kpiStatus").textContent = "جاهز";
    })
    .catch(err => {
      console.error(err);
      document.getElementById("kpiStatus").textContent = "خطأ";
      alert("حدث خطأ أثناء تحميل البيانات");
    });
  });
}
</script>

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');
:root {
    direction: rtl;
    --yellow: #ffd23c;
    --yellow2: #ffe26b;
    --green: #2f8f3a;
    --green2: #2aa334;
    --shadow: 0 4px 16px rgba(0,0,0,.1);
    --red: #e53935;
}
header.navbar,.navbar,.top-navbar,footer,.web-footer { display: none !important; }
body { padding: 0 !important; margin: 0 !important; background: #bfeaf4; font-family: "Cairo", sans-serif; direction: rtl; color: #0b1b22; }
.page_content,.page-content,main,.main-section { margin: 0 !important; padding: 0 !important; }
.sr-topbar { position: sticky; top: 0; z-index: 50; display: flex; gap: 8px; align-items: center; padding: 10px 12px; background: rgba(255,255,255,.35); border-bottom: 1px solid rgba(0,0,0,.15); backdrop-filter: blur(6px); }
.sr-btn-icon { border: none; cursor: pointer; border-radius: 999px; padding: 8px 12px; font-weight: 900; font-size: 15px; box-shadow: var(--shadow); background: var(--yellow2); border: 1px solid rgba(0,0,0,.2); }
.sr-title { font-weight: 900; font-size: 16px; margin-right: auto; margin-left: 8px; }
.sr-wrap { max-width: 900px; margin: 0 auto; padding: 12px 14px 40px; }
.sr-search-box { margin-bottom: 10px; }
.sr-search-box input { width: 100%; padding: 10px 14px; border-radius: 999px; border: 1px solid rgba(0,0,0,.2); font-family: "Cairo", sans-serif; font-size: 15px; font-weight: 700; background: rgba(255,255,255,.8); box-sizing: border-box; direction: rtl; }
.sr-selected-pill { display: flex; align-items: center; justify-content: space-between; background: var(--green2); color: #fff; border-radius: 999px; padding: 10px 16px; margin-bottom: 12px; font-weight: 900; font-size: 15px; }
.sr-selected-pill button { background: rgba(255,255,255,.3); border: none; border-radius: 999px; color: #fff; font-size: 16px; cursor: pointer; padding: 2px 8px; }
.sr-menu-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-top: 8px; }
.sr-menu-tile { background: var(--yellow); border: 1px solid rgba(0,0,0,.2); border-radius: 16px; padding: 20px 12px; text-align: center; font-weight: 900; font-size: 15px; cursor: pointer; box-shadow: var(--shadow); transition: .15s; }
.sr-menu-tile:active { transform: scale(.97); }
.sr-card { background: rgba(255,255,255,.7); border-radius: 14px; padding: 16px; box-shadow: var(--shadow); }
.sr-card .row { display: flex; justify-content: space-between; padding: 8px 0; border-bottom: 1px solid rgba(0,0,0,.08); font-size: 14px; font-weight: 700; }
.sr-card .row .val { font-weight: 900; font-size: 15px; }
.sr-card .neg .val { color: var(--red); }
.sr-card .pos .val { color: var(--green); }
.sr-table-wrap { border-radius: 14px; overflow-x: auto; border: 1px solid rgba(0,0,0,.2); box-shadow: var(--shadow); -webkit-overflow-scrolling: touch; }
table { width: 100%; border-collapse: collapse; min-width: 500px; }
thead th { background: linear-gradient(180deg, var(--green2), var(--green)); color: #fff; padding: 9px 8px; font-weight: 900; font-size: 12px; border-left: 1px solid rgba(255,255,255,.2); white-space: nowrap; }
tbody td { background: var(--yellow); border-top: 1px solid rgba(0,0,0,.15); border-left: 1px solid rgba(0,0,0,.1); padding: 7px 8px; font-weight: 700; font-size: 12px; white-space: nowrap; }
tbody tr:nth-child(even) td { background: #ffe16a; }
.sr-btn { border: none; cursor: pointer; border-radius: 999px; padding: 8px 18px; font-family: "Cairo", sans-serif; font-weight: 900; font-size: 13px; box-shadow: var(--shadow); background: var(--yellow2); border: 1px solid rgba(0,0,0,.2); }
.cust-item { padding: 12px 14px; background: rgba(255,255,255,.6); border-radius: 12px; margin-bottom: 8px; cursor: pointer; font-weight: 700; border: 1px solid rgba(0,0,0,.1); }
.cust-item:active { background: var(--yellow); }
.cust-item .bal { font-weight: 900; font-size: 13px; }
.cust-item .bal.neg { color: var(--red); }
.cust-item .agent-tag { font-size: 11px; color: #555; margin-top: 2px; }
@media print { .sr-topbar, #btnBack, button { display: none !important; } .sr-wrap { padding: 0; } }

javascript:
var CK = null, CN = null, CA = null, currentView = null;

function fmt(n) { return Number(n || 0).toLocaleString("ar-LY", { minimumFractionDigits: 3 }); }
function fmtDate(d) { return d ? String(d).substring(0, 10) : ""; }
function showEl(id) { document.getElementById(id).style.display = ""; }
function hideEl(id) { document.getElementById(id).style.display = "none"; }

function goBack() {
    hideEl(currentView);
    showEl("viewMenu");
    document.getElementById("btnBack").style.display = "none";
    document.getElementById("topTitle").innerText = CN || "بيانات المندوبين";
    currentView = null;
}

function showView(id) {
    if (currentView) hideEl(currentView);
    showEl(id);
    currentView = id;
    document.getElementById("btnBack").style.display = "";
    var titles = {
        viewReport:    "التقرير المبسط",
        viewClosed:    "الطلبيات المغلقة",
        viewCancelled: "الطلبيات الملغاة",
        viewStatement: "كشف الحساب"
    };
    document.getElementById("topTitle").innerText = titles[id] || "";
    if (id === "viewReport")    loadReport();
    if (id === "viewClosed")    loadClosed();
    if (id === "viewCancelled") loadCancelled();
    if (id === "viewStatement") loadStatement();
}

// Load agent list into dropdown
function loadAgents() {
    frappe.call({
        method: "master_get_customers",
        args: { search: "", agent_email: "" },
        callback: function(r) {
            var data = (r.message || {}).data || [];
            var agents = {};
            data.forEach(function(c) {
                if (c.agent_email && c.agent_name) {
                    agents[c.agent_email] = c.agent_name;
                }
            });
            var sel = document.getElementById("agentFilter");
            Object.keys(agents).sort().forEach(function(email) {
                var opt = document.createElement("option");
                opt.value = email;
                opt.innerText = agents[email];
                sel.appendChild(opt);
            });
        }
    });
}

var searchTimer = null;
function doSearch() {
    clearTimeout(searchTimer);
    searchTimer = setTimeout(function() {
        var q     = document.getElementById("searchInput").value;
        var agent = document.getElementById("agentFilter").value;
        document.getElementById("customerList").innerHTML = "<div style='text-align:center;padding:12px'>&#x23F3; جاري البحث...</div>";
        frappe.call({
            method: "master_get_customers",
            args: { search: q, agent_email: agent },
            callback: function(r) {
                var data = (r.message || {}).data || [];
                var list = document.getElementById("customerList");
                list.innerHTML = "";
                if (!data.length) {
                    list.innerHTML = "<div style='padding:12px;text-align:center'>لا نتائج</div>";
                    return;
                }
                data.forEach(function(c) {
                    var bal = parseFloat(c.balance || 0);
                    var bc  = bal > 0 ? "neg" : "pos";
                    var el  = document.createElement("div");
                    el.className = "cust-item";
                    el.dataset.key   = c.lmt_key;
                    el.dataset.name  = c.customer_name;
                    el.dataset.agent = c.agent_name || "";
                    el.innerHTML = "<div>" + c.customer_name + "</div>"
                        + "<div class='agent-tag'>&#x1F464; " + (c.agent_name || "") + "</div>"
                        + "<div class='bal " + bc + "'>الرصيد: " + fmt(bal) + " د.ل</div>";
                    el.onclick = function() {
                        selectCustomer(this.dataset.key, this.dataset.name, this.dataset.agent);
                    };
                    list.appendChild(el);
                });
            }
        });
    }, 350);
}

function selectCustomer(key, name, agent) {
    CK = key; CN = name; CA = agent;
    hideEl("viewSearch");
    document.getElementById("selectedName").innerText  = name;
    document.getElementById("selectedAgent").innerText = agent ? ("المندوب: " + agent) : "";
    showEl("selectedPill");
    showEl("viewMenu");
    document.getElementById("topTitle").innerText = name;
}

function clearCustomer() {
    CK = null; CN = null; CA = null;
    if (currentView) { hideEl(currentView); currentView = null; }
    hideEl("selectedPill");
    hideEl("viewMenu");
    showEl("viewSearch");
    document.getElementById("searchInput").value = "";
    document.getElementById("customerList").innerHTML = "";
    document.getElementById("topTitle").innerText = "بيانات المندوبين";
    document.getElementById("btnBack").style.display = "none";
    doSearch();
}

function loadReport() {
    document.getElementById("reportCard").innerHTML = "<div style='text-align:center;padding:20px'>&#x23F3; جاري التحميل...</div>";
    frappe.call({
        method: "master_simple_report",
        args: { customer_key: CK },
        callback: function(r) {
            var d   = (r.message || {}).data || {};
            var bal = parseFloat(d.balance || 0);
            var html = "";
            html += "<div class='row'><span>الاسم</span><span class='val'>"       + (d.customer_name || "") + "</span></div>";
            html += "<div class='row'><span>المندوب</span><span class='val'>"     + (d.agent_name || "") + "</span></div>";
            html += "<div class='row'><span>النوع</span><span class='val'>"       + (d.customer_type || "") + "</span></div>";
            html += "<div class='row'><span>المدينة</span><span class='val'>"     + (d.location || "") + "</span></div>";
            html += "<div class='row'><span>إجمالي المبيعات</span><span class='val'>" + fmt(d.sales) + " د.ل</span></div>";
            html += "<div class='row pos'><span>إجمالي التحصيل</span><span class='val'>" + fmt(d.receive) + " د.ل</span></div>";
            html += "<div class='row " + (bal > 0 ? "neg" : "pos") + "'><span>الرصيد</span><span class='val'>" + fmt(bal) + " د.ل</span></div>";
            html += "<div class='row'><span>نسبة الديون</span><span class='val'>" + (parseFloat(d.percentage || 0) * 100).toFixed(1) + "%</span></div>";
            html += "<div class='row'><span>آخر بيع</span><span class='val'>"     + fmtDate(d.last_sale_date) + "</span></div>";
            html += "<div class='row'><span>آخر تحصيل</span><span class='val'>"  + fmtDate(d.last_received_date) + "</span></div>";
            document.getElementById("reportCard").innerHTML = html;
        }
    });
}

function loadClosed() {
    var search = document.getElementById("closedSearch") ? document.getElementById("closedSearch").value : "";
    frappe.call({
        method: "master_closed_orders",
        args: { customer_key: CK, search: search },
        callback: function(r) {
            var rows = (r.message || {}).data || [];
            var wrap = document.getElementById("closedTable");
            if (!rows.length) { wrap.innerHTML = "<div style='padding:14px;text-align:center'>لا يوجد طلبيات</div>"; return; }
            var tbl = document.createElement("table");
            tbl.innerHTML = "<thead><tr><th>الفاتورة</th><th>التاريخ</th><th>النوع</th><th>الصافي</th><th>الكميات</th><th>فاتورة</th></tr></thead>";
            var tb = document.createElement("tbody");
            rows.forEach(function(o) {
                var tr  = document.createElement("tr");
                var btn = document.createElement("button");
                btn.className   = "sr-btn";
                btn.innerText   = "🧾";
                btn.dataset.oid = o.lmt_order_id;
                btn.onclick = function() { openInvoice(this.dataset.oid); };
                tr.innerHTML = "<td>" + (o.invoice || o.lmt_order_id) + "</td><td>" + fmtDate(o.order_date) + "</td><td>" + (o.trans_type || "") + "</td><td>" + fmt(o.total_cost) + "</td><td>" + fmt(o.total_qty) + "</td><td></td>";
                tr.lastElementChild.appendChild(btn);
                tb.appendChild(tr);
            });
            tbl.appendChild(tb); wrap.innerHTML = ""; wrap.appendChild(tbl);
        }
    });
}

function loadCancelled() {
    frappe.call({
        method: "master_cancelled_orders",
        args: { customer_key: CK },
        callback: function(r) {
            var rows = (r.message || {}).data || [];
            var wrap = document.getElementById("cancelledTable");
            if (!rows.length) { wrap.innerHTML = "<div style='padding:14px;text-align:center'>لا يوجد طلبيات ملغاة</div>"; return; }
            var tbl = document.createElement("table");
            tbl.innerHTML = "<thead><tr><th>الفاتورة</th><th>التاريخ</th><th>النوع</th><th>الصافي</th><th>السبب</th></tr></thead>";
            var tb = document.createElement("tbody");
            rows.forEach(function(o) {
                var tr = document.createElement("tr");
                tr.innerHTML = "<td>" + (o.invoice || o.lmt_order_id) + "</td><td>" + fmtDate(o.order_date) + "</td><td>" + (o.trans_type || "") + "</td><td>" + fmt(o.total_cost) + "</td><td>" + (o.reason || "") + "</td>";
                tb.appendChild(tr);
            });
            tbl.appendChild(tb); wrap.innerHTML = ""; wrap.appendChild(tbl);
        }
    });
}

function loadStatement() {
    frappe.call({
        method: "master_account_statement",
        args: { customer_key: CK },
        callback: function(r) {
            var rows = (r.message || {}).data || [];
            var wrap = document.getElementById("statementTable");
            if (!rows.length) { wrap.innerHTML = "<div style='padding:14px;text-align:center'>لا يوجد حركات</div>"; return; }
            var tbl = document.createElement("table");
            tbl.innerHTML = "<thead><tr><th>التاريخ</th><th>المرجع</th><th>النوع</th><th>مدين</th><th>دائن</th><th>خصم تسوية</th><th>الرصيد</th></tr></thead>";
            var tb = document.createElement("tbody");
            rows.forEach(function(o) {
                var bal  = parseFloat(o.running_balance || 0);
                var disc = parseFloat(o.discount || 0);
                var tr   = document.createElement("tr");
                var discCell = disc > 0 ? "<span style='color:#e65100;font-weight:900'>" + fmt(disc) + "</span>" : "";
                tr.innerHTML = "<td>" + fmtDate(o.date) + "</td><td>" + (o.ref || "") + "</td><td>" + (o.trans_type || "") + "</td>"
                    + "<td>" + (parseFloat(o.debit || 0) > 0 ? fmt(o.debit) : "") + "</td>"
                    + "<td>" + (parseFloat(o.credit || 0) > 0 ? fmt(o.credit) : "") + "</td>"
                    + "<td>" + discCell + "</td>"
                    + "<td style='font-weight:900;color:" + (bal > 0 ? "#e53935" : "#2f8f3a") + "'>" + fmt(bal) + "</td>";
                tb.appendChild(tr);
            });
            tbl.appendChild(tb); wrap.innerHTML = ""; wrap.appendChild(tbl);
        }
    });
}

function openInvoice(oid) {
    frappe.call({
        method: "lmt_legacy_get_invoice",
        args: { order_id: oid },
        callback: function(r) {
            var lmt_name = (r.message || {}).lmt_name || "";
            if (!lmt_name) { frappe.msgprint("لم يتم العثور على الطلب"); return; }
            window.open("/api/method/frappe.utils.print_format.download_pdf?doctype=LMT%20Order&name=" + encodeURIComponent(lmt_name) + "&format=LMT%20Legacy%20Invoice&no_letterhead=0", "_blank");
        }
    });
}

function printStatementPDF() {
    if (!CK) { frappe.msgprint("اختر زبون أولاً"); return; }
    var btn = document.getElementById("btnStatementPrint");
    var orig = btn.innerHTML;
    btn.innerHTML = "&#x23F3; جاري تجهيز كشف الحساب...";
    btn.disabled = true;
    frappe.call({
        method: "lmt_legacy_get_real_customer_6",
        args: { customer_key: CK, customer_name: CN },
        callback: function(r) {
            if (r.message) {
                var pdfUrl = "/api/method/frappe.utils.print_format.download_pdf"
                    + "?doctype=Customer"
                    + "&name=" + encodeURIComponent(r.message)
                    + "&format=LMT%20Legacy%20Customer%20Statement"
                    + "&no_letterhead=1";
                window.open(pdfUrl, "_blank");
            } else {
                frappe.msgprint("خطأ: لم يتم العثور على بيانات هذا الزبون.");
            }
            btn.innerHTML = orig;
            btn.disabled = false;
        }
    });
}

frappe.ready(function() {
    document.getElementById("searchInput").addEventListener("input", doSearch);
    loadAgents();
    doSearch();
});

css:
* { box-sizing: border-box; margin: 0; padding: 0; }

body {
    background: #0f1420;
    color: #f0f0f0;
    font-family: 'Tajawal', sans-serif;
    direction: rtl;
    min-height: 100vh;
    padding-bottom: 60px;
}

/* ── Topbar ── */
.topbar {
    background: #1a2035;
    border-bottom: 3px solid #f5c518;
    padding: 11px 14px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    position: sticky;
    top: 0;
    z-index: 100;
    box-shadow: 0 2px 12px rgba(0,0,0,0.4);
}
.topbar-title { font-size: 17px; font-weight: 900; color: #f5c518; }
.topbar-left  { display: flex; gap: 8px; }

.btn-icon {
    background: #f5c518;
    border: none;
    border-radius: 50%;
    width: 34px; height: 34px;
    font-size: 15px; font-weight: 700;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    transition: transform 0.15s;
}
.btn-icon:active { transform: scale(0.9); }

/* ── Container ── */
.container { max-width: 720px; margin: 0 auto; padding: 14px; }

/* ── Filter Card ── */
.filter-card {
    background: #1a2035;
    border-radius: 16px;
    padding: 16px;
    margin-bottom: 14px;
    border: 1px solid #2a3250;
}
.filter-title {
    font-size: 13px; font-weight: 700; color: #f5c518;
    margin-bottom: 12px;
}
.filter-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 10px;
    margin-bottom: 12px;
}
.filter-item { display: flex; flex-direction: column; gap: 4px; }
.filter-label { font-size: 11px; color: #888; }

select, input[type="date"] {
    background: #0f1420;
    border: 1px solid #2a3250;
    border-radius: 10px;
    color: #f0f0f0;
    font-family: 'Tajawal', sans-serif;
    font-size: 13px;
    padding: 9px 12px;
    width: 100%;
    appearance: none;
    -webkit-appearance: none;
    cursor: pointer;
}
select:focus, input[type="date"]:focus {
    outline: none; border-color: #f5c518;
}

/* ── Status Pills ── */
.status-pills {
    display: flex; gap: 8px; flex-wrap: wrap;
    margin-bottom: 12px;
}
.pill {
    padding: 7px 16px;
    border-radius: 20px;
    font-size: 12px; font-weight: 700;
    cursor: pointer;
    border: 2px solid transparent;
    transition: all 0.2s;
    font-family: 'Tajawal', sans-serif;
    background: #0f1420;
}
.pill-all  { color: #aaa; }
.pill-new  { color: #28a745; }
.pill-pick { color: #fd7e14; }
.pill-disp { color: #dc3545; }

.pill.active { border-color: currentColor; }
.pill-all.active  { background: #2a3250; color: #f0f0f0; }
.pill-new.active  { background: #1a3a2a; }
.pill-pick.active { background: #3a2a1a; }
.pill-disp.active { background: #3a1a1a; }

/* ── Load Button ── */
.btn-load {
    width: 100%;
    background: #f5c518; color: #0f1420;
    border: none; border-radius: 12px;
    padding: 13px;
    font-size: 15px; font-weight: 900;
    cursor: pointer; font-family: 'Tajawal', sans-serif;
    transition: all 0.2s;
    display: flex; align-items: center; justify-content: center; gap: 8px;
}
.btn-load:active { transform: scale(0.98); }
.btn-load:disabled { opacity: 0.5; cursor: not-allowed; }

/* ── Summary Bar ── */
.summary-bar {
    background: #1a2035;
    border-radius: 12px;
    padding: 12px 16px;
    margin-bottom: 12px;
    display: flex;
    align-items: center;
    justify-content: space-around;
    border: 1px solid #2a3250;
}
.summary-stat { text-align: center; }
.num { font-size: 22px; font-weight: 900; }
.lbl { font-size: 10px; color: #888; margin-top: 2px; }
.num-total { color: #f5c518; }
.num-new   { color: #28a745; }
.num-pick  { color: #fd7e14; }
.num-disp  { color: #dc3545; }

/* ── Bulk Bar ── */
.bulk-bar {
    background: #1a2035;
    border-radius: 12px;
    padding: 12px 14px;
    margin-bottom: 12px;
    border: 1px solid #2a3250;
    display: none;
}
.bulk-bar.visible { display: block; }
.bulk-label { font-size: 12px; color: #aaa; margin-bottom: 8px; }
.bulk-count { color: #f5c518; font-weight: 900; }
.bulk-btns  { display: flex; gap: 8px; flex-wrap: wrap; }
.bulk-btns .btn { flex: 1; min-width: 90px; }

/* ── Select All Row ── */
.select-all-row {
    display: flex; align-items: center; gap: 8px;
    font-size: 12px; color: #666;
    margin-bottom: 8px; padding: 0 2px;
}
#selectAll {
    width: 16px; height: 16px;
    cursor: pointer;
    accent-color: #f5c518;
}

/* ── Order Cards ── */
.order-card {
    background: #1a2035;
    border-radius: 14px;
    padding: 14px;
    margin-bottom: 10px;
    border: 1px solid #2a3250;
    border-right: 4px solid #2a3250;
    transition: border-color 0.2s;
}
.order-card.selected      { border-color: #f5c518 !important; }
.order-card.ws-NEW        { border-right-color: #28a745; }
.order-card.ws-PICKING    { border-right-color: #fd7e14; }
.order-card.ws-DISPATCHED { border-right-color: #dc3545; }

.card-header {
    display: flex; align-items: flex-start; gap: 10px;
    margin-bottom: 10px;
}
.card-cb {
    width: 18px; height: 18px;
    cursor: pointer; flex-shrink: 0; margin-top: 3px;
    accent-color: #f5c518;
}
.order-meta  { flex: 1; min-width: 0; }
.order-name  { font-size: 11px; font-weight: 800; color: #f5c518; font-family: monospace; direction: ltr; display: block; }
.order-customer { font-size: 14px; font-weight: 700; color: #f0f0f0; margin-top: 2px; }
.order-sub   { font-size: 11px; color: #555; margin-top: 2px; }
.order-amount { font-size: 16px; font-weight: 900; color: #f5c518; white-space: nowrap; }

.info-row {
    display: flex; align-items: center;
    justify-content: space-between;
    margin-bottom: 8px;
}

/* Badges */
.badge { display: inline-block; border-radius: 8px; padding: 3px 10px; font-size: 11px; font-weight: 700; }
.badge-NEW        { background: #1a3a2a; color: #28a745; border: 1px solid #28a74530; }
.badge-PICKING    { background: #3a2a1a; color: #fd7e14; border: 1px solid #fd7e1430; }
.badge-DISPATCHED { background: #3a1a1a; color: #dc3545; border: 1px solid #dc354530; }
.badge-OTHER      { background: #2a2a2a; color: #888; }

/* Logs */
.logs-row { display: flex; gap: 5px; align-items: center; margin-bottom: 8px; }
.logs-lbl { font-size: 10px; color: #555; margin-left: 4px; }
.log-dot {
    width: 22px; height: 22px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-size: 10px; font-weight: 700;
}
.log-on  { background: #28a745; color: #fff; }
.log-off { background: #1f2535; color: #444; border: 1px solid #333; }

/* DN chips */
.dn-chips { display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 6px; }
.dn-chip {
    background: #0f1420;
    border: 1px solid #2a3250;
    border-radius: 6px;
    padding: 2px 8px;
    font-size: 10px; color: #7ab8f5;
    font-family: monospace; direction: ltr;
}

/* Fix buttons */
.fix-btns { display: flex; gap: 6px; margin-top: 10px; flex-wrap: wrap; }

.btn {
    border: none; border-radius: 8px;
    padding: 7px 14px;
    font-size: 12px; font-weight: 700;
    cursor: pointer; font-family: 'Tajawal', sans-serif;
    transition: all 0.15s;
}
.btn:active { transform: scale(0.96); }
.btn-new  { background: #28a745; color: #fff; }
.btn-pick { background: #fd7e14; color: #fff; }
.btn-disp { background: #dc3545; color: #fff; }

/* ── Messages ── */
.msg {
    padding: 10px 14px; border-radius: 10px;
    font-size: 13px; font-weight: 600;
    margin-bottom: 12px; display: none;
}
.msg.show    { display: block; }
.msg.success { background: #1a3a2a; border: 1px solid #28a745; color: #5cb85c; }
.msg.error   { background: #3a1a1a; border: 1px solid #dc3545; color: #e57373; }
.msg.info    { background: #1a2535; border: 1px solid #4a90d9; color: #7ab8f5; }

/* ── Spinner ── */
.spinner {
    width: 16px; height: 16px;
    border: 2px solid #0f1420;
    border-top-color: #f5c518;
    border-radius: 50%;
    animation: spin 0.7s linear infinite;
    display: inline-block;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ── Empty State ── */
.empty-state { text-align: center; padding: 40px 20px; color: #444; }
.empty-state .icon { font-size: 40px; margin-bottom: 10px; }

javascript:
let allOrders = [];
let selectedStatus = '';

// ── Init ─────────────────────────────────────────────────────
async function init() {
    const today = new Date();
    const prior = new Date();
    prior.setDate(today.getDate() - 30);
    document.getElementById('dateTo').value   = today.toISOString().slice(0, 10);
    document.getElementById('dateFrom').value = prior.toISOString().slice(0, 10);

    try {
        const res = await frappe.call({ method: 'wh_fix_get_filters' });
        const { warehouses, sales_reps } = res.message;

        const wSel = document.getElementById('filterWarehouse');
        warehouses.forEach(w => {
            const o = document.createElement('option');
            o.value = w; o.textContent = w;
            wSel.appendChild(o);
        });

        const rSel = document.getElementById('filterRep');
        sales_reps.forEach(r => {
            const o = document.createElement('option');
            o.value = r.name; o.textContent = r.label || r.name;
            rSel.appendChild(o);
        });
    } catch(e) {
        showMsg('خطأ في تحميل الفلاتر: ' + (e.message || ''), 'error');
    }
}

// ── Status Pill ───────────────────────────────────────────────
function setPill(el, val) {
    document.querySelectorAll('.pill').forEach(p => p.classList.remove('active'));
    el.classList.add('active');
    selectedStatus = val;
}

// ── Load Orders ───────────────────────────────────────────────
async function loadOrders() {
    const btn = document.getElementById('btnLoad');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner"></span> جاري التحميل...';
    hideMsg();

    try {
        const res = await frappe.call({
            method: 'wh_fix_get_orders',
            args: {
                warehouse:        document.getElementById('filterWarehouse').value,
                sales_rep:        document.getElementById('filterRep').value,
                date_from:        document.getElementById('dateFrom').value,
                date_to:          document.getElementById('dateTo').value,
                warehouse_status: selectedStatus
            }
        });

        allOrders = res.message || [];
        renderOrders();
        updateSummary();
        document.getElementById('resultSection').style.display = 'block';
        document.getElementById('summaryBar').style.display    = 'flex';

        if (!allOrders.length) {
            showMsg('لا توجد طلبات تطابق الفلتر', 'info');
        } else {
            showMsg(`تم تحميل ${allOrders.length} طلب`, 'success');
        }
    } catch(e) {
        showMsg('خطأ: ' + (e.message || JSON.stringify(e)), 'error');
    } finally {
        btn.disabled = false;
        btn.innerHTML = '🔍 عرض الطلبات';
    }
}

// ── Render Orders ─────────────────────────────────────────────
function renderOrders() {
    const list = document.getElementById('orderList');
    list.innerHTML = '';
    document.getElementById('selectAll').checked = false;
    updateBulkBar();

    if (!allOrders.length) {
        list.innerHTML = `<div class="empty-state">
            <div class="icon">📭</div><div>لا توجد طلبات</div>
        </div>`;
        return;
    }

    allOrders.forEach((o, i) => {
        const ws = o.custom_warehouse_status || 'OTHER';

        const badgeMap = {
            NEW:        ['badge-NEW',        'جديد'],
            PICKING:    ['badge-PICKING',    'تجهيز'],
            DISPATCHED: ['badge-DISPATCHED', 'تم الإرسال'],
        };
        const [badgeCls, badgeLbl] = badgeMap[ws] || ['badge-OTHER', ws];

        const dns = (o.delivery_notes || [])
            .map(d => `<span class="dn-chip">${d.name}</span>`).join('');

        const card = document.createElement('div');
        card.className = `order-card ws-${ws}`;
        card.id = `card-${i}`;

        card.innerHTML = `
            <div class="card-header">
                <input type="checkbox" class="card-cb" data-idx="${i}" data-name="${o.name}"
                    onchange="onCardCheck()">
                <div class="order-meta">
                    <span class="order-name">${o.name}</span>
                    <div class="order-customer">${o.customer || '—'}</div>
                    <div class="order-sub">${o.transaction_date || ''} | ${o.set_warehouse || ''}</div>
                </div>
                <div class="order-amount">${(o.grand_total || 0).toLocaleString()} د.ل</div>
            </div>

            <div class="info-row">
                <span class="badge ${badgeCls}">${badgeLbl}</span>
                <span style="font-size:11px; color:#555;">${o.workflow_state || ''}</span>
            </div>

            <div class="logs-row">
                <span class="logs-lbl">Logs:</span>
                ${[1,2,3,4].map(n =>
                    `<div class="log-dot ${o['custom_log_'+n] ? 'log-on' : 'log-off'}">${n}</div>`
                ).join('')}
            </div>

            ${dns ? `<div class="dn-chips">${dns}</div>` : ''}

            <div class="fix-btns">
                <button class="btn btn-new"  onclick="fixOne('${o.name}','NEW')">✅ جديد</button>
                <button class="btn btn-pick" onclick="fixOne('${o.name}','PICKING')">📦 تجهيز</button>
                <button class="btn btn-disp" onclick="fixOne('${o.name}','DISPATCHED')">🚚 تم الإرسال</button>
            </div>
        `;
        list.appendChild(card);
    });

    updateBulkBar();
}

// ── Summary ───────────────────────────────────────────────────
function updateSummary() {
    document.getElementById('statTotal').textContent = allOrders.length;
    document.getElementById('statNew').textContent   = allOrders.filter(o => o.custom_warehouse_status === 'NEW').length;
    document.getElementById('statPick').textContent  = allOrders.filter(o => o.custom_warehouse_status === 'PICKING').length;
    document.getElementById('statDisp').textContent  = allOrders.filter(o => o.custom_warehouse_status === 'DISPATCHED').length;
}

// ── Checkbox Logic ────────────────────────────────────────────
function toggleAll(checked) {
    document.querySelectorAll('.card-cb').forEach(cb => {
        cb.checked = checked;
        const card = document.getElementById(`card-${cb.dataset.idx}`);
        if (card) card.classList.toggle('selected', checked);
    });
    updateBulkBar();
}

function onCardCheck() {
    document.querySelectorAll('.card-cb').forEach(cb => {
        const card = document.getElementById(`card-${cb.dataset.idx}`);
        if (card) card.classList.toggle('selected', cb.checked);
    });
    const total   = document.querySelectorAll('.card-cb').length;
    const checked = document.querySelectorAll('.card-cb:checked').length;
    const sa = document.getElementById('selectAll');
    sa.checked       = checked === total && total > 0;
    sa.indeterminate = checked > 0 && checked < total;
    updateBulkBar();
}

function getSelected() {
    return [...document.querySelectorAll('.card-cb:checked')].map(cb => cb.dataset.name);
}

function updateBulkBar() {
    const sel = getSelected().length;
    document.getElementById('bulkCount').textContent = sel;
    document.getElementById('bulkBar').classList.toggle('visible', sel > 0);
}

// ── Fix Actions ───────────────────────────────────────────────
async function fixOne(name, state) {
    await doFix([name], state);
}

async function bulkFix(state) {
    const sel = getSelected();
    if (!sel.length) { showMsg('حدد طلباً واحداً على الأقل', 'error'); return; }
    await doFix(sel, state);
}

async function doFix(orders, state) {
    hideMsg();
    showMsg('جاري الإصلاح...', 'info');
    try {
        const res = await frappe.call({
            method: 'wh_fix_set_state',
            args: {
                orders:       orders.join(','),
                target_state: state
            }
        });
        const r = res.message;
        if (r.fixed.length)  showMsg(`✅ تم إصلاح ${r.fixed.length} طلب بنجاح`, 'success');
        if (r.errors.length) showMsg(`⚠️ أخطاء: ${r.errors.map(e => e.name + ': ' + e.error).join(' | ')}`, 'error');
        await loadOrders();
    } catch(e) {
        showMsg('خطأ: ' + (e.message || e), 'error');
    }
}

// ── Messages ──────────────────────────────────────────────────
function showMsg(text, type) {
    const el = document.getElementById('mainMsg');
    el.className = `msg show ${type}`;
    el.textContent = text;
}
function hideMsg() {
    document.getElementById('mainMsg').className = 'msg';
}

// ── Boot ──────────────────────────────────────────────────────
frappe.ready(() => init());

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;800;900&display=swap');

:root, html { 
    --primary-blue: #004b80; 
    --bg-main: #bfeaf4;
    --yellow: #ffd23c;
    --yellow-light: #ffe26b;
    --green: #2f8f3a;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
    --text: #0b1b22;
    direction: rtl;
}

* { box-sizing: border-box; }

body, .page-container, .main-section, .appshell, .content { 
    background-color: var(--bg-main) !important; 
    font-family: "Cairo", sans-serif !important;
    margin: 0; padding: 0; min-height: 100vh;
}

header, footer, .web-footer, .navbar { display: none !important; }

/* ===== UNIFIED TOPBAR ===== */
.sr-topbar {
    display: flex !important; flex-direction: row !important; justify-content: space-between !important;
    align-items: center !important; padding: 0 15px !important; height: 65px !important;
    width: 100% !important; box-sizing: border-box !important; direction: ltr !important;
    background: rgba(255, 255, 255, 0.4) !important; backdrop-filter: blur(10px) !important;
    border-bottom: 1px solid rgba(0,0,0,0.1) !important; position: fixed; top: 0; left: 0; right: 0; z-index: 1100;
}
.topbar-left { display: flex !important; gap: 8px !important; flex: none !important; order: 1 !important; }
.topbar-right { display: flex !important; flex-direction: row !important; align-items: center !important; gap: 12px !important; flex: none !important; order: 2 !important; direction: rtl !important; }
.sr-title { text-align: right !important; margin: 0 !important; font-weight: 900; font-size: 16px; color: var(--text); font-family: "Cairo", sans-serif !important; }

.sr-btn-icon { 
    background-color: var(--yellow-light) !important; border: 1px solid rgba(0,0,0,0.2) !important; 
    border-radius: 999px !important; font-size: 16px !important; font-weight: 900 !important;
    cursor: pointer !important; width: 40px !important; height: 40px !important; 
    display: flex !important; align-items: center !important; justify-content: center !important; 
    box-shadow: var(--shadow) !important; margin: 0 !important; color: #0b1b22 !important; padding: 0 !important;
}

/* --- CARDS & UI --- */
.sr-wrap { max-width: 1100px; margin: 0 auto; padding: 85px 12px 30px; } 
.sr-card { 
    background: rgba(255, 255, 255, 0.4); border-radius: 14px; 
    padding: 18px; margin-bottom: 15px; backdrop-filter: blur(6px);
    border: 1px solid rgba(0,0,0,0.1); box-shadow: var(--shadow);
}

.sr-pill { 
    background: var(--yellow-light); border: 1px solid rgba(0,0,0,0.2); 
    border-radius: 999px; padding: 8px 16px; margin-bottom: 10px;
    display: flex; align-items: center; gap: 10px; box-shadow: var(--shadow);
}
.sr-pill label { font-weight: 900; font-size: 14px; color: var(--text); white-space: nowrap; margin: 0; }
.sr-pill select { flex: 1; border: none; background: transparent; font-family: "Cairo", sans-serif; font-weight: 800; font-size: 14px; color: var(--text); outline: none; direction: rtl; }

.sr-btn { 
    border: 1px solid rgba(0,0,0,0.2); cursor: pointer; border-radius: 999px; 
    padding: 10px 22px; font-family: "Cairo", sans-serif; font-weight: 900; 
    background: #fff; box-shadow: var(--shadow); color: var(--text); transition: 0.2s;
}
.sr-btn:active { transform: scale(0.95); }
.sr-btn.primary { background: var(--yellow); }

/* --- KPIS --- */
.kpis { display: grid; grid-template-columns: repeat(2, 1fr); gap: 10px; margin-top: 15px; }
.kpi { background: rgba(255,255,255,0.6); border-radius: 12px; padding: 12px 5px; text-align: center; border: 1px solid rgba(0,0,0,0.1); box-shadow: var(--shadow); }
.kpi-label { font-size: 12px; font-weight: 900; color: #444; }
.kpi-val { font-size: 15px; font-weight: 900; color: var(--primary-blue); margin-top: 6px; }

/* --- TABLE --- */
.table-wrap { 
    overflow: auto; 
    border: 2px solid #555; 
    border-radius: 12px; 
    background: white; 
    margin-top: 10px; 
}
table { width: 100%; border-collapse: collapse; min-width: 700px; }
th { 
    background: var(--green) !important; 
    color: white !important; 
    font-weight: 900; 
    padding: 14px 10px; 
    font-size: 14px; 
    border: 1.5px solid #333 !important; 
}
td { 
    border: 1.5px solid #555 !important; 
    padding: 12px 10px; 
    font-size: 13px; 
    text-align: center; 
    font-weight: 700; 
    color: var(--text); 
}

tbody tr { transition: filter 0.2s; }
tbody tr:nth-child(odd) { background-color: var(--yellow-light) !important; }
tbody tr:nth-child(even) { background-color: var(--bg-main) !important; }
tbody tr:hover { filter: brightness(0.95); }

/* --- MODAL SPECIFIC STYLES --- */
.modal-overlay { position: fixed; top:0; left:0; right:0; bottom:0; background: rgba(0,0,0,0.5); z-index: 2000; display:flex; justify-content:center; align-items: flex-start; backdrop-filter: blur(4px); }
.hidden { display: none !important; }
.preview-table { width: 100%; border-collapse: collapse; margin-top: 15px; background: white; }
.preview-table th { background: #555 !important; color: #fff !important; font-size: 12px; padding: 10px 8px; border: 1px solid #444 !important; text-align: center; }
.preview-table td { font-size: 12px; padding: 8px; border: 1px solid #ccc !important; font-weight: 800; background: transparent !important; color: #000; }

.status-badge { display: inline-block; padding: 6px 14px; border-radius: 999px; font-weight: 900; font-size: 12px; border: 1px solid rgba(0,0,0,0.1); background: #fff; box-shadow: var(--shadow); color: var(--text); }

/* --- Style Frappe Standard Popups (msgprint & confirm) --- */
.modal-content {
    background-color: #bfeaf4 !important;
    border-radius: 14px !important;
    border: 1px solid rgba(0,0,0,0.2) !important;
    box-shadow: 0 10px 30px rgba(0,0,0,.08) !important;
    color: #0b1b22 !important;
    font-family: "Cairo", sans-serif !important;
}
.modal-header {
    border-bottom: 1px solid rgba(0,0,0,0.1) !important;
    background-color: transparent !important;
}
.modal-title {
    font-weight: 900 !important;
    color: #0b1b22 !important;
}
.modal-body {
    font-weight: 700 !important;
    color: #0b1b22 !important;
    background-color: #bfeaf4 !important;
}
.modal-footer {
    border-top: 1px solid rgba(0,0,0,0.1) !important;
    background-color: #bfeaf4 !important;
}
.modal-header .btn-close, .modal-header .close {
    color: #0b1b22 !important;
    opacity: 0.8 !important;
    text-shadow: none !important;
}
.msgprint {
    font-family: "Cairo", sans-serif !important;
    font-weight: 700 !important;
    direction: rtl !important;
    text-align: right !important;
    line-height: 1.9 !important;
}

javascript:
let C_AG = null;

const setSt = function(t) { document.getElementById("st").textContent = t; };
const fmt = function(x) { return Number(x||0).toLocaleString(undefined, {minimumFractionDigits: 2}); };

function getCsrfToken() {
    if (window.frappe && frappe.csrf_token) return frappe.csrf_token;
    let meta = document.querySelector('meta[name="csrf-token"]');
    if (meta && meta.content) return meta.content;
    return "";
}

async function fJ(u, method, body) {
  if (!method) method = "GET";
  const opts = {
    method: method,
    headers: { 
        "X-Frappe-CSRF-Token": getCsrfToken(),
        "Content-Type": "application/json"
    }
  };
  if (body) opts.body = JSON.stringify(body);
  const r = await fetch(u, opts);
  const text = await r.text();
  if (!r.ok) {
    let errMsg = "حدث خطأ في النظام";
    try {
        const j = JSON.parse(text);
        if (j._server_messages) errMsg = JSON.parse(JSON.parse(j._server_messages)[0]).message;
        else if (j.exc) errMsg = "خطأ برمجي (راجع الـ Console)";
        else if (j.message) errMsg = j.message;
    } catch(e) {}
    throw new Error(errMsg);
  }
  try { 
      const j = JSON.parse(text);
      return j.message !== undefined ? j.message : (j.data !== undefined ? j.data : j); 
  } 
  catch(e) { return text; }
}

function reset(){
  document.getElementById("tb").innerHTML = "<tr><td colspan='7' style='padding:30px; background:transparent;'>الرجاء اختيار المندوب لعرض البيانات</td></tr>";
  document.getElementById("kC").innerText = "0";
  document.getElementById("kV").innerText = "0.00";
  setSt("مستعد");
}

async function load(){
  try {
    const m = await fJ("/api/method/lmt_supervisor_so_approval_agents");
    const s = document.getElementById("ag_sel");
    const w = document.getElementById("ag_wrp");
    const i = document.getElementById("ag_inf");

    if(m.can_select_agent !== 1){ 
      w.classList.add('hidden');
      i.classList.remove('hidden');
      C_AG = m.agents[0] ? m.agents[0].user : window.CURRENT_USER; 
      i.innerText = "المندوب: " + (m.agents[0] ? m.agents[0].full_name : C_AG);
    } else {
      s.innerHTML = '<option value="">-- اختر المندوب --</option><option value="__ALL__">🔍 كل المندوبين</option>';
      m.agents.forEach(function(a) {
        let o = document.createElement("option");
        o.value = a.user;
        o.innerText = a.full_name;
        s.appendChild(o);
      });
      s.onchange = function(e) { C_AG = e.target.value; };
    }
  } catch(e){
    setSt("خطأ في جلب بيانات المناديب");
  }
}

async function gen(){
  if(!C_AG) return setSt("الرجاء اختيار مندوب");
  setSt("جاري التحميل...");

  try {
    const fields = ["name","customer_name","transaction_date","grand_total","custom_special_discount_customer_pct","custom_special_discount_agent_pct","custom_special_discount","custom_exceptional_discount","additional_discount_percentage"];
    const baseFilters = [["docstatus","=",0]];
    if (C_AG !== "__ALL__") baseFilters.push(["owner","=",C_AG]);
    const url1 = "/api/resource/Sales Order?filters=" + encodeURIComponent(JSON.stringify(baseFilters.concat([["custom_special_discount","=",1]]))) + "&fields=" + encodeURIComponent(JSON.stringify(fields)) + "&limit_page_length=200&order_by=creation desc";
    const url2 = "/api/resource/Sales Order?filters=" + encodeURIComponent(JSON.stringify(baseFilters.concat([["custom_exceptional_discount","=",1]]))) + "&fields=" + encodeURIComponent(JSON.stringify(fields)) + "&limit_page_length=200&order_by=creation desc";
    const [r1, r2] = await Promise.all([fJ(url1), fJ(url2)]);
    const seen = {};
    const rows = [];
    [].concat(r1 || [], r2 || []).forEach(function(x) { if (!seen[x.name]) { seen[x.name] = 1; rows.push(x); } });

    document.getElementById("kC").innerText = rows.length;
    let totalVal = rows.reduce(function(sum, r) { return sum + (r.grand_total||0); }, 0);
    document.getElementById("kV").innerText = fmt(totalVal);

    if (rows.length === 0) {
      document.getElementById("tb").innerHTML = "<tr><td colspan='7' style='padding:30px; background:transparent;'>لا توجد طلبات تخفيض خاص معلقة لهذا المندوب</td></tr>";
      setSt("تم التحميل");
      return;
    }

    document.getElementById("tb").innerHTML = rows.map(function(x) {
      return "<tr>" +
        "<td style='font-weight:900; color:var(--primary-blue); cursor:pointer; text-decoration: underline;' onclick='showPreview(\"" + x.name + "\")'>" + x.name + "</td>" +
        "<td style='font-weight:900;'>" + (x.customer_name || "") + "</td>" +
        "<td>" + (x.transaction_date || "") + "</td>" +
        "<td style='font-weight:900; color:#2f8f3a;'>" + (x.custom_special_discount ? (x.custom_special_discount_customer_pct || 0) + "%" : (x.additional_discount_percentage || 0) + "%") + "</td>" +
        "<td style='font-weight:900; color:#ef4444;'>" + (x.custom_special_discount ? (x.custom_special_discount_agent_pct || 0) + "%" : "—") + "</td>" +
        "<td style='font-weight:900;'>" + fmt(x.grand_total) + "</td>" +
        "<td>" +
          "<div style='display:flex; gap:6px; justify-content:center;'>" +
             "<button class='sr-btn primary' style='padding:6px 12px; font-size:12px;' onclick='approveOrder(\"" + x.name + "\")'>اعتماد ✅</button>" +
             "<button class='sr-btn' style='padding:6px 12px; font-size:12px; background:#ef4444; color:white; border:none;' onclick='rejectOrder(\"" + x.name + "\")'>رفض 🗑️</button>" +
          "</div>" +
        "</td>" +
      "</tr>";
    }).join("");

    setSt("تم التحديث");
  } catch(e){
    setSt("حدث خطأ");
  }
}

async function showPreview(name) {
    const modal = document.getElementById('previewModal');
    const body = document.getElementById('previewBody');
    const title = document.getElementById('previewTitle');
    
    modal.classList.remove('hidden');
    body.innerHTML = "<div style='text-align:center; padding:30px; font-weight:800;'>جاري جلب تفاصيل الطلب...</div>";
    title.innerText = "تفاصيل الطلب: " + name;

    try {
        let docObj = await fJ("/api/resource/Sales Order/" + encodeURIComponent(name));
        let doc = docObj.data ? docObj.data : docObj;
        
        let itemsArr = doc.items || [];
        let itemsHtml = itemsArr.map(function(i) {
            return "<tr>" +
                "<td style='text-align:right;'>" + (i.item_name || "") + "</td>" +
                "<td style='text-align:center;'>" + i.qty + "</td>" +
                "<td style='text-align:center;'>" + fmt(i.rate) + "</td>" +
                "<td style='text-align:center;'>" + fmt(i.amount) + "</td>" +
                "<td style='text-align:center;'>" + (i.is_free_item ? "مجاني" : "بيع") + "</td>" +
            "</tr>";
        }).join("");

        let html = 
            "<div style='background:#f9f9f9; padding:10px; border-radius:8px; border:1px solid #eee; margin-bottom:10px; direction: rtl; text-align: right;'>" +
                "<div style='margin-bottom:8px; font-size:14px;'><strong style='color:var(--primary-blue);'>الزبون:</strong> " + (doc.customer_name || "") + "</div>" +
                "<div style='margin-bottom:8px; font-size:14px;'><strong style='color:var(--primary-blue);'>التخفيض:</strong> الشركة " + (doc.custom_special_discount_customer_pct || 0) + "% | المندوب " + (doc.custom_special_discount_agent_pct || 0) + "%</div>" +
                "<div style='font-size:14px;'><strong style='color:var(--primary-blue);'>المندوب:</strong> " + (doc.owner || "") + "</div>" +
            "</div>" +
            "<div style='max-height: 40vh; overflow-y:auto; border-radius:8px; border: 1px solid #ccc; direction: rtl;'>" +
                "<table class='preview-table' style='margin-top:0;'>" +
                    "<thead style='position:sticky; top:0; z-index:10;'>" +
                        "<tr>" +
                            "<th style='text-align:right;'>الصنف</th>" +
                            "<th>الكمية</th>" +
                            "<th>السعر</th>" +
                            "<th>المجموع</th>" +
                            "<th>النوع</th>" +
                        "</tr>" +
                    "</thead>" +
                    "<tbody>" +
                        itemsHtml +
                    "</tbody>" +
                "</table>" +
            "</div>" +
            "<div style='text-align:left; margin-top:15px; padding:10px; background:var(--yellow-light); border-radius:8px; border:1px solid rgba(0,0,0,0.1);'>" +
                "<strong style='font-size:16px;'>الإجمالي: <span style='color:var(--primary-blue);'>" + fmt(doc.grand_total) + "</span> د.ل</strong>" +
            "</div>";
            
        body.innerHTML = html;
    } catch(e) {
        body.innerHTML = "<div style='color:red; text-align:center; padding:20px; font-weight:800;'>⚠️ تعذر جلب التفاصيل:<br>" + e.message + "</div>";
    }
}

async function approveOrder(soName) {
    if (!confirm("هل أنت متأكد من اعتماد وترحيل الطلب [" + soName + "]؟")) return;

    setSt("جاري التحقق من المخزون...");
    try {
        await fJ("/api/method/validate_qty_on_submit_api", "POST", { order_name: soName });

        setSt("جاري الترحيل...");
        await fJ("/api/resource/Sales Order/" + encodeURIComponent(soName), "PUT", { docstatus: 1, workflow_state: "To Deliver" });

        frappe.msgprint({title:'✅ تمت العملية',message:'تم اعتماد وترحيل الطلب <b>'+soName+'</b> بنجاح',indicator:'green'});
        gen();
    } catch(e) {
        frappe.msgprint({title:'⚠️ خطأ أثناء الاعتماد',message:e.message,indicator:'red',wide:true});
        setSt("فشلت العملية");
    }
}

async function rejectOrder(soName) {
    if (!confirm("هل أنت متأكد من رفض وحذف الطلب [" + soName + "] نهائياً؟")) return;

    setSt("جاري حذف " + soName + "...");
    try {
        await fJ("/api/resource/Sales Order/" + encodeURIComponent(soName), "DELETE");
        frappe.msgprint({title:'✅ تمت العملية',message:'تم رفض وحذف الطلب <b>'+soName+'</b> بنجاح',indicator:'green'});
        gen();
    } catch(e) {
        frappe.msgprint({title:'⚠️ خطأ أثناء الحذف',message:e.message,indicator:'red',wide:true});
        setSt("فشلت العملية");
    }
}

if (window.CURRENT_USER === "Guest") {
  window.location.href = "/login";
} else {
  reset();
  load();
}

