javascript:
(function(){
    var CATEGORY_ICONS = {
        'Financial': '💰',
        'Stock':     '📦',
        'Sales':     '🛒',
        'Receivables': '💳',
        'Purchase':  '🏭',
        'Other':     '📋'
    };
    var CATEGORY_ORDER = ['Financial','Receivables','Sales','Stock','Purchase','Employee','Other'];

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/reports-hub-1';
            return;
        }
        loadReports();
    });

    function loadReports(){
        frappe.call({
            method: 'lmt_report_menu_items_v1',
            callback: function(r){
                document.getElementById('rhLoading').style.display = 'none';
                var main = document.getElementById('rhMain');
                main.style.display = 'block';
                if (!r || !r.message || !r.message.length){
                    main.innerHTML = '<div style="text-align:center;padding:40px;color:#888;">لا توجد تقارير متاحة</div>';
                    return;
                }
                renderReports(r.message);
            },
            error: function(){
                document.getElementById('rhLoading').innerHTML = '<div style="color:#c0392b;">خطأ في تحميل التقارير</div>';
            }
        });
    }

    function renderReports(items){
        var grouped = {};
        for (var i = 0; i < items.length; i++){
            var cat = items[i].category || 'Other';
            if (!grouped[cat]) grouped[cat] = [];
            grouped[cat].push(items[i]);
        }

        var html = '';
        for (var c = 0; c < CATEGORY_ORDER.length; c++){
            var cat = CATEGORY_ORDER[c];
            if (!grouped[cat] || !grouped[cat].length) continue;
            var catIcon = CATEGORY_ICONS[cat] || '📋';
            html += '<div class="rh-cat-header">' + catIcon + ' ' + getCatArabic(cat) + '</div>';
            html += '<div class="rh-grid">';
            var list = grouped[cat];
            for (var j = 0; j < list.length; j++){
                var it = list[j];
                var icon = getIcon(it);
                html += '<div class="rh-card" onclick="location.href=\'' + (it.route || '#') + '\'">'
                       + '<div class="rh-card-icon">' + icon + '</div>'
                       + '<div class="rh-card-label">' + (it.title_ar || it.title_en || '') + '</div>'
                       + '</div>';
            }
            html += '</div>';
        }
        document.getElementById('rhMain').innerHTML = html;
    }

    function getIcon(it){
        if (it.icon_type === 'Emoji' && it.emoji) return it.emoji;
        if (it.icon_type === 'FontAwesome' && it.fa_class) return '<i class="fa ' + it.fa_class + '"></i>';
        if (it.icon_type === 'ImageURL' && it.image_url) return '<img src="' + it.image_url + '">';
        return '📄';
    }

    function getCatArabic(cat){
        var map = {
            'Financial':   'التقارير المالية',
            'Stock':       'تقارير المخزون',
            'Sales':       'تقارير المبيعات',
            'Receivables': 'تقارير الذمم المدينة',
            'Purchase':    'تقارير المشتريات',
            'Other':       'تقارير أخرى'
        };
        return map[cat] || cat;
    }
})();

