javascript:
(function(){
    var ALL_ACCOUNTS = [];
    var ALL_CUSTOMERS = [];
    var ALL_EMPLOYEES = [];
    var ALL_COST_CENTERS = [];
    var ROWS = [];
    var filtersVisible = true;

    function $(id){ return document.getElementById(id); }
    function fmt(v){ return parseFloat(v || 0).toLocaleString('en-US', {minimumFractionDigits: 2, maximumFractionDigits: 2}); }
    function shortDate(d){ if (!d) return ''; var s = String(d).substring(0,10).split('-'); return s[2]+'/'+s[1]; }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/gl-report-1';
            return;
        }
        setDefaultDates();
        loadFilters();
        wire();
    });

    function setDefaultDates(){
        var now = new Date();
        var y = now.getFullYear();
        $('fFromDate').value = y + '-01-01';
        $('fToDate').value = now.toISOString().substring(0,10);
    }

    function loadFilters(){
        frappe.call({
            method: 'lmt_gl_filters_v1',
            callback: function(r){
                if (!r || !r.message) return;
                var d = r.message;
                ALL_ACCOUNTS = d.accounts || [];
                ALL_CUSTOMERS = d.customers || [];
                ALL_EMPLOYEES = d.employees || [];
                ALL_COST_CENTERS = d.cost_centers || [];

                var ccSel = $('fCostCenter');
                for (var i = 0; i < ALL_COST_CENTERS.length; i++){
                    var o = document.createElement('option');
                    o.value = ALL_COST_CENTERS[i].name;
                    o.textContent = ALL_COST_CENTERS[i].name;
                    ccSel.appendChild(o);
                }

                var empSel = $('fEmployee');
                for (var i = 0; i < ALL_EMPLOYEES.length; i++){
                    var o = document.createElement('option');
                    o.value = ALL_EMPLOYEES[i].name;
                    o.textContent = ALL_EMPLOYEES[i].employee_name + ' (' + ALL_EMPLOYEES[i].name + ')';
                    empSel.appendChild(o);
                }
            }
        });
    }

    function wire(){
        $('btnSearch').addEventListener('click', doSearch);
        $('btnClear').addEventListener('click', doClear);
        $('btnToggleFilters').addEventListener('click', toggleFilters);

        // Account search
        $('fAccount').addEventListener('input', function(){
            var q = this.value.trim().toLowerCase();
            var list = $('accountResults');
            if (q.length < 1){ list.style.display = 'none'; return; }
            var matches = [];
            for (var i = 0; i < ALL_ACCOUNTS.length; i++){
                var a = ALL_ACCOUNTS[i];
                if (a.name.toLowerCase().indexOf(q) > -1 || (a.account_name && a.account_name.toLowerCase().indexOf(q) > -1)){
                    matches.push(a);
                }
                if (matches.length >= 15) break;
            }
            if (!matches.length){ list.style.display = 'none'; return; }
            list.innerHTML = '';
            for (var i = 0; i < matches.length; i++){
                var div = document.createElement('div');
                div.className = 'dd-item';
                div.textContent = matches[i].name;
                div.setAttribute('data-val', matches[i].name);
                div.addEventListener('click', function(){ $('fAccount').value = this.getAttribute('data-val'); $('accountResults').style.display = 'none'; });
                list.appendChild(div);
            }
            list.style.display = 'block';
        });

        // Party search
        $('fParty').addEventListener('input', function(){
            var q = this.value.trim().toLowerCase();
            var list = $('partyResults');
            var ptype = $('fPartyType').value;
            if (q.length < 1 || !ptype){ list.style.display = 'none'; return; }
            var source = ptype === 'Customer' ? ALL_CUSTOMERS : ALL_EMPLOYEES;
            var nameField = ptype === 'Customer' ? 'customer_name' : 'employee_name';
            var matches = [];
            for (var i = 0; i < source.length; i++){
                var p = source[i];
                if (p.name.toLowerCase().indexOf(q) > -1 || (p[nameField] && p[nameField].toLowerCase().indexOf(q) > -1)){
                    matches.push(p);
                }
                if (matches.length >= 15) break;
            }
            if (!matches.length){ list.style.display = 'none'; return; }
            list.innerHTML = '';
            for (var i = 0; i < matches.length; i++){
                var div = document.createElement('div');
                div.className = 'dd-item';
                div.textContent = (matches[i][nameField] || '') + ' — ' + matches[i].name;
                div.setAttribute('data-val', matches[i].name);
                div.addEventListener('click', function(){ $('fParty').value = this.getAttribute('data-val'); $('partyResults').style.display = 'none'; });
                list.appendChild(div);
            }
            list.style.display = 'block';
        });

        // Close dropdowns on outside click
        document.addEventListener('click', function(e){
            if (!e.target.closest('#fAccount') && !e.target.closest('#accountResults')) $('accountResults').style.display = 'none';
            if (!e.target.closest('#fParty') && !e.target.closest('#partyResults')) $('partyResults').style.display = 'none';
        });
    }

    function toggleFilters(){
        filtersVisible = !filtersVisible;
        $('glFilters').style.display = filtersVisible ? 'block' : 'none';
        $('btnToggleFilters').textContent = filtersVisible ? '▲ إخفاء الفلاتر' : '▼ إظهار الفلاتر';
    }

    function doSearch(){
        var params = {
            account: $('fAccount').value.trim(),
            from_date: $('fFromDate').value,
            to_date: $('fToDate').value,
            cost_center: $('fCostCenter').value,
            party_type: $('fPartyType').value,
            party: $('fParty').value.trim(),
            employee: $('fEmployee').value
        };

        $('glLoading').style.display = 'block';
        $('glTableWrap').style.display = 'none';
        $('glSummary').style.display = 'none';

        frappe.call({
            method: 'lmt_gl_report_v1',
            args: params,
            callback: function(r){
                $('glLoading').style.display = 'none';
                if (!r || !r.message){
                    $('glSummary').innerHTML = '<div style="color:#c0392b;text-align:center;">خطأ في تحميل البيانات</div>';
                    $('glSummary').style.display = 'flex';
                    return;
                }
                ROWS = r.message.rows || [];
                var opening = r.message.opening || 0;
                renderTable(ROWS, opening, params.account);

                // Auto-hide filters after search on mobile
                if (window.innerWidth < 600 && filtersVisible){
                    toggleFilters();
                }
            },
            error: function(){
                $('glLoading').style.display = 'none';
                $('glSummary').innerHTML = '<div style="color:#c0392b;text-align:center;">خطأ في الاتصال</div>';
                $('glSummary').style.display = 'flex';
            }
        });
    }

    function doClear(){
        $('fAccount').value = '';
        $('fFromDate').value = '';
        $('fToDate').value = '';
        $('fCostCenter').value = '';
        $('fPartyType').value = '';
        $('fParty').value = '';
        $('fEmployee').value = '';
        $('glTableWrap').style.display = 'none';
        $('glSummary').style.display = 'none';
        setDefaultDates();
    }

    function renderTable(rows, opening, hasAccount){
        var body = $('glBody');
        var totalDebit = 0, totalCredit = 0;
        var balance = opening;
        var html = '';

        // Opening row if account selected
        if (hasAccount){
            html += '<tr class="opening-row">'
                + '<td></td><td></td><td class="col-account">رصيد افتتاحي</td>'
                + '<td></td><td></td>'
                + '<td class="balance-cell">' + fmt(opening) + '</td>'
                + '</tr>';
        }

        for (var i = 0; i < rows.length; i++){
            var r = rows[i];
            var d = parseFloat(r.debit || 0);
            var c = parseFloat(r.credit || 0);
            totalDebit += d;
            totalCredit += c;
            if (hasAccount) balance += d - c;

            html += '<tr onclick="showDetail(' + i + ')">'
                + '<td>' + (i + 1) + '</td>'
                + '<td>' + shortDate(r.posting_date) + '</td>'
                + '<td class="col-account">' + (r.account || '') + '</td>'
                + '<td class="debit-cell">' + (d ? fmt(d) : '') + '</td>'
                + '<td class="credit-cell">' + (c ? fmt(c) : '') + '</td>'
                + '<td class="balance-cell">' + (hasAccount ? fmt(balance) : '') + '</td>'
                + '</tr>';
        }

        // Total row
        var closingBal = hasAccount ? balance : totalDebit - totalCredit;
        html += '<tr class="total-row">'
            + '<td></td><td></td><td class="col-account">الإجمالي</td>'
            + '<td class="debit-cell">' + fmt(totalDebit) + '</td>'
            + '<td class="credit-cell">' + fmt(totalCredit) + '</td>'
            + '<td class="balance-cell">' + fmt(closingBal) + '</td>'
            + '</tr>';

        body.innerHTML = html;
        $('glTableWrap').style.display = 'block';

        // Summary
        $('glSummary').innerHTML =
            '<div class="s-item"><span class="s-label">عدد القيود</span><span class="s-val">' + rows.length + '</span></div>'
            + '<div class="s-item"><span class="s-label">إجمالي مدين</span><span class="s-val s-debit">' + fmt(totalDebit) + '</span></div>'
            + '<div class="s-item"><span class="s-label">إجمالي دائن</span><span class="s-val s-credit">' + fmt(totalCredit) + '</span></div>'
            + '<div class="s-item"><span class="s-label">الرصيد</span><span class="s-val s-balance">' + fmt(closingBal) + '</span></div>';
        $('glSummary').style.display = 'flex';
    }

    // Detail modal
    window.showDetail = function(idx){
        var r = ROWS[idx];
        if (!r) return;
        var html = '<div style="font-size:16px;font-weight:700;text-align:center;margin-bottom:10px;">📒 تفاصيل القيد</div>';
        var fields = [
            ['التاريخ', shortDate(r.posting_date)],
            ['الحساب', r.account],
            ['مدين', fmt(r.debit)],
            ['دائن', fmt(r.credit)],
            ['نوع الطرف', r.party_type || '-'],
            ['الطرف', r.party || '-'],
            ['نوع المستند', r.voucher_type || '-'],
            ['رقم المستند', r.voucher_no || '-'],
            ['مقابل', r.against || '-'],
            ['مركز التكلفة', r.cost_center || '-'],
