javascript:
(function(){
    var filtersVisible = true;
    var ROOT_ORDER = ['Asset','Liability','Equity','Income','Expense'];
    var ROOT_AR = {'Asset':'\u0623\u0635\u0648\u0644','Liability':'\u062e\u0635\u0648\u0645','Equity':'\u062d\u0642\u0648\u0642 \u0645\u0644\u0643\u064a\u0629','Income':'\u0625\u064a\u0631\u0627\u062f\u0627\u062a','Expense':'\u0645\u0635\u0631\u0648\u0641\u0627\u062a'};

    function $(id){ return document.getElementById(id); }
    function fmt(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/trial-balance-1';
            return;
        }
        setDates();
        loadCC();
        wire();
    });

    function setDates(){
        var now = new Date();
        $('fFromDate').value = now.getFullYear() + '-01-01';
        $('fToDate').value = now.toISOString().substring(0,10);
    }

    function loadCC(){
        frappe.call({
            method: 'lmt_gl_filters_v1',
            callback: function(r){
                if (!r || !r.message) return;
                var ccs = r.message.cost_centers || [];
                var sel = $('fCostCenter');
                for (var i=0; i<ccs.length; i++){
                    var o = document.createElement('option');
                    o.value = ccs[i].name; o.textContent = ccs[i].name;
                    sel.appendChild(o);
                }
            }
        });
    }

    function wire(){
        $('btnSearch').addEventListener('click', doSearch);
        $('btnToggle').addEventListener('click', function(){
            filtersVisible = !filtersVisible;
            $('tbFilters').style.display = filtersVisible ? 'block' : 'none';
            this.textContent = filtersVisible ? '\u25b2 \u0625\u062e\u0641\u0627\u0621' : '\u25bc \u0625\u0638\u0647\u0627\u0631';
        });
    }

    function doSearch(){
        $('tbLoading').style.display = 'block';
        $('tbTableWrap').style.display = 'none';
        $('tbSummary').style.display = 'none';

        frappe.call({
            method: 'lmt_trial_balance_v1',
            args: {
                from_date: $('fFromDate').value,
                to_date: $('fToDate').value,
                cost_center: $('fCostCenter').value
            },
            callback: function(r){
                $('tbLoading').style.display = 'none';
                if (!r || !r.message){
                    $('tbSummary').innerHTML = '<div style="color:#c0392b;text-align:center;">\u062e\u0637\u0623</div>';
                    $('tbSummary').style.display = 'flex';
                    return;
                }
                render(r.message);
                if (window.innerWidth < 600 && filtersVisible){
                    filtersVisible = false;
                    $('tbFilters').style.display = 'none';
                    $('btnToggle').textContent = '\u25bc \u0625\u0638\u0647\u0627\u0631';
                }
            },
            error: function(){
                $('tbLoading').style.display = 'none';
            }
        });
    }

    function render(rows){
        // Group by root_type
        var grouped = {};
        for (var i=0; i<rows.length; i++){
            var rt = rows[i].root_type || 'Other';
            if (!grouped[rt]) grouped[rt] = [];
            grouped[rt].push(rows[i]);
        }

        var html = '';
        var grandOp = 0, grandDr = 0, grandCr = 0, grandCl = 0;
        var totalAccounts = 0;

        for (var ri=0; ri<ROOT_ORDER.length; ri++){
            var rt = ROOT_ORDER[ri];
            if (!grouped[rt] || !grouped[rt].length) continue;
            var list = grouped[rt];
            var subOp=0, subDr=0, subCr=0, subCl=0;

            html += '<tr class="group-row"><td colspan="5">' + (ROOT_AR[rt]||rt) + '</td></tr>';

            for (var j=0; j<list.length; j++){
                var r = list[j];
                subOp += r.opening; subDr += r.debit; subCr += r.credit; subCl += r.closing;
                totalAccounts++;
                html += '<tr>'
                    + '<td class="col-acct" title="' + r.account + '">' + (r.account_name || r.account) + '</td>'
                    + '<td>' + fmt(r.opening) + '</td>'
                    + '<td class="debit-cell">' + fmt(r.debit) + '</td>'
                    + '<td class="credit-cell">' + fmt(r.credit) + '</td>'
                    + '<td class="closing-cell">' + fmt(r.closing) + '</td>'
                    + '</tr>';
            }

            html += '<tr class="subtotal-row">'
                + '<td style="text-align:right;">\u0625\u062c\u0645\u0627\u0644\u064a ' + (ROOT_AR[rt]||rt) + '</td>'
                + '<td>' + fmt(subOp) + '</td>'
                + '<td class="debit-cell">' + fmt(subDr) + '</td>'
                + '<td class="credit-cell">' + fmt(subCr) + '</td>'
                + '<td class="closing-cell">' + fmt(subCl) + '</td>'
                + '</tr>';

            grandOp += subOp; grandDr += subDr; grandCr += subCr; grandCl += subCl;
        }

        html += '<tr class="grand-total-row">'
            + '<td style="text-align:right;">\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u0639\u0627\u0645</td>'
            + '<td>' + fmt(grandOp) + '</td>'
            + '<td>' + fmt(grandDr) + '</td>'
            + '<td>' + fmt(grandCr) + '</td>'
            + '<td>' + fmt(grandCl) + '</td>'
            + '</tr>';

        $('tbBody').innerHTML = html;
        $('tbTableWrap').style.display = 'block';

        $('tbSummary').innerHTML =
            '<div class="s-item"><span class="s-label">\u0639\u062f\u062f \u0627\u0644\u062d\u0633\u0627\u0628\u0627\u062a</span><span class="s-val">' + totalAccounts + '</span></div>'
            + '<div class="s-item"><span class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u0645\u062f\u064a\u0646</span><span class="s-val" style="color:#c0392b;">' + fmt(grandDr) + '</span></div>'
            + '<div class="s-item"><span class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u062f\u0627\u0626\u0646</span><span class="s-val" style="color:#27ae60;">' + fmt(grandCr) + '</span></div>';
        $('tbSummary').style.display = 'flex';
    }
})();

