    function fmt(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/profit-loss-1';
            return;
        }
        var now = new Date();
        $('fFromDate').value = now.getFullYear() + '-01-01';
        $('fToDate').value = now.toISOString().substring(0,10);
        loadCC();
        wire();
    });

    function loadCC(){
        frappe.call({
            method: 'lmt_gl_filters_v1',
            callback: function(r){
                if (!r || !r.message) return;
                var ccs = r.message.cost_centers || [];
                var sel = $('fCostCenter');
                for (var i=0; i<ccs.length; i++){
                    var o = document.createElement('option');
                    o.value = ccs[i].name; o.textContent = ccs[i].name;
                    sel.appendChild(o);
                }
            }
        });
    }

    function wire(){
        $('btnSearch').addEventListener('click', doSearch);
        $('btnToggle').addEventListener('click', function(){
            filtersVisible = !filtersVisible;
            $('plFilters').style.display = filtersVisible ? 'block' : 'none';
            this.textContent = filtersVisible ? '\u25b2 \u0625\u062e\u0641\u0627\u0621' : '\u25bc \u0625\u0638\u0647\u0627\u0631';
        });
    }

    function doSearch(){
        $('plLoading').style.display = 'block';
        $('plContent').style.display = 'none';
        $('plProfit').style.display = 'none';

        frappe.call({
            method: 'lmt_profit_loss_v1',
            args: {
                from_date: $('fFromDate').value,
                to_date: $('fToDate').value,
                cost_center: $('fCostCenter').value
            },
            callback: function(r){
                $('plLoading').style.display = 'none';
                if (!r || !r.message){
                    $('plProfit').innerHTML = '\u062e\u0637\u0623 \u0641\u064a \u0627\u0644\u062a\u062d\u0645\u064a\u0644';
                    $('plProfit').className = 'pl-profit-banner loss';
                    $('plProfit').style.display = 'block';
                    return;
                }
                render(r.message);
                if (window.innerWidth < 600 && filtersVisible){
                    filtersVisible = false;
                    $('plFilters').style.display = 'none';
                    $('btnToggle').textContent = '\u25bc \u0625\u0638\u0647\u0627\u0631';
                }
            },
            error: function(){
                $('plLoading').style.display = 'none';
            }
        });
    }

    function render(rows){
        var income = [], expense = [];
        var totalIncome = 0, totalExpense = 0;

        for (var i=0; i<rows.length; i++){
            var r = rows[i];
            if (r.root_type === 'Income'){
                income.push(r);
                totalIncome += r.amount;
            } else {
                expense.push(r);
                totalExpense += r.amount;
            }
        }

        var netProfit = totalIncome - totalExpense;
        var isProfit = netProfit >= 0;

        // Profit banner
        var banner = $('plProfit');
        banner.className = 'pl-profit-banner ' + (isProfit ? 'profit' : 'loss');
        banner.innerHTML = '<div class="profit-label">' + (isProfit ? '\u0635\u0627\u0641\u064a \u0627\u0644\u0631\u0628\u062d' : '\u0635\u0627\u0641\u064a \u0627\u0644\u062e\u0633\u0627\u0631\u0629') + '</div>'
            + '<div>' + fmt(Math.abs(netProfit)) + '</div>';
        banner.style.display = 'block';

        var html = '';

        // Income section
        html += '<div class="pl-section">';
        html += '<div class="pl-section-header income"><span>\u0625\u064a\u0631\u0627\u062f\u0627\u062a</span><span>' + income.length + ' \u062d\u0633\u0627\u0628</span></div>';
        for (var i=0; i<income.length; i++){
            var r = income[i];
            html += '<div class="pl-row"><span class="pl-row-name">' + (r.account_name || r.account) + '</span>'
                + '<span class="pl-row-amt positive">' + fmt(r.amount) + '</span></div>';
        }
        html += '<div class="pl-section-total"><span>\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u0625\u064a\u0631\u0627\u062f\u0627\u062a</span><span style="color:#1e8449;">' + fmt(totalIncome) + '</span></div>';
        html += '</div>';

        // Expense section
        html += '<div class="pl-section">';
        html += '<div class="pl-section-header expense"><span>\u0645\u0635\u0631\u0648\u0641\u0627\u062a</span><span>' + expense.length + ' \u062d\u0633\u0627\u0628</span></div>';
        for (var i=0; i<expense.length; i++){
            var r = expense[i];
            html += '<div class="pl-row"><span class="pl-row-name">' + (r.account_name || r.account) + '</span>'
                + '<span class="pl-row-amt negative">' + fmt(r.amount) + '</span></div>';
        }
        html += '<div class="pl-section-total"><span>\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u0645\u0635\u0631\u0648\u0641\u0627\u062a</span><span style="color:#c0392b;">' + fmt(totalExpense) + '</span></div>';
        html += '</div>';

        $('plContent').innerHTML = html;
        $('plContent').style.display = 'block';
    }
})();

