    var filtersVisible = true;
    function $(id){ return document.getElementById(id); }
    function fmt(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/balance-sheet-1';
            return;
        }
        $('fToDate').value = new Date().toISOString().substring(0,10);
        loadCC();
        wire();
    });

    function loadCC(){
        frappe.call({
            method: 'lmt_gl_filters_v1',
            callback: function(r){
                if (!r || !r.message) return;
                var ccs = r.message.cost_centers || [];
                var sel = $('fCostCenter');
                for (var i=0; i<ccs.length; i++){
                    var o = document.createElement('option');
                    o.value = ccs[i].name; o.textContent = ccs[i].name;
                    sel.appendChild(o);
                }
            }
        });
    }

    function wire(){
        $('btnSearch').addEventListener('click', doSearch);
        $('btnToggle').addEventListener('click', function(){
            filtersVisible = !filtersVisible;
            $('bsFilters').style.display = filtersVisible ? 'block' : 'none';
            this.textContent = filtersVisible ? '\u25b2 \u0625\u062e\u0641\u0627\u0621' : '\u25bc \u0625\u0638\u0647\u0627\u0631';
        });
    }

    function doSearch(){
        $('bsLoading').style.display = 'block';
        $('bsContent').style.display = 'none';

        frappe.call({
            method: 'lmt_balance_sheet_v1',
            args: {
                to_date: $('fToDate').value,
                cost_center: $('fCostCenter').value
            },
            callback: function(r){
                $('bsLoading').style.display = 'none';
                if (!r || !r.message){ return; }
                render(r.message.rows, r.message.net_profit);
                if (window.innerWidth < 600 && filtersVisible){
                    filtersVisible = false;
                    $('bsFilters').style.display = 'none';
                    $('btnToggle').textContent = '\u25bc \u0625\u0638\u0647\u0627\u0631';
                }
            },
            error: function(){ $('bsLoading').style.display = 'none'; }
        });
    }

    function render(rows, netProfit){
        var sections = {'Asset':[], 'Liability':[], 'Equity':[]};
        var totals = {'Asset':0, 'Liability':0, 'Equity':0};

        for (var i=0; i<rows.length; i++){
            var r = rows[i];
            var rt = r.root_type;
            if (sections[rt]){
                sections[rt].push(r);
                totals[rt] += r.balance;
            }
        }

        var totalAssets = totals['Asset'];
        var totalLiabEquity = totals['Liability'] + totals['Equity'] + netProfit;
        var diff = Math.abs(totalAssets - totalLiabEquity);
        var balanced = diff < 0.01;

        var html = '';

        // Balance check banner
        html += '<div class="bs-balance-check ' + (balanced ? 'balanced' : 'unbalanced') + '">';
        html += '<div class="check-label">' + (balanced ? '\u2705 \u0627\u0644\u0645\u064a\u0632\u0627\u0646\u064a\u0629 \u0645\u062a\u0648\u0627\u0632\u0646\u0629' : '\u26a0\ufe0f \u0627\u0644\u0645\u064a\u0632\u0627\u0646\u064a\u0629 \u063a\u064a\u0631 \u0645\u062a\u0648\u0627\u0632\u0646\u0629 (' + fmt(diff) + ')') + '</div>';
        html += '<div class="check-amounts">';
        html += '<span>\u0623\u0635\u0648\u0644: ' + fmt(totalAssets) + '</span>';
        html += '<span>\u062e\u0635\u0648\u0645+\u0645\u0644\u0643\u064a\u0629: ' + fmt(totalLiabEquity) + '</span>';
        html += '</div></div>';

        // Asset section
        html += buildSection('Asset', '\u0623\u0635\u0648\u0644', 'asset', sections['Asset'], totals['Asset']);

        // Liability section
        html += buildSection('Liability', '\u062e\u0635\u0648\u0645', 'liability', sections['Liability'], totals['Liability']);

        // Equity section
        html += buildSection('Equity', '\u062d\u0642\u0648\u0642 \u0645\u0644\u0643\u064a\u0629', 'equity', sections['Equity'], totals['Equity']);

        // Net profit as separate section
        html += '<div class="bs-section">';
        html += '<div class="bs-section-header profit"><span>\u0635\u0627\u0641\u064a \u0627\u0644\u0631\u0628\u062d / \u0627\u0644\u062e\u0633\u0627\u0631\u0629</span></div>';
        html += '<div class="bs-section-total"><span>\u0635\u0627\u0641\u064a \u0627\u0644\u0631\u0628\u062d</span><span style="color:' + (netProfit >= 0 ? '#1e8449' : '#c0392b') + ';">' + fmt(netProfit) + '</span></div>';
        html += '</div>';

        // Total L+E+Profit
        html += '<div class="bs-section">';
        html += '<div class="bs-section-total" style="background:#2c3e50;color:#fff;border-radius:12px;">';
        html += '<span>\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u062e\u0635\u0648\u0645 + \u0627\u0644\u0645\u0644\u0643\u064a\u0629 + \u0627\u0644\u0631\u0628\u062d</span>';
        html += '<span>' + fmt(totalLiabEquity) + '</span>';
        html += '</div></div>';

        $('bsContent').innerHTML = html;
        $('bsContent').style.display = 'block';
    }

    function buildSection(rt, label, cls, items, total){
        var h = '<div class="bs-section">';
        h += '<div class="bs-section-header ' + cls + '"><span>' + label + '</span><span>' + items.length + ' \u062d\u0633\u0627\u0628</span></div>';
        for (var i=0; i<items.length; i++){
            var r = items[i];
            h += '<div class="bs-row"><span class="bs-row-name">' + (r.account_name || r.account) + '</span>'
                + '<span class="bs-row-amt">' + fmt(r.balance) + '</span></div>';
        }
        h += '<div class="bs-section-total"><span>\u0625\u062c\u0645\u0627\u0644\u064a ' + label + '</span><span>' + fmt(total) + '</span></div>';
        h += '</div>';
        return h;
    }
})();

