javascript:
(function(){
    var ALL_ROWS = [];
    var activeBucket = '';

    function $(id){ return document.getElementById(id); }
    function fmt(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/ar-ageing-1';
            return;
        }
        $('fAsOf').value = new Date().toISOString().substring(0,10);
        $('btnSearch').addEventListener('click', doSearch);
        $('fSearch').addEventListener('input', filterList);
    });

    function doSearch(){
        $('arLoading').style.display = 'block';
        $('arBuckets').style.display = 'none';
        $('arSummary').style.display = 'none';
        $('arList').style.display = 'none';
        activeBucket = '';

        frappe.call({
            method: 'lmt_ar_ageing_v1',
            args: { as_of: $('fAsOf').value },
            callback: function(r){
                $('arLoading').style.display = 'none';
                if (!r || !r.message) return;
                ALL_ROWS = r.message.rows || [];
                renderBuckets(r.message);
                renderSummary(r.message);
                renderList(ALL_ROWS);
            },
            error: function(){ $('arLoading').style.display = 'none'; }
        });
    }

    function renderBuckets(d){
        var bk = d.buckets;
        var bc = d.bucket_counts;
        var html = '';
        var items = [
            {key:'0_30', label:'0-30 \u064a\u0648\u0645', cls:'bk-green'},
            {key:'31_60', label:'31-60 \u064a\u0648\u0645', cls:'bk-yellow'},
            {key:'61_90', label:'61-90 \u064a\u0648\u0645', cls:'bk-orange'},
            {key:'90_plus', label:'90+ \u064a\u0648\u0645', cls:'bk-red'}
        ];
        for (var i=0; i<items.length; i++){
            var it = items[i];
            html += '<div class="ar-bucket ' + it.cls + '" data-bk="' + it.key + '">'
                + '<div class="bk-label">' + it.label + '</div>'
                + '<div class="bk-amount">' + fmt(bk[it.key]) + '</div>'
                + '<div class="bk-count">' + bc[it.key] + ' \u0632\u0628\u0648\u0646</div>'
                + '</div>';
        }
        $('arBuckets').innerHTML = html;
        $('arBuckets').style.display = 'grid';

        // Bucket click filter
        var cards = $('arBuckets').querySelectorAll('.ar-bucket');
        for (var i=0; i<cards.length; i++){
            cards[i].addEventListener('click', function(){
                var bk = this.getAttribute('data-bk');
                if (activeBucket === bk){
                    activeBucket = '';
                } else {
                    activeBucket = bk;
                }
                // Update active state
                var all = $('arBuckets').querySelectorAll('.ar-bucket');
                for (var j=0; j<all.length; j++) all[j].classList.remove('active');
                if (activeBucket) this.classList.add('active');
                filterList();
            });
        }
    }

    function renderSummary(d){
        $('arSummary').innerHTML =
            '<div class="s-item"><div class="s-label">\u0639\u062f\u062f \u0627\u0644\u0632\u0628\u0627\u0626\u0646</div><div>' + d.total_customers + '</div></div>'
            + '<div class="s-item"><div class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u062f\u064a\u0648\u0646</div><div>' + fmt(d.grand_total) + '</div></div>';
        $('arSummary').style.display = 'flex';
    }

    function renderList(rows){
        var html = '';
        for (var i=0; i<rows.length; i++){
            var r = rows[i];
            var balCls = r.balance < 5000 ? 'low' : '';
            html += '<div class="ar-cust-card" data-cust="' + r.customer + '" data-bucket="' + r.bucket + '">'
                + '<div class="ar-cust-info">'
                + '<div class="ar-cust-name">' + (r.customer_name || r.customer) + '</div>'
                + '<div class="ar-cust-id">' + r.customer + '</div>'
                + '<div class="ar-cust-days">' + r.days + ' \u064a\u0648\u0645</div>'
                + '</div>'
                + '<div class="ar-cust-bal ' + balCls + '">' + fmt(r.balance) + '</div>'
                + '</div>';
        }
        $('arList').innerHTML = html || '<div style="text-align:center;padding:20px;color:#888;">\u0644\u0627 \u062a\u0648\u062c\u062f \u0646\u062a\u0627\u0626\u062c</div>';
        $('arList').style.display = 'block';

        // Click to open customer statement
        var cards = $('arList').querySelectorAll('.ar-cust-card');
        for (var i=0; i<cards.length; i++){
            cards[i].addEventListener('click', function(){
                var cust = this.getAttribute('data-cust');
                window.location.href = '/customer-statement-1?customer=' + encodeURIComponent(cust);
            });
        }
    }

    function filterList(){
        var q = $('fSearch').value.trim().toLowerCase();
        var filtered = [];
        for (var i=0; i<ALL_ROWS.length; i++){
            var r = ALL_ROWS[i];
            if (activeBucket && r.bucket !== activeBucket) continue;
            if (q && (r.customer_name || '').toLowerCase().indexOf(q) === -1 && r.customer.toLowerCase().indexOf(q) === -1) continue;
            filtered.push(r);
        }
        renderList(filtered);
    }
})();

