javascript:
(function(){
    var ALL_CUSTOMERS = [];
    var ROWS = [];
    var filtersVisible = true;

    function $(id){ return document.getElementById(id); }
    function fmt(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); }
    function shortDate(d){ if (!d) return ''; var s = String(d).substring(0,10).split('-'); return s[2]+'/'+s[1]; }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/customer-statement-1';
            return;
        }
        var now = new Date();
        $('fFromDate').value = now.getFullYear() + '-01-01';
        $('fToDate').value = now.toISOString().substring(0,10);
        loadCustomers();
        wire();

        // Auto-load if ?customer= in URL
        var params = new URLSearchParams(window.location.search);
        var custParam = params.get('customer');
        if (custParam){
            $('fCustomerVal').value = custParam;
            $('fCustomer').style.display = 'none';
            $('csCustName').textContent = custParam;
            $('csCustBadge').style.display = 'flex';
            // Auto search after filters load
            setTimeout(function(){ doSearch(); }, 500);
        }
    });

    function loadCustomers(){
        frappe.call({
            method: 'lmt_gl_filters_v1',
            callback: function(r){
                if (!r || !r.message) return;
                ALL_CUSTOMERS = r.message.customers || [];
            }
        });
    }

    function wire(){
        $('btnSearch').addEventListener('click', doSearch);
        $('btnToggle').addEventListener('click', function(){
            filtersVisible = !filtersVisible;
            $('csFilters').style.display = filtersVisible ? 'block' : 'none';
            this.textContent = filtersVisible ? '\u25b2 \u0625\u062e\u0641\u0627\u0621' : '\u25bc \u0625\u0638\u0647\u0627\u0631';
        });

        $('fCustomer').addEventListener('focus', function(){ showCustList(''); });
        $('fCustomer').addEventListener('input', function(){
            showCustList(this.value.trim().toLowerCase());
        });
        document.addEventListener('click', function(e){
            if (!e.target.closest('#fCustomer') && !e.target.closest('#custResults'))
                $('custResults').style.display = 'none';
        });
    }

    function showCustList(q){
        var list = $('custResults');
        var matches = [];
        for (var i=0; i<ALL_CUSTOMERS.length; i++){
            var c = ALL_CUSTOMERS[i];
            if (!q || c.name.toLowerCase().indexOf(q) > -1 || (c.customer_name && c.customer_name.toLowerCase().indexOf(q) > -1)){
                matches.push(c);
            }
            if (matches.length >= 30) break;
        }
        if (!matches.length){ list.style.display = 'none'; return; }
        list.innerHTML = '';
        for (var i=0; i<matches.length; i++){
            var div = document.createElement('div');
            div.className = 'dd-item';
            div.textContent = (matches[i].customer_name || '') + ' \u2014 ' + matches[i].name;
            div.setAttribute('data-val', matches[i].name);
            div.setAttribute('data-name', matches[i].customer_name || matches[i].name);
            div.addEventListener('click', function(){
                var val = this.getAttribute('data-val');
                var nm = this.getAttribute('data-name');
                $('fCustomerVal').value = val;
                $('fCustomer').style.display = 'none';
                $('csCustName').textContent = nm + ' (' + val + ')';
                $('csCustBadge').style.display = 'flex';
                $('custResults').style.display = 'none';
            });
            list.appendChild(div);
        }
        list.style.display = 'block';
    }

    window.clearCustomer = function(){
        $('fCustomerVal').value = '';
        $('fCustomer').value = '';
        $('fCustomer').style.display = 'block';
        $('csCustBadge').style.display = 'none';
    };

    function doSearch(){
        var cust = $('fCustomerVal').value;
        if (!cust){
            frappe.msgprint('\u0627\u062e\u062a\u0631 \u0639\u0645\u064a\u0644 \u0623\u0648\u0644\u0627\u064b');
            return;
        }

        $('csLoading').style.display = 'block';
        $('csTableWrap').style.display = 'none';
        $('csSummary').style.display = 'none';

        frappe.call({
            method: 'lmt_customer_statement_v1',
            args: {
                customer: cust,
                from_date: $('fFromDate').value,
                to_date: $('fToDate').value
            },
            callback: function(r){
                $('csLoading').style.display = 'none';
                if (!r || !r.message || r.message.error) return;
                ROWS = r.message.rows || [];

                // Update badge with proper name
                if (r.message.customer_name){
                    $('csCustName').textContent = r.message.customer_name + ' (' + cust + ')';
                }

                renderTable(ROWS, r.message.opening);

                if (window.innerWidth < 600 && filtersVisible){
                    filtersVisible = false;
                    $('csFilters').style.display = 'none';
                    $('btnToggle').textContent = '\u25bc \u0625\u0638\u0647\u0627\u0631';
                }
            },
            error: function(){ $('csLoading').style.display = 'none'; }
        });
    }

    function renderTable(rows, opening){
        var balance = opening;
        var totalDr = 0, totalCr = 0;
        var html = '';

        html += '<tr class="opening-row"><td></td><td></td><td></td><td></td><td class="balance-cell">' + fmt(opening) + '</td></tr>';

        for (var i=0; i<rows.length; i++){
            var r = rows[i];
            var d = parseFloat(r.debit || 0);
            var c = parseFloat(r.credit || 0);
            totalDr += d;
            totalCr += c;
            balance += d - c;

            html += '<tr onclick="showCSDetail(' + i + ')">'
                + '<td>' + (i+1) + '</td>'
                + '<td>' + shortDate(r.posting_date) + '</td>'
                + '<td class="debit-cell">' + (d ? fmt(d) : '') + '</td>'
                + '<td class="credit-cell">' + (c ? fmt(c) : '') + '</td>'
                + '<td class="balance-cell">' + fmt(balance) + '</td>'
                + '</tr>';
        }

        html += '<tr class="total-row"><td></td><td>\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a</td>'
            + '<td class="debit-cell">' + fmt(totalDr) + '</td>'
            + '<td class="credit-cell">' + fmt(totalCr) + '</td>'
            + '<td class="balance-cell">' + fmt(balance) + '</td></tr>';

        $('csBody').innerHTML = html;
        $('csTableWrap').style.display = 'block';

        $('csSummary').innerHTML =
            '<div class="s-item"><span class="s-label">\u0639\u062f\u062f \u0627\u0644\u0642\u064a\u0648\u062f</span><span>' + rows.length + '</span></div>'
            + '<div class="s-item"><span class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u0645\u062f\u064a\u0646</span><span style="color:#c0392b;">' + fmt(totalDr) + '</span></div>'
            + '<div class="s-item"><span class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u062f\u0627\u0626\u0646</span><span style="color:#27ae60;">' + fmt(totalCr) + '</span></div>'
            + '<div class="s-item"><span class="s-label">\u0627\u0644\u0631\u0635\u064a\u062f</span><span style="font-weight:700;">' + fmt(balance) + '</span></div>';
        $('csSummary').style.display = 'flex';
    }

    window.showCSDetail = function(idx){
        var r = ROWS[idx];
        if (!r) return;
        var html = '<div style="font-size:16px;font-weight:700;text-align:center;margin-bottom:10px;">\u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u0642\u064a\u062f</div>';
        var fields = [
            ['\u0627\u0644\u062a\u0627\u0631\u064a\u062e', shortDate(r.posting_date)],
            ['\u0645\u062f\u064a\u0646', fmt(r.debit)],
            ['\u062f\u0627\u0626\u0646', fmt(r.credit)],
            ['\u0646\u0648\u0639 \u0627\u0644\u0645\u0633\u062a\u0646\u062f', r.voucher_type || '-'],
            ['\u0631\u0642\u0645 \u0627\u0644\u0645\u0633\u062a\u0646\u062f', r.voucher_no || '-'],
            ['\u0645\u0642\u0627\u0628\u0644', r.against || '-'],
            ['\u0645\u0631\u0643\u0632 \u0627\u0644\u062a\u0643\u0644\u0641\u0629', r.cost_center || '-'],
            ['\u0645\u0644\u0627\u062d\u0638\u0627\u062a', r.remarks || '-']
        ];
        for (var i=0; i<fields.length; i++){
            html += '<div class="d-row"><span class="d-label">' + fields[i][0] + '</span><span class="d-val">' + fields[i][1] + '</span></div>';
        }
        html += '<div style="text-align:center;margin-top:12px;"><button onclick="closeCSDetail()" style="background:#7f8c8d;color:#fff;border:none;padding:10px 30px;border-radius:10px;font-size:14px;cursor:pointer;font-family:inherit;">\u0625\u063a\u0644\u0627\u0642</button></div>';

        $('csDetailModal').innerHTML = html;
        $('csDetailOverlay').style.display = 'block';
        $('csDetailModal').style.display = 'block';
    };

    window.closeCSDetail = function(){
        $('csDetailOverlay').style.display = 'none';
        $('csDetailModal').style.display = 'none';
    };
})();

