javascript:
(function(){
    var ALL_ROWS = [];
    function $(id){ return document.getElementById(id); }
    function fmt(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); }
    function fmtQty(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:0,maximumFractionDigits:0}); }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/stock-balance-1';
            return;
        }
        wire();
        doSearch();
    });

    function wire(){
        $('btnSearch').addEventListener('click', doSearch);
        $('fSearch').addEventListener('input', filterAndRender);
    }

    function doSearch(){
        $('sbLoading').style.display = 'block';
        $('sbList').style.display = 'none';
        $('sbSummary').style.display = 'none';

        frappe.call({
            method: 'lmt_stock_balance_v1',
            args: {
                warehouse: $('fWarehouse').value,
                item_group: $('fItemGroup').value
            },
            callback: function(r){
                $('sbLoading').style.display = 'none';
                if (!r || !r.message) return;
                ALL_ROWS = r.message.rows || [];

                // Populate filter dropdowns (first load)
                if ($('fWarehouse').options.length <= 1){
                    var whs = r.message.warehouses || [];
                    for (var i=0; i<whs.length; i++){
                        var o = document.createElement('option');
                        o.value = whs[i]; o.textContent = whs[i];
                        $('fWarehouse').appendChild(o);
                    }
                    var igs = r.message.item_groups || [];
                    for (var i=0; i<igs.length; i++){
                        var o = document.createElement('option');
                        o.value = igs[i]; o.textContent = igs[i];
                        $('fItemGroup').appendChild(o);
                    }
                }
                filterAndRender();
            },
            error: function(){ $('sbLoading').style.display = 'none'; }
        });
    }

    function filterAndRender(){
        var q = $('fSearch').value.trim().toLowerCase();
        var filtered = ALL_ROWS;
        if (q){
            filtered = [];
            for (var i=0; i<ALL_ROWS.length; i++){
                var r = ALL_ROWS[i];
                if ((r.item_name && r.item_name.toLowerCase().indexOf(q) > -1) || r.item_code.toLowerCase().indexOf(q) > -1){
                    filtered.push(r);
                }
            }
        }

        // Group by item
        var grouped = {};
        var order = [];
        for (var i=0; i<filtered.length; i++){
            var r = filtered[i];
            if (!grouped[r.item_code]){
                grouped[r.item_code] = {item_name: r.item_name, item_group: r.item_group, warehouses: [], totalQty: 0, totalVal: 0};
                order.push(r.item_code);
            }
            grouped[r.item_code].warehouses.push(r);
            grouped[r.item_code].totalQty += parseFloat(r.actual_qty || 0);
            grouped[r.item_code].totalVal += parseFloat(r.stock_value || 0);
        }

        var html = '';
        var grandQty = 0, grandVal = 0;

        for (var i=0; i<order.length; i++){
            var ic = order[i];
            var g = grouped[ic];
            grandQty += g.totalQty;
            grandVal += g.totalVal;

            html += '<div class="sb-item-card">';
            html += '<div class="sb-item-header"><span class="sb-item-name">' + (g.item_name || ic) + '</span>';
            html += '<span class="sb-item-group">' + (g.item_group || '') + '</span></div>';

            for (var j=0; j<g.warehouses.length; j++){
                var w = g.warehouses[j];
                html += '<div class="sb-wh-row">';
                html += '<span class="sb-wh-name">' + w.warehouse + '</span>';
                html += '<span><span class="sb-wh-qty">' + fmtQty(w.actual_qty) + '</span> <span class="sb-wh-val">(' + fmt(w.stock_value) + ')</span></span>';
                html += '</div>';
            }

            if (g.warehouses.length > 1){
                html += '<div class="sb-item-total">';
                html += '<span>\u0625\u062c\u0645\u0627\u0644\u064a</span>';
                html += '<span><span class="total-qty">' + fmtQty(g.totalQty) + '</span> <span class="total-val">(' + fmt(g.totalVal) + ')</span></span>';
                html += '</div>';
            }
            html += '</div>';
        }

        $('sbList').innerHTML = html || '<div style="text-align:center;padding:20px;color:#888;">\u0644\u0627 \u062a\u0648\u062c\u062f \u0646\u062a\u0627\u0626\u062c</div>';
        $('sbList').style.display = 'block';

        $('sbSummary').innerHTML =
            '<div class="s-item"><div class="s-label">\u0639\u062f\u062f \u0627\u0644\u0623\u0635\u0646\u0627\u0641</div><div>' + order.length + '</div></div>'
            + '<div class="s-item"><div class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u0643\u0645\u064a\u0629</div><div>' + fmtQty(grandQty) + '</div></div>'
            + '<div class="s-item"><div class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u0627\u0644\u0642\u064a\u0645\u0629</div><div>' + fmt(grandVal) + '</div></div>';
        $('sbSummary').style.display = 'flex';
    }
})();

