javascript:
(function(){
    var ALL_ITEMS = [];
    var ALL_WH = [];
    var ROWS = [];
    var filtersVisible = true;

    function $(id){ return document.getElementById(id); }
    function fmt(v){ return parseFloat(v||0).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}); }
    function fmtQty(v){ var n = parseFloat(v||0); return n > 0 ? '+' + n : '' + n; }
    function shortDate(d){ if (!d) return ''; var s = String(d).substring(0,10).split('-'); return s[2]+'/'+s[1]; }

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/stock-ledger-1';
            return;
        }
        var now = new Date();
        $('fFromDate').value = now.getFullYear() + '-01-01';
        $('fToDate').value = now.toISOString().substring(0,10);
        wire();
        // Initial load to get filter options
        doSearch();
    });

    function wire(){
        $('btnSearch').addEventListener('click', doSearch);
        $('btnToggle').addEventListener('click', function(){
            filtersVisible = !filtersVisible;
            $('slFilters').style.display = filtersVisible ? 'block' : 'none';
            this.textContent = filtersVisible ? '\u25b2 \u0625\u062e\u0641\u0627\u0621' : '\u25bc \u0625\u0638\u0647\u0627\u0631';
        });

        $('fItem').addEventListener('focus', function(){ showItemList(''); });
        $('fItem').addEventListener('input', function(){
            showItemList(this.value.trim().toLowerCase());
        });
        document.addEventListener('click', function(e){
            if (!e.target.closest('#fItem') && !e.target.closest('#itemResults'))
                $('itemResults').style.display = 'none';
        });
    }

    function showItemList(q){
        var list = $('itemResults');
        var matches = [];
        for (var i=0; i<ALL_ITEMS.length; i++){
            var it = ALL_ITEMS[i];
            if (!q || it.item_code.toLowerCase().indexOf(q) > -1 || (it.item_name && it.item_name.toLowerCase().indexOf(q) > -1)){
                matches.push(it);
            }
            if (matches.length >= 30) break;
        }
        if (!matches.length){ list.style.display = 'none'; return; }
        list.innerHTML = '';
        for (var i=0; i<matches.length; i++){
            var div = document.createElement('div');
            div.className = 'dd-item';
            div.textContent = (matches[i].item_name || '') + ' \u2014 ' + matches[i].item_code;
            div.setAttribute('data-val', matches[i].item_code);
            div.addEventListener('click', function(){
                $('fItem').value = this.getAttribute('data-val');
                $('itemResults').style.display = 'none';
            });
            list.appendChild(div);
        }
        list.style.display = 'block';
    }

    function doSearch(){
        $('slLoading').style.display = 'block';
        $('slTableWrap').style.display = 'none';
        $('slSummary').style.display = 'none';

        frappe.call({
            method: 'lmt_stock_ledger_v1',
            args: {
                item_code: $('fItem').value.trim(),
                warehouse: $('fWarehouse').value,
                from_date: $('fFromDate').value,
                to_date: $('fToDate').value
            },
            callback: function(r){
                $('slLoading').style.display = 'none';
                if (!r || !r.message) return;
                ROWS = r.message.rows || [];

                // Populate filters on first load
                if (!ALL_ITEMS.length){
                    ALL_ITEMS = r.message.items || [];
                    ALL_WH = r.message.warehouses || [];
                    var whSel = $('fWarehouse');
                    if (whSel.options.length <= 1){
                        for (var i=0; i<ALL_WH.length; i++){
                            var o = document.createElement('option');
                            o.value = ALL_WH[i]; o.textContent = ALL_WH[i];
                            whSel.appendChild(o);
                        }
                    }
                }

                renderTable(ROWS);

                if (window.innerWidth < 600 && filtersVisible && ROWS.length){
                    filtersVisible = false;
                    $('slFilters').style.display = 'none';
                    $('btnToggle').textContent = '\u25bc \u0625\u0638\u0647\u0627\u0631';
                }
            },
            error: function(){ $('slLoading').style.display = 'none'; }
        });
    }

    function renderTable(rows){
        var html = '';
        var totalIn = 0, totalOut = 0;

        for (var i=0; i<rows.length; i++){
            var r = rows[i];
            var qty = parseFloat(r.actual_qty || 0);
            if (qty > 0) totalIn += qty;
            else totalOut += Math.abs(qty);
            var qtyCls = qty >= 0 ? 'qty-in' : 'qty-out';

            html += '<tr onclick="showSLDetail(' + i + ')">'
                + '<td>' + (i+1) + '</td>'
                + '<td>' + shortDate(r.posting_date) + '</td>'
                + '<td class="col-item">' + (r.item_name || r.item_code) + '</td>'
                + '<td class="col-wh">' + (r.warehouse || '') + '</td>'
                + '<td class="' + qtyCls + '">' + fmtQty(qty) + '</td>'
                + '<td class="bal-cell">' + parseFloat(r.qty_after_transaction || 0) + '</td>'
                + '</tr>';
        }

        $('slBody').innerHTML = html;
        $('slTableWrap').style.display = 'block';

        $('slSummary').innerHTML =
            '<div class="s-item"><div class="s-label">\u0639\u062f\u062f \u0627\u0644\u062d\u0631\u0643\u0627\u062a</div><div>' + rows.length + '</div></div>'
            + '<div class="s-item"><div class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u062f\u062e\u0648\u0644</div><div style="color:#2ecc71;">+' + totalIn + '</div></div>'
            + '<div class="s-item"><div class="s-label">\u0625\u062c\u0645\u0627\u0644\u064a \u062e\u0631\u0648\u062c</div><div style="color:#e74c3c;">-' + totalOut + '</div></div>';
        $('slSummary').style.display = 'flex';
    }

    window.showSLDetail = function(idx){
        var r = ROWS[idx];
        if (!r) return;
        var html = '<div style="font-size:16px;font-weight:700;text-align:center;margin-bottom:10px;">\u062a\u0641\u0627\u0635\u064a\u0644 \u062d\u0631\u0643\u0629 \u0627\u0644\u0645\u062e\u0632\u0648\u0646</div>';
        var fields = [
            ['\u0627\u0644\u062a\u0627\u0631\u064a\u062e', shortDate(r.posting_date)],
            ['\u0627\u0644\u0635\u0646\u0641', (r.item_name || '') + ' (' + r.item_code + ')'],
            ['\u0627\u0644\u0645\u062e\u0632\u0646', r.warehouse || '-'],
            ['\u0627\u0644\u0643\u0645\u064a\u0629', fmtQty(r.actual_qty)],
            ['\u0627\u0644\u0631\u0635\u064a\u062f \u0628\u0639\u062f', '' + (r.qty_after_transaction || 0)],
            ['\u0633\u0639\u0631 \u0627\u0644\u062a\u0642\u064a\u064a\u0645', fmt(r.valuation_rate)],
            ['\u0642\u064a\u0645\u0629 \u0627\u0644\u0645\u062e\u0632\u0648\u0646', fmt(r.stock_value)],
            ['\u0646\u0648\u0639 \u0627\u0644\u0645\u0633\u062a\u0646\u062f', r.voucher_type || '-'],
            ['\u0631\u0642\u0645 \u0627\u0644\u0645\u0633\u062a\u0646\u062f', r.voucher_no || '-'],
            ['\u0631\u0642\u0645 \u0627\u0644\u062f\u0641\u0639\u0629', r.batch_no || '-']
        ];
        for (var i=0; i<fields.length; i++){
            html += '<div class="d-row"><span class="d-label">' + fields[i][0] + '</span><span class="d-val">' + fields[i][1] + '</span></div>';
        }
        html += '<div style="text-align:center;margin-top:12px;"><button onclick="closeSLDetail()" style="background:#7f8c8d;color:#fff;border:none;padding:10px 30px;border-radius:10px;font-size:14px;cursor:pointer;font-family:inherit;">\u0625\u063a\u0644\u0627\u0642</button></div>';

        $('slDetailModal').innerHTML = html;
        $('slDetailOverlay').style.display = 'block';
        $('slDetailModal').style.display = 'block';
    };

    window.closeSLDetail = function(){
        $('slDetailOverlay').style.display = 'none';
        $('slDetailModal').style.display = 'none';
    };
})();

