javascript:
(function(){
    var CATEGORY_ICONS = {
        'Employee':   '\ud83d\udc65',
        'Salary':     '\ud83d\udcb0',
        'Payroll':    '\ud83c\udfe7',
        'Leave':      '\ud83c\udfd6\ufe0f',
        'Attendance': '\u23f0',
        'Other':      '\ud83d\udccb'
    };
    var CATEGORY_ORDER = ['Employee','Salary','Payroll','Leave','Attendance','Other'];
    var CAT_AR = {
        'Employee':   '\u0627\u0644\u0645\u0648\u0638\u0641\u064a\u0646',
        'Salary':     '\u0627\u0644\u0631\u0648\u0627\u062a\u0628',
        'Payroll':    '\u062a\u0634\u063a\u064a\u0644 \u0627\u0644\u0631\u0648\u0627\u062a\u0628',
        'Leave':      '\u0627\u0644\u0625\u062c\u0627\u0632\u0627\u062a',
        'Attendance': '\u0627\u0644\u062d\u0636\u0648\u0631',
        'Other':      '\u0623\u062e\u0631\u0649'
    };

    frappe.ready(function(){
        if (!frappe.session || frappe.session.user === 'Guest'){
            window.location.href = '/login?redirect-to=/hr-hub-1';
            return;
        }
        loadItems();
    });

    function loadItems(){
        frappe.call({
            method: 'lmt_hr_menu_items_v1',
            callback: function(r){
                document.getElementById('rhLoading').style.display = 'none';
                var main = document.getElementById('rhMain');
                main.style.display = 'block';
                if (!r || !r.message || !r.message.length){
                    main.innerHTML = '<div style="text-align:center;padding:40px;color:#888;">\u0644\u0627 \u062a\u0648\u062c\u062f \u0639\u0646\u0627\u0635\u0631</div>';
                    return;
                }
                renderItems(r.message);
            },
            error: function(){
                document.getElementById('rhLoading').innerHTML = '<div style="color:#c0392b;">\u062e\u0637\u0623</div>';
            }
        });
    }

    function renderItems(items){
        var grouped = {};
        for (var i = 0; i < items.length; i++){
            var cat = items[i].category || 'Other';
            if (!grouped[cat]) grouped[cat] = [];
            grouped[cat].push(items[i]);
        }
        var html = '';
        for (var c = 0; c < CATEGORY_ORDER.length; c++){
            var cat = CATEGORY_ORDER[c];
            if (!grouped[cat] || !grouped[cat].length) continue;
            html += '<div class="rh-cat-header">' + (CATEGORY_ICONS[cat] || '') + ' ' + (CAT_AR[cat] || cat) + '</div>';
            html += '<div class="rh-grid">';
            var list = grouped[cat];
            for (var j = 0; j < list.length; j++){
                var it = list[j];
                var icon = it.emoji || '\ud83d\udcc4';
                if (it.icon_type === 'FontAwesome' && it.fa_class) icon = '<i class="fa ' + it.fa_class + '"></i>';
                if (it.icon_type === 'ImageURL' && it.image_url) icon = '<img src="' + it.image_url + '">';
                html += '<div class="rh-card" onclick="location.href=\'' + (it.route || '#') + '\'">'
                    + '<div class="rh-card-icon">' + icon + '</div>'
                    + '<div class="rh-card-label">' + (it.title_ar || it.title_en || '') + '</div>'
                    + '</div>';
            }
            html += '</div>';
        }
        document.getElementById('rhMain').innerHTML = html;
    }
})();

