javascript:
(function(){
    var ALL_USERS=[], FILTERS={}, activeFilter='all', selectedUser=null;
    function $(id){return document.getElementById(id);}
    function fmt(d){if(!d)return '-';return String(d).substring(0,10);}

    frappe.ready(function(){
        if(!frappe.session||frappe.session.user==='Guest'){window.location.href='/login?redirect-to=/user-mgmt-1';return;}
        wireTabs();
        $('fSearch').addEventListener('input',filterAndRender);
        loadList();
    });

    function wireTabs(){
        var tabs=document.querySelectorAll('.um-tab');
        for(var i=0;i<tabs.length;i++){
            tabs[i].addEventListener('click',function(){
                for(var j=0;j<tabs.length;j++) tabs[j].classList.remove('active');
                this.classList.add('active');
                activeFilter=this.getAttribute('data-filter');
                if(activeFilter==='new'){
                    $('umList').style.display='none';$('fSearch').style.display='none';
                    showNewForm();
                } else {
                    $('umNewForm').style.display='none';$('umList').style.display='block';$('fSearch').style.display='block';
                    filterAndRender();
                }
            });
        }
    }

    function loadList(){
        $('umLoading').style.display='block';$('umList').style.display='none';
        frappe.call({method:'lmt_user_mgmt_v1',args:{action:'list'},callback:function(r){
            $('umLoading').style.display='none';
            if(!r||!r.message) return;
            ALL_USERS=r.message.users||[];
            FILTERS=r.message;
            renderSummary();
            filterAndRender();
        }});
    }

    function renderSummary(){
        var total=ALL_USERS.length,enabled=0,disabled=0;
        for(var i=0;i<ALL_USERS.length;i++){
            if(ALL_USERS[i].enabled) enabled++; else disabled++;
        }
        $('umSummary').innerHTML=
            '<div class="um-sum-card"><div class="sv" style="color:#2c3e50;">'+total+'</div><div class="sl">\u0627\u0644\u0625\u062c\u0645\u0627\u0644\u064a</div></div>'
            +'<div class="um-sum-card"><div class="sv" style="color:#27ae60;">'+enabled+'</div><div class="sl">\u0645\u0641\u0639\u0644</div></div>'
            +'<div class="um-sum-card"><div class="sv" style="color:#e74c3c;">'+disabled+'</div><div class="sl">\u0645\u0639\u0637\u0644</div></div>';
        $('umSummary').style.display='grid';
    }

    function filterAndRender(){
        var q=$('fSearch').value.trim().toLowerCase();
        var filtered=[];
        for(var i=0;i<ALL_USERS.length;i++){
            var u=ALL_USERS[i];
            if(activeFilter==='enabled'&&!u.enabled) continue;
            if(activeFilter==='disabled'&&u.enabled) continue;
            if(q&&(u.full_name||'').toLowerCase().indexOf(q)===-1&&u.email.toLowerCase().indexOf(q)===-1) continue;
            filtered.push(u);
        }
        renderList(filtered);
    }

    function renderList(users){
        var html='';
        for(var i=0;i<users.length;i++){
            var u=users[i];
            var statusCls=u.enabled?'on':'off';
            var statusTxt=u.enabled?'\u0645\u0641\u0639\u0644 \u2705':'\u0645\u0639\u0637\u0644 \u26d4';
            html+='<div class="um-user-card'+(u.enabled?'':' disabled-user')+'" data-email="'+u.email+'">'
                +'<div class="um-user-info">'
                +'<div class="um-user-name">'+(u.full_name||u.first_name||u.email)+'</div>'
                +'<div class="um-user-email">'+u.email+'</div>'
                +'<div class="um-user-role">'+(u.role_profile_name||'-')+'</div>'
                +'</div><div class="um-user-right">'
                +'<div class="um-user-status '+statusCls+'">'+statusTxt+'</div>'
                +'<div class="um-user-last">'+fmt(u.last_active)+'</div>'
                +'</div></div>';
        }
        $('umList').innerHTML=html||'<div style="text-align:center;padding:20px;color:#888;">\u0644\u0627 \u062a\u0648\u062c\u062f \u0646\u062a\u0627\u0626\u062c</div>';
        $('umList').style.display='block';
        var cards=$('umList').querySelectorAll('.um-user-card');
        for(var i=0;i<cards.length;i++){
            cards[i].addEventListener('click',function(){openEditModal(this.getAttribute('data-email'));});
        }
    }

    function makeSelect(id,options,selected,placeholder){
        var h='<select id="'+id+'" class="um-finput"><option value="">'+(placeholder||'--')+'</option>';
        for(var i=0;i<options.length;i++){
            var val=typeof options[i]==='object'?options[i].name:options[i];
            h+='<option value="'+val+'"'+(val===selected?' selected':'')+'>'+val+'</option>';
        }
        return h+'</select>';
    }

    function makeSection(title,icon,id,collapsed,content){
        return '<div class="um-section"><div class="um-section-head'+(collapsed?' collapsed':'')+'" onclick="toggleUMSection(\''+id+'\',this)"><span>'+icon+' '+title+'</span><span class="arrow">\u25bc</span></div>'
            +'<div id="'+id+'" class="um-section-body'+(collapsed?' hidden':'')+'">'+content+'</div></div>';
    }

    function openEditModal(email){
        selectedUser=null;
        for(var i=0;i<ALL_USERS.length;i++){if(ALL_USERS[i].email===email){selectedUser=ALL_USERS[i];break;}}
        if(!selectedUser) return;
        var u=selectedUser;

        var html='<div class="um-modal-header"><div class="mh-name">'+(u.full_name||u.email)+'</div><div class="mh-email">'+u.email+'</div></div>';

        // Enable/Disable toggle
        var toggleHtml='<div class="um-toggle">'
            +'<div class="um-toggle-switch'+(u.enabled?' on':'')+'" id="togEnabled" onclick="toggleEnabled()">'
            +'<div class="knob"></div></div>'
            +'<span class="um-toggle-label" id="togLabel">'+(u.enabled?'\u0645\u0641\u0639\u0644 \u2705':'\u0645\u0639\u0637\u0644 \u26d4')+'</span></div>';

        // Basic
        var basic=toggleHtml
            +'<div class="um-row"><div class="um-field"><label>\u0627\u0644\u0627\u0633\u0645 \u0627\u0644\u0623\u0648\u0644 <span class="req">*</span></label><input id="edt_first_name" class="um-finput" value="'+(u.first_name||'')+'"></div>'
            +'<div class="um-field"><label>\u0627\u0644\u0644\u0642\u0628</label><input id="edt_last_name" class="um-finput" value="'+(u.last_name||'')+'"></div></div>'
