            +'<div class="um-field"><label>Company %</label><input type="number" id="edt_lmt_percentage_2" class="um-finput" value="'+(u.lmt_percentage_2||0)+'" step="0.01"></div></div>'
            +'<div class="um-row"><div class="um-field"><label>Percentage 1</label><input type="number" id="edt_percentage_1" class="um-finput" value="'+(u.percentage_1||0)+'" step="0.01"></div>'
            +'<div class="um-field"><label>Percentage 2</label><input type="number" id="edt_percentage_2" class="um-finput" value="'+(u.percentage_2||0)+'" step="0.01"></div></div>'
            +'<div class="um-row"><div class="um-field"><label>Booklet Start</label><input type="number" id="edt_lmt_booklet_start" class="um-finput" value="'+(u.lmt_booklet_start||0)+'"></div>'
            +'<div class="um-field"><label>Booklet End</label><input type="number" id="edt_lmt_booklet_end" class="um-finput" value="'+(u.lmt_booklet_end||0)+'"></div></div>'
            +'<div class="um-row"><div class="um-field"><label>Week Start</label>'+makeSelect('edt_lmt_week_start_day',["Saturday","Sunday","Monday","Tuesday","Wednesday","Thursday","Friday"],u.lmt_week_start_day)+'</div>'
            +'<div class="um-field"><label>Week End</label>'+makeSelect('edt_lmt_week_end_day',["Saturday","Sunday","Monday","Tuesday","Wednesday","Thursday","Friday"],u.lmt_week_end_day)+'</div></div>'
            +'<div class="um-field"><label>\u0627\u0644\u0645\u0634\u0631\u0641</label>'+makeSelect('edt_lmt_supervisor_user',FILTERS.all_users_list||[],u.lmt_supervisor_user)+'</div>'
            +'<div class="um-field"><label>Invoice Counter</label><input type="number" id="edt_custom_invoice_counter" class="um-finput" value="'+(u.custom_invoice_counter||0)+'"></div>';
        html+=makeSection('\u0625\u0639\u062f\u0627\u062f\u0627\u062a \u062e\u0627\u0635\u0629','\u2699\ufe0f','secSetup',true,setup);

        // Generalized Text
        var gtxt='<div class="um-row"><div class="um-field"><label>TXT 1</label><input id="edt_custom_txt_1" class="um-finput" value="'+(u.custom_txt_1||'')+'"></div>'
            +'<div class="um-field"><label>TXT 2</label><input id="edt_custom_txt_2" class="um-finput" value="'+(u.custom_txt_2||'')+'"></div></div>'
