            +'<div class="um-field"><label>TXT 5</label><input id="edt_custom_txt_5" class="um-finput" value="'+(u.custom_txt_5||'')+'"></div>';
        html+=makeSection('\u062d\u0642\u0648\u0644 \u0646\u0635\u064a\u0629','\U0001f4dd','secTxt',true,gtxt);

        // Generalized Checks + Numbers
        var gnum='<div class="um-row"><div class="um-field"><label>LOG 1</label><select id="edt_custom_log_1" class="um-finput"><option value="0"'+(u.custom_log_1?'':' selected')+'>☐</option><option value="1"'+(u.custom_log_1?' selected':'')+'>☑</option></select></div>'
            +'<div class="um-field"><label>LOG 2</label><select id="edt_custom_log_2" class="um-finput"><option value="0"'+(u.custom_log_2?'':' selected')+'>☐</option><option value="1"'+(u.custom_log_2?' selected':'')+'>☑</option></select></div></div>'
            +'<div class="um-row"><div class="um-field"><label>LOG 3</label><select id="edt_custom_log_3" class="um-finput"><option value="0"'+(u.custom_log_3?'':' selected')+'>☐</option><option value="1"'+(u.custom_log_3?' selected':'')+'>☑</option></select></div>'
            +'<div class="um-field"><label>LOG 4</label><select id="edt_custom_log_4" class="um-finput"><option value="0"'+(u.custom_log_4?'':' selected')+'>☐</option><option value="1"'+(u.custom_log_4?' selected':'')+'>☑</option></select></div></div>'
            +'<div class="um-field"><label>LOG 5</label><select id="edt_custom_log_5" class="um-finput"><option value="0"'+(u.custom_log_5?'':' selected')+'>☐</option><option value="1"'+(u.custom_log_5?' selected':'')+'>☑</option></select></div>'
            +'<div class="um-row"><div class="um-field"><label>INT 1</label><input type="number" id="edt_custom_int_1" class="um-finput" value="'+(u.custom_int_1||0)+'"></div>'
            +'<div class="um-field"><label>INT 2</label><input type="number" id="edt_custom_int_2" class="um-finput" value="'+(u.custom_int_2||0)+'"></div></div>'
            +'<div class="um-row"><div class="um-field"><label>INT 3</label><input type="number" id="edt_custom_int_3" class="um-finput" value="'+(u.custom_int_3||0)+'"></div>'
            +'<div class="um-field"><label>INT 4</label><input type="number" id="edt_custom_int_4" class="um-finput" value="'+(u.custom_int_4||0)+'"></div></div>'
            +'<div class="um-field"><label>INT 5</label><input type="number" id="edt_custom_int_5" class="um-finput" value="'+(u.custom_int_5||0)+'"></div>'
            +'<div class="um-row"><div class="um-field"><label>DEC 1</label><input type="number" id="edt_custom_dec_1" class="um-finput" value="'+(u.custom_dec_1||0)+'" step="0.01"></div>'
            +'<div class="um-field"><label>DEC 2</label><input type="number" id="edt_custom_dec_2" class="um-finput" value="'+(u.custom_dec_2||0)+'" step="0.01"></div></div>'
            +'<div class="um-row"><div class="um-field"><label>DEC 3</label><input type="number" id="edt_custom_dec_3" class="um-finput" value="'+(u.custom_dec_3||0)+'" step="0.01"></div>'
            +'<div class="um-field"><label>DEC 4</label><input type="number" id="edt_custom_dec_4" class="um-finput" value="'+(u.custom_dec_4||0)+'" step="0.01"></div></div>'
            +'<div class="um-field"><label>DEC 5</label><input type="number" id="edt_custom_dec_5" class="um-finput" value="'+(u.custom_dec_5||0)+'" step="0.01"></div>';
        html+=makeSection('\u062d\u0642\u0648\u0644 \u0631\u0642\u0645\u064a\u0629','\U0001f522','secNum',true,gnum);

        // Password reset
        var pwd='<div class="um-field"><label>\u0643\u0644\u0645\u0629 \u0645\u0631\u0648\u0631 \u062c\u062f\u064a\u062f\u0629</label><input type="password" id="edt_password" class="um-finput" placeholder="\u0627\u062a\u0631\u0643 \u0641\u0627\u0631\u063a\u0627\u064b \u0625\u0630\u0627 \u0644\u0627 \u062a\u0631\u064a\u062f \u0627\u0644\u062a\u063a\u064a\u064a\u0631"></div>'
            +'<button id="btnResetPwd" class="um-btn-reset" onclick="resetPassword()">\U0001f511 \u062a\u063a\u064a\u064a\u0631 \u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631</button>';
        html+=makeSection('\u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631','\U0001f511','secPwd',true,pwd);

        html+='<div id="edtStatus" class="um-status" style="display:none;"></div>';
        html+='<div class="um-modal-actions"><button id="btnEdtSave" class="um-btn-save">\U0001f4be \u062d\u0641\u0638</button><button class="um-btn-cancel" onclick="closeUMModal()">\u0625\u0644\u063a\u0627\u0621</button></div>';

        $('umModal').innerHTML=html;
        $('umOverlay').style.display='block';$('umModal').style.display='block';
        $('umOverlay').onclick=closeUMModal;
        $('btnEdtSave').addEventListener('click',saveUser);
    }

    window.toggleEnabled=function(){
        var tog=$('togEnabled');
        var label=$('togLabel');
        if(tog.classList.contains('on')){
            tog.classList.remove('on');
            label.textContent='\u0645\u0639\u0637\u0644 \u26d4';
        } else {
            tog.classList.add('on');
            label.textContent='\u0645\u0641\u0639\u0644 \u2705';
        }
    };

    function saveUser(){
        if(!selectedUser) return;
        var enabled=$('togEnabled').classList.contains('on')?1:0;
        $('btnEdtSave').disabled=true;
        showSt('edtStatus','\u062c\u0627\u0631\u064a \u0627\u0644\u062d\u0641\u0638...','success');

        frappe.call({method:'lmt_user_mgmt_v1',args:{
            action:'update',user:selectedUser.email,
            first_name:$('edt_first_name').value.trim(),
            last_name:$('edt_last_name').value.trim(),
            username:$('edt_username').value.trim(),
            mobile_no:$('edt_mobile_no').value.trim(),
            role_profile_name:$('edt_role_profile').value,
            module_profile:$('edt_module_profile').value,
            language:$('edt_language').value,
            gender:$('edt_gender').value,
            birth_date:$('edt_birth_date').value,
            enabled:enabled,
            warehouse:$('edt_warehouse').value,
            percentage_1:$('edt_percentage_1').value,
            percentage_2:$('edt_percentage_2').value,
            lmt_percentage_1:$('edt_lmt_percentage_1').value,
            lmt_percentage_2:$('edt_lmt_percentage_2').value,
            lmt_booklet_start:$('edt_lmt_booklet_start').value,
            lmt_booklet_end:$('edt_lmt_booklet_end').value,
            lmt_week_start_day:$('edt_lmt_week_start_day').value,
            lmt_week_end_day:$('edt_lmt_week_end_day').value,
            lmt_supervisor_user:$('edt_lmt_supervisor_user').value,
            custom_invoice_counter:$('edt_custom_invoice_counter').value,
            custom_txt_1:$('edt_custom_txt_1').value,custom_txt_2:$('edt_custom_txt_2').value,
            custom_txt_3:$('edt_custom_txt_3').value,custom_txt_4:$('edt_custom_txt_4').value,
            custom_txt_5:$('edt_custom_txt_5').value,
            custom_log_1:$('edt_custom_log_1').value,custom_log_2:$('edt_custom_log_2').value,
            custom_log_3:$('edt_custom_log_3').value,custom_log_4:$('edt_custom_log_4').value,
            custom_log_5:$('edt_custom_log_5').value,
            custom_int_1:$('edt_custom_int_1').value,custom_int_2:$('edt_custom_int_2').value,
            custom_int_3:$('edt_custom_int_3').value,custom_int_4:$('edt_custom_int_4').value,
            custom_int_5:$('edt_custom_int_5').value,
            custom_dec_1:$('edt_custom_dec_1').value,custom_dec_2:$('edt_custom_dec_2').value,
            custom_dec_3:$('edt_custom_dec_3').value,custom_dec_4:$('edt_custom_dec_4').value,
            custom_dec_5:$('edt_custom_dec_5').value
        },
            callback:function(r){
                $('btnEdtSave').disabled=false;
                if(!r||!r.message||r.message.error){showSt('edtStatus',(r&&r.message)?r.message.error:'\u062e\u0637\u0623','error');return;}
                showSt('edtStatus','\u2705 \u062a\u0645 \u0627\u0644\u062d\u0641\u0638','success');
                setTimeout(function(){closeUMModal();loadList();},1500);
            },
            error:function(e){$('btnEdtSave').disabled=false;var msg='\u062e\u0637\u0623';try{if(e&&e._server_messages)msg=JSON.parse(JSON.parse(e._server_messages)[0]).message||msg;}catch(ex){}showSt('edtStatus',msg,'error');}
        });
    }

    window.resetPassword=function(){
        var pwd=$('edt_password').value;
        if(!pwd){showSt('edtStatus','\u0623\u062f\u062e\u0644 \u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631 \u0627\u0644\u062c\u062f\u064a\u062f\u0629','error');return;}
        frappe.call({method:'lmt_user_mgmt_v1',args:{action:'reset_password',user:selectedUser.email,password:pwd},
            callback:function(r){
                if(r&&r.message&&r.message.success){showSt('edtStatus','\u2705 \u062a\u0645 \u062a\u063a\u064a\u064a\u0631 \u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631','success');$('edt_password').value='';}
                else showSt('edtStatus','\u062e\u0637\u0623','error');
            },
            error:function(){showSt('edtStatus','\u062e\u0637\u0623','error');}
        });
    };

    function showNewForm(){
        var html='<div class="um-new-card"><div class="um-new-title">\u2795 \u0625\u0636\u0627\u0641\u0629 \u0645\u0633\u062a\u062e\u062f\u0645 \u062c\u062f\u064a\u062f</div>'
            +'<div class="um-field"><label>\u0627\u0644\u0628\u0631\u064a\u062f \u0627\u0644\u0625\u0644\u0643\u062a\u0631\u0648\u0646\u064a <span class="req">*</span></label><input id="new_email" class="um-finput" type="email" placeholder="user@example.com"></div>'
            +'<div class="um-row"><div class="um-field"><label>\u0627\u0644\u0627\u0633\u0645 \u0627\u0644\u0623\u0648\u0644 <span class="req">*</span></label><input id="new_first_name" class="um-finput"></div>'
            +'<div class="um-field"><label>\u0627\u0644\u0644\u0642\u0628</label><input id="new_last_name" class="um-finput"></div></div>'
            +'<div class="um-row"><div class="um-field"><label>\u0627\u0633\u0645 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645</label><input id="new_username" class="um-finput"></div>'
            +'<div class="um-field"><label>\u0627\u0644\u062c\u0648\u0627\u0644</label><input id="new_mobile" class="um-finput"></div></div>'
            +'<div class="um-field"><label>\u0643\u0644\u0645\u0629 \u0627\u0644\u0645\u0631\u0648\u0631</label><input type="password" id="new_password" class="um-finput" placeholder="\u0627\u062e\u062a\u064a\u0627\u0631\u064a"></div>'
            +'<div class="um-row"><div class="um-field"><label>\u0645\u0644\u0641 \u0627\u0644\u0635\u0644\u0627\u062d\u064a\u0627\u062a</label>'+makeSelect('new_role_profile',FILTERS.role_profiles||[],'')+'</div>'
            +'<div class="um-field"><label>\u0645\u0644\u0641 \u0627\u0644\u0648\u062d\u062f\u0627\u062a</label>'+makeSelect('new_module_profile',FILTERS.module_profiles||[],'')+'</div></div>'
            +'<div class="um-row"><div class="um-field"><label>\u0627\u0644\u0644\u063a\u0629</label>'+makeSelect('new_language',FILTERS.languages||[],'')+'</div>'
            +'<div class="um-field"><label>\u0627\u0644\u062c\u0646\u0633</label>'+makeSelect('new_gender',FILTERS.genders||[],'')+'</div></div>'
            +'<div id="newStatus" class="um-status" style="display:none;"></div>'
            +'<button id="btnNewSave" class="um-btn-save" style="width:100%;margin-top:10px;">\U0001f4be \u0625\u0636\u0627\u0641\u0629 \u0627\u0644\u0645\u0633\u062a\u062e\u062f\u0645</button></div>';
        $('umNewForm').innerHTML=html;
        $('umNewForm').style.display='block';
        $('btnNewSave').addEventListener('click',saveNewUser);
    }

    function saveNewUser(){
        var email=$('new_email').value.trim();
        var first=$('new_first_name').value.trim();
        if(!email||!first){showSt('newStatus','\u0627\u0644\u0628\u0631\u064a\u062f \u0648\u0627\u0644\u0627\u0633\u0645 \u0645\u0637\u0644\u0648\u0628\u0627\u0646','error');return;}
        $('btnNewSave').disabled=true;
        showSt('newStatus','\u062c\u0627\u0631\u064a \u0627\u0644\u0625\u0636\u0627\u0641\u0629...','success');
        frappe.call({method:'lmt_user_mgmt_v1',args:{
            action:'new_user',email:email,first_name:first,
            last_name:$('new_last_name').value.trim(),
            username:$('new_username').value.trim(),
            mobile_no:$('new_mobile').value.trim(),
            password:$('new_password').value,
            role_profile_name:$('new_role_profile').value,
            module_profile:$('new_module_profile').value,
            language:$('new_language').value,
            gender:$('new_gender').value
        },
            callback:function(r){
                $('btnNewSave').disabled=false;
                if(!r||!r.message||r.message.error){showSt('newStatus',(r&&r.message)?r.message.error:'\u062e\u0637\u0623','error');return;}
                showSt('newStatus','\u2705 \u062a\u0645 \u0625\u0636\u0627\u0641\u0629 '+(r.message.full_name||'')+' ('+r.message.name+')','success');
                setTimeout(function(){loadList();},2000);
            },
            error:function(e){$('btnNewSave').disabled=false;var msg='\u062e\u0637\u0623';try{if(e&&e._server_messages)msg=JSON.parse(JSON.parse(e._server_messages)[0]).message||msg;}catch(ex){}showSt('newStatus',msg,'error');}
        });
    }

    function showSt(id,msg,t){var el=$(id);el.textContent=msg;el.className='um-status '+t;el.style.display='block';}

    window.toggleUMSection=function(id,head){
        var body=$(id);
        if(body.classList.contains('hidden')){body.classList.remove('hidden');head.classList.remove('collapsed');}
        else{body.classList.add('hidden');head.classList.add('collapsed');}
    };
    window.closeUMModal=function(){$('umOverlay').style.display='none';$('umModal').style.display='none';};
})();

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');
header.navbar, .navbar, .top-navbar, footer, .web-footer { display:none !important; }
body { padding:0 !important; margin:0 !important; background:#bfeaf4; font-family:"Cairo",sans-serif; direction:rtl; color:#0b1b22; }
.page_content, .page-content, main, .main-section { margin:0 !important; padding:0 !important; }

:root{ --bg:#bfeaf4; --yellow:#ffd23c; --yellow2:#ffe26b; --green:#2f8f3a; --green2:#2aa334; --shadow:0 10px 30px rgba(0,0,0,.08); }
.sr-topbar{ position:sticky; top:0; z-index:50; display:flex; gap:10px; align-items:center; padding:10px 12px; background:rgba(255,255,255,.35); border-bottom:1px solid rgba(0,0,0,.15); backdrop-filter: blur(6px); }
