.edit-table-input:focus { outline:none; border-color:var(--green); box-shadow: 0 0 0 2px rgba(47,143,58,0.2); }

javascript:
const el = (id) => document.getElementById(id);
const fmt = (n) => Number(n||0).toLocaleString(undefined, {minimumFractionDigits:2});
let agentsData = [];
let rawCustomerData = { orders: [], payments: [] };

function init(){
    loadAgents();
    el("cmAgent").addEventListener("change", populateCustomers);
    el("cmCustomer").addEventListener("change", loadCustomerData);
}

function loadAgents(){
    frappe.call({ method: "cm-get-customers-3", callback: (r) => {
        const sel = el("cmAgent"); sel.innerHTML = '<option value="">اختر المندوب...</option>';
        if(r.message){
            agentsData = r.message;
            agentsData.forEach(a => { sel.appendChild(new Option(a.agent_name, a.agent_email)); });
        }
    }});
}

function populateCustomers(){
    const email = el("cmAgent").value;
    const sel = el("cmCustomer"); sel.innerHTML = '<option value="">اختر الزبون...</option>';
    el("cmKpis").style.display = "none"; el("cmOrdersTb").innerHTML = ''; el("cmPaymentsTb").innerHTML = '';

    if(!email) return;
    const agent = agentsData.find(a => a.agent_email === email);
    if(agent && agent.customers){
        agent.customers.forEach(c => { sel.appendChild(new Option(c.customer_name || c.name, c.name)); });
    }
}

function loadCustomerData(){
    const customer = el("cmCustomer").value;
    if(!customer) return;

    el("cmOrdersTb").innerHTML = '<tr><td colspan="4">⏳ جاري التحميل...</td></tr>';

    frappe.call({
        method: "cm-get-customer-data-3",
        args: { customer: customer },
        callback: (r) => {
            if(r.message){
                rawCustomerData = r.message;
                el("cmKpis").style.display = "grid";
                renderOrders(r.message.orders);
                renderPayments(r.message.payments);

                const totOrd = (r.message.orders||[]).reduce((sum, o) => sum + (o.total_cost || o.grand_total || 0), 0);
                const totPay = (r.message.payments||[]).reduce((sum, p) => sum + (p.received || p.paid_amount || 0), 0);
                el("cmTotalOrders").innerText = fmt(totOrd);
                el("cmTotalPayments").innerText = fmt(totPay);
            }
        }
    });
}

function renderOrders(orders){
    const tb = el("cmOrdersTb"); tb.innerHTML = "";
    if(!orders.length) return tb.innerHTML = '<tr><td colspan="4">لا توجد طلبات</td></tr>';
    orders.forEach(o => {
        const tr = document.createElement("tr");
        tr.className = "clickable";
        tr.onclick = () => openOrderModal(o);
        tr.innerHTML = `<td class="name">${o.invoice || o.name}</td><td>${o.order_date || ''}</td><td class="num">${fmt(o.total_cost)}</td><td>${o.order_status || ''}</td>`;
        tb.appendChild(tr);
    });
}

function renderPayments(payments){
    const tb = el("cmPaymentsTb"); tb.innerHTML = "";
    if(!payments.length) return tb.innerHTML = '<tr><td colspan="3">لا توجد دفعات</td></tr>';
    payments.forEach(p => {
        const tr = document.createElement("tr");
        tr.className = "clickable";
        tr.onclick = () => openPaymentModal(p);
        tr.innerHTML = `<td class="name">${p.receipt_number || p.name}</td><td>${p.date || ''}</td><td class="num">${fmt(p.received)}</td>`;
        tb.appendChild(tr);
    });
}

function closeModal(){ 
    el("cmModalOverlay").style.display = "none"; 
}

function openPaymentModal(p){
    el("cmModalTitle").innerText = "تفاصيل دفعة: " + (p.receipt_number || p.name);
    el("cmModalBody").innerHTML = `
        <div class="modal-group">
            <label>المبلغ المستلم (Received)</label>
            <input type="number" id="modPayAmount" value="${p.received || 0}" disabled style="background:#e9ecef;">
        </div>
        <div class="modal-group">
            <label>التاريخ (Date)</label>
            <input type="date" id="modPayDate" value="${p.date || ''}" disabled style="background:#e9ecef;">
        </div>
    `;

    el("cmSaveBtn").onclick = () => saveSingleRecord("LMT Payment", p.name, {
        received: parseFloat(el("modPayAmount").value) || 0,
        date: el("modPayDate").value
    });

    el("cmModalOverlay").style.display = "flex";
}

function openOrderModal(o){
    el("cmModalTitle").innerText = "تفاصيل الطلب: " + (o.invoice || o.name);

    // HEADER SECTION: Disabled (Read-Only)
    el("cmModalBody").innerHTML = `
        <div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(120px, 1fr)); gap:10px;">
            <div class="modal-group">
                <label>التاريخ</label>
                <input type="date" id="modOrdDate" value="${o.order_date || o.transaction_date || ''}" disabled style="background:#e9ecef;">
            </div>
            <div class="modal-group">
                <label>الحالة</label>
                <select id="modOrdStatus" disabled style="background:#e9ecef; opacity:1;">
                    <option value="Complete" ${o.order_status=='Complete'?'selected':''}>Complete</option>
                    <option value="Draft" ${o.order_status=='Draft'?'selected':''}>Draft</option>
                    <option value="Cancelled" ${o.order_status=='Cancelled'?'selected':''}>Cancelled</option>
                </select>
            </div>
            <div class="modal-group">
                <label>الإجمالي (Gross)</label>
                <input type="number" id="modOrdTotal2" value="${o.order_total2 || 0}" disabled style="background:#e9ecef;">
            </div>
            <div class="modal-group">
                <label>الخصم (Discount)</label>
                <input type="number" step="0.01" id="modOrdDiscount" value="${o.discount || 0}" disabled style="background:#e9ecef;">
            </div>
            <div class="modal-group">
                <label>الصافي (Net)</label>
                <div style="display:flex; gap:5px;">
                    <input type="number" id="modOrdTotal" value="${o.total_cost || 0}" disabled style="flex:1; background:#e9ecef;">
                    <button class="sr-btn-icon" onclick="recalculateOrderTotal()" title="إعادة الحساب" style="border-radius:8px; padding:0 12px; background:var(--yellow); border:1px solid rgba(0,0,0,0.2);">🧮</button>
                </div>
            </div>
        </div>
        <hr style="border:0; border-top:1px solid rgba(0,0,0,0.1); margin:10px 0;">
        <h4 style="margin:0; font-weight:900;">الأصناف (جاري التحميل...)</h4>

        <div class="sr-table-wrap" style="overflow-x:auto;">
            <table style="width:100%; min-width:700px; margin:0;">
                <thead>
                    <tr>
                        <th style="text-align:right">الصنف</th>
                        <th style="width:80px">الكمية</th>
                        <th style="width:100px">السعر</th>
                        <th style="width:80px">مجاني</th>
                        <th style="width:100px">الإجمالي</th>
                    </tr>
                </thead>
                <tbody id="modOrdItemsList">
                    <tr><td colspan="5" style="text-align:center;">⏳ جاري التحميل...</td></tr>
                </tbody>
            </table>
        </div>
    `;

    el("cmSaveBtn").onclick = () => saveOrderAndItems(o.name);
    el("cmModalOverlay").style.display = "flex";

    frappe.call({
        method: "cm-get-order-items-3",
        args: { order_id: o.name, invoice: o.invoice },
        callback: (r) => {
            const list = el("modOrdItemsList");
            list.innerHTML = "";

            if(!r.message || r.message.length === 0){
                list.innerHTML = "<tr><td colspan='5' style='text-align:center; padding:20px;'>لا توجد أصناف تابعة لهذا الطلب</td></tr>"; 
                return;
            }

            el("cmModalBody").querySelector("h4").innerText = `الأصناف (${r.message.length})`;

            r.message.forEach(item => {
                const tr = document.createElement("tr");
                tr.dataset.itemname = item.name;

                const productName = item.product_name2 || item.name;
                const isActuallyFree = (item.free == 1); 
                const lineTotal = isActuallyFree ? 0 : (item.quantity || 0) * (item.price || 0);

                // ITEMS SECTION: Unlocked and active!
                tr.innerHTML = `
                    <td class="name" style="white-space:normal; font-size:14px;">${productName}</td>
                    <td style="padding:6px;"><input type="number" class="edit-table-input item-qty" value="${item.quantity || 0}" oninput="recalculateOrderTotal()"></td>
                    <td style="padding:6px;"><input type="number" class="edit-table-input item-price" value="${item.price || 0}" oninput="recalculateOrderTotal()"></td>
                    <td style="padding:6px;">
                        <select class="edit-table-input item-free" onchange="recalculateOrderTotal()">
                            <option value="0" ${!isActuallyFree?'selected':''}>لا</option>
                            <option value="1" ${isActuallyFree?'selected':''}>نعم</option>
                        </select>
                    </td>
                    <td style="padding:6px; text-align:center; font-weight:900; color:var(--green);" class="item-line-total">${fmt(lineTotal)}</td>
                `;
                list.appendChild(tr);
            });
        }
    });
}

function recalculateOrderTotal() {
    let order_total2 = 0;
    const itemRows = document.querySelectorAll("#modOrdItemsList tr[data-itemname]");

    // Calculates Gross Total from items
    itemRows.forEach(tr => {
        const qty = parseFloat(tr.querySelector(".item-qty").value) || 0;
        const price = parseFloat(tr.querySelector(".item-price").value) || 0;
        const isFree = tr.querySelector(".item-free").value === "1";

        const lineTotal = isFree ? 0 : (qty * price);
        tr.querySelector(".item-line-total").innerText = fmt(lineTotal);
        order_total2 += lineTotal;
    });

    el("modOrdTotal2").value = order_total2;

    // Reads the LOCKED discount percentage from the header
    const rawDiscount = parseFloat(el("modOrdDiscount").value) || 0;
    const discountDecimal = rawDiscount > 1 ? (rawDiscount / 100) : rawDiscount; 

    // Applies the percentage to the new Gross Total to find the Net Total
    const total_cost = order_total2 - (discountDecimal * order_total2);

    el("modOrdTotal").value = total_cost;
}

function saveSingleRecord(doctype, docname, updatesObj){
    el("cmSaveBtn").innerText = "جاري الحفظ...";
    el("cmSaveBtn").disabled = true;

    frappe.call({
        method: "cm-update-record-3",
        args: { doctype: doctype, docname: docname, updates: JSON.stringify(updatesObj) },
        callback: (r) => {
            el("cmSaveBtn").innerText = "حفظ التغييرات";
            el("cmSaveBtn").disabled = false;
            if(r.message && r.message.status === "success"){
                frappe.show_alert({message: "تم الحفظ بنجاح!", indicator: 'green'});
                closeModal();
                loadCustomerData(); 
            } else {
                frappe.msgprint("Error: " + (r.message ? r.message.message : "Unknown Error"));
            }
        }
    });
}

function saveOrderAndItems(orderName){
    el("cmSaveBtn").innerText = "جاري الحفظ...";
    el("cmSaveBtn").disabled = true;

    // Ensure final math is perfect
    recalculateOrderTotal(); 

    // Package the payload
    const payload = {
        order_name: orderName,
        order_updates: {
            order_date: el("modOrdDate").value,
            order_status: el("modOrdStatus").value,
            order_total2: parseFloat(el("modOrdTotal2").value) || 0,
            discount: parseFloat(el("modOrdDiscount").value) || 0,
            total_cost: parseFloat(el("modOrdTotal").value) || 0
        },
        items: []
    };

    const itemRows = document.querySelectorAll("#modOrdItemsList tr[data-itemname]");
    itemRows.forEach(tr => {
        const qty = parseFloat(tr.querySelector(".item-qty").value) || 0;
        const price = parseFloat(tr.querySelector(".item-price").value) || 0;
        const freeVal = tr.querySelector(".item-free").value;

        payload.items.push({
            name: tr.dataset.itemname,
            updates: {
                quantity: qty,
                price: price,
                free: freeVal,
                total: freeVal === "1" ? 0 : (qty * price)
            }
        });
    });

    frappe.call({
        method: "cm-save-full-order-3",
        args: { payload: JSON.stringify(payload) },
        callback: (r) => {
            el("cmSaveBtn").innerText = "حفظ التغييرات";
            el("cmSaveBtn").disabled = false;

            if(r.message && r.message.status === "success"){
                frappe.show_alert({message: "تم حفظ الطلب والأصناف بنجاح!", indicator: 'green'});
                closeModal();
                loadCustomerData(); 
            } else {
                frappe.msgprint({
                    title: 'خطأ أثناء الحفظ',
                    indicator: 'red',
                    message: "Error: " + (r.message ? r.message.message : "Server Failed")
                });
            }
        }
    });
}

frappe.ready(init);

css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;600;700;900&display=swap');

:root{
    --bg-main: #bfeaf4;
    --yellow: #ffd23c;
    --yellow-light: #ffe26b;
    --green: #2f8f3a;
    --green2: #2aa334;
    --red: #e74c3c;
    --orange: #f39c12;
    --blue: #3498db;
    --shadow: 0 10px 30px rgba(0,0,0,.08);
    --text: #0b1b22;
}

body, html {
    padding:0 !important; margin:0 !important;
    background:var(--bg-main) !important;
    font-family:"Cairo",sans-serif !important;
    direction:rtl; color:var(--text); min-height:100vh;
}
header.navbar, .navbar, .top-navbar, footer, .web-footer { display:none !important; }
.page_content, .page-content, main, .main-section { margin:0 !important; padding:0 !important; }

.sr-topbar {
    display: flex !important;
    justify-content: space-between !important;
    align-items: center !important;
    padding: 0 15px !important;
    height: 65px !important;
    width: 100% !important;
    box-sizing: border-box !important;
    direction: ltr !important;
    background: rgba(255,255,255,0.4) !important;
    backdrop-filter: blur(10px) !important;
    border-bottom: 1px solid rgba(0,0,0,0.1) !important;
    position: fixed; top:0; left:0; right:0; z-index:1100;
}
.topbar-left  { display:flex !important; gap:8px !important; order:1 !important; }
.topbar-right { display:flex !important; align-items:center !important; gap:12px !important; order:2 !important; direction:rtl !important; }
.sr-title     { text-align:right !important; margin:0 !important; font-weight:900; font-size:16px; color:var(--text); }

.sr-btn-icon {
    background-color: var(--yellow-light) !important;
    border: 1px solid rgba(0,0,0,0.2) !important;
    border-radius: 999px !important;
    font-size: 16px !important; font-weight:900 !important;
    cursor: pointer !important;
    width:40px !important; height:40px !important;
    display:flex !important; align-items:center !important; justify-content:center !important;
    box-shadow:var(--shadow) !important;
    color:var(--text) !important; padding:0 !important;
}

.sr-wrap    { max-width:1100px; margin:0 auto; padding:85px 14px 30px; }
.sr-filters { display:grid; gap:10px; margin-bottom:14px; }

.sr-pill {
    background:var(--yellow);
    border:1px solid rgba(0,0,0,.25);
    border-radius:999px;
    padding:10px 14px;
    box-shadow:var(--shadow);
    display:flex; align-items:center; justify-content:space-between; gap:10px;
}
.sr-pill label { font-weight:900; white-space:nowrap; margin-left:10px; min-width:60px; color:var(--text); }

.year-pill { border-radius:18px !important; padding:10px 14px !important; flex-wrap:wrap; }
#yearBtns  { display:flex; gap:6px; flex-wrap:wrap; justify-content:flex-end; flex:1; }
.yr-btn {
    border:1.5px solid rgba(0,0,0,0.25); border-radius:999px;
    padding:4px 14px; font-family:"Cairo",sans-serif;
    font-weight:900; font-size:13px; cursor:pointer;
    background:rgba(255,255,255,0.55); color:var(--text); transition:0.15s;
}
.yr-btn.active { background:var(--green); color:#fff; border-color:var(--green); }
.yr-btn:active { transform:scale(0.94); }

.sr-actions { display:flex; gap:10px; flex-wrap:wrap; }
.sr-btn {
    border:1px solid rgba(0,0,0,.25); cursor:pointer; border-radius:999px;
    padding:10px 20px; font-family:"Cairo",sans-serif;
    font-weight:900; box-shadow:var(--shadow);
    background:var(--yellow-light); color:var(--text); transition:0.2s;
}
.sr-btn:active { transform:scale(0.95); }
.sr-btn.primary { background:var(--yellow); }
.sr-btn.print   { background:#ff7a7a; color:#fff; border-color:rgba(0,0,0,0.1); }

.sr-kpis-4 {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 10px;
    margin: 10px 0 15px;
}
.sr-kpis-3 {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 10px;
    margin: 5px 0 10px;
}
.sr-kpis-1 {
    display: grid;
    grid-template-columns: 1fr;
    gap: 10px;
    margin: 5px 0 10px;
    max-width: 300px;
}
.sr-section-title {
    font-weight: 900;
    font-size: 15px;
    color: var(--text);
    margin: 15px 0 5px;
    padding-right: 5px;
}
.sr-kpi {
    border: 1px solid rgba(0,0,0,.12);
    border-radius: 14px;
    padding: 14px 10px;
    box-shadow: var(--shadow);
    text-align: center;
    color: #fff;
}
.sr-kpi .t { font-weight:700; font-size:11px; margin-top:5px; opacity:0.95; }
.sr-kpi .v { font-weight:900; font-size:24px; }
.kpi-ok   { background: linear-gradient(180deg, #4CAF50, var(--green)); }
.kpi-bad  { background: linear-gradient(180deg, #ff6b6b, var(--red)); }
.kpi-info { background: linear-gradient(180deg, #5dade2, var(--blue)); }
.kpi-warn { background: linear-gradient(180deg, #f5b041, var(--orange)); }

.sr-loading {
    text-align:center; padding:40px; font-size:16px; font-weight:800;
    color:var(--text); background:rgba(255,255,255,.4);
    border-radius:12px; box-shadow:var(--shadow);
}

.stitle {
    color:#fff; padding:10px 18px; border-radius:999px;
    margin:20px 0 10px; display:inline-block;
    font-weight:900; font-size:14px; box-shadow:var(--shadow);
}
.st-red { background: linear-gradient(180deg, #ff6b6b, var(--red)); }
.st-org { background: linear-gradient(180deg, #f5b041, var(--orange)); }

.sr-table-wrap {
    border-radius:12px; overflow-x:auto;
    border:2px solid #555; box-shadow:var(--shadow);
    margin-top:10px; -webkit-overflow-scrolling:touch;
    background:#fff;
}
table { width:100%; border-collapse:collapse; min-width:500px; }

thead th {
    background:linear-gradient(180deg,var(--green2),var(--green)) !important;
    color:#fff !important; padding:12px 8px; font-weight:900; font-size:14px;
    border-left:1.5px solid #333 !important;
    border-bottom:1.5px solid #333 !important;
    text-align:center; white-space:nowrap;
}
tbody td {
    border-top:1.5px solid #555 !important;
    border-left:1.5px solid #555 !important;
    padding:10px 8px; font-weight:800; font-size:13px;
    text-align:center; white-space:nowrap; color:var(--text);
}
tbody tr:nth-child(odd)  td { background-color:var(--yellow-light) !important; }
tbody tr:nth-child(even) td { background-color:var(--bg-main) !important; }
tbody tr:hover { filter:brightness(0.95); }
tbody td a { color:#0056b3; text-decoration:none; font-weight:900; }
tbody td a:hover { text-decoration:underline; }

.sr-clean {
    text-align:center; padding:40px 20px;
    background:linear-gradient(180deg, #4CAF50, var(--green));
    color:#fff; border-radius:14px;
    font-size:20px; font-weight:900;
    box-shadow:var(--shadow); margin:20px 0;
}

javascript:
function init(){
  document.querySelectorAll(".yr-btn").forEach(btn => {
    btn.addEventListener("click", function(){
      document.querySelectorAll(".yr-btn").forEach(b => b.classList.remove("active"));
      this.classList.add("active");
      doCheck();
    });
  });
  document.getElementById("srRun").addEventListener("click", doCheck);
  doCheck();
}

function getYear(){
  const active = document.querySelector(".yr-btn.active");
  return active ? active.dataset.year : "2026";
}

function setKpiClass(el, count, goodClass, badClass){
  el.classList.remove(goodClass, badClass);
  el.classList.add(count === 0 ? goodClass : badClass);
}

function doCheck() {
  const y = getYear();
  document.getElementById('srRun').innerText = "⏳";
  document.getElementById('ld').style.display = 'block';
  document.getElementById('res').style.display = 'none';

  fetch('/api/method/health_check?year=' + y, {
    headers: {
      'X-Frappe-CSRF-Token': frappe.csrf_token,
      'Accept': 'application/json'
    }
  })
  .then(r => r.json())
  .then(r => {
    const d = r.message;
    document.getElementById('srRun').innerText = "تحديث";

    // Invoices
    document.getElementById('vNoTeam').innerText = d.no_team.length;
    document.getElementById('vOk').innerText = d.ok;
    document.getElementById('vTotal').innerText = d.total;

    // Sales Orders
    document.getElementById('vSoNoTeam').innerText = d.so_no_team.length;
    document.getElementById('vSoOk').innerText = d.so_ok;
    document.getElementById('vSoTotal').innerText = d.total_so;

    // Delivery Notes
    document.getElementById('vDnNoTeam').innerText = d.dn_no_team.length;
    document.getElementById('vDnTotal').innerText = d.total_dn;
    document.getElementById('vDnRegular').innerText = d.total_dn_regular;
    document.getElementById('vDnReturns').innerText = d.total_dn_returns;

    setKpiClass(document.getElementById('kpiNoTeam'), d.no_team.length, 'kpi-ok', 'kpi-bad');
    setKpiClass(document.getElementById('kpiSoNoTeam'), d.so_no_team.length, 'kpi-ok', 'kpi-bad');
    setKpiClass(document.getElementById('kpiDnNoTeam'), d.dn_no_team.length, 'kpi-ok', 'kpi-bad');

    let h = '';

    if (d.no_team.length > 0) {
      h += '<div class="stitle st-red">❌ فواتير بدون فريق مبيعات (' + d.no_team.length + ')</div>';
      h += '<div class="sr-table-wrap"><table><thead><tr><th>#</th><th>الفاتورة</th><th>المالك</th><th>التاريخ</th><th>العميل</th></tr></thead><tbody>';
      d.no_team.forEach((row, i) => {
        h += '<tr><td>' + (i + 1) + '</td>';
        h += '<td><a href="/app/sales-invoice/' + row.name + '" target="_blank">' + row.name + '</a></td>';
        h += '<td>' + row.owner_name + '</td>';
        h += '<td>' + row.posting_date + '</td>';
        h += '<td>' + (row.customer || '') + '</td></tr>';
      });
      h += '</tbody></table></div>';
    }

    if (d.so_no_team.length > 0) {
      h += '<div class="stitle st-red">⚠️ أوامر بيع بدون فريق مبيعات (' + d.so_no_team.length + ')</div>';
      h += '<div class="sr-table-wrap"><table><thead><tr><th>#</th><th>أمر البيع</th><th>المالك</th><th>التاريخ</th><th>العميل</th></tr></thead><tbody>';
      d.so_no_team.forEach((row, i) => {
        h += '<tr><td>' + (i + 1) + '</td>';
        h += '<td><a href="/app/sales-order/' + row.name + '" target="_blank">' + row.name + '</a></td>';
        h += '<td>' + row.owner_name + '</td>';
        h += '<td>' + row.transaction_date + '</td>';
        h += '<td>' + (row.customer_name || '') + '</td></tr>';
      });
      h += '</tbody></table></div>';
    }

    if (d.dn_no_team.length > 0) {
      h += '<div class="stitle st-red">🚚 مذكرات تسليم بدون فريق مبيعات (' + d.dn_no_team.length + ')</div>';
      h += '<div class="sr-table-wrap"><table><thead><tr><th>#</th><th>المذكرة</th><th>المالك</th><th>التاريخ</th><th>العميل</th></tr></thead><tbody>';
      d.dn_no_team.forEach((row, i) => {
        h += '<tr><td>' + (i + 1) + '</td>';
        h += '<td><a href="/app/delivery-note/' + row.name + '" target="_blank">' + row.name + '</a></td>';
        h += '<td>' + row.owner_name + '</td>';
        h += '<td>' + row.posting_date + '</td>';
        h += '<td>' + (row.customer || '') + '</td></tr>';
      });
      h += '</tbody></table></div>';
    }

    if (d.standalone_dn && d.standalone_dn.length > 0) {
  h += '<div class="stitle st-org">ℹ️ مذكرات بدون أمر بيع - مرتجعات أو مباشر (' + d.standalone_dn.length + ')</div>';
  h += '<div class="sr-table-wrap"><table><thead><tr><th>#</th><th>المذكرة</th><th>النوع</th><th>المالك</th><th>التاريخ</th><th>العميل</th><th>القيمة</th></tr></thead><tbody>';
  d.standalone_dn.forEach((row, i) => {
    h += '<tr><td>' + (i + 1) + '</td>';
    h += '<td><a href="/app/delivery-note/' + row.name + '" target="_blank">' + row.name + '</a></td>';
    h += '<td>' + row.type + '</td>';
    h += '<td>' + row.owner_name + '</td>';
    h += '<td>' + row.posting_date + '</td>';
    h += '<td>' + (row.customer || '') + '</td>';
    h += '<td>' + (row.grand_total || 0).toLocaleString() + '</td></tr>';
  });
  h += '</tbody></table></div>';
}

    if (d.no_team.length === 0 && d.so_no_team.length === 0 && d.dn_no_team.length === 0) {
      h = '<div class="sr-clean">✅ جميع المستندات سليمة</div>';
    }

    document.getElementById('ld').style.display = 'none';
    document.getElementById('res').style.display = 'block';
    document.getElementById('res').innerHTML = h;
  });
}

frappe.ready(init);
